import React, { useState, useEffect, useRef, useMemo } from "react";

// ── ErrorBoundary — prevents white screens ──
class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, info) { console.error("ErrorBoundary caught:", error, info); }
  render() {
    if (this.state.hasError) {
      return React.createElement("div", { style: { position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }, onClick: () => this.setState({ hasError: false, error: null }) },
        React.createElement("div", { style: { background:"#1a1a2e", border:"1px solid rgba(245,158,11,.3)", borderRadius:16, padding:32, textAlign:"center", maxWidth:400 }, onClick: e => e.stopPropagation() },
          React.createElement("p", { style: { fontSize: 36, marginBottom: 12 } }, "⚠️"),
          React.createElement("p", { style: { color: "#f59e0b", fontWeight: 700, fontSize: 16, marginBottom: 8 } }, "حدث خطأ في عرض هذا القسم"),
          React.createElement("p", { style: { color: "#9ca3af", fontSize: 12, marginBottom: 16, direction:"ltr", wordBreak:"break-all" } }, String(this.state.error?.message || "")),
          React.createElement("button", { onClick: () => this.setState({ hasError: false, error: null }), style: { padding: "10px 24px", borderRadius: 10, border: "1px solid #f59e0b", background: "rgba(245,158,11,.1)", color: "#f59e0b", cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize:14 } }, "🔄 إعادة المحاولة")
        )
      );
    }
    return this.props.children;
  }
}

const API   = "/api/ai";        // موحد — كل النماذج عبر ai.js
const AI    = "/api/ai";        // نفس النقطة

const MODEL          = "claude-sonnet-4-20250514";
const MODEL_GEMINI   = "gemini-3.1-pro";
const MODEL_FLASH    = "gemini-2.5-flash";
const MODEL_DEEPSEEK = "deepseek-chat";
const MODEL_GPT     = "gpt-4o-mini";

// دالة استدعاء موحدة تدعم كل النماذج — مع إعادة محاولة + احتياطي
const AI_FALLBACK_ORDER = [MODEL_GEMINI, MODEL_FLASH, MODEL];

async function _callAISingle(msgs, sys, model, hdrs) {
  const fetchHeaders = { "Content-Type": "application/json" };
  if (hdrs?.["anthropic-beta"]) fetchHeaders["anthropic-beta"] = hdrs["anthropic-beta"];
  const res = await fetch(AI, {
    method: "POST",
    headers: fetchHeaders,
    body: JSON.stringify({ model, max_tokens: 4000, system: sys, messages: msgs }),
  });
  const d = await res.json();
  if (!res.ok) {
    const errMsg = d?.error?.message || ("API error " + res.status);
    if (res.status === 413) throw new Error("الملف كبير جداً — حاول ملفاً أصغر أو انسخ النص يدوياً");
    throw new Error(errMsg);
  }
  const text = d?.content?.[0]?.text || d?.candidates?.[0]?.content?.parts?.[0]?.text || "";
  if (!text) throw new Error("لم يرد الذكاء الاصطناعي بأي نص");
  return text;
}

async function callAIModel(msgs, sys, model, hdrs) {
  const usedModel = model || MODEL;
  // Build fallback list: requested model first, then others
  const fallbacks = [usedModel, ...AI_FALLBACK_ORDER.filter(m => m !== usedModel)];
  let lastErr = null;

  for (const tryModel of fallbacks) {
    // Try up to 2 times per model
    for (let attempt = 0; attempt < 2; attempt++) {
      try {
        if (attempt > 0) await new Promise(r => setTimeout(r, 2000)); // Wait 2s before retry
        const text = await _callAISingle(msgs, sys, tryModel, hdrs);
        if (tryModel !== usedModel) console.log("⚡ AI fallback: " + usedModel + " → " + tryModel);
        // Parse JSON
        let clean = text.replace(/```json\s*/gi,"").replace(/```\s*/g,"").trim();
        const s1 = clean.indexOf("{"), e1 = clean.lastIndexOf("}");
        if (s1 !== -1 && e1 !== -1) { try { return JSON.parse(clean.slice(s1, e1 + 1)); } catch {} }
        const s2 = clean.indexOf("["), e2 = clean.lastIndexOf("]");
        if (s2 !== -1 && e2 !== -1) { try { return JSON.parse(clean.slice(s2, e2 + 1)); } catch {} }
        return { _rawText: text, fullName: "" };
      } catch(err) {
        lastErr = err;
        console.warn("AI attempt failed (" + tryModel + " #" + (attempt+1) + "):", err.message);
      }
    }
  }
  throw lastErr || new Error("فشلت كل محاولات الذكاء الاصطناعي — حاول مرة أخرى لاحقاً");
}

