// دالة Migration — تحديث مرشحي قاعدة البيانات (تعمل مرة واحدة فقط v37.60)
// ══════════════════════════════════════════════════════════════════════════════
const MIGRATION_VERSION = "v37.60";

// خريطة تحويل الـ IDs
const SPEC_ID_MIGRATIONS = {
  "planning":  "pm_planning",
  "bim":       "bim_drafting",
  "it_ai":     "cs_sw_ai",
  "pr":        "pr_media",
};

// خريطة تحويل المسميات (primarySpec / secondarySpec نصي)
const SPEC_LABEL_MIGRATIONS = {
  "مهندس تخطيط مشاريع":              "إدارة المشاريع والتخطيط",
  "مهندس BIM ورسام هندسي":            "نمذجة BIM والرسم الهندسي",
  "تقنية المعلومات والذكاء الاصطناعي":"حاسب / برمجيات / ذكاء اصطناعي",
  "علاقات عامة وخدمة عملاء":          "علاقات عامة وخدمة عملاء / الاتصال والإعلام",
  "أمن وسلامة":                       "مهندس / أخصائي سلامة",
  "مهندس مساحة":                      "مهندس مساحة / مساح",
  "شؤون قانونية":                      "شؤون قانونية / الحقوق / القانون",
};

// خريطة تحويل hayaGrade
const HAYA_GRADE_MIGRATIONS = {
  "مهندس تحت الاختبار": "مهندس",
  "تقني": "تقني هندسة",
};

async function runMigration(db, candidatesList) {
  try {
    const migDone = await db.get("migration:" + MIGRATION_VERSION).catch(() => null);
    if (migDone) return { skipped: true, reason: "تم تطبيق هذه المرحلة من قبل" };

    let updatedCount = 0;
    const updated = [];

    for (const cand of (candidatesList || [])) {
      let changed = false;
      const c = { ...cand };

      // 1. تحديث primarySpecId
      if (c.primarySpecId && SPEC_ID_MIGRATIONS[c.primarySpecId]) {
        c.primarySpecId = SPEC_ID_MIGRATIONS[c.primarySpecId];
        changed = true;
      }
      // 2. تحديث secondarySpecId
      if (c.secondarySpecId && SPEC_ID_MIGRATIONS[c.secondarySpecId]) {
        c.secondarySpecId = SPEC_ID_MIGRATIONS[c.secondarySpecId];
        changed = true;
      }

      // 3. تحديث primarySpec (نصي)
      if (c.primarySpec && SPEC_LABEL_MIGRATIONS[c.primarySpec]) {
        c.primarySpec = SPEC_LABEL_MIGRATIONS[c.primarySpec];
        changed = true;
      }
      // 4. تحديث secondarySpec (نصي)
      if (c.secondarySpec && SPEC_LABEL_MIGRATIONS[c.secondarySpec]) {
        c.secondarySpec = SPEC_LABEL_MIGRATIONS[c.secondarySpec];
        changed = true;
      }

      // 5. تحديث biSpec (مصفوفة التصنيفات الإضافية)
      if (Array.isArray(c.biSpec)) {
        c.biSpec = c.biSpec.map(tag => {
          if (!tag) return tag;
          const label = typeof tag === "object" ? (tag.ar || tag.label || "") : tag;
          const newLabel = SPEC_LABEL_MIGRATIONS[label];
          if (newLabel) {
            changed = true;
            return typeof tag === "object" ? { ...tag, ar: newLabel, label: newLabel } : newLabel;
          }
          return tag;
        });
      }

      // 6. تحديث hayaGrade
      if (c.hayaGrade && HAYA_GRADE_MIGRATIONS[c.hayaGrade]) {
        c.hayaGrade = HAYA_GRADE_MIGRATIONS[c.hayaGrade];
        changed = true;
      }

      if (changed) {
        updatedCount++;
        updated.push(c);
        const uid = c.uid || c.idNumber || c.email;
        if (uid) await db.set("cand:" + uid, c).catch(() => {});
      }
    }

    // تسجيل اكتمال المرحلة
    await db.set("migration:" + MIGRATION_VERSION, {
      at: new Date().toISOString(),
      updated: updatedCount,
      total: (candidatesList || []).length,
    }).catch(() => {});

    return { done: true, updated: updatedCount, total: (candidatesList || []).length };
  } catch (e) {
    return { error: true, msg: String(e) };
  }
}

// ██  قاعدة البيانات                                                          ██
// ██  المصدر الأول: السيرفر (Vercel Blob)                                     ██
// ██  نسخة احتياطية: localStorage (تُكتب مع كل تعديل)                        ██
// ██  القراءة عند البدء: سيرفر أولاً → لو فاضي يقرأ localStorage             ██
// ══════════════════════════════════════════════════════════════════════════════

let _dbCache = {};
let _dbReady = false;
let _dbDirty = false;
let _dbSyncing = false;
let _dbSyncTimer = null;
let _dbModifiedKeys = new Set(); // 🔑 فقط المفاتيح اللي تغيّرت محلياً

const db = {
  init: async () => {
    try {
      const res = await fetch("/api/db?action=loadAll");
      if (res.ok) {
        const result = await res.json();
        if (result.ok && result.data) {
          _dbCache = result.data;
          // Validate indices
          const fixIdx = (prefix, idxKey) => {
            const idx = _dbCache[idxKey] || [];
            const recs = Object.keys(_dbCache).filter(k => k.startsWith(prefix) && k !== idxKey).map(k => k.slice(prefix.length));
            const missing = recs.filter(id => !idx.includes(id));
            if (missing.length > 0) {
              _dbCache[idxKey] = [...new Set([...idx, ...missing])];
              _dbModifiedKeys.add(idxKey);
              _dbDirty = true;
            }
          };
          fixIdx("c:", "c:idx");
          fixIdx("e:", "e:idx");
          fixIdx("job:", "job:idx");
          const usrIdx = _dbCache["users:idx"] || [];
          const usrRecs = Object.keys(_dbCache).filter(k => k.startsWith("user:") && k !== "users:idx").map(k => k.slice(5));
          const usrMissing = usrRecs.filter(id => !usrIdx.includes(id));
          if (usrMissing.length > 0) {
            _dbCache["users:idx"] = [...new Set([...usrIdx, ...usrMissing])];
            _dbModifiedKeys.add("users:idx");
            _dbDirty = true;
          }
        }
      }
    } catch (e) { console.warn("⚠️ Server unreachable:", e.message); }

    try { const s = localStorage.getItem("hma_session"); if (s) _dbCache["session:current"] = JSON.parse(s); } catch {}
    _dbReady = true;

    // Health check
    const kc = Object.keys(_dbCache).filter(k => k !== "session:current").length;
    const lk = parseInt(localStorage.getItem("hma_db_key_count") || "0");
    if (lk > 15 && kc < lk * 0.5) {
      try {
        const r = await fetch("/api/backup?action=load"); const d = await r.json();
        if (d.success && d.data && Object.keys(d.data).length > kc) {
          for (const [k, v] of Object.entries(d.data)) { if (k !== "session:current" && !_dbCache[k]) { _dbCache[k] = v; _dbModifiedKeys.add(k); } }
          _dbDirty = true;
        }
      } catch {}
      try { const es = _dbCache["settings:email"]; if (es?.user) fetch("/api/send-email", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ to:es.user, subject:"🚨 كوادر: فقدان بيانات", html:"<div dir='rtl'><h2 style='color:red'>🚨 "+kc+" مفتاح فقط (المتوقع "+lk+")</h2><p><a href='https://hma.engineer/#update'>تحقق</a></p></div>" }) }).catch(()=>{}); } catch {}
    }
    if (kc > 10) localStorage.setItem("hma_db_key_count", String(kc));
    if (_dbDirty) db._scheduleSync();

    // ── AUTO-REPAIR: إصلاح تلقائي عند التشغيل — بدون تدخل المستخدم ──
    if (Object.keys(_dbCache).length > 5) {
      let repairCount = 0;

      // 1. إصلاح تفعيل المرشحين
      const cidx = _dbCache["c:idx"] || [];
      for (const uid of cidx) {
        const c = _dbCache["c:" + uid];
        if (c && !c.activated && (c.activatedAt || c.evaluation || c.cvUploaded)) {
          c.activated = true;
          c.accountStatus = "مفعّل";
          if (!c.activatedAt) c.activatedAt = new Date().toISOString();
          _dbCache["c:" + uid] = c;
          _dbModifiedKeys.add("c:" + uid);
          _dbDirty = true;
          repairCount++;
        }
      }

      // 2. حذف الموظفين المكررين
      const eidx = _dbCache["e:idx"] || [];
      const empSeen = new Map();
      const empDupes = [];
      for (const uid of eidx) {
        const e = _dbCache["e:" + uid];
        if (!e) { empDupes.push(uid); continue; }
        const key = (e.email || "") + "|" + (e.idNumber || "");
        if (empSeen.has(key)) { empDupes.push(uid); } else { empSeen.set(key, uid); }
      }
      if (empDupes.length > 0) {
        for (const uid of empDupes) { delete _dbCache["e:" + uid]; _dbModifiedKeys.add("e:idx"); }
        _dbCache["e:idx"] = eidx.filter(x => !empDupes.includes(x));
        _dbDirty = true;
        repairCount += empDupes.length;
        // حذف المكررين من Redis
        for (const uid of empDupes) {
          fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"del", key:"e:"+uid }) }).catch(()=>{});
        }
      }

      // 3. حذف المستخدمين المكررين (بما فيهم المشرف المكرر)
      const uidx = _dbCache["users:idx"] || [];
      const usrSeen = new Map();
      const usrDupes = [];
      for (const uid of uidx) {
        const u = _dbCache["user:" + uid];
        if (!u) { usrDupes.push(uid); continue; }
        // المشرف: استخدم username كمفتاح فريد
        const key = u.role === "admin" ? "admin_role" : (u.email || u.username || "").toLowerCase();
        if (!key) continue;
        if (usrSeen.has(key)) {
          const oldUid = usrSeen.get(key);
          const oldU = _dbCache["user:" + oldUid];
          // احتفظ بالأقدم (الأصلي)
          if (oldU && new Date(oldU.createdAt||0) < new Date(u.createdAt||0)) {
            usrDupes.push(uid); // الجديد هو المكرر
          } else {
            usrDupes.push(oldUid); usrSeen.set(key, uid);
          }
        } else { usrSeen.set(key, uid); }
      }
      if (usrDupes.length > 0) {
        for (const uid of usrDupes) { delete _dbCache["user:" + uid]; }
        _dbCache["users:idx"] = uidx.filter(x => !usrDupes.includes(x));
        _dbModifiedKeys.add("users:idx");
        _dbDirty = true;
        repairCount += usrDupes.length;
        for (const uid of usrDupes) {
          fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"del", key:"user:"+uid }) }).catch(()=>{});
        }
      }

      if (repairCount > 0) {
        db._scheduleSync();
      }
    }
  },

  get: async (k) => {
    const v = _dbCache[k] ?? null;
    // 🛡️ Index keys MUST be arrays — auto-fix if corrupted to object/string
    if (k.endsWith(":idx") || k === "c:idx" || k === "e:idx" || k === "users:idx" || k === "job:idx") {
      if (v && !Array.isArray(v)) { console.warn("🛡️ Auto-fix: " + k + " was not array"); return []; }
    }
    return v;
  },

  set: async (k, v) => {
    if (["c:idx","e:idx","job:idx","users:idx"].includes(k) && Array.isArray(v) && v.length === 0) {
      const old = _dbCache[k]; if (Array.isArray(old) && old.length > 0) return;
    }
    _dbCache[k] = v;
    if (k === "session:current") { try { localStorage.setItem("hma_session", JSON.stringify(v)); } catch {} return; }
    // 🔒 Critical keys: save IMMEDIATELY to Redis, don't wait for sync
    if (k === "libs" || k === "job_titles" || k === "settings:email" || k === "orgchart:config") {
      try {
        await fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"set", key:k, value:v }) });
      } catch (e) { console.warn("Direct save failed:", k, e.message); }
      return; // لا تضيفه للـ sync — محفوظ مباشرة
    }
    _dbModifiedKeys.add(k);
    _dbDirty = true;
    db._scheduleSync();
  },

  del: async (k) => {
    if (["c:idx","e:idx","job:idx","users:idx"].includes(k)) return;
    delete _dbCache[k];
    if (k === "session:current") { try { localStorage.removeItem("hma_session"); } catch {} return; }
    _dbModifiedKeys.delete(k); // لا نحتاج نرسله في sync
    // 🔥 حذف فوري من Redis
    try { await fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"del", key:k }) }); } catch {}
  },

  list: async () => Object.keys(_dbCache),

  _scheduleSync: () => {
    if (_dbSyncTimer) clearTimeout(_dbSyncTimer);
    _dbSyncTimer = setTimeout(() => db._sync(), 2000);
  },

  _sync: async () => {
    if (_dbSyncing || !_dbDirty || _dbModifiedKeys.size === 0) return;
    _dbSyncing = true;
    try {
      // 🔑 أرسل فقط المفاتيح اللي تغيّرت — مش كل شيء!
      const keysToSync = [..._dbModifiedKeys];
      const payload = {};
      for (const k of keysToSync) {
        if (_dbCache[k] !== undefined) payload[k] = _dbCache[k];
      }
      if (Object.keys(payload).length === 0) { _dbDirty = false; _dbSyncing = false; return; }
      const res = await fetch("/api/db", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "sync", data: payload }),
      });
      const result = await res.json();
      if (res.ok && result.ok) {
        _dbDirty = false;
        _dbModifiedKeys.clear();
        try { localStorage.setItem("hma_db_key_count", String(Object.keys(_dbCache).filter(k=>k!=="session:current").length)); } catch {}
      }
    } catch (e) { console.error("❌ Sync:", e.message); }
    _dbSyncing = false;
  },

  forceSync: async () => { _dbDirty = true; await db._sync(); },

  refresh: async () => {
    if (!_dbReady || _dbDirty) return;
    try {
      const res = await fetch("/api/db?action=loadAll");
      const result = await res.json();
      if (result.ok && result.data && Object.keys(result.data).length > 0) {
        const sess = _dbCache["session:current"];
        _dbCache = result.data;
        if (sess) _dbCache["session:current"] = sess;
      }
    } catch {}
  },
};

// ── مزامنة قبل إغلاق الصفحة ──
window.addEventListener("beforeunload", () => {
  if (!_dbDirty || !_dbReady || _dbModifiedKeys.size === 0) return;
  // 🔑 أرسل فقط المفاتيح المعدّلة
  const payload = {};
  for (const k of _dbModifiedKeys) {
    if (_dbCache[k] !== undefined) payload[k] = _dbCache[k];
  }
  if (Object.keys(payload).length === 0) return;
  try {
    const blob = new Blob([JSON.stringify({ action: "sync", data: payload })], { type: "application/json" });
    navigator.sendBeacon("/api/db", blob);
  } catch {}
});

// ── تحديث عند العودة للصفحة ──
let _lastRefresh = 0;
window.addEventListener("focus", () => {
  const now = Date.now();
  if (_dbReady && now - _lastRefresh > 10000) {
    _lastRefresh = now;
    db.refresh();
  }
});

// ── Bilingual lib helpers ─────────────────────────────────────────────────────
// Extract Arabic label from lib item (string or {ar,en} object)
function libLabel(item, lang) {
  if (!item) return "";
  if (typeof item === "string") return item;
  if (lang === "en") return item.en || item.ar || "";
  return item.ar || item.en || "";
}
// Get all labels (for display in dropdowns etc)
// Normalize lib item to string for backward compat
// ── EmpBiBlock — simple tag editor for employee classifications ───────────────
function EmpBiBlock({ title, icon, field, data, set, libItems, isSpecs, specs }) {
  const [openCats, setOpenCats] = useState({});
  const [newVal, setNewVal] = useState("");
  const [moveIdx, setMoveIdx] = useState(null);
  const [moveSub, setMoveSub] = useState(null); // "other" or category name
  const tags = (data[field] || []).filter(t => !(t && typeof t === "object" && t.source === "screening"));
  const tagLabels = new Set(tags.map(t => (t.ar||t.en||"").toLowerCase().trim()).filter(Boolean));
  // Source tracking: green = from CV (arSource=cv/auto), yellow = user-added or not in lib
  const cvTags = new Set(tags.filter(t => t.arSource === "cv" || t.arSource === "auto").map(t => (t.ar||t.en||"").toLowerCase().trim()));

  const toggleCat = (cat) => setOpenCats(p => ({ ...p, [cat]: !p[cat] }));

  const addTag = (val, approved = true) => {
    if (!val.trim()) return;
    const exists = tagLabels.has(val.trim().toLowerCase());
    if (exists) return;
    set(field, [...tags, { ar: val.trim(), en: "", approved, arSource: "user" }]);
    setNewVal("");
  };
  const removeTag = (label) => set(field, tags.filter(t => (t.ar||t.en||"").toLowerCase() !== label.toLowerCase()));
  const isSelected = (label) => tagLabels.has(label.toLowerCase().trim());
  const isCv = (label) => cvTags.has(label.toLowerCase().trim());

  const getColor = (label) => {
    if (!isSelected(label)) return "gray";
    if (isCv(label)) return "green";
    return "yellow";
  };

  const tagStyle = (color) => ({
    padding: "6px 14px", borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: "pointer", display: "inline-flex", alignItems: "center", gap: 4, transition: "all .15s",
    background: color === "green" ? "#D1FAE5" : color === "yellow" ? "#FEF3C7" : "#F3F4F6",
    border: "1px solid " + (color === "green" ? "#6EE7B7" : color === "yellow" ? "#FCD34D" : "#D1D5DB"),
    color: color === "green" ? "#065F46" : color === "yellow" ? "#92400E" : "#374151",
    boxShadow: "0 1px 2px rgba(0,0,0,.04)",
  });

  // For specs: use hierarchical structure
  if (isSpecs && specs) {
    return (
      <div className="card" style={{ marginBottom: 10 }}>
        <div className="sec" style={{ marginBottom: 8 }}>{icon + " " + title}</div>
        <div style={{ display: "flex", gap: 6, fontSize: 10, color: "var(--text3)", marginBottom: 10 }}>
          <span style={{ color: "#065F46", background:"#D1FAE5", padding:"2px 8px", borderRadius:6, border:"1px solid #6EE7B7" }}>🟢 من السيرة الذاتية</span>
          <span style={{ color: "#92400E", background:"#FEF3C7", padding:"2px 8px", borderRadius:6, border:"1px solid #FCD34D" }}>🟡 مختار</span>
          <span style={{ color: "var(--text3)", background:"var(--input-bg)", padding:"2px 8px", borderRadius:6, border:"1px solid var(--input-border)" }}>⬜ متاح</span>
        </div>
        {specs.map(spec => {
          const isOpen = openCats[spec.id];
          const subLabels = (spec.subs || []).map(s => s.ar || s.en || "");
          const selectedCount = subLabels.filter(l => isSelected(l)).length + (isSelected(spec.label) ? 1 : 0);
          return (
            <div key={spec.id} style={{ marginBottom: 6, border: "1px solid var(--b)", borderRadius: 10, overflow: "hidden" }}>
              <div onClick={() => toggleCat(spec.id)}
                style={{ padding: "8px 12px", background: selectedCount > 0 ? "rgba(34,197,94,.08)" : "rgba(255,255,255,.02)", cursor: "pointer", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <span style={{ fontSize: 12, fontWeight: 700, color: selectedCount > 0 ? "#16a34a" : "var(--text2)" }}>
                  {spec.icon} {spec.label} {selectedCount > 0 && <span style={{ fontSize: 10, color: "#16a34a" }}>({selectedCount})</span>}
                </span>
                <span style={{ fontSize: 10, color: "var(--text3)" }}>{isOpen ? "▲" : "▼"}</span>
              </div>
              {isOpen && (
                <div style={{ padding: "8px 12px", display: "flex", flexWrap: "wrap", gap: 5 }}>
                  {(spec.subs || []).map((sub, si) => {
                    const lbl = sub.ar || sub.en || "";
                    const color = getColor(lbl);
                    const sel = isSelected(lbl);
                    const showMv = sel && moveIdx === spec.id+"_"+si;
                    const MOVE_TARGETS = [
                      { f:"biDept", label:"🏢 الإدارات" },
                      { f:"biSkill", label:"🛠️ المهارات" },
                      { f:"biSW", label:"💻 البرامج" },
                      { f:"biProj", label:"📋 أنواع المشاريع" },
                      { f:"biCert", label:"🏅 الشهادات" },
                    ];
                    const mS = { display:"block", width:"100%", textAlign:"right", padding:"5px 8px", borderRadius:5, border:"none", cursor:"pointer", fontFamily:"inherit", fontSize:11, color:"var(--text2)", background:"transparent", marginBottom:1 };
                    return (
                      <span key={si} style={{ ...tagStyle(color), position:"relative" }}
                        onClick={() => { if (!sel) addTag(lbl); }}>
                        {lbl} {sel && "✓"}
                        {sel && <>
                          <button onClick={e=>{e.stopPropagation(); setMoveIdx(showMv?null:spec.id+"_"+si); setMoveSub(null);}} style={{ background:"none", border:"none", cursor:"pointer", color:"inherit", fontSize:10, padding:"0 2px", lineHeight:1, opacity:0.6 }} title="نقل / تحويل">↔</button>
                          <button onClick={e=>{e.stopPropagation(); removeTag(lbl);}} style={{ background:"none", border:"none", cursor:"pointer", color:"inherit", fontSize:12, padding:0, lineHeight:1 }}>✕</button>
                        </>}
                        {showMv && (
                          <div onClick={e=>e.stopPropagation()} style={{ position:"absolute", top:"100%", right:0, zIndex:99, background:"var(--modal-bg,#1e1e22)", border:"1px solid rgba(245,158,11,.3)", borderRadius:10, padding:8, minWidth:200, boxShadow:"0 8px 24px rgba(0,0,0,.6)", marginTop:4 }}>
                            <p style={{ fontSize:9, color:"#60a5fa", fontWeight:700, marginBottom:4 }}>↔ تحويل إلى تصنيف آخر:</p>
                            {MOVE_TARGETS.map(mt => (
                              <button key={mt.f} onClick={()=>{
                                removeTag(lbl);
                                const tgt = (data[mt.f]||[]).filter(x=>!(x&&typeof x==="object"&&x.source==="screening"));
                                if (!tgt.some(x=>(x.ar||x.en||"").toLowerCase()===lbl.toLowerCase())) set(mt.f,[...tgt,{ar:lbl,en:sub.en||"",approved:true,arSource:"admin"}]);
                                setMoveIdx(null);
                              }} style={mS}
                                onMouseEnter={e=>e.currentTarget.style.background="rgba(59,130,246,.1)"}
                                onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                                {mt.label}
                              </button>
                            ))}
                            <div style={{ borderTop:"1px solid rgba(255,255,255,.08)", margin:"4px 0" }} />
                            <button onClick={()=>{ set("primarySpecId",spec.id); setMoveIdx(null); }}
                              style={{ ...mS, color:"#fbbf24", fontWeight:700 }}
                              onMouseEnter={e=>e.currentTarget.style.background="rgba(245,158,11,.06)"}
                              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                              ⭐ إضافة كتخصص رئيسي
                            </button>
                            {specs.filter(sp=>sp.id!==spec.id).map(sp => (
                              <button key={sp.id} onClick={()=>{ setMoveIdx(null); }}
                                style={mS}
                                onMouseEnter={e=>e.currentTarget.style.background="rgba(245,158,11,.06)"}
                                onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                                📂 {sp.icon} {sp.label}
                              </button>
                            ))}
                          </div>
                        )}
                      </span>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
        <div style={{ marginTop: 8, display: "flex", gap: 6 }}>
          <input value={newVal} onChange={e => setNewVal(e.target.value)} onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); addTag(newVal, false); } }}
            placeholder="+ تصنيف غير مسجل..." style={{ flex: 1, fontSize: 11 }} />
          <button onClick={() => addTag(newVal, false)} className="btn btn-ghost btn-sm" style={{ fontSize: 11 }}>+ إضافة</button>
        </div>
      </div>
    );
  }

  // For non-specs: group by cat field
  const normalizedItems = (libItems || []).map(x => {
    if (typeof x === "string") return { ar: x, en: "", cat: "" };
    if (x && typeof x === "object") return { ar: x.ar || x.label || x.en || "", en: x.en || "", cat: x.cat || "" };
    return { ar: String(x || ""), en: "", cat: "" };
  }).filter(x => x.ar);

  // Group by category
  const catMap = {};
  normalizedItems.forEach(item => {
    const cat = item.cat || "أخرى";
    if (!catMap[cat]) catMap[cat] = [];
    catMap[cat].push(item);
  });
  const categories = Object.keys(catMap);

  return (
    <div className="card" style={{ marginBottom: 10 }}>
      <div className="sec" style={{ marginBottom: 8 }}>{icon + " " + title}</div>
      <div style={{ display: "flex", gap: 6, fontSize: 10, color: "var(--text3)", marginBottom: 10 }}>
        <span style={{ color: "#065F46", background:"#D1FAE5", padding:"2px 8px", borderRadius:6, border:"1px solid #6EE7B7" }}>🟢 من السيرة الذاتية</span>
        <span style={{ color: "#92400E", background:"#FEF3C7", padding:"2px 8px", borderRadius:6, border:"1px solid #FCD34D" }}>🟡 مختار</span>
        <span style={{ color: "var(--text3)", background:"var(--input-bg)", padding:"2px 8px", borderRadius:6, border:"1px solid var(--input-border)" }}>⬜ متاح</span>
      </div>

      {/* Selected tags on top */}
      {tags.length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginBottom: 10, padding: "8px 10px", background: "#f0fdf4", borderRadius: 8, border: "1px solid #bbf7d0" }}>
          {tags.map((t, i) => {
            const lbl = t.ar || t.en || "";
            const color = isCv(lbl) ? "green" : "yellow";
            const showMove = moveIdx === i;
            const MOVE_TARGETS = [
              { f:"biSpec", label:"🏗️ التخصصات" },
              { f:"biDept", label:"🏢 الإدارات" },
              { f:"biSkill", label:"🛠️ المهارات" },
              { f:"biSW", label:"💻 البرامج" },
              { f:"biProj", label:"📋 أنواع المشاريع" },
              { f:"biCert", label:"🏅 الشهادات" },
            ].filter(x => x.f !== field);
            const mS = { display:"block", width:"100%", textAlign:"right", padding:"5px 8px", borderRadius:5, border:"none", cursor:"pointer", fontFamily:"inherit", fontSize:11, color:"var(--text2)", background:"transparent", marginBottom:1 };
            const doMove = (targetField) => {
              const newTags = tags.filter(x => (x.ar||x.en||"").toLowerCase() !== lbl.toLowerCase());
              set(field, newTags);
              const targetTags = (data[targetField] || []).filter(x => !(x && typeof x === "object" && x.source === "screening"));
              if (!targetTags.some(x => (x.ar||x.en||"").toLowerCase() === lbl.toLowerCase())) {
                set(targetField, [...targetTags, t]);
              }
              setMoveIdx(null); setMoveSub(null);
            };
            return (
              <span key={i} style={{ ...tagStyle(color), position: "relative" }}>
                {lbl}
                <button onClick={() => setMoveIdx(showMove ? null : i)} style={{ background:"none", border:"none", cursor:"pointer", color:"inherit", fontSize:10, padding:"0 2px", lineHeight:1, opacity:0.6 }} title="نقل / تحويل">↔</button>
                <button onClick={() => removeTag(lbl)} style={{ background:"none", border:"none", cursor:"pointer", color:"inherit", fontSize:12, padding:0, lineHeight:1 }}>✕</button>
                {showMove && (
                  <div style={{ position:"absolute", top:"100%", right:0, zIndex:99, background:"var(--modal-bg,#1e1e22)", border:"1px solid rgba(245,158,11,.3)", borderRadius:10, padding:8, minWidth:200, boxShadow:"0 8px 24px rgba(0,0,0,.6)", marginTop:4 }}>
                    <p style={{ fontSize:9, color:"#60a5fa", fontWeight:700, marginBottom:4 }}>↔ تحويل إلى تصنيف آخر:</p>
                    {MOVE_TARGETS.map(mt => (
                      <button key={mt.f} onClick={()=>doMove(mt.f)} style={mS}
                        onMouseEnter={e=>e.currentTarget.style.background="rgba(59,130,246,.1)"}
                        onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                        {mt.label}
                      </button>
                    ))}
                    {categories.length > 0 && <>
                      <div style={{ borderTop:"1px solid rgba(255,255,255,.08)", margin:"4px 0" }} />
                      <p style={{ fontSize:9, color:"var(--text3)", marginBottom:4 }}>📂 أقسام {title}:</p>
                      {categories.map(cat => (
                        <button key={cat} onClick={()=>setMoveIdx(null)}
                          style={mS}
                          onMouseEnter={e=>e.currentTarget.style.background="rgba(245,158,11,.06)"}
                          onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                          {cat}
                        </button>
                      ))}
                    </>}
                  </div>
                )}
              </span>
            );
          })}
        </div>
      )}

      {/* Grouped library items - collapsible */}
      {categories.map(cat => {
        const isOpen = openCats[cat];
        const items = catMap[cat];
        const selectedInCat = items.filter(item => isSelected(item.ar)).length;
        return (
          <div key={cat} style={{ marginBottom: 4, border: "1px solid var(--b)", borderRadius: 8, overflow: "hidden" }}>
            <div onClick={() => toggleCat(cat)}
              style={{ padding: "6px 10px", background: selectedInCat > 0 ? "rgba(34,197,94,.08)" : "rgba(255,255,255,.02)", cursor: "pointer", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: selectedInCat > 0 ? "#16a34a" : "var(--text3)" }}>
                {cat} {selectedInCat > 0 && <span style={{ fontSize: 10 }}>({selectedInCat})</span>}
              </span>
              <span style={{ fontSize: 9, color: "var(--text3)" }}>{isOpen ? "▲" : "▼"}</span>
            </div>
            {isOpen && (
              <div style={{ padding: "6px 10px", display: "flex", flexWrap: "wrap", gap: 4 }}>
                {items.map((item, ii) => {
                  const color = getColor(item.ar);
                  return (
                    <span key={ii} style={tagStyle(color)} onClick={() => { if (isSelected(item.ar)) removeTag(item.ar); else addTag(item.ar); }}>
                      {item.ar} {isSelected(item.ar) && "✓"}
                    </span>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}

      <div style={{ marginTop: 8, display: "flex", gap: 6 }}>
        <input value={newVal} onChange={e => setNewVal(e.target.value)} onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); addTag(newVal, false); } }}
          placeholder="+ تصنيف غير مسجل..." style={{ flex: 1, fontSize: 11 }} />
        <button onClick={() => addTag(newVal, false)} className="btn btn-ghost btn-sm" style={{ fontSize: 11 }}>+ إضافة</button>
      </div>
    </div>
  );
}

// ── Saudi Council of Engineers — Haya Tab ─────────────────────────────────────
function HayaBadge({ data }) {
  const hayaRankVal = typeof data.hayaRank === "object" ? (data.hayaRank?.ar || "") : (data.hayaRank || "");
  // If "غير مطلوب", show minimal badge
  if (hayaRankVal === "غير مطلوب") return (
    <div style={{ padding:"8px 14px", background:"rgba(148,163,184,.05)", border:"1px solid rgba(148,163,184,.15)", borderRadius:10, marginTop:10 }}>
      <div style={{ display:"flex", gap:8, alignItems:"center" }}>
        <span style={{ fontSize:14 }}>🏛️</span>
        <span style={{ fontSize:12, color:"var(--text3)" }}>عضوية الهيئة السعودية للمهندسين — غير مطلوب</span>
      </div>
    </div>
  );
  const hasMembership = !!data.hayaMemberNo;
  const today = new Date();
  const expiryDate = data.hayaExpiry ? new Date(data.hayaExpiry) : null;
  const daysLeft = expiryDate ? Math.ceil((expiryDate - today) / 86400000) : null;
  const isExpired = daysLeft !== null && daysLeft <= 0;
  const isUrgent  = daysLeft !== null && daysLeft > 0 && daysLeft <= 90;
  const color = isExpired?"#ef4444":isUrgent?"#f59e0b":hasMembership?"#22c55e":"#94a3b8";
  const alertBg = isExpired?"rgba(239,68,68,.06)":isUrgent?"rgba(245,158,11,.06)":!hasMembership?"rgba(148,163,184,.06)":"rgba(255,255,255,.03)";
  const alertBorder = isExpired?"rgba(239,68,68,.25)":isUrgent?"rgba(245,158,11,.25)":!hasMembership?"rgba(148,163,184,.2)":"var(--b)";

  const RANK_COLORS = {
    "مهندس":          { color:"#60a5fa", bg:"rgba(96,165,250,.12)"  },
    "مهندس مشارك":   { color:"#34d399", bg:"rgba(52,211,153,.12)"  },
    "مهندس محترف":   { color:"#f59e0b", bg:"rgba(245,158,11,.12)"  },
    "مهندس مستشار":  { color:"#e8eaf0", bg:"rgba(192,132,252,.12)" },
    "فني":            { color:"#94a3b8", bg:"rgba(148,163,184,.1)"  },
    "تقني":           { color:"#94a3b8", bg:"rgba(148,163,184,.1)"  },
  };
  const rc = RANK_COLORS[hayaRankVal] || { color:"var(--gold)", bg:"rgba(201,168,76,.1)" };

  return (
    <div style={{ padding:"10px 14px", background:alertBg, border:"1px solid "+alertBorder, borderRadius:10, marginTop:10 }}>
      <div style={{ display:"flex", gap:10, alignItems:"center", flexWrap:"wrap" }}>
        <span style={{ fontSize:16 }}>🏛️</span>
        <div style={{ flex:1 }}>
          <p style={{ fontSize:11, color:"var(--text3)", fontWeight:600, marginBottom:5 }}>الهيئة السعودية للمهندسين</p>
          <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
            {/* Rank badge */}
            {hayaRankVal && (
              <span style={{ fontSize:12, fontWeight:900, padding:"3px 12px", borderRadius:20,
                background:rc.bg, color:rc.color, border:"1px solid "+rc.color+"44" }}>
                {hayaRankVal}
              </span>
            )}
            {/* Membership status */}
            {hasMembership ? (
              <span style={{ fontWeight:700, fontSize:12, color }}>
                {isExpired?"❌ عضوية منتهية":isUrgent?"⚠️ تنتهي خلال "+daysLeft+" يوم":"✅ عضوية سارية"}
              </span>
            ) : (
              <span style={{ fontWeight:700, fontSize:12, color:"#f59e0b", padding:"2px 10px", borderRadius:8, background:"rgba(245,158,11,.1)", border:"1px solid rgba(245,158,11,.25)" }}>
                ⚠️ لم يتم تسجيل العضوية
              </span>
            )}
            {data.hayaMemberNo && <span style={S.txt3s11}>رقم: {data.hayaMemberNo}</span>}
          </div>
          {data.hayaExpiry && <p style={{ fontSize:11, color:"var(--text3)", marginTop:3 }}>{"الانتهاء: "+new Date(data.hayaExpiry).toLocaleDateString("ar-SA")}</p>}
        </div>

      </div>
    </div>
  );
}

// ── Users CRUD ──────────────────────────────────────────────────────────────
async function verifyPassword(username, pass) {
  try {
    const user = await getUser(username);
    if (!user || !user.passwordHash) return false;
    const hash = await hashPassword(pass);
    return hash === user.passwordHash;
  } catch { return false; }
}
async function hashPassword(pass) {
  const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(pass + "hr_salt_2024"));
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,"0")).join("");
}

async function saveUser(data) {
  const id = data.id || "usr_" + Date.now();
  const user = { ...data, id, updatedAt: new Date().toISOString() };
  await db.set("user:" + id, user);
  const idx = (await db.get("users:idx")) || [];
  // v37.101 FIX 2: إزالة duplicates + إضافة id إن لم يكن موجوداً
  const updatedIdx = idx.includes(id) ? [...new Set(idx)] : [...new Set([...idx, id])];
  if (updatedIdx.length !== idx.length || !idx.includes(id)) {
    await db.set("users:idx", updatedIdx);
  }
  return user;
}
async function getAllUsers() {
  const idx = (await db.get("users:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("user:" + id)));
  return all.filter(Boolean);
}
async function getUserByUsername(username) {
  const all = await getAllUsers();
  return all.find(u => u.username && u.username.toLowerCase() === username.toLowerCase()) || null;
}
async function getUserByEmail(email) {
  if (!email) return null;
  const all = await getAllUsers();
  const em = email.toLowerCase();
  const matches = all.filter(u => u.email && u.email.toLowerCase() === em);
  if (matches.length === 0) return null;
  // Prefer employee/admin over candidate when duplicates exist
  return matches.find(u => u.role === "admin") || matches.find(u => u.role === "employee") || matches.find(u => u.role === "hr_manager") || matches[0];
}
async function deleteUser(id) {
  await db.del("user:" + id);
  const idx = (await db.get("users:idx")) || [];
  await db.set("users:idx", idx.filter(x => x !== id));
}
async function initDefaultAdmin() {
  const all = await getAllUsers();
  if (all.find(u => u.role === "admin")) return;
  const passwordHash = await hashPassword("admin2024");
  await saveUser({ username:"admin", email:"", passwordHash, role:"admin", displayName:"المشرف الرئيسي", createdAt: new Date().toISOString() });
}

