// ── Tawasul auto-evaluation ──
function calcTawasulRating(reqs, empId) {
  const asReceiver = reqs.filter(r => (r.assignees||[]).some(a => a.id === empId));
  if (asReceiver.length === 0) return { stars:5, score:100, total:0 };
  let totalScore = 0;
  let count = 0;
  asReceiver.forEach(r => {
    const myAssignment = (r.assignees||[]).find(a => a.id === empId);
    if (!myAssignment || r.status === "draft") return;
    let score = 100;
    // Speed of acceptance (20%)
    if (myAssignment.acceptedAt && r.createdAt) {
      const hrs = (new Date(myAssignment.acceptedAt) - new Date(r.createdAt)) / 3600000;
      const speedScore = hrs <= 2 ? 100 : Math.max(0, 100 - (hrs - 2) * 10);
      score = score * 0.6 + speedScore * 0.2;
    }
    // On-time delivery (40%)
    if (myAssignment.deliveredAt && r.deadline) {
      const diff = (new Date(r.deadline) - new Date(myAssignment.deliveredAt)) / 86400000;
      const timeScore = diff >= 0 ? 100 : Math.max(0, 100 + diff * 10);
      score = score * 0.6 + timeScore * 0.4;
    }
    // Returns penalty (25% of remaining)
    const returns = myAssignment.returns || 0;
    score -= returns * 15;
    // Objections penalty (15%)
    if (myAssignment.objected) score -= 10;
    totalScore += Math.max(0, Math.min(100, Math.round(score)));
    count++;
  });
  const avg = count > 0 ? Math.round(totalScore / count) : 0;
  return { stars: Math.round(avg / 20), score: avg, total: count };
}

// ── Auto-escalation check ──
function checkTawasulEscalations(reqs) {
  const now = Date.now();
  const updates = [];
  reqs.forEach(r => {
    if (["closed","cancelled"].includes(r.status)) return;
    // Yellow: 3 days with open issue
    if (r.escalation !== "yellow" && r.escalation !== "red" && r.issueAt) {
      if (now - new Date(r.issueAt).getTime() > 3 * 86400000) {
        updates.push({ ...r, escalation: "yellow", escalatedAt: new Date().toISOString() });
      }
    }
    // Red: 7 days after yellow
    if (r.escalation === "yellow" && r.escalatedAt) {
      if (now - new Date(r.escalatedAt).getTime() > 7 * 86400000) {
        updates.push({ ...r, escalation: "red", redEscalatedAt: new Date().toISOString() });
      }
    }
  });
  return updates;
}

