function useLibs() {
  const [libs, setLibs] = useState(DEFAULT_LIBS);
  useEffect(() => {
    // ⏳ انتظر حتى db.init() يخلص — ثم حمّل من Redis مباشرة
    const loadLibs = async () => {
      // Wait for _dbReady
      let tries = 0;
      while (!_dbReady && tries < 50) { await new Promise(r => setTimeout(r, 100)); tries++; }
      
      // 🔒 حمّل من Redis مباشرة — لا تعتمد على الكاش
      let s = null;
      try {
        const res = await fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"get", key:"libs" }) });
        const result = await res.json();
        if (result.ok && result.value) s = result.value;
      } catch {}
      // Fallback to cache
      if (!s) s = await db.get("libs");
      
      if (!s) { 
        // أول مرة فقط — استخدم الافتراضيات في الذاكرة فقط (لا تحفظ في Redis!)
        setLibs(DEFAULT_LIBS); 
        return; 
      }
      const merged = { ...s };

      // 🔧 Migration: فصل "مهندس ميكانيكا وكهرباء" تلقائياً
      if (merged.specs) {
        const oldMepIdx = merged.specs.findIndex(sp => sp.id === "mep" && (sp.label||"").includes("ميكانيكا وكهرباء"));
        if (oldMepIdx !== -1) {
          merged.specs.splice(oldMepIdx, 1);
          // أضف التخصصات الجديدة لو مش موجودة
          if (!merged.specs.some(sp => sp.id === "mech")) {
            merged.specs.push({ id:"mech", label:"مهندس ميكانيكا", icon:"⚙️", aliases:["مهندس ميكانيكا","Mechanical Engineer","هندسة ميكانيكية","HVAC","مهندس تكييف"], subs:[{ar:"مهندس ميكانيكا",en:"Mechanical Engineering",aliases:["Mechanical","ميكانيكا","HVAC","تكييف"]}] });
          }
          if (!merged.specs.some(sp => sp.id === "elec")) {
            merged.specs.push({ id:"elec", label:"مهندس كهرباء", icon:"⚡", aliases:["مهندس كهرباء","Electrical Engineer","هندسة كهربائية"], subs:[{ar:"مهندس كهرباء",en:"Electrical Engineering",aliases:["Electrical","كهرباء"]}] });
          }
          if (!merged.specs.some(sp => sp.id === "safety")) {
            merged.specs.push({ id:"safety", label:"أمن وسلامة", icon:"🛡️", aliases:["أمن وسلامة","HSE","Safety","Fire Safety"], subs:[{ar:"الأمن والسلامة",en:"HSE / Fire Safety",aliases:["Safety","HSE","NEBOSH"]}] });
          }
          // فصل التصميم الداخلي من المعماري
          const archSpec = merged.specs.find(sp => sp.id === "arch");
          if (archSpec) {
            archSpec.subs = (archSpec.subs||[]).filter(sub => !(sub.ar||"").includes("تصميم داخلي") && !(sub.ar||"").includes("Interior"));
            archSpec.aliases = (archSpec.aliases||[]).filter(a => !a.includes("Interior") && !a.includes("مصمم داخلي"));
          }
          if (!merged.specs.some(sp => sp.id === "interior")) {
            merged.specs.push({ id:"interior", label:"تصميم داخلي", icon:"🎨", aliases:["تصميم داخلي","Interior Design","مصمم داخلي","ديكور"], subs:[{ar:"أخصائي تصميم داخلي",en:"Interior Design Specialist",aliases:["Interior Designer","مصمم داخلي"]}] });
          }
          // حفظ التعديل مباشرة في Redis
          try {
            await fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"set", key:"libs", value:merged }) });
          } catch {}
        }
      }

      // فقط أضف الحقول المفقودة (مش العناصر — الحقول الهيكلية)
      if (!merged.specs) merged.specs = DEFAULT_LIBS.specs;
      if (!merged.skills) merged.skills = DEFAULT_LIBS.skills;
      if (!merged.software) merged.software = DEFAULT_LIBS.software;
      if (!merged.certifications) merged.certifications = DEFAULT_LIBS.certifications;
      if (!merged.projectTypes) merged.projectTypes = DEFAULT_LIBS.projectTypes;
      if (!merged.jobTypes) merged.jobTypes = DEFAULT_LIBS.jobTypes;
      if (!merged.hayaGrades) merged.hayaGrades = DEFAULT_LIBS.hayaGrades;
      if (!merged.branches) merged.branches = DEFAULT_LIBS.branches;

      // Inject cat from defaults for items without cat (cosmetic only — no additions)
      const injectCat = (savedArr, defaultArr) => {
        if (!savedArr || !defaultArr) return savedArr || [];
        const defaultMap = {};
        (defaultArr || []).forEach(d => {
          const dLabel = (typeof d === "object" ? (d.ar || d.label || d.en || "") : (d || "")).toLowerCase();
          if (dLabel && typeof d === "object" && d.cat) defaultMap[dLabel] = d.cat;
        });
        return savedArr.map(item => {
          if (typeof item === "object" && !item.cat) {
            const label = (item.ar || item.label || item.en || "").toLowerCase();
            if (defaultMap[label]) return { ...item, cat: defaultMap[label] };
          }
          return item;
        });
      };
      merged.software = injectCat(merged.software, DEFAULT_LIBS.software);
      merged.skills = injectCat(merged.skills, DEFAULT_LIBS.skills);
      merged.certifications = injectCat(merged.certifications, DEFAULT_LIBS.certifications);
      merged.projectTypes = injectCat(merged.projectTypes, DEFAULT_LIBS.projectTypes);
      merged.jobTypes = injectCat(merged.jobTypes, DEFAULT_LIBS.jobTypes);

      setLibs(merged);
    };
    loadLibs();
  }, []);
  const save = async (v) => { 
    // 🔒 حفظ مباشر لـ Redis — لا ينتظر sync
    await db.set("libs", v); 
    setLibs(v);
  };
  const specsMap = Object.fromEntries((libs.specs || []).map(s => [s.id, s]));
  return { libs, saveLibs: save, specsMap };
}

