function useToast() {
  const [t, setT] = useState(null);
  const show = (msg, ok) => { setT({ msg, ok: ok !== false }); setTimeout(() => setT(null), 3000); };
  const el = t ? (
    <div style={{ position:"fixed",top:20,left:"50%",transform:"translateX(-50%)",zIndex:9998,padding:"11px 22px",borderRadius:10,fontWeight:700,fontSize:14,boxShadow:"0 8px 32px rgba(0,0,0,.5)",background:t.ok?"linear-gradient(135deg,#166534,#15803d)":"linear-gradient(135deg,#7f1d1d,#991b1b)",color:"#fff",border:"1px solid " + (t.ok ? "rgba(34,197,94,.3)" : "rgba(239,68,68,.3)") }}>
      {t.msg}
    </div>
  ) : null;
  return { show, toastEl: el };
}

function SkeletonLoader({ rows = 5, type = "table" }) {
  const shimmer = "linear-gradient(90deg, var(--skel-base,rgba(255,255,255,.04)) 25%, var(--skel-shine,rgba(255,255,255,.08)) 50%, var(--skel-base,rgba(255,255,255,.04)) 75%)";
  const bar = (w, h = 14, mb = 0) => (
    <div style={{ width: w, height: h, borderRadius: 6, background: shimmer, backgroundSize: "200% 100%", animation: "skel 1.4s ease infinite", marginBottom: mb }} />
  );
  if (type === "cards") return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12, padding: "8px 0" }}>
      {Array.from({ length: rows }).map((_, i) => (
        <div key={i} style={{ background: "var(--glass,rgba(255,255,255,.03))", border: "1px solid var(--b,#2d323a)", borderRadius: 12, padding: 16 }}>
          <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 12 }}>
            {bar(44, 44)}{/* avatar */}
            <div style={{ flex: 1 }}>{bar("60%", 14, 6)}{bar("40%", 10)}</div>
          </div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>{bar("30%", 10)}{bar("25%", 10)}{bar("20%", 10)}</div>
        </div>
      ))}
    </div>
  );
  // table skeleton
  return (
    <div style={{ background: "var(--glass,rgba(255,255,255,.03))", border: "1px solid var(--b,#2d323a)", borderRadius: 13, overflow: "hidden", padding: 16 }}>
      {/* header row */}
      <div style={{ display: "flex", gap: 16, marginBottom: 16, paddingBottom: 12, borderBottom: "1px solid var(--b,#2d323a)" }}>
        {bar("15%", 12)}{bar("25%", 12)}{bar("20%", 12)}{bar("15%", 12)}
      </div>
      {Array.from({ length: rows }).map((_, i) => (
        <div key={i} style={{ display: "flex", gap: 16, marginBottom: 14, alignItems: "center" }}>
          {bar("15%", 11)}{bar("25%", 11)}{bar("20%", 11)}{bar("15%", 11)}
        </div>
      ))}
    </div>
  );
}

async function callAI(msgs, sys, hdrs) {
  return callAIModel(msgs, sys, MODEL, hdrs);
}

function buildPrompt(libs) {
  const L = libs || DEFAULT_LIBS;
  const specs = (L.specs || []).map(s => {
    const subStr = (s.subs || []).map(sub => typeof sub === "object" ? `${sub.ar}/${sub.en||""}` : sub).join("|");
    return s.label + "/" + (s.aliases || []).join("/") + (subStr ? " [" + subStr + "]" : "");
  });
  return `You are an expert CV data extractor for an Arabic HR system. Extract ALL available data from this CV.
CRITICAL: Respond ONLY with a valid JSON object. No markdown, no explanation, no code blocks. Start with { end with }.

Extract this exact JSON structure (fill every field you can find):
{
  "fullName": "full Arabic name exactly as written",
  "fullNameEn": "full English name if written in English anywhere in CV",
  "phone": "PRIMARY phone - Saudi mobile (starts with 05, 9665, +9665) preferred",
  "phone2": "SECONDARY phone if multiple numbers found",
  "email": "email address",
  "idNumber": "ID or Iqama number if found",
  "nationality": "nationality in Arabic e.g. سعودي / مصري",
  "gender": "ذكر or أنثى",
  "city": "current city",
  "locationStatus": "داخل السعودية or خارج السعودية",
  "education": "highest degree e.g. بكالوريوس / ماجستير / دكتوراه",
  "university": "university name",
  "major": "field of study",
  "graduationYear": 2020,
  "yearsExperience": 5,
  "lastJob": "most recent job title",
  "lastCompany": "most recent company name",
  "expectedSalary": 0,
  "linkedinUrl": "linkedin URL if found",
  "companies": ["company1", "company2"],
  "SPEC": ["matching specialization from list below"],
  "DEPT": ["matching department"],
  "SKILL": ["matching skills"],
  "SW": ["matching software"],
  "PROJ": ["matching project types"],
  "CERT": ["matching certifications"],
  "hayaMemberNo": "SCE membership number if found (رقم العضوية في الهيئة السعودية للمهندسين)",
  "hayaRank": "SCE professional rank: مهندس / مهندس مشارك / مهندس محترف / مهندس مستشار / فني / تقني",
  "cvFullText": ""
}

CRITICAL EXTRACTION RULES:
- fullName: REQUIRED — extract name even if only in English
- fullNameEn: if name appears in English anywhere in CV
- nationality: convert to Arabic (Egyptian=مصري, Saudi=سعودي, Jordanian=أردني, Syrian=سوري, Lebanese=لبناني, Sudanese=سوداني, Yemeni=يمني, Pakistani=باكستاني, Indian=هندي, Filipino=فلبيني)
- education: use Arabic (Bachelor=بكالوريوس, Master=ماجستير, PhD=دكتوراه, Diploma=دبلوم, High School=ثانوية)
- graduationYear: look for graduation date, year of completion, تخرج — REQUIRED if found
- yearsExperience: calculate from work history dates. Current year is 2026.
- hayaMemberNo: look for SCE number, رقم العضوية, membership number, هيئة المهندسين رقم
- hayaRank: look for درجة مهندس / مشارك / محترف / مستشار or Professional Engineer / Associate
- SPEC match from: [${specs.join(" | ")}]
- DEPT match from: [${(L.jobTypes||[]).join(" | ")}]
- SKILL match from: [${(L.skills||[]).join(" | ")}]
- SW match from: [${(L.software||[]).join(" | ")}]
- PROJ match from: [${(L.projectTypes||[]).join(" | ")}]
- CERT match from: [${(L.certifications||[]).join(" | ")}]
- For SPEC/SKILL/SW/CERT: also include relevant items from CV NOT in the lists
- cvFullText: always empty string ""`;
}


// ── Phone Helpers ─────────────────────────────────────────────────────────────
async function extractFromText(text, libs) {
  const result = await callAIModel([{ role: "user", content: buildPrompt(libs) + "\n\n=== CV ===\n" + text }], null, MODEL_GEMINI);
  if (result) result._rawCvText = text.slice(0, 50000);
  return result;
}

async function extractFromFile(b64, mime, isPdf, libs) {
  const block = isPdf
    ? { type: "document", source: { type: "base64", media_type: "application/pdf", data: b64 } }
    : { type: "image", source: { type: "base64", media_type: mime, data: b64 } };
  // Gemini 3.1 Pro — أعلى دقة عربي 97% + multimodal
  const result = await callAIModel(
    [{ role: "user", content: [block, { type: "text", text: buildPrompt(libs) }] }],
    "You are a CV analyst. Return ONLY valid JSON.",
    MODEL_GEMINI,
    {}
  );
  return result;
}

async function normalize(raw, libs) {
  if (!raw) return null;
  const r = { ...raw };

  // ── Map all direct fields ──────────────────────────────────────────────────
  // fullNameEn — keep as-is if English, or use fullName if it's already English
  if (!r.fullNameEn && r.fullName && /^[a-zA-Z\s]+$/.test(r.fullName)) {
    r.fullNameEn = r.fullName;
  }

  // education mapping
  if (!r.education && r.major) r.education = r.major;

  // Ensure arrays
  r.specializations = raw.SPEC || r.specializations || [];
  r.departments     = raw.DEPT || r.departments || [];
  r.skills          = raw.SKILL || r.skills || [];
  r.software        = raw.SW || r.software || [];
  r.projectTypes    = raw.PROJ || r.projectTypes || [];
  r.certifications  = raw.CERT || r.certifications || [];

  // ── Match spec by aliases (Arabic + English) ─────────────────────────────
  const matchSpec = (text) => {
    if (!text || !libs?.specs) return null;
    const q = text.trim().toLowerCase();
    for (const spec of (libs.specs || [])) {
      const specAliases = [spec.label, ...(spec.aliases || [])];
      if (specAliases.some(a => q === a.toLowerCase() || q.includes(a.toLowerCase()) || a.toLowerCase().includes(q))) {
        return { specId: spec.id };
      }
      for (const sub of (spec.subs || [])) {
        const subAliases = typeof sub === "object"
          ? [sub.ar, sub.en, ...(sub.aliases || [])].filter(Boolean)
          : [sub];
        if (subAliases.some(a => a && (q === a.toLowerCase() || q.includes(a.toLowerCase()) || a.toLowerCase().includes(q)))) {
          return { specId: spec.id };
        }
      }
    }
    return null;
  };

  if (!r.specId && !r.primarySpecId) {
    const sources = [...(r.specializations || []), r.lastJob || "", r.lastCompany || ""];
    for (const s of sources) {
      const m = matchSpec(s);
      if (m) { r.specId = m.specId; r.primarySpecId = m.specId; break; }
    }
  }
  // Ensure primarySpecId is synced with specId
  if (r.specId && !r.primarySpecId) r.primarySpecId = r.specId;

  const allEn = [...r.skills, ...r.software, ...r.projectTypes, ...r.specializations, ...r.departments, ...r.certifications, ...(r.companies || [])].filter(t => t && !/[\u0600-\u06FF]/.test(t));
  let trans = {};
  if (allEn.length > 0) {
    try {
      const res = await callAIModel([{ role: "user", content: "Translate to Arabic. Return ONLY JSON like {\"AutoCAD\":\"اوتوكاد\"}. Terms: " + allEn.join(", ") }],
        "Technical translator. Return ONLY a JSON object.", MODEL_FLASH);
      if (res && typeof res === "object" && !Array.isArray(res)) trans = res;
    } catch {}
  }
    // Build alias map for smart spec matching
  const specAlias = {};
  (libs?.specs||[]).forEach(spec => {
    [spec.label,...(spec.aliases||[])].forEach(a=>{if(a)specAlias[a.toLowerCase()]=spec.label;});
    (spec.subs||[]).forEach(sub=>{
      const sa=typeof sub==="object"?sub.ar:sub, se=typeof sub==="object"?(sub.en||""):"";
      [sa,se,...(typeof sub==="object"?(sub.aliases||[]):[])].filter(Boolean).forEach(a=>{specAlias[a.toLowerCase()]=sa||se;});
    });
  });
  // Build alias maps for all other tabs
  const libAlias = {};
  ["skills","software","projectTypes","certifications","jobTypes"].forEach(tabId => {
    libAlias[tabId] = {};
    (libs?.[tabId]||[]).forEach(it => {
      const label = typeof it === "object" ? (it.ar||it.label||"") : (it||"");
      const en = typeof it === "object" ? (it.en||"") : "";
      const aliases = typeof it === "object" ? (it.aliases||[]) : [];
      [label, en, ...aliases].filter(Boolean).forEach(a => { libAlias[tabId][a.toLowerCase()] = label; });
    });
  });

  const toBi = (items, isSpec=false, tabId="") => (items || []).filter(Boolean).map(item => {
    const isAr = /[\u0600-\u06FF]/.test(item);
    const lbl  = item.trim().toLowerCase();
    if (isSpec && specAlias[lbl]) return { ar:specAlias[lbl], en:isAr?"":item, approved:true, arSource:"mapped" };
    // Check aliases for non-spec tabs
    if (!isSpec && tabId && libAlias[tabId] && libAlias[tabId][lbl]) {
      return { ar:libAlias[tabId][lbl], en:isAr?"":item, approved:true, arSource:"mapped" };
    }
    return { en: isAr ? "" : item, ar: isAr ? item : (trans[item] || ""), arSource: isAr ? "cv" : (trans[item] ? "auto" : ""), approved: isAr };
  });

  r.biSpec = toBi(r.specializations, true);
  r.biDept = toBi(r.departments, false, "jobTypes");
  r.biSkill = toBi(r.skills, false, "skills");
  r.biSW   = toBi(r.software, false, "software");
  r.biProj = toBi(r.projectTypes, false, "projectTypes");
  r.biCert = toBi(r.certifications, false, "certifications");
  r.biComp = toBi(r.companies || []);
  return r;
}
function makeCvSnapshot(rawText, source) {
  return {
    id: "cv_" + Date.now(),
    text: rawText ? rawText.slice(0, 50000) : "",
    source, // "upload" | "manual" | "internal"
    addedAt: new Date().toISOString(),
    addedBy: source === "internal" ? "المكتب" : "الموظف/المرشح"
  };
}

async function evalCandidate(c) {
  const data = "name=" + c.fullName + ",spec=" + (c.specializations || []).join(",") + ",exp=" + (c.yearsExperience || 0) + "y,skills=" + (c.skills || []).join(",") + ",sw=" + (c.software || []).join(",");
  return callAIModel([{ role: "user", content: 'Evaluate candidate. Return ONLY JSON: {"score":75,"level":"متوسط","strengths":["s1"],"weaknesses":["w1"],"recommendation":"توقيع العقد","summary":"..."}\nLevels: مبتدئ/متوسط/محترف/خبير — Recs: لم يتم القبول/قائمة الانتظار/اختبار/مقابلة أولى/مقابلة ثانية/إرسال عرض وظيفي/يسجل متعاون/توقيع العقد/يقبل كمتدرب\n' + data }], null, MODEL_GEMINI,
    "HR expert. Return ONLY JSON.");
}

// ── AI Eval Limits: admin=unlimited, HR/supervisor=once per candidate, employee=blocked ──
// ── هل السؤال ترشيحي؟ — فحص شامل يغطي البيانات القديمة والجديدة ──
function _isScreeningQ(q) { return !!(q && (q.isScreening || q.category === "ترشيح")); }

// ── حالة مرحلة المرشح التفصيلية ──
function getCandStageStatus(cand, allAssessments) {
  const rec = (cand.evaluation || {}).recommendation || "";
  if (!rec) return { stage: "", label: "بدون تقييم", color: "#94a3b8", icon: "⬜" };
  const candId = cand.idNumber || cand.email;
  const myExams = (allAssessments || []).filter(a => a.candidateId === candId);
  const doneExams = myExams.filter(a => a.status === "done");
  const approvedExams = doneExams.filter(a => a.gradeApproved);
  const gradedExams = doneExams.filter(a => a.gradedBy);
  if (rec === "اختبار") {
    if (myExams.length === 0) return { stage: "اختبار", label: "لم يُجهّز اختبار", color: "#ef4444", icon: "⚠️", needsExam: true };
    if (doneExams.length === 0) return { stage: "اختبار", label: "لم يختبر بعد", color: "#f59e0b", icon: "⏳" };
    if (gradedExams.length === 0) return { stage: "اختبار", label: "بانتظار التصحيح", color: "#a78bfa", icon: "📝" };
    if (approvedExams.length === 0) return { stage: "اختبار", label: "بانتظار الاعتماد", color: "#3b82f6", icon: "🔐" };
    return { stage: "اختبار", label: "✅ اعتمد — جاهز للمقابلة", color: "#22c55e", icon: "✅" };
  }
  const STAGE_MAP = { "مقابلة أولى": "🤝", "مقابلة ثانية": "🤝", "إرسال عرض وظيفي": "📨", "إرسال مسودة عقد": "📑", "توقيع العقد": "📝", "تدريب": "🎓", "قائمة الانتظار": "⏸️", "لم يتم القبول": "❌", "مرفوض من قبل المرشح": "🚫", "يقبل كمتدرب": "🎓", "يسجل متعاون": "🤝" };
  return { stage: rec, label: rec, color: rec === "لم يتم القبول" ? "#ef4444" : rec === "مرفوض من قبل المرشح" ? "#fb923c" : rec === "قائمة الانتظار" ? "#f59e0b" : rec === "تدريب" ? "#e879f9" : "#22c55e", icon: STAGE_MAP[rec] || "📋" };
}
// ── بادج حالة المرحلة ──
function CandStageBadge({ cand, allAssessments }) {
  const st = getCandStageStatus(cand, allAssessments);
  return <span style={{ fontSize:10, padding:"2px 8px", borderRadius:6, background:st.color+"18", color:st.color, border:"1px solid "+st.color+"35", fontWeight:700, whiteSpace:"nowrap" }}>{st.icon} {st.label}</span>;
}

// ── شريط مراحل التوظيف بأيقونات كبيرة + حالة تفصيلية ──
const _PIPE_STAGES = [
  { id:"cv", label:"استلام\nالسيرة", icon:"📄" },
  { id:"exam", label:"اختبار", icon:"📝" },
  { id:"iv1", label:"مقابلة\nأولى", icon:"🤝" },
  { id:"iv2", label:"مقابلة\nثانية", icon:"💬" },
  { id:"offer", label:"عرض\nوظيفي", icon:"⭐" },
  { id:"draft", label:"مسودة\nعقد", icon:"📑" },
  { id:"contract", label:"توقيع\nالعقد", icon:"📋" },
  { id:"training", label:"تدريب", icon:"🎓" },
];
const _PIPE_MAP = {"اختبار":1,"مقابلة أولى":2,"مقابلة ثانية":3,"إرسال عرض وظيفي":4,"إرسال مسودة عقد":5,"توقيع العقد":6,"تدريب":7,"قائمة الانتظار":1,"مرفوض من قبل المرشح":0,"لم يتم القبول":0};
function CandStageBar({ recommendation, examStatus, ivStatus }) {
  const ci = _PIPE_MAP[recommendation] || 0;
  return <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"center", gap:0, padding:"2px 0", marginBottom:6 }}>
    {_PIPE_STAGES.map((s, i) => {
      const done = i < ci; const active = i === ci;
      const ringClr = done ? "#22c55e" : active ? "#f59e0b" : "#334155";
      const ringBg = done ? "rgba(34,197,94,.12)" : active ? "rgba(245,158,11,.15)" : "rgba(255,255,255,.03)";
      const sz = active ? 32 : 22; const iSz = active ? 13 : 9;
      const lblClr = done ? "#4ade80" : active ? "#f59e0b" : "#475569";
      let stTxt = "", stClr = "#475569";
      if (s.id === "cv") { stTxt = "✓"; stClr = "#22c55e"; }
      else if (s.id === "exam") {
        if (done) { stTxt = "✅"; stClr = "#22c55e"; }
        else if (active && examStatus) { stTxt = examStatus; stClr = examStatus.includes("اعتماد")?"#3b82f6":examStatus.includes("تصحيح")?"#a78bfa":examStatus.includes("لم")?"#f87171":examStatus.includes("تم إرسال")?"#f59e0b":"#ef4444"; }
      } else if (s.id === "iv1" || s.id === "iv2") {
        if (done) { stTxt = "✅"; stClr = "#22c55e"; }
        else if (active && ivStatus) { stTxt = ivStatus; stClr = ivStatus.includes("تأكيد")?"#22c55e":ivStatus.includes("إرسال")?"#f59e0b":"#ef4444"; }
      } else if (done) { stTxt = "✅"; stClr = "#22c55e"; }
      return <React.Fragment key={s.id}>
        <div style={{ display:"flex", flexDirection:"column", alignItems:"center", flexShrink:0, width: active ? 52 : 40 }}>
          <div style={{ width:sz, height:sz, borderRadius:"50%", background:ringBg, border:(active?"3px":"2px")+" solid "+ringClr, display:"flex", alignItems:"center", justifyContent:"center", fontSize:iSz }}>
            {done ? <span style={{ color:"#22c55e", fontWeight:900, fontSize:iSz }}>✓</span> : <span style={{ fontSize:iSz }}>{s.icon}</span>}
          </div>
          <span style={{ fontSize: active?8:6, color:lblClr, fontWeight: active?800:400, marginTop:2, textAlign:"center", lineHeight:1.1, whiteSpace:"pre-line" }}>{s.label}</span>
          {stTxt && (done||active) && <span style={{ fontSize:6, color:stClr, fontWeight:700, marginTop:1, textAlign:"center", lineHeight:1.1, maxWidth:50, overflow:"hidden", textOverflow:"ellipsis" }}>{stTxt}</span>}
        </div>
        {i < _PIPE_STAGES.length - 1 && <div style={{ flex:1, height:2, background: done?"#22c55e":"#334155", margin:"0 -1px", marginTop: sz/2, minWidth:3 }} />}
      </React.Fragment>;
    })}
  </div>;
}

// ── بطاقة مرشح موحّدة مضغوطة — صف واحد — الضغط يفتح بطاقة التقييم ──
function UnifiedCandCard({ cand, allAssessments, evTasks, onOpen }) {
  const rec = (cand.evaluation||{}).recommendation||"";
  const scores = [...(cand.aiEvalHistory||[]).map(h=>h.score), ...(cand.evalTaskResults||[]).map(t=>t.totalScore)].filter(Boolean);
  const avg = scores.length ? Math.round(scores.reduce((a,b)=>a+b,0)/scores.length) : (cand.evaluation?.score||0);
  const tasks = (evTasks||[]).filter(t=>t.candidateId===(cand.uid||cand.email));
  const assigned = tasks.filter(t=>t.evaluatorName && t.status!=="completed" && t.status!=="rejected_eval").map(t=>t.evaluatorName);
  const st = getCandStageStatus(cand, allAssessments);
  const stColor = {"اختبار":"#3b82f6","مقابلة أولى":"#22c55e","مقابلة ثانية":"#8b5cf6","إرسال عرض وظيفي":"#f59e0b","توقيع العقد":"#10b981","إرسال مسودة عقد":"#06b6d4","تدريب":"#e879f9","قائمة الانتظار":"#94a3b8","مرفوض من قبل المرشح":"#fb923c"}[rec]||"#64748b";
  const examStatus = st.stage==="اختبار" ? st.label : null;
  return <div onClick={()=>onOpen&&onOpen(cand)} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12, padding:"10px 12px", borderRight:"3px solid "+stColor, cursor:"pointer", transition:"all .15s" }}
    onMouseEnter={e=>{e.currentTarget.style.borderColor="rgba(201,168,76,.25)";e.currentTarget.style.background="rgba(201,168,76,.03)";}}
    onMouseLeave={e=>{e.currentTarget.style.borderColor="var(--b)";e.currentTarget.style.background="var(--glass)";}}>
    <CandStageBar recommendation={rec} examStatus={examStatus} />
    <div style={{ display:"flex", alignItems:"center", gap:6, flexWrap:"wrap" }}>
      <span style={{ fontWeight:900, fontSize:13, color:"var(--gold)" }}>{cand.fullName||"—"}</span>
      {(cand.hrCode||cand.idNumber) && <span style={{ fontSize:9, color:"var(--text3)" }}>{cand.hrCode||cand.idNumber}</span>}
      {assigned.length > 0 && <>
        <span style={{ fontSize:9, color:"var(--text3)" }}>مسند إلى:</span>
        {assigned.map((name,ni)=><span key={ni} style={{ fontSize:9, padding:"1px 6px", borderRadius:4, background:"rgba(167,139,250,.1)", color:"#a78bfa", border:"1px solid rgba(167,139,250,.15)" }}>{name}</span>)}
      </>}
      {avg > 0 && <span style={{ marginRight:"auto", fontSize:16, fontWeight:900, color:avg>=81?"#4ade80":avg>=61?"#fbbf24":"#f87171" }}>{avg}</span>}
    </div>
  </div>;
}

function canDoAIEval(person, personType, username) {
  if (username === "admin") return { ok: true };
  const cu = window._currentUser || {};
  // مدير الموارد البشرية والمدير العام: بلا حدود
  if (cu.role === "hr_manager") return { ok: true };
  // Regular employees cannot use AI eval
  if (cu.role !== "supervisor" && cu.username !== "admin") {
    return { ok: false, msg: "تقييم الذكاء الاصطناعي متاح فقط للمدير العام ومدير الموارد البشرية والمشرفين" };
  }
  const history = person.aiEvalHistory || [];
  if (personType === "employee") {
    const now = new Date();
    const thisMonth = history.find(h => {
      const d = new Date(h.at);
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    });
    if (thisMonth) return { ok: false, msg: "تم عمل تقييم AI هذا الشهر بالفعل (" + new Date(thisMonth.at).toLocaleDateString("ar-SA") + ") — فقط المدير العام أو مدير الموارد البشرية يستطيع عمل تقييم إضافي" };
  } else {
    if (history.length > 0) return { ok: false, msg: "تم عمل تقييم AI لهذا المرشح بالفعل (" + new Date(history[0].at).toLocaleDateString("ar-SA") + ") — فقط المدير العام أو مدير الموارد البشرية يستطيع عمل تقييم إضافي" };
  }
  return { ok: true };
}

// ── Manual Eval Limits: admin=unlimited, HR/supervisor=once per candidate ──
function canDoManualEval(person, username, userId) {
  if (username === "admin") return { ok: true };
  const results = person.evalTaskResults || [];
  const mine = results.find(r => r.evaluatorId === userId || r.evaluatorName === (window._currentUser?.displayName || ""));
  if (mine) return { ok: false, msg: "قمت بتقييم هذا المرشح مسبقاً (" + new Date(mine.at).toLocaleDateString("ar-SA") + ") — فقط المدير العام يستطيع التقييم مرة أخرى" };
  return { ok: true };
}

// ── Eval Task helpers ──
async function saveEvalTask(task) {
  const key = "eval_task:" + (task.id || Date.now());
  task.id = task.id || key.split(":")[1];
  _dbCache[key] = task;
  // Save immediately to Redis (not deferred)
  try {
    await fetch("/api/db", { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ action:"set", key:key, value:task }) });
  } catch(e) { console.warn("saveEvalTask direct save failed:", e.message); }
  return task;
}

// ── Basma notifications ── v37.84
// يُرسل badges (tasks/exams/alerts) لبصمة لتظهر في تطبيق الموظف
async function notifyBasma(empIdNumber, notifications) {
  if (!empIdNumber) return;
  try {
    await fetch("https://b.hma.engineer/api/data?action=kadwar-sync", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        empId: empIdNumber,
        notifications: notifications || { tasks: 0, exams: 0, alerts: 0 },
      }),
      signal: AbortSignal.timeout(5000),
    });
  } catch (e) {
    console.warn("notifyBasma failed:", e.message); // فشل صامت — لا نوقف العملية
  }
}

// حساب وإرسال badges الموظف لبصمة (يُستدعى بعد أي تغيير)
async function syncEmpBadgesToBasma(empIdNumber) {
  if (!empIdNumber) return;
  try {
    const tasks = await getEvalTasks();
    const pendingTasks = tasks.filter(t =>
      t.status === "pending" &&
      (t.evaluatorIds?.includes(empIdNumber) || t.evaluatorId === empIdNumber)
    ).length;
    // إشعارات أخرى (يمكن إضافة exams و alerts لاحقاً)
    await notifyBasma(empIdNumber, { tasks: pendingTasks, exams: 0, alerts: 0 });
  } catch (e) { console.warn("syncEmpBadgesToBasma failed:", e.message); }
}
async function getEvalTasks() {
  // Re-read from server to get latest
  try {
    const res = await fetch("/api/db?action=loadAll");
    if (res.ok) { const r = await res.json(); if (r.ok && r.data) { Object.assign(_dbCache, r.data); } }
  } catch {}
  const all = _dbCache || {};
  return Object.entries(all).filter(([k]) => k.startsWith("eval_task:")).map(([,v]) => typeof v === "string" ? JSON.parse(v) : v);
}

