// ── SmartCheckModal ───────────────────────────────────────────────────────────
function SmartCheckModal({ cand, res, onClose, show, onEmailSent }) {
  const [ch, setCh] = useState({ system:true, email:true, whatsapp:false });
  const [editEmail, setEditEmail] = useState(res.emailDraft || "");
  const [sending, setSending] = useState(false);
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9000, display:"flex", alignItems:"flex-start", justifyContent:"center", padding:8, overflowY:"auto" }} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{ background:"var(--dark2)", border:"1px solid var(--b)", borderRadius:16, width:"100%", maxWidth:650, marginTop:8, marginBottom:60 }}>
        <div style={{ padding:"14px 16px", borderBottom:"1px solid var(--b)", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <span style={{ fontWeight:900, fontSize:15, color:"#10b981" }}>🔍 نتيجة الفحص الذكي — {cand.fullName}</span>
          <button onClick={onClose} style={{ width:28, height:28, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.3)", color:"#f87171", cursor:"pointer" }}>✕</button>
        </div>
        <div style={{ padding:"14px 16px" }}>
          {res.contradictions?.length > 0 && <div style={{ marginBottom:12, padding:"10px 14px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.2)", borderRadius:10 }}>
            <p style={{ fontWeight:700, color:"#f87171", marginBottom:6 }}>⚡ تناقضات</p>
            {res.contradictions.map((x,i)=><p key={i} style={{ fontSize:12, color:"var(--text2)", margin:"0 0 3px" }}>· {x}</p>)}
          </div>}
          {res.missing?.length > 0 && <div style={{ marginBottom:12, padding:"10px 14px", background:"rgba(245,158,11,.06)", border:"1px solid rgba(245,158,11,.2)", borderRadius:10 }}>
            <p style={{ fontWeight:700, color:"#f59e0b", marginBottom:6 }}>📋 بيانات ناقصة</p>
            {res.missing.map((x,i)=><p key={i} style={{ fontSize:12, color:"var(--text2)", margin:"0 0 3px" }}>· {x}</p>)}
          </div>}
          {res.alerts?.length > 0 && <div style={{ marginBottom:12, padding:"10px 14px", background:"rgba(96,165,250,.06)", border:"1px solid rgba(96,165,250,.2)", borderRadius:10 }}>
            <p style={{ fontWeight:700, color:"#60a5fa", marginBottom:6 }}>🔔 تنبيهات</p>
            {res.alerts.map((x,i)=><p key={i} style={{ fontSize:12, color:"var(--text2)", margin:"0 0 3px" }}>· {x}</p>)}
          </div>}
          {res.action && <div style={{ marginBottom:12, padding:"10px 14px", background:"rgba(167,139,250,.06)", border:"1px solid rgba(167,139,250,.2)", borderRadius:10 }}>
            <p style={{ fontWeight:700, color:"#a78bfa", marginBottom:4 }}>💡 اقتراح الإجراء</p>
            <p style={{ fontSize:12, color:"var(--text2)", margin:0 }}>{res.action}</p>
          </div>}
          <div style={{ marginBottom:12 }}>
            <p style={{ fontWeight:700, color:"var(--text)", marginBottom:6, fontSize:13 }}>📧 رسالة البريد الجاهزة</p>
            <textarea value={editEmail} onChange={e=>setEditEmail(e.target.value)} rows={6}
              style={{ width:"100%", padding:"10px 12px", borderRadius:10, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontSize:12, fontFamily:"inherit", resize:"vertical", boxSizing:"border-box" }} />
          </div>
          {/* ── قنوات الإرسال ── */}
          <div style={{ marginBottom:10, padding:"8px 12px", background:"rgba(201,168,76,.04)", border:"1px solid rgba(201,168,76,.15)", borderRadius:10 }}>
            <p style={{ fontSize:11, fontWeight:700, color:"var(--gold)", marginBottom:6 }}>📡 قنوات الإرسال:</p>
            <div style={{ display:"flex", gap:10, flexWrap:"wrap" }}>
              <label style={{ display:"flex", alignItems:"center", gap:4, fontSize:11, color:"var(--text2)", opacity:.6 }}>
                <input type="checkbox" checked={true} disabled style={{ accentColor:"#0f766e" }} /> 🖥️ النظام <span style={{ fontSize:9 }}>(إلزامي)</span>
              </label>
              <label style={{ display:"flex", alignItems:"center", gap:4, fontSize:11, color:"var(--text2)", cursor:"pointer" }}>
                <input type="checkbox" checked={ch.email} onChange={e=>setCh(p=>({...p,email:e.target.checked}))} style={{ accentColor:"#10b981" }} /> 📧 البريد
              </label>
              <label style={{ display:"flex", alignItems:"center", gap:4, fontSize:11, color:cand.phone?"var(--text2)":"var(--text3)", cursor:cand.phone?"pointer":"not-allowed" }}>
                <input type="checkbox" checked={ch.whatsapp} onChange={e=>setCh(p=>({...p,whatsapp:e.target.checked}))} disabled={!cand.phone} style={{ accentColor:"#25d366" }} /> 💬 واتساب
              </label>
            </div>
          </div>
          <div style={{ display:"flex", gap:8 }}>
            <button onClick={async()=>{
              const sendCheck = canSendTo(cand, "screening");
              if (!sendCheck.ok) { show(sendCheck.reason); return; }
              setSending(true);
              try {
                const pid=cand.uid||cand.idNumber||cand.email;
                // 🖥️ النظام — إلزامي
                if(pid) await saveNotification({message:"📋 "+editEmail.slice(0,100),type:"screening",targetId:pid,sentBy:"إدارة الموارد البشرية",read:false,createdAt:new Date().toISOString()}).catch(()=>{});
                // 📧 البريد
                if(ch.email&&cand.email){
                  const bodyHtml = editEmail.split("\n").map(line=>line.trim()?`<p style="font-size:14px;color:#1a2235;line-height:1.8;margin:0 0 8px;direction:rtl;text-align:right">${line}</p>`:`<br/>`).join("\n");
                  const fullHtml = `<div style="max-width:600px;margin:0 auto;padding:24px;font-family:'Segoe UI',Tahoma,sans-serif;direction:rtl">\n${bodyHtml}\n${emailUnifiedFooter()}\n</div>`;
                  const r = await sendEmail({to:cand.email, subject:"فرز طلبات التوظيف — كوادر HMA", html:fullHtml, _logOpts:{candidateId:pid, name:cand.fullName}});
                  if(r.error) throw new Error(r.error);
                  if(r.skipped&&!ch.whatsapp) throw new Error(r.reason||"البريد غير مهيأ");
                }
                // 💬 واتساب
                if(ch.whatsapp&&cand.phone){
                  const waNum=(cand.phone||"").replace(/^0/,"966").replace(/[^0-9]/g,"");
                  window.open("https://wa.me/"+waNum+"?text="+encodeURIComponent(editEmail),"_blank");
                }
                // سجل الأحداث
                if(pid) addPersonEvent(pid,{type:"message",text:"📋 رسالة فحص"+(ch.email?" — بريد":"")+(ch.whatsapp?" — واتساب":"")+" — نظام",by:window._currentUser?.displayName||"",byRole:"admin",private:false}).catch(()=>{});
                show("✅ تم الإرسال");
                if(onEmailSent) onEmailSent(cand);
                onClose();
              } catch(e){show("❌ فشل: "+(e.message||"تحقق من الإعدادات"));}
              setSending(false);
            }} disabled={sending} style={{ flex:1, padding:"10px", borderRadius:10, border:"none", background:"linear-gradient(135deg,#10b981,#059669)", color:"#fff", fontWeight:900, fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>
              {sending?"⏳ جاري الإرسال...":"📤 إرسال الرسالة"}
            </button>
            <button onClick={onClose} style={{ padding:"10px 16px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>إغلاق</button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── CandEvalPage — full evaluation page for a candidate ──────────────────────
function CandEvalPage({ cand, onClose, onSave, employeeTask }) {
  const cu = window._currentUser || {};
  const isAdm = cu.username === "admin";
  const isHR = cu.role === "hr_manager";
  // في وضع الموظف: مقيّم فقط — لا يوافق ولا يعدّل
  const isEmpEvaluator = !!employeeTask;
  // 🔒 حيادية التقييم: الموظف لا يشوف تقييمات الآخرين إلا بعد اعتماد تقييمه
  const evalApproved = isEmpEvaluator && employeeTask.status === "completed" && !!employeeTask.approvedAt;
  const _empHide = isEmpEvaluator && !evalApproved;
  // v37.78: مساعد المشرف نفس وضع المُسنَد له — لا يرى شيء حتى اكتمال التقييم
  const isAsst = cu.role === "assistant_supervisor";
  // hideOtherEvals يتحدث ديناميكيًا لمساعد المشرف (يعتمد على liveTasks المحملة لاحقًا)
  const canApprove = !isEmpEvaluator && (isAdm || isHR);
  const canEdit = isAdm && !isEmpEvaluator;
  const userName = cu.displayName || cu.username || "المشرف";
  const userRole = isAdm ? "المدير العام" : isHR ? "مدير الموارد البشرية" : (cu.jobTitle || cu.role || "مشرف");

  // هل أرسل الموظف تقييمه بالفعل؟
  const empTaskDone = isEmpEvaluator && employeeTask.status !== "pending";
  const [hasSubmitted, setHasSubmitted] = useState(empTaskDone);

  const [tab, setTab] = useState("info");
  const [ivDate, setIvDate] = useState(""); const [ivTime, setIvTime] = useState(""); const [ivLoc, setIvLoc] = useState("");
  const [ivSaved, setIvSaved] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [liveTasks, setLiveTasks] = useState([]);
  // v37.78: مساعد المشرف لا يرى نتائج إلا بعد اكتمال كل التكليفات المعلقة
  const asstAllTasksDone = isAsst ? liveTasks.length > 0 && liveTasks.every(t => t.status === "completed") : true;
  const hideOtherEvals = _empHide || (isAsst && !asstAllTasksDone);
  const [chatMsg, setChatMsg] = useState("");
  const [refreshKey, setRefreshKey] = useState(0);
  const hasAnyEval = (cand.aiEvalHistory||[]).length > 0 || Object.keys(cand.stageEvaluations||{}).length > 0 || (cand.evalTaskResults||[]).length > 0;
  const [openAccs, setOpenAccs] = useState({}); // v37.42: كل القوائم مقفلة بالافتراض
  const [editingScore, setEditingScore] = useState(null); // { taskIdx, score, recommendation }
  const { show, toastEl } = useToast();
  const { confirm, dlg: confirmDlg } = useConfirm();
  const [aiEvalLoading, setAiEvalLoading] = useState(false);

  // v37.77: تقييم AI — فقط المشرف ومدير HR
  const canRunAIEval = (isAdm || isHR) && !isEmpEvaluator;
  const doAIEval = async () => {
    const check = canDoAIEval(cand, "candidate", cu.username);
    if (!check.ok) { show("⚠️ " + check.msg); return; }
    const ok = await confirm("🤖 تشغيل تقييم الذكاء الاصطناعي لـ " + (cand.fullName||"") + "؟\n\nسيتم تحليل السيرة الذاتية والتصنيفات والخبرات.");
    if (!ok) return;
    setAiEvalLoading(true);
    try {
      const ev = await evalCandidate(cand);
      const aiHistoryEntry = { ...ev, at: new Date().toISOString(), by: cu.displayName || "AI", type: "ai" };
      // v37.89 FIX: AI يُضاف للتاريخ كاقتراح فقط — لا يغيّر recommendation
      // الاقتراح محفوظ في aiHistoryEntry.recommendation للاطلاع
      // المرحلة تظل كما هي — نقلها يدوي من صفحة المراحل
      const prevRec = cand.evaluation?.recommendation || "";
      const upd = {
        ...cand,
        evaluation: {
          ...(cand.evaluation || {}),
          // نحفظ score الأحدث من AI لكن نبقي recommendation الأصلي
          score: ev.score,
          strengths: ev.strengths,
          weaknesses: ev.weaknesses,
          notes: ev.notes,
          // recommendation القديم لا يتغير — الاقتراح الجديد في aiHistoryEntry
          recommendation: prevRec,
          aiRecommendation: ev.recommendation, // اقتراح AI منفصل كمرجع
        },
        evaluatedAt: new Date().toISOString(),
        aiEvalHistory: [...(cand.aiEvalHistory || []), aiHistoryEntry]
      };
      if (onSave) await onSave(upd);
      show("✅ تم تقييم " + (cand.fullName||""));
    } catch (e) { show("❌ " + (e.message || "فشل التقييم")); }
    setAiEvalLoading(false);
  };

  // ── نظام تصحيح واعتماد الاختبارات v37.39 ──
  const [candAssessments, setCandAssessments] = useState([]);
  const [showExamReview, setShowExamReview] = useState(null); // popup read-only
  const [examGradingId, setExamGradingId] = useState(null); // which assessment being graded
  const [examWrittenGrades, setExamWrittenGrades] = useState({}); // {qId: {score, by, at}}
  const [examOverrides, setExamOverrides] = useState({}); // {qId: {newScore, note}}
  const [approvalPwd, setApprovalPwd] = useState("");
  const [approving, setApproving] = useState(false);
  const [examQuestions, setExamQuestions] = useState([]);

  const toggleAcc = (k) => setOpenAccs(p => ({ ...p, [k]: !p[k] }));

  useEffect(() => {
    const candId = cand.uid || cand.email;
    getEvalTasks().then(all => setLiveTasks(all.filter(t => t.candidateId === candId))).catch(()=>{});
    // تحميل اختبارات المرشح
    Promise.all([getAllAssessments(), getAllQuestions()]).then(([allA, allQ]) => {
      const mine = allA.filter(a => a.candidateId === (cand.idNumber||cand.email) && a.status === "done");
      setCandAssessments(mine);
      setExamQuestions(allQ);
    }).catch(()=>{});
  }, [cand, refreshKey]);

  // Scores
  const aiHistory = cand.aiEvalHistory || [];
  const stageEvals = cand.stageEvaluations || {};
  const evalResults = cand.evalTaskResults || [];
  const examScore = cand.examScore || null;
  const allVals = [...aiHistory.filter(h=>h.score).map(h=>h.score), ...Object.values(stageEvals).flatMap(ev=>(ev.evaluations||[ev]).filter(e=>e.total).map(e=>e.total)), ...evalResults.filter(t=>t.totalScore).map(t=>t.totalScore), ...(examScore?[examScore]:[])];
  const overall = allVals.length ? Math.round(allVals.reduce((a,b)=>a+b,0)/allVals.length) : 0;
  const avgOf = arr => arr.length ? Math.round(arr.reduce((a,b)=>a+b,0)/arr.length) : null;
  const aiAvg = avgOf(aiHistory.filter(h=>h.score).map(h=>h.score));
  const humanAvg = avgOf([...Object.values(stageEvals).flatMap(ev=>(ev.evaluations||[ev]).filter(e=>e.total).map(e=>e.total)), ...evalResults.filter(t=>t.totalScore).map(t=>t.totalScore)]);
  const examAvg = examScore || null;
  const oC = v => v>=81?"#4ade80":v>=61?"#fbbf24":"#f87171";

  // Job title info
  const jt = (window._jobTitles||[]).find(j => j.id === cand.jobTitleId) || null;
  const [jp, setJp] = useState(null); // job posting linked to candidate
  useEffect(()=>{
    getAllJobs().then(jobs=>{
      const cid = cand.uid||cand.idNumber||cand.email;
      const found = jobs.find(j=>(j.linkedCandidates||[]).includes(cid));
      if(found) setJp(found);
    }).catch(()=>{});
  },[cand.uid,cand.idNumber,cand.email]);

  // Chat
  const allChats = liveTasks.flatMap(t => (t.chat||[]).map(m => ({...m, taskId:t.id}))).sort((a,b)=>(a.at||"").localeCompare(b.at||""));
  const doChat = async () => {
    if (!chatMsg.trim()) return;
    const activeTask = liveTasks.find(t => t.status === "pending_approval") || liveTasks[liveTasks.length-1];
    if (!activeTask) { show("⚠️ لا يوجد تقييم للمناقشة"); return; }
    const msg = { by: userName, role: isAdm?"admin":isHR?"hr":"evaluator", text: chatMsg.trim(), at: new Date().toISOString() };
    const updTask = { ...activeTask, chat: [...(activeTask.chat||[]), msg] };
    await saveEvalTask(updTask);
    addPersonEvent(cand.uid||cand.email, { type:"eval_chat", text:"💬 "+userName+": "+chatMsg.trim(), by:userName, byRole:userRole, private:false }).catch(()=>{});
    setChatMsg(""); setRefreshKey(k=>k+1); show("📤 تم");
  };

  const doApprove = async () => {
    const task = liveTasks.find(t => t.status === "pending_approval");
    if (!task) return;
    const rec = task.evalResult?.recommendation;
    const REC_MAP = {"مقابلة أولى":"interview1","اختبار":"assessment","مقابلة ثانية":"interview2","إرسال عرض وظيفي":"offer","إرسال مسودة عقد":"draft_contract","توقيع العقد":"contract","تدريب":"training","قائمة الانتظار":"waiting","لم يتم القبول":"rejected","مرفوض من قبل المرشح":"candidate_rejected","يقبل كمتدرب":"trainee","يسجل متعاون":"collaborator"};
    const updTask = { ...task, status:"completed", approvedAt:new Date().toISOString(), approvedBy:userName };
    await saveEvalTask(updTask);
    // v37.84: تحديث badge في بصمة (المهمة اكتملت)
    if (task.evaluatorIds?.length || task.evaluatorId) {
      const evalIds = task.evaluatorIds || [task.evaluatorId];
      for (const id of evalIds.filter(Boolean)) {
        syncEmpBadgesToBasma(id).catch(()=>{});
      }
    }
    // 🔔 إشعار الموظف المُقيِّم بالاعتماد
    if (task.evaluatorId) {
      await saveNotification({
        message: "✅ تم اعتماد تقييمك للمرشح " + (cand.fullName||"") + " — يمكنك الآن الإطلاع على تقييمات الإدارات الأخرى",
        type: "eval_approved", targetId: task.evaluatorId,
        sentBy: userName, read: false,
        candidateId: cand.uid||cand.email,
        createdAt: new Date().toISOString(),
      }).catch(()=>{});
    }
    if (rec || task.evalResult) {
      // جلب آخر نسخة من المرشح من قاعدة البيانات قبل التحديث
      let freshCand = cand;
      try {
        const cid = cand.uid || cand.idNumber || cand.email;
        if (cid) {
          const fetched = await db.get("c:" + cid).catch(() => null);
          if (fetched && fetched.uid) freshCand = fetched;
        }
      } catch {}
      // أضف نتيجة التقييم لـ evalTaskResults
      const evalResult = { ...task.evalResult, taskId: task.id, approvedAt: new Date().toISOString(), approvedBy: userName };
      const upd = {
        ...freshCand,
        evalTaskResults: [...(freshCand.evalTaskResults || []), evalResult],
        ...(rec ? { evaluation: { ...(freshCand.evaluation || {}), recommendation: rec } } : {}),
      };
      if (onSave) await onSave(upd);
      addPersonEvent(cand.uid||cand.email, { type:"stage", text:"✅ موافقة → "+(rec||"تقييم مُعتمد"), by:userName, byRole:"admin", private:false }).catch(()=>{});
    }
    setRefreshKey(k=>k+1); show("✅ تمت الموافقة"+(rec?" → "+rec:""));
  };
  const doReject = async () => {
    const task = liveTasks.find(t => t.status === "pending_approval");
    if (!task) return;
    await saveEvalTask({ ...task, status:"rejected_eval", rejectedAt:new Date().toISOString(), rejectedBy:userName });
    setRefreshKey(k=>k+1); show("❌ رفض");
  };

  const handleEvalSubmit = async (evalData) => {
    const result = { ...evalData, taskId:"direct_"+Date.now() };
    const upd = { ...cand, evalTaskResults:[...(cand.evalTaskResults||[]), result] };
    if (onSave) await onSave(upd);
    // Create a task for discussion
    const task = { id:Date.now().toString(), candidateId:cand.uid||cand.email, candidateName:cand.fullName, evaluatorId:cu.username, evaluatorName:userName, status:"pending_approval", assignedAt:new Date().toISOString(), assignedBy:userName, completedAt:new Date().toISOString(), evalResult:{ score:evalData.totalScore, recommendation:evalData.recommendation, evaluatorName:userName }, chat:[] };
    await saveEvalTask(task);
    addPersonEvent(cand.uid||cand.email, { type:"eval", text:"📋 تقييم "+userRole+" بواسطة "+userName+" — "+evalData.totalScore+"/100 — التوصية: "+evalData.recommendation, by:userName, byRole:userRole, private:false }).catch(()=>{});
    setShowForm(false); setRefreshKey(k=>k+1); show("✅ تم حفظ التقييم");
  };

  // ── هل كل الاختبارات معتمدة؟ (الترتيب الإجباري) ──
  const allExamsApproved = candAssessments.length === 0 || candAssessments.every(a => a.gradeApproved);
  const hasCompletedExam = candAssessments.length > 0;

  // ── v37.39: هل المرشح في مرحلة الاختبار ولم يُعتمد بعد؟ → إخفاء كل أقسام التقييم ──
  const candRec = (cand.evaluation || {}).recommendation || "";
  const isAtExamStage = candRec === "اختبار";
  const needsExamFirst = isAtExamStage && !allExamsApproved;
  const [hrNotified, setHrNotified] = useState(false);

  // إذا المرشح في مرحلة الاختبار ولا يوجد اختبار مُجهّز → إشعار HR تلقائي
  useEffect(() => {
    if (isAtExamStage && candAssessments.length === 0 && !hrNotified && liveTasks.length >= 0) {
      const candId = cand.uid || cand.email;
      // تحقق: هل سبق إرسال إشعار لهذا المرشح؟
      const notifKey = "exam_notif_sent_" + candId;
      if (sessionStorage.getItem(notifKey)) return;
      sessionStorage.setItem(notifKey, "1");
      setHrNotified(true);
      // إرسال تعليق تلقائي في المناقشات
      const autoMsg = "⚠️ هذا المرشح في مرحلة الاختبار ولم يُجهّز له اختبار بعد — يُرجى تجهيز اختبار من قسم الاختبارات";
      const activeTask = liveTasks.find(t => t.status !== "completed" && t.status !== "rejected_eval") || liveTasks[0];
      if (activeTask) {
        const msg = { by: "النظام", role: "system", text: autoMsg, at: new Date().toISOString() };
        saveEvalTask({ ...activeTask, chat: [...(activeTask.chat || []), msg] }).catch(() => {});
      }
      // إشعار لمدير الموارد البشرية
      (async () => {
        try {
          const allUsers = await getAllUsers();
          const hrUsers = allUsers.filter(u => u.role === "hr_manager" || u.username === "admin");
          for (const hr of hrUsers) {
            await saveNotification({
              message: "⚠️ المرشح " + (cand.fullName || "") + " في مرحلة الاختبار ولم يُجهّز له اختبار — يُرجى تجهيز اختبار من قسم الاختبارات",
              type: "exam_needed", targetId: hr.linkedId || hr.username || hr.id,
              sentBy: "النظام", read: false,
              candidateId: candId,
              createdAt: new Date().toISOString(),
            });
          }
        } catch {}
      })();
    }
  }, [isAtExamStage, candAssessments.length, liveTasks.length]);

  // ── تصحيح الأسئلة المكتوبة ──
  const doGradeWritten = async (asmntId) => {
    const asmnt = candAssessments.find(a => a.id === asmntId);
    if (!asmnt) return;
    const newWrittenGrades = {};
    Object.entries(examWrittenGrades).forEach(([qId, data]) => {
      newWrittenGrades[qId] = { score: data.score || 0, by: userName, at: new Date().toISOString() };
    });
    const newOverrides = [];
    Object.entries(examOverrides).forEach(([qId, data]) => {
      if (data.newScore !== undefined) {
        const q = examQuestions.find(x => x.id === qId);
        const oldScore = asmnt.scores?.[qId] || 0;
        newOverrides.push({ questionId: qId, oldScore, newScore: data.newScore, by: userName, at: new Date().toISOString(), note: data.note || "" });
      }
    });
    const upd = {
      ...asmnt,
      writtenGrades: { ...(asmnt.writtenGrades || {}), ...newWrittenGrades },
      gradeOverrides: [...(asmnt.gradeOverrides || []), ...newOverrides],
      gradedBy: userName,
      gradedAt: new Date().toISOString(),
    };
    // إعادة حساب الدرجة
    const qs = (asmnt.selectedQs || []).map(id => examQuestions.find(q => q.id === id)).filter(Boolean);
    const scoredQs = qs.filter(q => !_isScreeningQ(q) && !q.isKPIExam);
    let total = 0;
    scoredQs.forEach(q => {
      if (q.type === "written") {
        total += (upd.writtenGrades?.[q.id]?.score) || 0;
      } else {
        const override = [...(upd.gradeOverrides || [])].reverse().find(o => o.questionId === q.id);
        total += override ? override.newScore : (asmnt.scores?.[q.id] || 0);
      }
    });
    const maxPts = scoredQs.reduce((s, q) => s + (q.points || 1), 0) || 1;
    upd.finalScore = total;
    upd.finalPct = Math.round(total / maxPts * 100);
    upd.scores = { ...(asmnt.scores || {}), ...Object.fromEntries(Object.entries(newWrittenGrades).map(([k, v]) => [k, v.score])) };
    const saved = await saveAssessment(upd);
    setCandAssessments(p => p.map(x => x.id === saved.id ? saved : x));
    addPersonEvent(cand.uid || cand.email, { type: "exam_graded", text: "📝 تم تصحيح الاختبار بواسطة " + userName, by: userName, byRole: userRole, private: false }).catch(() => {});
    setExamGradingId(null); setExamWrittenGrades({}); setExamOverrides({});
    show("✅ تم حفظ التصحيح");
  };

  // ── اعتماد نتيجة الاختبار ──
  // ── تصحيح ذكي بـ AI للأسئلة المكتوبة ──
  const [aiExamGrading, setAiExamGrading] = useState(false);
  const [aiExamComments, setAiExamComments] = useState({});
  const doAIGradeExam = async (asmntId) => {
    const asmnt = candAssessments.find(a => a.id === asmntId);
    if (!asmnt) return;
    const qs = (asmnt.selectedQs || []).map(id => examQuestions.find(q => q.id === id)).filter(Boolean);
    const writtenQs = qs.filter(q => !_isScreeningQ(q) && !q.isKPIExam && q.type === "written");
    if (!writtenQs.length) { show("لا توجد أسئلة مكتوبة للتصحيح"); return; }
    setAiExamGrading(true);
    const suggestions = {}; const comments = {};
    for (const q of writtenQs) {
      const ans = asmnt.answers?.[q.id];
      if (!ans) continue;
      try {
        const prompt = `أنت مصحح اختبارات محترف. صحح الإجابة التالية بدقة.\nالسؤال: ${q.text}\nالإجابة النموذجية: ${q.hint||"لا توجد إجابة نموذجية"}\nإجابة المرشح: ${ans}\nالدرجة الكاملة: ${q.points}\n\nقيّم الإجابة وأعطها درجة من 0 إلى ${q.points}.\nأرجع JSON فقط: {"score": رقم, "comment": "تعليق مختصر يوضح سبب الدرجة"}`;
        const res = await callAIModel([{role:"user",content:prompt}],"أنت مصحح اختبارات. أرجع JSON فقط.",MODEL_FLASH);
        if (res?.score != null) {
          suggestions[q.id] = { score: Math.min(Math.max(0, Math.round(res.score)), q.points) };
          comments[q.id] = res.comment || "";
        }
      } catch {}
    }
    setExamWrittenGrades(p => {
      const upd = { ...p };
      Object.entries(suggestions).forEach(([qId, data]) => { upd[qId] = { ...upd[qId], score: data.score }; });
      return upd;
    });
    setAiExamComments(p => ({ ...p, ...comments }));
    setAiExamGrading(false);
    show("✅ تم التصحيح الذكي — راجع الدرجات ثم اضغط حفظ");
  };

  const doApproveExam = async (asmntId) => {
    if (!approvalPwd.trim()) { show("⚠️ أدخل كلمة السر"); return; }
    setApproving(true);
    try {
      const user = await getUserByUsername(cu.username);
      if (!user) { show("⚠️ خطأ في حساب المستخدم"); setApproving(false); return; }
      const hash = await hashPassword(approvalPwd);
      if (hash !== user.passwordHash) { show("❌ كلمة السر غير صحيحة"); setApproving(false); return; }
      const asmnt = candAssessments.find(a => a.id === asmntId);
      if (!asmnt) { setApproving(false); return; }
      const upd = { ...asmnt, gradeApproved: true, gradeApprovedBy: userName, gradeApprovedAt: new Date().toISOString() };
      const saved = await saveAssessment(upd);
      setCandAssessments(p => p.map(x => x.id === saved.id ? saved : x));
      addPersonEvent(cand.uid || cand.email, { type: "exam_approved", text: "✅ تم اعتماد نتيجة الاختبار بواسطة " + userName, by: userName, byRole: userRole, private: false }).catch(() => {});
      show("✅ تم اعتماد نتيجة الاختبار");
    } catch (err) { show("⚠️ خطأ: " + err.message); }
    setApproving(false); setApprovalPwd("");
  };

  // Accordion header helper
  const accHead = (key, title, score, badge, right) => (
    <div onClick={()=>toggleAcc(key)} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 14px", cursor:"pointer", borderBottom:openAccs[key]?"0.5px solid var(--b)":"none" }}>
      <div style={{ display:"flex", alignItems:"center", gap:6, flexWrap:"wrap" }}>
        <span style={{ fontSize:11, color:"var(--text3)" }}>{openAccs[key]?"▾":"▸"}</span>
        <span style={{ fontSize:12, fontWeight:700, color:"var(--text)" }}>{title}</span>
        {score!=null && <span style={{ fontSize:11, padding:"2px 8px", borderRadius:6, background:oC(score)+"18", color:oC(score), fontWeight:700 }}>{score}/100</span>}
        {badge && <span style={{ fontSize:10, padding:"2px 6px", borderRadius:6, background:badge.bg, color:badge.c }}>{badge.t}</span>}
      </div>
      {right && <span style={{ fontSize:10, color:"var(--text3)" }}>{right}</span>}
    </div>
  );

  const TABS = [{id:"info",l:"البيانات"},{id:"exp",l:"الخبرة"},{id:"tags",l:"التصنيفات"},{id:"cv",l:"السيرة الذاتية"}];

  const printCard = (mode) => {
    const isInternal = mode === "internal";
    const n = cand.fullName || "";
    const num = cand.hrCode || cand.idNumber || "";
    const t = new Date().toLocaleDateString("ar-SA");
    const logo = typeof HMA_LOGO_OFFER !== "undefined" ? HMA_LOGO_OFFER : "";
    const esc = (s) => (s||"").replace(/</g,"&lt;").replace(/>/g,"&gt;");
    const scColor = (s) => s>=81?"#16a34a":s>=61?"#d97706":"#dc2626";
    const stgName = (k) => ({interview1:"مقابلة أولى",assessment:"اختبار",interview2:"مقابلة ثانية",offer:"عرض وظيفي",contract:"توقيع العقد"})[k]||k;

    // ── بيانات شخصية ──
    const fields = [["📞 الجوال",cand.phone],["✉️ البريد",cand.email],["🆔 رقم الهوية",cand.idNumber],["🌍 الجنسية",cand.nationality],["👤 الجنس",cand.gender],["📍 المدينة",cand.city],["🌐 الموقع",cand.locationStatus],["🔤 الاسم بالإنجليزية",cand.fullNameEn],["🎓 المؤهل",(cand.education||"")+(cand.university?" — "+cand.university:"")],["📚 التخصص",cand.major],["💰 الراتب المتوقع",isInternal&&cand.expectedSalary?Number(cand.expectedSalary).toLocaleString()+" ريال":""],["📅 الإتاحة",cand.availabilityStatus||cand.availability],["🔗 LinkedIn",cand.linkedinUrl],["💼 آخر مسمى",cand.lastJob],["🏢 آخر شركة",cand.lastCompany],["🎂 سنة التخرج",cand.graduationYear?String(cand.graduationYear):""],["📊 سنوات الخبرة",cand.yearsExperience?cand.yearsExperience+" سنة":""]].filter(([,v])=>v&&String(v).trim());
    const specs = [...(cand.biSpec||[]),...(cand.biSkill||[]),...(cand.biSW||[]),...(cand.biCert||[]),...(cand.biDept||[]),...(cand.biProj||[])].filter(t2=>t2.ar);

    // ── المسمى الوظيفي (من الهيكل + الإعلان) ──
    const src = jt || jp || null;
    let jtHtml = "";
    if (src) {
      jtHtml = "<div class=sec-green><h3>💼 المسمى الوظيفي المرشح له"+(jp?" — من إعلان وظيفي":"")+"</h3><table>";
      [["المسمى",src.title],["الإدارة",src.department||jp?.department],["الدرجة",jt?.gradeRef||jp?.gradeCode],["الراتب",jt?.salaryRange],["المدينة",jp?.city],["نوع العقد",jp?.contractType],["الحد الأدنى للخبرة",jp?.minExperience?jp.minExperience+" سنة":""]].filter(([,v])=>v).forEach(([l,v])=>{jtHtml+="<tr><td class=lbl>"+l+"</td><td>"+esc(v)+"</td></tr>";});
      jtHtml += "</table>";
      if(jt?.description||jp?.description) jtHtml+="<p class=det><b>📝 الوصف:</b> "+esc(jt?.description||jp?.description)+"</p>";
      if(jt?.tasks) jtHtml+="<p class=det><b>📋 المهام:</b> "+esc(jt.tasks)+"</p>";
      if((jt?.duties||jp?.duties||[]).length>0) jtHtml+="<p class=det><b>📋 المهام:</b></p><ul>"+(jt?.duties||jp?.duties||[]).map(d=>"<li>"+esc(d)+"</li>").join("")+"</ul>";
      if(jt?.requirements) jtHtml+="<p class=det><b>📌 المتطلبات:</b> "+esc(jt.requirements)+"</p>";
      const tagList = (label,arr) => arr?.length>0?"<p class=det><b>"+label+":</b> "+arr.map(s=>"<span class=tag>"+esc(s)+"</span>").join(" ")+"</p>":"";
      jtHtml += tagList("🔧 المهارات",jp?.requiredSkills)+tagList("💻 البرامج",jp?.requiredSoftware)+tagList("🏅 الشهادات",jp?.requiredCertifications)+tagList("🏗️ أنواع المشاريع",jp?.requiredProjectTypes)+tagList("📚 الدورات",jp?.courses);
      if((jt?.kpiCriteria||[]).length>0) jtHtml+="<p class=det><b>📊 مؤشرات KPI:</b></p><table>"+(jt.kpiCriteria||[]).map(k=>"<tr><td class=lbl>"+(k.label||k.name||"")+"</td><td style=\"font-weight:900;color:#16a34a\">"+(k.weight||k.pct||"")+"%</td></tr>").join("")+"</table>";
      jtHtml += "</div>";
    }

    // ── تقييمات AI — بالتفصيل ──
    const aiH = (cand.aiEvalHistory||[]);
    let aiHtml = "";
    if(aiH.length>0){
      aiHtml = "<h3>🤖 تقييمات الذكاء الاصطناعي</h3>";
      aiH.forEach((h,i)=>{
        aiHtml += "<div class=eval-card><div class=eval-head><span class=sc style=\"color:"+scColor(h.score||0)+"\">"+h.score+"/100</span><span>"+(h.level||"")+" — "+(h.recommendation||"")+"</span><span class=meta>"+(h.by||"AI")+" · "+(h.at?new Date(h.at).toLocaleDateString("ar-SA"):"")+"</span></div>";
        if(isInternal) {
          if(h.summary) aiHtml+="<p class=det>"+esc(h.summary)+"</p>";
          if(h.strengths?.length) aiHtml+="<p class=det><b>نقاط القوة:</b> "+h.strengths.join("، ")+"</p>";
          if(h.weaknesses?.length) aiHtml+="<p class=det><b>نقاط الضعف:</b> "+h.weaknesses.join("، ")+"</p>";
        }
        aiHtml += "</div>";
      });
    }

    // ── تقييمات المراحل — بالتفصيل ──
    const stageE = Object.entries(cand.stageEvaluations||{});
    let stageHtml = "";
    if(stageE.length>0){
      stageHtml = "<h3>📊 تقييمات المراحل</h3>";
      stageE.forEach(([stg,ev])=>{
        stageHtml += "<div class=eval-card><div class=eval-head><span class=sc style=\"color:"+scColor(ev.total||ev.score||0)+"\">"+(ev.total||ev.score||"—")+"/100</span><span>"+stgName(stg)+"</span><span class=meta>"+(ev.by||"")+" · "+(ev.at?new Date(ev.at).toLocaleDateString("ar-SA"):"")+"</span></div>";
        if(ev.notes) stageHtml+="<p class=det>"+esc(ev.notes)+"</p>";
        stageHtml += "</div>";
      });
    }

    // ── تقييمات التكليف — بالتفصيل ──
    const taskR = (cand.evalTaskResults||[]);
    let taskHtml = "";
    if(taskR.length>0){
      taskHtml = "<h3>📋 تقييمات التكليف</h3>";
      taskR.forEach(r=>{
        taskHtml += "<div class=eval-card><div class=eval-head><span class=sc style=\"color:"+scColor(r.totalScore||0)+"\">"+(r.totalScore||0)+"/100</span><span>"+esc(r.evaluatorName||"")+"</span><span class=meta>التوصية: "+(r.recommendation||"—")+" · "+(r.at?new Date(r.at).toLocaleDateString("ar-SA"):"")+"</span></div>";
        if(isInternal) {
          if(r.technical!=null) taskHtml+="<table><tr><td class=lbl>فني</td><td>"+r.technical+"/100</td><td class=lbl>إداري</td><td>"+(r.admin||0)+"/100</td><td class=lbl>لغوي</td><td>"+(r.language||0)+"/100</td></tr></table>";
          if(r.technicalNotes) taskHtml+="<p class=det><b>فني:</b> "+esc(r.technicalNotes)+"</p>";
          if(r.adminNotes) taskHtml+="<p class=det><b>إداري:</b> "+esc(r.adminNotes)+"</p>";
          if(r.languageNotes) taskHtml+="<p class=det><b>لغوي:</b> "+esc(r.languageNotes)+"</p>";
          if(r.generalNotes) taskHtml+="<p class=det><b>ملاحظات عامة:</b> "+esc(r.generalNotes)+"</p>";
          if(r.recommendationText) taskHtml+="<p class=det><b>شرح التوصية:</b> "+esc(r.recommendationText)+"</p>";
          if(r.thread?.length>0){ taskHtml+="<p class=det><b>💬 المناقشة:</b></p>"; r.thread.forEach(msg=>{ taskHtml+="<p class=chat><b>"+esc(msg.by||"")+"</b> ("+new Date(msg.at).toLocaleDateString("ar-SA")+"): "+esc(msg.text||"")+"</p>"; }); }
        }
        taskHtml += "</div>";
      });
    }

    // ── تصنيفات مجمّعة بالنوع ──
    const specsByType = {};
    specs.forEach(s => { const t2=s.source||"other"; if(!specsByType[t2]) specsByType[t2]=[]; specsByType[t2].push(s.ar); });
    const specLabels = {spec:"التخصصات",skill:"المهارات",sw:"البرامج",cert:"الشهادات",dept:"الإدارات",proj:"المشاريع",screening:"الفحص",other:"أخرى"};

    let html = '<!DOCTYPE html><html dir=rtl lang=ar><head><meta charset=UTF-8><title>بطاقة تقييم — '+esc(n)+'</title>'
      + '<style>'
      + '@page{size:A4;margin:15mm 12mm}'
      + 'body{font-family:Arial;direction:rtl;font-size:10px;line-height:1.5;color:#1a2235;margin:0;padding:0}'
      + 'table{width:100%;border-collapse:collapse;margin:4px 0;page-break-inside:avoid}'
      + 'td{padding:4px 7px;border:1px solid #ddd;font-size:10px}'
      + 'h2{font-size:15px;margin:0}'
      + 'h3{font-size:12px;margin:10px 0 4px;padding-bottom:3px}'
      + '.hdr{display:flex;align-items:center;justify-content:space-between;border-bottom:3px solid #c9a84c;padding-bottom:8px;margin-bottom:0}'
      + '.sec-red{background:#fef2f2;border:2px solid #fca5a5;border-radius:10px;padding:10px 12px;margin:8px 0;page-break-inside:avoid}'
      + '.sec-red h3{color:#dc2626;border-bottom:1px solid #fca5a5;margin:0 0 6px}'
      + '.sec-red td.lbl{background:#fee2e2;font-weight:700;width:22%;color:#991b1b}'
      + '.sec-green{background:#e8f5e9;border:2px solid #a5d6a7;border-radius:10px;padding:10px 12px;margin:8px 0;page-break-inside:avoid}'
      + '.sec-green h3{color:#16a34a;border-bottom:1px solid #a5d6a7;margin:0 0 6px}'
      + '.sec-green td.lbl{background:#c8e6c9;font-weight:700;width:28%;color:#166534}'
      + '.sec-eval{background:#fef9ef;border:2px solid #e5dcc8;border-radius:10px;padding:10px 12px;margin:8px 0;page-break-inside:avoid}'
      + '.sec-eval h3{color:#92400e;border-bottom:1px solid #e5dcc8;margin:0 0 6px}'
      + '.tag{display:inline-block;padding:2px 7px;border-radius:4px;font-size:9px;margin:2px;font-weight:600}'
      + '.tag-r{background:#fee2e2;color:#dc2626}'
      + '.tag-g{background:#dcfce7;color:#16a34a}'
      + '.sc{font-size:16px;font-weight:900}'
      + '.det{font-size:10px;margin:3px 0;color:#444;line-height:1.6}'
      + '.eval-card{background:#fff;border:1px solid #e5dcc8;border-radius:6px;padding:8px 10px;margin:5px 0;page-break-inside:avoid}'
      + '.eval-head{display:flex;align-items:center;gap:8px;flex-wrap:wrap}'
      + '.meta{font-size:9px;color:#888}'
      + '.chat{font-size:9px;color:#555;margin:2px 0;padding:2px 6px;background:#f5f5f5;border-radius:3px}'
      + '.grid2{display:grid;grid-template-columns:1fr 1fr;gap:4px}'
      + 'ul{margin:3px 0;padding-right:16px}li{margin-bottom:1px}'
      + 'pre{font-size:9px;white-space:pre-wrap;background:#fff5f5;padding:8px;border-radius:6px;border:1px solid #fca5a5;page-break-inside:avoid;max-height:300px;overflow:hidden}'
      + '</style></head><body>'

      // ── الهيدر ──
      + '<div class=hdr><div><h2 style="color:#c9a84c">📋 بطاقة تقييم مرشح</h2>'
      + '<p style="margin:2px 0;font-size:13px;font-weight:900">'+esc(n)+(num?' — <span style="color:#c9a84c">#'+esc(num)+'</span>':'')+'</p>'
      + '<p style="margin:2px 0;font-size:9px;color:#888">'+t+' — مكتب هاني محمد عسيري للاستشارات الهندسية</p></div>'
      + (logo?'<img src="'+logo+'" style="height:55px"/>':'')+'</div>'

      // ═══ القسم الأحمر: البيانات الشخصية + المهارات + السيرة ═══
      + '<div class=sec-red>'
      + '<h3>👤 البيانات الشخصية والمهارات</h3>'
      + '<div class=grid2><table>' + fields.slice(0,Math.ceil(fields.length/2)).map(([l,v])=>'<tr><td class=lbl>'+l+'</td><td>'+esc(v)+'</td></tr>').join('') + '</table>'
      + '<table>' + fields.slice(Math.ceil(fields.length/2)).map(([l,v])=>'<tr><td class=lbl>'+l+'</td><td>'+esc(v)+'</td></tr>').join('') + '</table></div>'
      + (cand.hayaMemberNo?'<p style="font-size:10px;margin:4px 0">🏛️ <b>عضوية الهيئة:</b> '+esc(cand.hayaMemberNo)+' — '+esc(typeof cand.hayaRank==="object"?(cand.hayaRank?.ar||""):cand.hayaRank||"")+(cand.hayaExpiry?" — ينتهي: "+new Date(cand.hayaExpiry).toLocaleDateString("ar-SA"):"")+'</p>':'')
      + (cand.notes?'<p style="font-size:10px;margin:4px 0">📝 <b>ملاحظات:</b> '+esc(cand.notes)+'</p>':'')
      + (specs.length>0?'<div style="margin-top:6px">'+Object.entries(specsByType).map(([k,arr])=>'<div style="margin-bottom:3px"><b style="font-size:9px;color:#991b1b">'+(specLabels[k]||k)+':</b> '+arr.map(s=>'<span class="tag tag-r">'+esc(s)+'</span>').join('')+'</div>').join('')+'</div>':'')
      + (cand.cvFullText?'<div style="margin-top:6px"><b style="font-size:9px;color:#991b1b">📄 السيرة الذاتية:</b><pre>'+esc(cand.cvFullText.slice(0,3000))+'</pre></div>':'')
      + '</div>'

      // ═══ القسم الأخضر: الوصف الوظيفي ═══
      + jtHtml;

    // ── مراحل التوظيف ──
    const rec2 = cand.evaluation?.recommendation || "";
    const PIPE = ["اختبار","مقابلة أولى","مقابلة ثانية","إرسال عرض وظيفي","توقيع العقد"];
    const pipeIdx2 = PIPE.indexOf(rec2);
    let pipeHtml = '<div style="margin:8px 0;display:flex;align-items:center;justify-content:center;gap:3px;flex-wrap:wrap">';
    PIPE.forEach((s,i) => {
      const done = i < pipeIdx2; const active = i === pipeIdx2;
      const bg = done?"#16a34a":active?"#c9a84c":"#ddd";
      const clr = (done||active)?"#fff":"#888";
      pipeHtml += '<span style="padding:3px 8px;border-radius:20px;font-size:9px;font-weight:700;background:'+bg+';color:'+clr+'">'+(done?"✓ ":active?"● ":"")+s+'</span>';
      if (i < PIPE.length-1) pipeHtml += '<span style="color:#ccc;font-size:7px">→</span>';
    });
    pipeHtml += '</div>';

    // ── حالات الاختبار والمقابلات — بالتفصيل ──
    const asmtDone = cand.assessmentResult || cand.stageEvaluations?.assessment;
    let asmtHtml = '';
    // v37.39: طباعة اختبارات مفصّلة (داخلي فقط)
    if (isInternal && candAssessments.length > 0) {
      candAssessments.forEach(ca => {
        const caQs = (ca.selectedQs||[]).map(id=>examQuestions.find(q=>q.id===id)).filter(Boolean);
        const caScoredQs = caQs.filter(q=>!_isScreeningQ(q)&&!q.isKPIExam);
        const caScreenQs = caQs.filter(q=>_isScreeningQ(q));
        const caMax = caScoredQs.reduce((s,q)=>s+(q.points||1),0)||1;
        const caPct = ca.finalPct || Math.round((ca.finalScore||0)/caMax*100);
        asmtHtml += '<div class=eval-card style="border-right:3px solid #f59e0b"><div class=eval-head><b style="color:#92400e">📝 '+(ca.title||"اختبار")+'</b>';
        asmtHtml += '<span class=sc style="color:'+scColor(caPct)+'">'+caPct+'%</span>';
        asmtHtml += '<span class=meta>'+(ca.finalScore||0)+'/'+caMax+' نقطة</span>';
        if(ca.gradeApproved) asmtHtml += '<span class=meta style="color:#16a34a"> ✅ معتمد: '+esc(ca.gradeApprovedBy||"")+'</span>';
        asmtHtml += '</div>';
        if(ca.gradedBy) asmtHtml += '<p class=meta>صحّحه: '+esc(ca.gradedBy)+' · '+(ca.gradedAt?new Date(ca.gradedAt).toLocaleDateString("ar-SA"):"")+'</p>';
        asmtHtml += '<table><thead><tr><th style="font-size:9px;padding:3px;text-align:right">السؤال</th><th style="font-size:9px;padding:3px;width:50px">النوع</th><th style="font-size:9px;padding:3px;width:60px">الإجابة</th><th style="font-size:9px;padding:3px;width:50px">الدرجة</th><th style="font-size:9px;padding:3px;width:60px">المصحح</th></tr></thead><tbody>';
        caQs.forEach(q => {
          const ans = ca.answers?.[q.id];
          const isScrn = _isScreeningQ(q);
          const wg = ca.writtenGrades?.[q.id];
          const ovr = (ca.gradeOverrides||[]).filter(o=>o.questionId===q.id).pop();
          const sc = q.type==="written" ? (wg?.score||ca.scores?.[q.id]||0) : (ovr?ovr.newScore:(ca.scores?.[q.id]||0));
          const typeL = isScrn?"معلومة":q.type==="tf"?"ص/خ":q.type==="mcq"?"اختيار":"كتابة";
          let ansStr = "";
          if(q.type==="tf") ansStr=ans===true?"صح":ans===false?"خطأ":"—";
          else if(q.type==="mcq") ansStr=ans!=null?(q.options?.[ans]||"—"):"—";
          else ansStr=(ans||"—").slice(0,40);
          const bg = isScrn?"background:rgba(167,139,250,.06)":"";
          asmtHtml += '<tr style="'+bg+'"><td style="font-size:9px;padding:3px">'+esc(q.text.slice(0,80))+'</td><td style="font-size:9px;padding:3px;text-align:center">'+typeL+'</td><td style="font-size:9px;padding:3px">'+esc(ansStr)+'</td><td style="font-size:9px;padding:3px;text-align:center;font-weight:700;color:'+(isScrn?"#a78bfa":sc>0?"#16a34a":"#dc2626")+'">'+(isScrn?"—":sc+"/"+q.points)+'</td><td style="font-size:8px;padding:3px;color:#888">'+(wg?esc(wg.by):(ovr?"✏️"+esc(ovr.by):"تلقائي"))+'</td></tr>';
        });
        asmtHtml += '</tbody></table></div>';
      });
    } else {
      asmtHtml += '<div class=eval-card style="border-right:3px solid #f59e0b"><div class=eval-head><b style="color:#92400e">📝 الاختبار</b>';
      if (asmtDone) {
        asmtHtml += '<span class=sc style="color:'+scColor(asmtDone.score||asmtDone.total||0)+'">'+(asmtDone.score||asmtDone.total||"—")+'/100</span>';
        asmtHtml += '<span class=meta>'+(asmtDone.at?new Date(asmtDone.at).toLocaleDateString("ar-SA"):"")+'</span></div>';
        if(isInternal && asmtDone.notes) asmtHtml += '<p class=det>'+esc(asmtDone.notes)+'</p>';
        if(isInternal && asmtDone.by) asmtHtml += '<p class=meta>المقيّم: '+esc(asmtDone.by)+'</p>';
      } else {
        asmtHtml += '</div><p style="color:#888;font-size:10px;margin:4px 0">⬜ لم يقم بالاختبار بعد</p>';
      }
      asmtHtml += '</div>';
    }

    const iv1Done = cand.stageEvaluations?.interview1;
    let iv1Html = '<div class=eval-card style="border-right:3px solid #22c55e"><div class=eval-head><b style="color:#92400e">🤝 المقابلة الأولى</b>';
    if (iv1Done) {
      iv1Html += '<span class=sc style="color:'+scColor(iv1Done.total||iv1Done.score||0)+'">'+(iv1Done.total||iv1Done.score||"—")+'/100</span>';
      iv1Html += '<span class=meta>'+(iv1Done.by||"")+" · "+(iv1Done.at?new Date(iv1Done.at).toLocaleDateString("ar-SA"):"")+'</span></div>';
      if(isInternal) {
        if(iv1Done.notes) iv1Html += '<p class=det>'+esc(iv1Done.notes)+'</p>';
        if(iv1Done.technical!=null) iv1Html += '<table><tr><td class=lbl>فني</td><td>'+iv1Done.technical+'/100</td><td class=lbl>إداري</td><td>'+(iv1Done.admin||0)+'/100</td><td class=lbl>لغوي</td><td>'+(iv1Done.language||0)+'/100</td></tr></table>';
      }
    } else {
      iv1Html += '</div><p style="color:#888;font-size:10px;margin:4px 0">⬜ لم تتم بعد</p>';
    }
    iv1Html += '</div>';

    const iv2Done = cand.stageEvaluations?.interview2;
    let iv2Html = '<div class=eval-card style="border-right:3px solid #3b82f6"><div class=eval-head><b style="color:#92400e">🤝 المقابلة الثانية</b>';
    if (iv2Done) {
      iv2Html += '<span class=sc style="color:'+scColor(iv2Done.total||iv2Done.score||0)+'">'+(iv2Done.total||iv2Done.score||"—")+'/100</span>';
      iv2Html += '<span class=meta>'+(iv2Done.by||"")+" · "+(iv2Done.at?new Date(iv2Done.at).toLocaleDateString("ar-SA"):"")+'</span></div>';
      if(isInternal) {
        if(iv2Done.notes) iv2Html += '<p class=det>'+esc(iv2Done.notes)+'</p>';
        if(iv2Done.technical!=null) iv2Html += '<table><tr><td class=lbl>فني</td><td>'+iv2Done.technical+'/100</td><td class=lbl>إداري</td><td>'+(iv2Done.admin||0)+'/100</td><td class=lbl>لغوي</td><td>'+(iv2Done.language||0)+'/100</td></tr></table>';
      }
    } else {
      iv2Html += '</div><p style="color:#888;font-size:10px;margin:4px 0">⬜ لم تتم بعد</p>';
    }
    iv2Html += '</div>';

    // ── التعليقات الداخلية ──
    const allComments = [...(cand.evalTaskResults||[]).flatMap(r=>r.thread||[]), ...(cand.discussion||[])].filter(Boolean);
    let commHtml = "";
    if (isInternal && allComments.length > 0) {
      commHtml = '<h3 style="color:#92400e">💬 التعليقات الداخلية (' + allComments.length + ')</h3>';
      allComments.forEach(msg => {
        commHtml += '<div class=chat><b>' + esc(msg.by||"") + '</b> (' + (msg.at||msg.date?new Date(msg.at||msg.date).toLocaleDateString("ar-SA"):"") + '): ' + esc(msg.text||msg.message||"") + '</div>';
      });
    }

    // ── الراتب — داخلي فقط ──
    const salaryLine = isInternal && cand.expectedSalary ? '<p style="font-size:10px;margin:6px 0;color:#dc2626;font-weight:700">💰 الراتب المتوقع: ' + Number(cand.expectedSalary).toLocaleString() + ' ريال</p>' : '';

    html += '<div class=sec-eval>'
      + '<h3>⭐ مسار التوظيف والتقييمات</h3>'
      + pipeHtml
      + aiHtml
      + asmtHtml
      + iv1Html
      + iv2Html
      + salaryLine
      + taskHtml
      + commHtml;
    // ── المتوسط العام ──
    const allScores = [...(cand.aiEvalHistory||[]).map(h=>h.score),...(cand.evalTaskResults||[]).map(r=>r.totalScore),...Object.values(cand.stageEvaluations||{}).map(e=>e.total||e.score)].filter(s=>s!=null&&s>0);
    if (allScores.length > 0) {
      const avg = Math.round(allScores.reduce((a,b)=>a+b,0)/allScores.length);
      html += '<div style="text-align:center;padding:10px 0;margin-top:8px;border-top:2px solid #e5dcc8"><p style="font-size:10px;color:#92400e;margin:0 0 4px">المتوسط العام من '+allScores.length+' تقييم</p><span style="font-size:28px;font-weight:900;color:'+(avg>=81?'#16a34a':avg>=61?'#d97706':'#dc2626')+'">'+avg+'/100</span></div>';
    }
    html += ((!aiHtml&&!taskHtml&&!commHtml)?'<p style="text-align:center;color:#888;font-size:10px">لا توجد تقييمات بعد</p>':'')
      + '</div>'
      + '</body></html>';
    const w = window.open("","_blank");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),500);}
    else show("⚠️ فعّل النوافذ المنبثقة");
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9000, display:"flex", alignItems:"flex-start", justifyContent:"center", padding:"8px", overflowY:"auto" }} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{ background:"var(--dark2,#1a1a2e)", border:"1px solid var(--b)", borderRadius:16, width:"100%", maxWidth:700, marginTop:8, marginBottom:60 }}>
        {toastEl}{confirmDlg}
        {/* Header */}
        <div style={{ padding:"14px 16px", borderBottom:"1px solid var(--b)" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
            <p style={{ fontSize:10, color:"var(--gold)", fontWeight:700, margin:0, letterSpacing:1 }}>📋 بطاقة تقييم مرشح</p>
            <div style={{ display:"flex", gap:6, alignItems:"center" }}>
              {canApprove && <>
                <button onClick={()=>printCard("internal")} style={{ padding:"3px 10px", borderRadius:6, background:"rgba(201,168,76,.1)", border:"1px solid rgba(201,168,76,.3)", color:"var(--gold)", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>🖨️ داخلي</button>
                <button onClick={()=>printCard("external")} style={{ padding:"3px 10px", borderRadius:6, background:"rgba(96,165,250,.1)", border:"1px solid rgba(96,165,250,.3)", color:"#60a5fa", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>📄 خارجي</button>
              </>}
              <button onClick={onClose} style={{ width:28, height:28, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:14, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
            </div>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:38, height:38, borderRadius:"50%", background:"rgba(245,158,11,.15)", display:"flex", alignItems:"center", justifyContent:"center", fontWeight:700, fontSize:13, color:"#f59e0b" }}>{(cand.fullName||"?").split(" ").slice(0,2).map(w=>w[0]).join("")}</div>
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                <span style={{ fontWeight:900, fontSize:16, color:"var(--text)" }}>{cand.fullName}</span>
                {(cand.idNumber||cand.hrCode) && <span style={{ fontSize:10, padding:"2px 7px", borderRadius:5, background:"rgba(201,168,76,.1)", color:"var(--gold)", fontWeight:700 }}>#{cand.hrCode||cand.idNumber}</span>}
              </div>
              {cand.phone && <div style={{ display:"flex", gap:6, marginTop:4 }}>
                <a href={"https://wa.me/"+(cand.phone||"").replace(/^0/,"966").replace(/[^0-9]/g,"")+"?text="+encodeURIComponent("السلام عليكم "+(cand.fullName||"")+"،\nنود التنسيق معكم بخصوص التقييم الوظيفي.\n\n🔴 تنبيه مهم:\nنود التنويه بأن التقديم على الوظائف ومتابعة الطلبات تتم حصريًا عبر الموقع الإلكتروني الخاص بمكتبنا لاستقبال طلبات التوظيف والتدريب.\nنأمل منكم التسجيل في المنصة واستكمال الطلبات المرسلة لكم، وذلك لتمكيننا من دراسة ملفكم الوظيفي بشكل كامل.\n🔗 https://hma.engineer\n\nمع التحية،\n"+(cu.displayName||"إدارة الموارد البشرية")+"\nنظام كوادر HMA\n⚙️ إدارة الإشعارات: hma.engineer/unsubscribe")} target="_blank" rel="noopener" onClick={()=>{const pid=cand.uid||cand.idNumber||cand.email;if(pid)addPersonEvent(pid,{type:"contact",text:"💬 تواصل واتساب — "+userName,by:userName,byRole:userRole,private:false}).catch(()=>{});}} style={{ padding:"3px 10px", borderRadius:6, background:"rgba(37,211,102,.1)", border:"1px solid rgba(37,211,102,.3)", color:"#25d366", fontSize:10, fontWeight:700, textDecoration:"none", display:"inline-flex", alignItems:"center", gap:3 }}>💬 واتساب</a>
                <a href={"tel:"+(cand.phone||"")} onClick={()=>{const pid=cand.uid||cand.idNumber||cand.email;if(pid)addPersonEvent(pid,{type:"contact",text:"📞 اتصال هاتفي — "+userName,by:userName,byRole:userRole,private:false}).catch(()=>{});}} style={{ padding:"3px 10px", borderRadius:6, background:"rgba(96,165,250,.1)", border:"1px solid rgba(96,165,250,.3)", color:"#60a5fa", fontSize:10, fontWeight:700, textDecoration:"none", display:"inline-flex", alignItems:"center", gap:3 }}>📞 اتصال</a>
                <a href={"mailto:"+(cand.email||"")+"?subject="+encodeURIComponent("بخصوص التقييم الوظيفي — كوادر HMA")+"&body="+encodeURIComponent("السلام عليكم "+(cand.fullName||"")+"،\nنود التنسيق معكم بخصوص التقييم الوظيفي.\n\nمع التحية،\n"+userName+"\nإدارة الموارد البشرية — نظام كوادر HMA")} onClick={()=>{const pid=cand.uid||cand.idNumber||cand.email;if(pid)addPersonEvent(pid,{type:"contact",text:"📧 بريد إلكتروني — "+userName,by:userName,byRole:userRole,private:false}).catch(()=>{});}} style={{ padding:"3px 10px", borderRadius:6, background:"rgba(201,168,76,.1)", border:"1px solid rgba(201,168,76,.3)", color:"var(--gold)", fontSize:10, fontWeight:700, textDecoration:"none", display:"inline-flex", alignItems:"center", gap:3 }}>📧 بريد</a>
              </div>}
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:"flex", borderBottom:"1px solid var(--b)", overflowX:"auto" }}>
          {TABS.map(t => <button key={t.id} onClick={()=>setTab(t.id)} style={{ flex:1, padding:"9px 6px", border:"none", borderBottom:tab===t.id?"2px solid var(--accent)":"2px solid transparent", background:tab===t.id?"var(--accent-d)":"transparent", color:tab===t.id?"var(--accent)":"var(--text3)", fontFamily:"inherit", fontSize:11, fontWeight:700, cursor:"pointer", whiteSpace:"nowrap" }}>{t.l}</button>)}
        </div>

        {/* Tab content - simplified */}
        <div style={{ padding:"12px 16px", borderBottom:"1px solid var(--b)", fontSize:12, color:"var(--text2)" }}>
          {tab === "info" && <div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(140px, 1fr))", gap:8, marginBottom:8 }}>
              {[["📞 الجوال",cand.phone],["✉️ البريد",cand.email],["🆔 رقم الهوية",cand.idNumber],["🌍 الجنسية",cand.nationality],["👤 الجنس",cand.gender],["📍 المدينة",cand.city],["🌐 الموقع",cand.locationStatus],["🔤 الاسم بالإنجليزية",cand.fullNameEn],["🎓 المؤهل",(cand.education||"")+(cand.university?" — "+cand.university:"")],["📚 التخصص",cand.major],["💰 الراتب المتوقع",cand.expectedSalary?Number(cand.expectedSalary).toLocaleString()+" ريال":""],["📅 الإتاحة",cand.availabilityStatus||cand.availability],["🎓 نوع التدريب",cand.trainingType],["🔗 LinkedIn",cand.linkedinUrl],["💼 آخر مسمى",cand.lastJob],["🏢 آخر شركة",cand.lastCompany],["🎂 سنة التخرج",cand.graduationYear?String(cand.graduationYear):""],["📊 سنوات الخبرة",cand.yearsExperience?cand.yearsExperience+" سنة":""]].filter(([,v])=>v&&String(v).trim()).map(([l,v])=>
                <div key={l} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 10px", overflow:"hidden" }}><p style={{ fontSize:9, color:"var(--text3)", margin:"0 0 1px" }}>{l}</p><p style={{ fontSize:12, fontWeight:700, margin:0, wordBreak:"break-word", overflowWrap:"anywhere" }}>{v}</p></div>
              )}
            </div>
            {cand.notes && <div style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 10px", marginBottom:8 }}><p style={{ fontSize:9, color:"var(--text3)", margin:"0 0 1px" }}>📝 ملاحظات</p><p style={{ fontSize:12, fontWeight:700, margin:0, wordBreak:"break-word", overflowWrap:"anywhere" }}>{cand.notes}</p></div>}
            {cand.hayaMemberNo && <div style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 10px" }}><p style={{ fontSize:9, color:"var(--text3)", margin:"0 0 1px" }}>🏛️ عضوية الهيئة</p><p style={{ fontSize:12, fontWeight:700, margin:0, wordBreak:"break-word", overflowWrap:"anywhere" }}>{cand.hayaMemberNo} — {typeof cand.hayaRank==="object"?(cand.hayaRank?.ar||""):cand.hayaRank||""}{cand.hayaExpiry?" — ينتهي: "+new Date(cand.hayaExpiry).toLocaleDateString("ar-SA"):""}</p></div>}
          </div>}
          {tab === "exp" && <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(140px, 1fr))", gap:8 }}>
            {[["💼 آخر مسمى",cand.lastJob],["🏢 آخر شركة",cand.lastCompany],["📊 سنوات الخبرة",cand.yearsExperience?cand.yearsExperience+" سنة":""],["🎂 سنة التخرج",cand.graduationYear]].filter(([,v])=>v).map(([l,v])=>
              <div key={l} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 10px", flex:1, minWidth:120 }}><p style={{ fontSize:9, color:"var(--text3)", margin:"0 0 1px" }}>{l}</p><p style={{ fontSize:12, fontWeight:700, margin:0, wordBreak:"break-word", overflowWrap:"anywhere" }}>{v}</p></div>
            )}
            {(cand.companies||[]).length>0 && <div style={{ width:"100%", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 10px" }}><p style={{ fontSize:9, color:"var(--text3)", margin:"0 0 4px" }}>🏛️ الشركات السابقة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{(cand.companies||[]).map((c,i)=><span key={i} style={{ fontSize:11, padding:"2px 8px", borderRadius:6, background:"rgba(255,255,255,.06)", color:"var(--text2)", border:"1px solid var(--b)" }}>{c}</span>)}</div></div>}
          </div>}
          {tab === "tags" && <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
            {[...(cand.skills||[]),...(cand.software||[]),...(cand.certifications||[]),...(cand.specializations||[])].map((t,i)=> <span key={i} style={{ fontSize:10, padding:"3px 8px", borderRadius:6, background:"var(--glass)", border:"1px solid var(--b)", color:"var(--text2)" }}>{typeof t==="object"?(t.ar||t.en||""):t}</span>)}
            {[...(cand.skills||[]),...(cand.software||[]),...(cand.certifications||[]),...(cand.specializations||[])].length===0 && <p style={{ color:"var(--text3)" }}>لا توجد تصنيفات</p>}
          </div>}
          {tab === "cv" && <div>
            {(cand.cvHistory||[]).length > 0 ? <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {[...(cand.cvHistory||[])].reverse().map((snap,i) => {
                const isJson = (() => { try { const p = JSON.parse(snap.text||""); return p && typeof p === "object"; } catch { return false; } })();
                const displayText = isJson ? (() => { try { const p = JSON.parse(snap.text); return [p.fullName&&"الاسم: "+p.fullName, p.lastJob&&"آخر وظيفة: "+p.lastJob, p.yearsExperience&&"الخبرة: "+p.yearsExperience+" سنة", p.education&&"المؤهل: "+p.education].filter(Boolean).join("\n"); } catch { return snap.text||""; } })() : snap.text || "";
                return <CVAccordion key={snap.id||i} snap={snap} isLatest={i===0} displayText={displayText} onRemove={null} />;
              })}
            </div> : (cand.cvFullText ? <CVAccordion snap={{ id:"legacy", text:cand.cvFullText, addedAt:cand.createdAt, source:"legacy" }} isLatest={true} displayText={cand.cvFullText} onRemove={null} /> : <p style={{ color:"var(--text3)", textAlign:"center", padding:16 }}>لا توجد سيرة ذاتية</p>)}
          </div>}
        </div>

        {/* Job Title Accordion */}

        {/* ══ v37.39: بانر المرحلة — المرشح في مرحلة الاختبار ══ */}
        {needsExamFirst && <div style={{ padding:"12px 16px", borderBottom:"1px solid var(--b)", background:"rgba(239,68,68,.04)" }}>
          <div style={{ padding:"12px 14px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.25)", borderRadius:10, textAlign:"center" }}>
            <p style={{ fontSize:14, fontWeight:900, color:"#f87171", marginBottom:6 }}>📝 المرشح في مرحلة الاختبار</p>
            {candAssessments.length === 0 && <p style={{ fontSize:12, color:"#f59e0b", marginBottom:4 }}>⚠️ لم يُجهّز اختبار بعد — تم إشعار مدير الموارد البشرية تلقائياً</p>}
            {candAssessments.length > 0 && !candAssessments.some(a=>a.gradedBy) && <p style={{ fontSize:12, color:"#a78bfa", marginBottom:4 }}>📝 الاختبار مكتمل — بانتظار التصحيح</p>}
            {candAssessments.some(a=>a.gradedBy) && !candAssessments.every(a=>a.gradeApproved) && <p style={{ fontSize:12, color:"#3b82f6", marginBottom:4 }}>🔐 تم التصحيح — بانتظار اعتماد النتيجة</p>}
            <p style={{ fontSize:11, color:"var(--text3)", margin:0 }}>أقسام التقييم والمقابلة ستظهر بعد اعتماد نتيجة الاختبار</p>
          </div>
        </div>}
        
        {(jt||jp) && <div style={{ borderBottom:"1px solid var(--b)", borderRight:"3px solid #16a34a", background:"rgba(34,197,94,.04)" }}>
          {accHead("jt", "💼 المسمى الوظيفي المرشح له", null, null, (jt?.title||jp?.title||"")+(jt?.gradeRef?" — "+jt.gradeRef:"")+(jp?" — من إعلان وظيفي":""))}
          {openAccs.jt && <div style={{ padding:"12px 16px", fontSize:11, color:"var(--text2)", lineHeight:1.8 }}>
            {/* ── البيانات الأساسية ── */}
            <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginBottom:8 }}>
              {[["المسمى",jt?.title||jp?.title],["الإدارة",jt?.department||jp?.department],["الدرجة",jt?.gradeRef||jp?.gradeCode],["الراتب",jt?.salaryRange],["المدينة",jp?.city],["نوع العقد",jp?.contractType],["الحد الأدنى للخبرة",jp?.minExperience?jp.minExperience+" سنة":""]].filter(([,v])=>v).map(([l,v])=>
                <div key={l} style={{ background:"rgba(34,197,94,.06)", border:"1px solid rgba(34,197,94,.15)", borderRadius:8, padding:"6px 10px", flex:1, minWidth:100 }}><p style={{ fontSize:9, color:"#16a34a", margin:"0 0 1px", fontWeight:700 }}>{l}</p><p style={{ fontSize:11, fontWeight:700, margin:0 }}>{v}</p></div>
              )}
            </div>
            {/* ── الوصف الوظيفي ── */}
            {(jt?.description||jp?.description) && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>📝 الوصف الوظيفي</p><p style={{ margin:0, fontSize:11, whiteSpace:"pre-wrap" }}>{jt?.description||jp?.description}</p></div>}
            {/* ── المهام ── */}
            {((jt?.duties||jp?.duties||[]).length>0||(jt?.tasks)) && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>📋 المهام الوظيفية</p>
              {jt?.tasks && <p style={{ margin:0, fontSize:11, whiteSpace:"pre-wrap" }}>{jt.tasks}</p>}
              {(jt?.duties||jp?.duties||[]).length>0 && <ul style={{ margin:"4px 0", paddingRight:16 }}>{(jt?.duties||jp?.duties||[]).map((d,i)=><li key={i} style={{ fontSize:11, marginBottom:2 }}>{d}</li>)}</ul>}
            </div>}
            {/* ── المتطلبات ── */}
            {jt?.requirements && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>📌 المتطلبات</p><p style={{ margin:0, fontSize:11, whiteSpace:"pre-wrap" }}>{jt.requirements}</p></div>}
            {/* ── المهارات المطلوبة ── */}
            {(jp?.requiredSkills||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>🔧 المهارات المطلوبة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{jp.requiredSkills.map((s,i)=><span key={i} style={{ padding:"2px 8px", borderRadius:6, background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.15)", fontSize:10, color:"#16a34a", fontWeight:600 }}>{s}</span>)}</div></div>}
            {/* ── البرامج المطلوبة ── */}
            {(jp?.requiredSoftware||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>💻 البرامج المطلوبة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{jp.requiredSoftware.map((s,i)=><span key={i} style={{ padding:"2px 8px", borderRadius:6, background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.15)", fontSize:10, color:"#16a34a", fontWeight:600 }}>{s}</span>)}</div></div>}
            {/* ── الشهادات المطلوبة ── */}
            {(jp?.requiredCertifications||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>🏅 الشهادات المطلوبة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{jp.requiredCertifications.map((s,i)=><span key={i} style={{ padding:"2px 8px", borderRadius:6, background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.15)", fontSize:10, color:"#16a34a", fontWeight:600 }}>{s}</span>)}</div></div>}
            {/* ── أنواع المشاريع ── */}
            {(jp?.requiredProjectTypes||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>🏗️ أنواع المشاريع المطلوبة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{jp.requiredProjectTypes.map((s,i)=><span key={i} style={{ padding:"2px 8px", borderRadius:6, background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.15)", fontSize:10, color:"#16a34a", fontWeight:600 }}>{s}</span>)}</div></div>}
            {/* ── الدورات ── */}
            {(jp?.courses||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>📚 الدورات المطلوبة</p><div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>{jp.courses.map((s,i)=><span key={i} style={{ padding:"2px 8px", borderRadius:6, background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.15)", fontSize:10, color:"#16a34a", fontWeight:600 }}>{s}</span>)}</div></div>}
            {/* ── معايير KPI ── */}
            {(jt?.kpiCriteria||[]).length>0 && <div style={{ background:"rgba(34,197,94,.03)", border:"1px solid rgba(34,197,94,.1)", borderRadius:8, padding:"8px 10px", marginBottom:6 }}><p style={{ fontSize:10, color:"#16a34a", margin:"0 0 2px", fontWeight:700 }}>📊 مؤشرات الأداء (KPI)</p><div>{(jt.kpiCriteria||[]).map((k,i)=><div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"3px 0", borderBottom:"1px solid rgba(34,197,94,.08)" }}><span style={{ fontSize:11 }}>{k.label||k.name||""}</span><span style={{ fontSize:10, fontWeight:700, color:"#16a34a" }}>{k.weight||k.pct||""}%</span></div>)}</div></div>}
          </div>}
        </div>}

        {/* AI Eval Accordion — مخفي عن الموظف المقيّم */}
        {!needsExamFirst && !hideOtherEvals && aiHistory.length > 0 && aiHistory.map((h,i) => { const isEditingAI = editingScore?.type==="ai" && editingScore?.taskIdx===i; return <div key={"ai"+i} style={{ borderBottom:"1px solid var(--b)", borderRight:"3px solid #a78bfa" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ flex:1 }}>{accHead("ai"+i, "تقييم الذكاء الاصطناعي", h.score, h.level?{bg:"rgba(245,158,11,.12)",c:"#f59e0b",t:h.level}:null, (h.by||"AI")+" · "+(h.at?new Date(h.at).toLocaleDateString("ar-SA"):""))}</div>
            {isAdm && <button onClick={e=>{e.stopPropagation();setEditingScore(isEditingAI?null:{type:"ai",taskIdx:i,score:h.score||0});}} style={{ margin:"0 10px", fontSize:11, padding:"3px 8px", borderRadius:6, border:"1px solid rgba(167,139,250,.3)", background:"rgba(167,139,250,.08)", color:"#a78bfa", cursor:"pointer" }}>✏️</button>}
          </div>
          {isEditingAI && isAdm && <div style={{ padding:"10px 14px", background:"rgba(167,139,250,.06)", borderBottom:"1px solid var(--b)" }}>
            <p style={{ fontSize:11, color:"#a78bfa", marginBottom:6 }}>تعديل درجة AI (المدير العام فقط)</p>
            <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:8 }}>
              <label style={{ fontSize:11, color:"var(--text3)" }}>الدرجة:</label>
              <input type="number" min="0" max="100" value={editingScore.score} onChange={e=>setEditingScore(p=>({...p,score:+e.target.value}))} style={{ width:70, padding:"5px 8px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontSize:12, fontFamily:"inherit" }} />
            </div>
            <div style={{ display:"flex", gap:6 }}>
              <button onClick={async()=>{
                const newHistory=[...cand.aiEvalHistory]; newHistory[i]={...h,score:editingScore.score};
                const upd={...cand,aiEvalHistory:newHistory};
                { const eOk = await confirm("تأكيد تعديل درجة AI؟\n\nسيتم تحديث التقييم في ملف المرشح."); if(!eOk)return; if(onSave) await onSave(upd); setEditingScore(null); setRefreshKey(k=>k+1); show("✅ تم تعديل درجة AI"); };
              }} style={{ flex:1, padding:"7px", borderRadius:8, border:"none", background:"linear-gradient(135deg,#a78bfa,#7c3aed)", color:"#fff", fontWeight:900, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>حفظ</button>
              <button onClick={()=>setEditingScore(null)} style={{ padding:"7px 12px", borderRadius:8, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit", fontSize:12 }}>إلغاء</button>
            </div>
          </div>}
          {openAccs["ai"+i] && <div style={{ padding:"12px 16px", fontSize:11 }}>
            {h.summary && <div style={{ background:"var(--glass)", borderRadius:8, padding:"10px 12px", marginBottom:10, color:"var(--text2)", lineHeight:1.8, fontSize:12 }}>"{h.summary}"</div>}
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:10 }}>
              {(h.strengths||[]).length>0 && <div style={{ background:"rgba(96,165,250,.06)" }}><p style={{ fontSize:11, fontWeight:700, color:"#60a5fa", margin:"0 0 4px" }}>✅ نقاط القوة</p>{h.strengths.map((s,si)=><p key={si} style={{ fontSize:11, color:"var(--text2)", margin:"0 0 3px", lineHeight:1.6 }}>· {s}</p>)}</div>}
              {(h.weaknesses||[]).length>0 && <div style={{ background:"rgba(167,139,250,.06)" }}><p style={{ fontSize:11, fontWeight:700, color:"#a78bfa", margin:"0 0 4px" }}>⚠ نقاط الضعف</p>{h.weaknesses.map((w,wi)=><p key={wi} style={{ fontSize:11, color:"var(--text2)", margin:"0 0 3px", lineHeight:1.6 }}>· {w}</p>)}</div>}
            </div>
            {/* Score + bar */}
            <div style={{ marginBottom:10 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:4 }}>
                <span style={{ fontSize:12, color:"var(--text2)" }}>الدرجة</span>
                <span style={{ fontSize:20, fontWeight:900, color:oC(h.score||0) }}>{h.score||0}<span style={{ fontSize:12, color:"var(--text3)" }}>/100</span></span>
              </div>
              <div style={{ height:6, background:"var(--glass)", borderRadius:3, overflow:"hidden" }}><div style={{ height:"100%", width:(h.score||0)+"%", background:oC(h.score||0), borderRadius:3 }}/></div>
            </div>
            {/* Recommendation */}
            {h.recommendation && <div style={{ marginBottom:10 }}>
              <p style={{ fontSize:12, color:"var(--text2)", marginBottom:6 }}>التوصية</p>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:4 }}>
                {["لم يتم القبول","قائمة الانتظار","اختبار","مقابلة أولى","مقابلة ثانية","إرسال عرض وظيفي","يسجل متعاون","توقيع العقد","يقبل كمتدرب"].map(r=><div key={r} style={{ padding:"5px 3px", borderRadius:6, textAlign:"center", fontSize:10, border:r===h.recommendation?"2px solid var(--accent)":"1px solid var(--b)", background:r===h.recommendation?"var(--accent-d)":"transparent", color:r===h.recommendation?"var(--accent)":"var(--text3)", fontWeight:r===h.recommendation?700:400 }}>{r}</div>)}
              </div>
              <div style={{ marginTop:6, padding:"6px 10px", borderRadius:6, background:"rgba(245,158,11,.08)", textAlign:"center", fontSize:12, fontWeight:700, color:"#f59e0b" }}>التوصية الحالية: {h.recommendation}</div>
            </div>}
            {/* Level */}
            {h.level && <div>
              <p style={{ fontSize:12, color:"var(--text2)", marginBottom:6 }}>المستوى</p>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr", gap:4 }}>
                {["مبتدئ","متوسط","محترف","خبير"].map(lv=><div key={lv} style={{ padding:"5px", borderRadius:6, textAlign:"center", fontSize:11, border:lv===h.level?"2px solid var(--accent)":"1px solid var(--b)", background:lv===h.level?"var(--accent-d)":"transparent", color:lv===h.level?"var(--accent)":"var(--text3)", fontWeight:lv===h.level?700:400 }}>{lv}</div>)}
              </div>
            </div>}
          </div>}
        </div>; })}

        {/* Human Eval Accordions — مخفي عن الموظف المقيّم */}
        {!needsExamFirst && !hideOtherEvals && evalResults.map((t,i) => { const live = liveTasks.find(lt => lt.id === t.taskId) || {}; const st = live.status||"completed"; const isEditing = editingScore?.taskIdx===i; return <div key={"ev"+i} style={{ borderBottom:"1px solid var(--b)", borderRight:"3px solid #60a5fa" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ flex:1 }}>{accHead("ev"+i, "تقييم "+(t.evaluatorName||userRole), t.totalScore, st==="completed"?{bg:"rgba(34,197,94,.12)",c:"#4ade80",t:"✅"}:st==="pending_approval"?{bg:"rgba(245,158,11,.12)",c:"#f59e0b",t:"⏳"}:st==="rejected_eval"?{bg:"rgba(239,68,68,.12)",c:"#f87171",t:"❌"}:null, (t.evaluatorName||"")+" · "+(t.at?new Date(t.at).toLocaleDateString("ar-SA"):""))}</div>
            {isAdm && <button onClick={e=>{e.stopPropagation();setEditingScore(isEditing?null:{taskIdx:i,score:t.totalScore,recommendation:t.recommendation||"",idx:i});}} style={{ margin:"0 10px", fontSize:11, padding:"3px 8px", borderRadius:6, border:"1px solid rgba(201,168,76,.3)", background:"rgba(201,168,76,.08)", color:"var(--gold)", cursor:"pointer" }}>✏️</button>}
          </div>
          {isEditing && isAdm && <div style={{ padding:"10px 14px", background:"rgba(201,168,76,.06)", borderBottom:"1px solid var(--b)" }}>
            <p style={{ fontSize:11, color:"var(--gold)", marginBottom:6 }}>تعديل النتيجة (المدير العام فقط)</p>
            <div style={{ display:"flex", gap:8, marginBottom:8, alignItems:"center" }}>
              <label style={{ fontSize:11, color:"var(--text3)" }}>الدرجة:</label>
              <input type="number" min="0" max="100" value={editingScore.score} onChange={e=>setEditingScore(p=>({...p,score:+e.target.value}))} style={{ width:70, padding:"5px 8px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontSize:12, fontFamily:"inherit" }} />
            </div>
            <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginBottom:8 }}>
              {["اختبار","مقابلة أولى","مقابلة ثانية","إرسال عرض وظيفي","توقيع العقد","قائمة الانتظار","لم يتم القبول"].map(r=>(
                <button key={r} onClick={()=>setEditingScore(p=>({...p,recommendation:r}))} style={{ padding:"3px 8px", borderRadius:6, fontSize:10, border:"1px solid "+(editingScore.recommendation===r?"rgba(201,168,76,.5)":"var(--b)"), background:editingScore.recommendation===r?"rgba(201,168,76,.12)":"transparent", color:editingScore.recommendation===r?"var(--gold)":"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>{r}</button>
              ))}
            </div>
            <div style={{ display:"flex", gap:6 }}>
              <button onClick={async()=>{ const newResults=[...cand.evalTaskResults]; newResults[i]={...t,totalScore:editingScore.score,recommendation:editingScore.recommendation}; const upd={...cand,evalTaskResults:newResults}; if(onSave) await onSave(upd); setEditingScore(null); setRefreshKey(k=>k+1); show("✅ تم التعديل"); }} style={{ flex:1, padding:"7px", borderRadius:8, border:"none", background:"linear-gradient(135deg,#c9a84c,#a8893a)", color:"#0b0f1a", fontWeight:900, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>حفظ</button>
              <button onClick={()=>setEditingScore(null)} style={{ padding:"7px 12px", borderRadius:8, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit", fontSize:12 }}>إلغاء</button>
            </div>
          </div>}
          {openAccs["ev"+i] && <div style={{ padding:"12px 16px", fontSize:11 }}>
            <p style={{ color:"var(--text2)", marginBottom:4 }}>فني: <b>{t.technical}</b> · إداري: <b>{t.admin}</b> · لغوي: <b>{t.language}</b></p>
            {t.technicalNotes && <p style={{ fontSize:10, color:"var(--text3)", margin:"0 0 2px" }}>🔧 {t.technicalNotes}</p>}
            {t.adminNotes && <p style={{ fontSize:10, color:"var(--text3)", margin:"0 0 2px" }}>📋 {t.adminNotes}</p>}
            {t.languageNotes && <p style={{ fontSize:10, color:"var(--text3)", margin:"0 0 2px" }}>🗣️ {t.languageNotes}</p>}
            {t.generalNotes && <p style={{ fontSize:10, color:"var(--text3)", margin:"0 0 2px" }}>📝 {t.generalNotes}</p>}
            {t.recommendation && <p style={{ fontWeight:700, color:"#a78bfa", marginTop:4 }}>التوصية: {t.recommendation} {t.recommendationText?" — "+t.recommendationText:""}</p>}
          </div>}
        </div>; })}

        {/* Stage Eval Accordions — مخفي عن الموظف المقيّم */}
        {!needsExamFirst && !hideOtherEvals && Object.entries(stageEvals).map(([stg,ev]) => <div key={"stg"+stg} style={{ borderBottom:"1px solid var(--b)", borderRight:"3px solid #94a3b8" }}>
          {accHead("stg"+stg, "تقييم مرحلة: "+({"interview1":"مقابلة أولى","assessment":"اختبار","interview2":"مقابلة ثانية","offer":"عرض وظيفي","contract":"توقيع العقد","waiting":"قائمة انتظار","rejected":"اعتذار"}[stg]||stg), ev.total||ev.score, null, (ev.by||"")+" · "+(ev.at?new Date(ev.at).toLocaleDateString("ar-SA"):""))}
          {openAccs["stg"+stg] && <div style={{ padding:"12px 16px", fontSize:11 }}>
            {(ev.evaluations||[ev]).map((e,j) => <p key={j} style={{ color:"var(--text2)", marginBottom:2 }}>{e.by} — فني:{e.technical} إداري:{e.admin} لغوي:{e.language} = <b>{e.total}/100</b> {e.notes?" — "+e.notes:""}</p>)}
          </div>}
        </div>)}

        {/* ══ نظام تصحيح واعتماد الاختبارات v37.39 ══ */}
        {candAssessments.map((asmnt, aIdx) => {
          const qs = (asmnt.selectedQs || []).map(id => examQuestions.find(q => q.id === id)).filter(Boolean);
          const scoredQs = qs.filter(q => !_isScreeningQ(q) && !q.isKPIExam);
          const screeningQs = qs.filter(q => _isScreeningQ(q));
          const writtenQs = scoredQs.filter(q => q.type === "written");
          const autoQs = scoredQs.filter(q => q.type !== "written");
          const maxPts = scoredQs.reduce((s, q) => s + (q.points || 1), 0) || 1;
          const pct = asmnt.finalPct || (asmnt.finalScore != null ? Math.round(asmnt.finalScore / maxPts * 100) : null);
          const isGrading = examGradingId === asmnt.id;
          const isApproved = !!asmnt.gradeApproved;
          const isGraded = !!asmnt.gradedBy;
          const canGrade = isEmpEvaluator || isAdm || isHR;
          const canOverrideAuto = isAdm || isHR;
          const accKey = "asmnt" + aIdx;
          const examBadge = isApproved ? { bg: "rgba(34,197,94,.12)", c: "#4ade80", t: "✅ معتمد" } : isGraded ? { bg: "rgba(245,158,11,.12)", c: "#f59e0b", t: "⏳ بانتظار الاعتماد" } : { bg: "rgba(96,165,250,.12)", c: "#60a5fa", t: "📝 يحتاج تصحيح" };
          return <div key={asmnt.id} style={{ borderBottom: "1px solid var(--b)", borderRight: "3px solid " + (isApproved ? "#22c55e" : isGraded ? "#f59e0b" : "#3b82f6") }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div style={{ flex: 1 }}>{accHead(accKey, "📝 " + (asmnt.title || "اختبار"), pct, examBadge, (asmnt.candidateName || "") + " · " + (asmnt.submittedAt ? new Date(asmnt.submittedAt).toLocaleDateString("ar-SA") : ""))}</div>
              {isApproved && <span onClick={() => setShowExamReview(asmnt)} style={{ margin: "0 10px", fontSize: 16, cursor: "pointer", padding: "3px 8px", borderRadius: 6, background: "rgba(34,197,94,.08)", border: "1px solid rgba(34,197,94,.2)" }} title="عرض نتائج الاختبار">📝</span>}
            </div>
            {openAccs[accKey] && <div style={{ padding: "12px 16px", fontSize: 11 }}>
              {/* الدرجة الإجمالية */}
              {pct != null && <div style={{ textAlign: "center", padding: 12, background: pct >= 70 ? "rgba(34,197,94,.06)" : "rgba(239,68,68,.06)", borderRadius: 10, marginBottom: 12, border: "1px solid " + (pct >= 70 ? "rgba(34,197,94,.2)" : "rgba(239,68,68,.2)") }}>
                <div style={{ fontSize: 28, fontWeight: 900, color: pct >= 81 ? "#4ade80" : pct >= 61 ? "#fbbf24" : "#f87171" }}>{pct}%</div>
                <div style={{ fontSize: 12, color: "var(--text3)" }}>{asmnt.finalScore || 0} / {maxPts} نقطة</div>
                {asmnt.gradedBy && <div style={{ fontSize: 10, color: "var(--text3)", marginTop: 4 }}>صحّحه: {asmnt.gradedBy} · {asmnt.gradedAt ? new Date(asmnt.gradedAt).toLocaleDateString("ar-SA") : ""}</div>}
                {asmnt.gradeApprovedBy && <div style={{ fontSize: 10, color: "#4ade80", marginTop: 2 }}>اعتمدها: {asmnt.gradeApprovedBy} · {asmnt.gradeApprovedAt ? new Date(asmnt.gradeApprovedAt).toLocaleDateString("ar-SA") : ""}</div>}
              </div>}

              {/* التصحيح التلقائي */}
              {autoQs.length > 0 && <div style={{ padding: "8px 12px", background: "rgba(34,197,94,.04)", border: "1px solid rgba(34,197,94,.15)", borderRadius: 8, marginBottom: 10 }}>
                <p style={{ fontSize: 11, fontWeight: 700, color: "#4ade80", marginBottom: 6 }}>✅ التصحيح التلقائي ({autoQs.length} سؤال)</p>
                {autoQs.map(q => {
                  const ans = asmnt.answers?.[q.id];
                  let isCorrect = null;
                  if (q.type === "tf") isCorrect = ans === q.correctTf;
                  if (q.type === "mcq") isCorrect = ans === q.correctIdx;
                  const override = (asmnt.gradeOverrides || []).filter(o => o.questionId === q.id).pop();
                  const currentScore = override ? override.newScore : (asmnt.scores?.[q.id] || 0);
                  return <div key={q.id} style={{ display: "flex", alignItems: "center", gap: 6, padding: "4px 0", borderBottom: "1px solid rgba(255,255,255,.04)", flexWrap: "wrap" }}>
                    <span style={{ fontSize: 14 }}>{isCorrect ? "✅" : "❌"}</span>
                    <span style={{ flex: 1, fontSize: 11, color: "var(--text2)" }}>{q.text.slice(0, 60)}{q.text.length > 60 ? "..." : ""}</span>
                    <span style={{ fontSize: 11, fontWeight: 700, color: isCorrect ? "#4ade80" : "#f87171" }}>{currentScore}/{q.points}</span>
                    {override && <span style={{ fontSize: 9, color: "#f59e0b", background: "rgba(245,158,11,.1)", padding: "1px 6px", borderRadius: 4 }}>معدّل: {override.by}</span>}
                    {canOverrideAuto && isGrading && <div style={{ display: "flex", gap: 4, alignItems: "center" }}>
                      <input type="number" min="0" max={q.points} value={examOverrides[q.id]?.newScore ?? currentScore} onChange={e => setExamOverrides(p => ({ ...p, [q.id]: { ...p[q.id], newScore: Math.min(+e.target.value, q.points) } }))} style={{ width: 45, textAlign: "center", fontSize: 11, padding: "2px 4px", borderRadius: 4, border: "1px solid var(--b)", background: "var(--glass)", color: "var(--text)" }} />
                      <input placeholder="ملاحظة" value={examOverrides[q.id]?.note || ""} onChange={e => setExamOverrides(p => ({ ...p, [q.id]: { ...p[q.id], note: e.target.value } }))} style={{ width: 100, fontSize: 10, padding: "2px 6px", borderRadius: 4, border: "1px solid var(--b)", background: "var(--glass)", color: "var(--text)" }} />
                    </div>}
                  </div>;
                })}
              </div>}

              {/* الأسئلة المكتوبة — تصحيح */}
              {writtenQs.length > 0 && <div style={{ padding: "8px 12px", background: "rgba(167,139,250,.04)", border: "1px solid rgba(167,139,250,.15)", borderRadius: 8, marginBottom: 10 }}>
                <p style={{ fontSize: 11, fontWeight: 700, color: "#a78bfa", marginBottom: 6 }}>📝 الأسئلة المكتوبة ({writtenQs.length} سؤال)</p>
                {writtenQs.map(q => {
                  const ans = asmnt.answers?.[q.id];
                  const existingGrade = asmnt.writtenGrades?.[q.id];
                  const currentScore = existingGrade?.score || asmnt.scores?.[q.id] || 0;
                  return <div key={q.id} style={{ padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,.04)" }}>
                    <p style={{ fontSize: 12, color: "var(--text)", marginBottom: 4, lineHeight: 1.5 }}>{q.text}</p>
                    <div style={{ padding: "6px 10px", background: "rgba(255,255,255,.03)", borderRadius: 6, fontSize: 12, color: "var(--text2)", marginBottom: 6, lineHeight: 1.6 }}>{ans || <em style={{ color: "var(--text3)" }}>لم يُجب</em>}</div>
                    {q.hint && <p style={{ fontSize: 10, color: "var(--text3)", marginBottom: 4 }}>النموذجية: {q.hint}</p>}
                    {existingGrade && <p style={{ fontSize: 10, color: "#a78bfa" }}>صحّحه: {existingGrade.by} — {currentScore}/{q.points}</p>}
                    {isGrading && canGrade && <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 4 }}>
                      <span style={{ fontSize: 11, color: "var(--text3)" }}>الدرجة (من {q.points}):</span>
                      <input type="number" min="0" max={q.points} value={examWrittenGrades[q.id]?.score ?? currentScore} onChange={e => setExamWrittenGrades(p => ({ ...p, [q.id]: { score: Math.min(+e.target.value, q.points) } }))} style={{ width: 55, textAlign: "center", fontSize: 12, padding: "3px 6px", borderRadius: 6, border: "1px solid rgba(167,139,250,.3)", background: "var(--glass)", color: "var(--text)" }} />
                      {aiExamComments[q.id] && <span style={{ fontSize: 9, color: "#a78bfa", background: "rgba(167,139,250,.08)", padding: "2px 6px", borderRadius: 4, border: "1px solid rgba(167,139,250,.2)" }}>🤖 AI</span>}
                    </div>}
                    {aiExamComments[q.id] && isGrading && <div style={{ marginTop: 4, padding: "4px 8px", background: "rgba(167,139,250,.06)", border: "1px solid rgba(167,139,250,.12)", borderRadius: 6 }}>
                      <p style={{ fontSize: 10, color: "#c4b5fd", lineHeight: 1.4 }}>💬 {aiExamComments[q.id]}</p>
                    </div>}
                  </div>;
                })}
              </div>}

              {/* أسئلة الترشيح — معلومة فقط */}
              {screeningQs.length > 0 && <div style={{ padding: "8px 12px", background: "rgba(167,139,250,.04)", border: "1px solid rgba(167,139,250,.15)", borderRadius: 8, marginBottom: 10 }}>
                <p style={{ fontSize: 11, fontWeight: 700, color: "#a78bfa", marginBottom: 6 }}>🏷️ معلومات ترشيح (بدون درجة)</p>
                {screeningQs.map(q => <div key={q.id} style={{ padding: "4px 0", borderBottom: "1px solid rgba(255,255,255,.04)" }}>
                  <p style={{ fontSize: 11, color: "var(--text)" }}>{q.text}</p>
                  <p style={{ fontSize: 11, color: "var(--text2)", marginTop: 2 }}>{asmnt.answers?.[q.id] != null ? (typeof asmnt.answers[q.id] === "boolean" ? (asmnt.answers[q.id] ? "نعم" : "لا") : q.type === "mcq" ? (q.options?.[asmnt.answers[q.id]] || "—") : asmnt.answers[q.id]) : "لم يُجب"}</p>
                </div>)}
              </div>}

              {/* أزرار التصحيح + تصحيح ذكي AI */}
              {!isApproved && canGrade && <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 10 }}>
                {!isGrading && <>
                  <button onClick={() => { setExamGradingId(asmnt.id); setExamWrittenGrades({}); setExamOverrides({}); }} style={{ flex: 1, padding: "8px", borderRadius: 8, border: "1px solid rgba(167,139,250,.4)", background: "rgba(167,139,250,.08)", color: "#a78bfa", fontWeight: 700, fontSize: 12, cursor: "pointer", fontFamily: "inherit" }}>✏️ تصحيح يدوي</button>
                  {writtenQs.length > 0 && <button onClick={() => { setExamGradingId(asmnt.id); setExamWrittenGrades({}); setExamOverrides({}); doAIGradeExam(asmnt.id); }} disabled={aiExamGrading} style={{ flex: 1, padding: "8px", borderRadius: 8, border: "1px solid rgba(167,139,250,.4)", background: "linear-gradient(135deg,rgba(167,139,250,.15),rgba(124,58,237,.15))", color: "#c4b5fd", fontWeight: 700, fontSize: 12, cursor: "pointer", fontFamily: "inherit", opacity: aiExamGrading ? 0.6 : 1 }}>{aiExamGrading ? "⏳ جاري التصحيح..." : "🤖 تصحيح ذكي بـ AI"}</button>}
                </>}
                {isGrading && <>
                  {writtenQs.length > 0 && <button onClick={() => doAIGradeExam(asmnt.id)} disabled={aiExamGrading} style={{ flex: "0 0 auto", padding: "8px 14px", borderRadius: 8, border: "1px solid rgba(167,139,250,.3)", background: "rgba(167,139,250,.08)", color: "#c4b5fd", fontWeight: 700, fontSize: 12, cursor: "pointer", fontFamily: "inherit", opacity: aiExamGrading ? 0.6 : 1 }}>{aiExamGrading ? "⏳..." : "🤖 AI"}</button>}
                  <button onClick={() => doGradeWritten(asmnt.id)} style={{ flex: 1, padding: "8px", borderRadius: 8, border: "none", background: "linear-gradient(135deg,#a78bfa,#7c3aed)", color: "#fff", fontWeight: 900, fontSize: 12, cursor: "pointer", fontFamily: "inherit" }}>💾 حفظ التصحيح</button>
                  <button onClick={() => { setExamGradingId(null); setExamWrittenGrades({}); setExamOverrides({}); }} style={{ padding: "8px 14px", borderRadius: 8, border: "1px solid var(--b)", background: "transparent", color: "var(--text3)", cursor: "pointer", fontFamily: "inherit", fontSize: 12 }}>إلغاء</button>
                </>}
              </div>}

              {/* اعتماد النتيجة — بكلمة سر */}
              {!isApproved && isGraded && !isGrading && (isEmpEvaluator || isAdm || isHR) && <div style={{ padding: "10px 12px", background: "rgba(34,197,94,.04)", border: "1px solid rgba(34,197,94,.2)", borderRadius: 8, marginBottom: 10 }}>
                <p style={{ fontSize: 12, fontWeight: 700, color: "#4ade80", marginBottom: 8 }}>🔐 اعتماد نتيجة الاختبار</p>
                <p style={{ fontSize: 10, color: "var(--text3)", marginBottom: 8 }}>أدخل كلمة سر حسابك للتأكيد — يُسجّل باسمك</p>
                <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                  <input type="password" value={approvalPwd} onChange={e => setApprovalPwd(e.target.value)} placeholder="كلمة السر" onKeyDown={e => { if (e.key === "Enter") doApproveExam(asmnt.id); }} style={{ flex: 1, padding: "7px 10px", borderRadius: 6, border: "1px solid rgba(34,197,94,.3)", background: "var(--glass)", color: "var(--text)", fontSize: 12, fontFamily: "inherit" }} />
                  <button onClick={() => doApproveExam(asmnt.id)} disabled={approving} style={{ padding: "7px 16px", borderRadius: 8, border: "none", background: "linear-gradient(135deg,#22c55e,#16a34a)", color: "#fff", fontWeight: 900, fontSize: 12, cursor: "pointer", fontFamily: "inherit", opacity: approving ? 0.6 : 1 }}>{approving ? "⏳..." : "✅ اعتماد"}</button>
                </div>
              </div>}
            </div>}
          </div>;
        })}

        {/* ── popup عرض نتائج الاختبار — للإطلاع فقط بعد الاعتماد ── */}
        {showExamReview && (() => {
          const ar = showExamReview;
          const qs = (ar.selectedQs || []).map(id => examQuestions.find(q => q.id === id)).filter(Boolean);
          const scoredQs = qs.filter(q => !_isScreeningQ(q) && !q.isKPIExam);
          const screeningQs = qs.filter(q => _isScreeningQ(q));
          const maxPts = scoredQs.reduce((s, q) => s + (q.points || 1), 0) || 1;
          const pct = ar.finalPct || Math.round((ar.finalScore || 0) / maxPts * 100);
          return <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.65)", backdropFilter: "blur(4px)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }} onClick={e => { if (e.target === e.currentTarget) setShowExamReview(null); }}>
            <div style={{ background: "var(--modal-bg,#1a1a2e)", border: "1px solid var(--b)", borderRadius: 16, padding: 20, width: "100%", maxWidth: 580, maxHeight: "85vh", overflowY: "auto" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
                <h3 style={{ color: "var(--gold)", fontWeight: 900, fontSize: 15, margin: 0 }}>📝 نتائج الاختبار — {ar.title || "اختبار"}</h3>
                <button onClick={() => setShowExamReview(null)} style={{ width: 28, height: 28, borderRadius: "50%", background: "rgba(239,68,68,.12)", border: "1px solid rgba(239,68,68,.35)", color: "#f87171", fontSize: 14, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
              </div>
              <div style={{ textAlign: "center", padding: 14, background: pct >= 70 ? "rgba(34,197,94,.06)" : "rgba(239,68,68,.06)", borderRadius: 10, marginBottom: 14, border: "1px solid " + (pct >= 70 ? "rgba(34,197,94,.2)" : "rgba(239,68,68,.2)") }}>
                <div style={{ fontSize: 32, fontWeight: 900, color: pct >= 81 ? "#4ade80" : pct >= 61 ? "#fbbf24" : "#f87171" }}>{pct}%</div>
                <div style={{ fontSize: 12, color: "var(--text3)" }}>{ar.finalScore || 0} / {maxPts}</div>
                <div style={{ fontSize: 10, color: "#4ade80", marginTop: 4 }}>اعتمدها: {ar.gradeApprovedBy} · {ar.gradeApprovedAt ? new Date(ar.gradeApprovedAt).toLocaleDateString("ar-SA") : ""}</div>
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {qs.map((q, qi) => {
                  const ans = ar.answers?.[q.id];
                  const isScreening = _isScreeningQ(q);
                  let isCorrect = null;
                  if (!isScreening) { if (q.type === "tf") isCorrect = ans === q.correctTf; if (q.type === "mcq") isCorrect = ans === q.correctIdx; }
                  const override = (ar.gradeOverrides || []).filter(o => o.questionId === q.id).pop();
                  const wGrade = ar.writtenGrades?.[q.id];
                  const score = q.type === "written" ? (wGrade?.score || ar.scores?.[q.id] || 0) : (override ? override.newScore : (ar.scores?.[q.id] || 0));
                  return <div key={q.id} style={{ padding: "8px 10px", background: isScreening ? "rgba(167,139,250,.04)" : "var(--glass)", border: "1px solid " + (isScreening ? "rgba(167,139,250,.15)" : isCorrect === true ? "rgba(34,197,94,.2)" : isCorrect === false ? "rgba(239,68,68,.2)" : "var(--b)"), borderRadius: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 3 }}>
                      <span style={{ fontSize: 12, color: "var(--text)", flex: 1 }}>{(qi + 1) + ". " + q.text}</span>
                      {!isScreening && <span style={{ fontSize: 11, fontWeight: 700, color: isCorrect === true ? "#4ade80" : isCorrect === false ? "#f87171" : "#a78bfa" }}>{score}/{q.points}</span>}
                      {isScreening && <span style={{ fontSize: 9, padding: "1px 6px", borderRadius: 4, background: "rgba(167,139,250,.15)", color: "#c4b5fd" }}>معلومة</span>}
                    </div>
                    {q.type === "tf" && <p style={{ fontSize: 11, color: "var(--text2)" }}>الإجابة: {ans === true ? "صح" : ans === false ? "خطأ" : "لم يُجب"}{!isScreening && " — الصحيحة: " + (q.correctTf ? "صح" : "خطأ")}</p>}
                    {q.type === "mcq" && <p style={{ fontSize: 11, color: "var(--text2)" }}>الإجابة: {ans != null ? (q.options?.[ans] || "—") : "لم يُجب"}{!isScreening && " — الصحيحة: " + (q.options?.[q.correctIdx] || "")}</p>}
                    {q.type === "written" && <div>
                      <p style={{ fontSize: 11, color: "var(--text2)", lineHeight: 1.5 }}>{ans || "لم يُجب"}</p>
                      {wGrade && <p style={{ fontSize: 10, color: "#a78bfa", marginTop: 3 }}>صحّحه: {wGrade.by}</p>}
                    </div>}
                    {override && <p style={{ fontSize: 9, color: "#f59e0b", marginTop: 2 }}>تم تعديل النتيجة بواسطة {override.by}{override.note ? " — " + override.note : ""}</p>}
                  </div>;
                })}
              </div>
            </div>
          </div>;
        })()}

        {/* Exam Results Accordion (legacy simple) — مخفي عن الموظف المقيّم */}
        {!hideOtherEvals && examScore && candAssessments.length === 0 && <div style={{ borderBottom:"1px solid var(--b)", borderRight:"3px solid #94a3b8" }}>
          {accHead("exam", "نتائج الاختبار", examScore, null, "اختبار · "+(cand.examAt?new Date(cand.examAt).toLocaleDateString("ar-SA"):""))}
          {openAccs.exam && <div style={{ padding:"12px 16px", fontSize:11, color:"var(--text2)" }}><p>الدرجة: <b>{examScore}/100</b></p></div>}
        </div>}

        

        {/* Overall Score — مخفي عن الموظف المقيّم ومساعد المشرف حتى اكتمال التقييم */}
        {!needsExamFirst && !hideOtherEvals && <div style={{ padding:"14px 16px", borderBottom:"1px solid var(--b)", textAlign:"center" }}>
          <p style={{ fontSize:10, color:"var(--text3)", margin:"0 0 4px" }}>المتوسط الإجمالي ({allVals.length} تقييم)</p>
          <p style={{ fontSize:26, fontWeight:900, color:oC(overall), margin:0 }}>{overall}<span style={{ fontSize:13, color:"var(--text3)" }}>/100</span></p>
          <div style={{ display:"flex", gap:5, justifyContent:"center", flexWrap:"wrap", marginTop:6 }}>
            {aiAvg!=null && <span style={{ fontSize:9, padding:"2px 6px", borderRadius:5, background:"rgba(167,139,250,.12)", color:"#c4b5fd" }}>AI:{aiAvg}</span>}
            {humanAvg!=null && <span style={{ fontSize:9, padding:"2px 6px", borderRadius:5, background:"rgba(245,158,11,.12)", color:"#f59e0b" }}>بشري:{humanAvg}</span>}
            {examAvg!=null && <span style={{ fontSize:9, padding:"2px 6px", borderRadius:5, background:"rgba(34,197,94,.12)", color:"#4ade80" }}>اختبار:{examAvg}</span>}
          </div>
          {canRunAIEval && <button onClick={doAIEval} disabled={aiEvalLoading} style={{ marginTop:10, padding:"8px 20px", borderRadius:10, border:"1px solid rgba(167,139,250,.4)", background:aiEvalLoading?"rgba(167,139,250,.15)":"rgba(167,139,250,.08)", color:"#c4b5fd", fontSize:12, fontWeight:700, cursor:aiEvalLoading?"wait":"pointer", fontFamily:"inherit", display:"inline-flex", alignItems:"center", gap:6 }}>{aiEvalLoading ? "⏳ جاري التقييم..." : "🤖 تقييم بالذكاء الاصطناعي"}</button>}
        </div>}

        {/* ── جدولة مقابلة — فقط بعد اكتمال الاختبار ── */}
        {allExamsApproved && cand.stage === "assessment" && (isEmpEvaluator || canApprove) && cand.phone && (
          <div style={{ padding:"10px 16px", borderBottom:"1px solid var(--b)" }}>
            <div style={{ background:"rgba(37,211,102,.06)", border:"1px solid rgba(37,211,102,.2)", borderRadius:10, padding:"10px 12px" }}>
              <p style={{ fontSize:12, fontWeight:700, color:"#25d366", marginBottom:8 }}>📅 تحديد موعد المقابلة</p>
              <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:8 }}>
                <input type="date" value={ivDate} onChange={e=>setIvDate(e.target.value)} style={{ flex:"1 1 120px", fontSize:12, padding:"6px 8px" }} />
                <input type="time" value={ivTime} onChange={e=>setIvTime(e.target.value)} style={{ flex:"1 1 80px", fontSize:12, padding:"6px 8px" }} />
                <input value={ivLoc} onChange={e=>setIvLoc(e.target.value)} placeholder="المكان أو رابط الاجتماع" style={{ flex:"2 1 160px", fontSize:12, padding:"6px 8px" }} />
              </div>
              <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                <button onClick={async()=>{
                  if(!ivDate){show("⚠️ حدد التاريخ");return;}
                  const cid=cand.uid||cand.idNumber||cand.email;
                  if(cid){
                    await db.set("interview_schedule:"+cid, {date:ivDate,time:ivTime,location:ivLoc,scheduledBy:userName,scheduledAt:new Date().toISOString()});
                    setIvSaved(true); show("✅ تم حفظ موعد المقابلة");
                  }
                }} className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"#25d366", borderColor:"rgba(37,211,102,.3)" }}>
                  {ivSaved?"✅ تم الحفظ":"💾 حفظ الموعد"}
                </button>
                {ivDate && (<>
                  <a href={"https://wa.me/"+(cand.phone||"").replace(/^0/,"966").replace(/[^0-9]/g,"")+"?text="+encodeURIComponent("السلام عليكم "+(cand.fullName||"")+"،\nنود إبلاغكم بموعد المقابلة:\n📅 التاريخ: "+ivDate+(ivTime?" الساعة "+ivTime:"")+"\n📍 المكان: "+(ivLoc||"سيتم تحديده")+"\n\n🔴 تنبيه مهم:\nنود التنويه بأن التقديم على الوظائف ومتابعة الطلبات تتم حصريًا عبر الموقع الإلكتروني الخاص بمكتبنا لاستقبال طلبات التوظيف والتدريب.\nنأمل منكم التسجيل في المنصة واستكمال الطلبات المرسلة لكم، وذلك لتمكيننا من دراسة ملفكم الوظيفي بشكل كامل.\n🔗 https://hma.engineer\n\nمع التحية،\n"+userName+"\nنظام كوادر HMA\n⚙️ إدارة الإشعارات: hma.engineer/unsubscribe")}
                    target="_blank" rel="noopener" onClick={()=>{const pid2=cand.uid||cand.idNumber||cand.email;if(pid2)addPersonEvent(pid2,{type:"contact",text:"💬 واتساب — موعد مقابلة "+ivDate,by:userName,byRole:userRole,private:false}).catch(()=>{});}}
                    className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"#25d366", borderColor:"rgba(37,211,102,.3)", textDecoration:"none" }}>
                    💬 واتساب
                  </a>
                  {cand.email && <a href={"mailto:"+cand.email+"?subject="+encodeURIComponent("موعد المقابلة — كوادر HMA")+"&body="+encodeURIComponent("السلام عليكم "+(cand.fullName||"")+"،\nنود إبلاغكم بموعد المقابلة:\n📅 التاريخ: "+ivDate+(ivTime?" الساعة "+ivTime:"")+"\n📍 المكان: "+(ivLoc||"سيتم تحديده")+"\n\nمع التحية،\n"+userName+"\nإدارة الموارد البشرية — نظام كوادر HMA")}
                    onClick={()=>{const pid2=cand.uid||cand.idNumber||cand.email;if(pid2)addPersonEvent(pid2,{type:"contact",text:"📧 بريد — موعد مقابلة "+ivDate,by:userName,byRole:userRole,private:false}).catch(()=>{});}}
                    className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"var(--gold)", borderColor:"rgba(201,168,76,.3)", textDecoration:"none" }}>
                    📧 بريد
                  </a>}
                </>)}
              </div>
            </div>
          </div>
        )}

        {/* Add Eval button — للمشرف/HR فقط */}
        {(canApprove || isAdm) && <div style={{ display:"flex", gap:6, padding:"10px 16px", borderBottom:"1px solid var(--b)", flexWrap:"wrap" }}>
          {!needsExamFirst && !showForm && <div onClick={()=>{ if(hasCompletedExam && !allExamsApproved){show("⛔ يجب اعتماد نتيجة الاختبار أولاً");return;} const chk=canDoManualEval(cand,cu.username,cu.username); if(!chk.ok){show(chk.msg);return;} setShowForm(true); }} style={{ flex:1, padding:10, background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, textAlign:"center", cursor:"pointer" }}><span style={{ fontSize:12, fontWeight:700, color:"var(--accent)" }}>▸ إضافة تقييم</span></div>}
          <div onClick={()=>{if(window.confirm("سيتم حفظ البيانات وتوجيهك لقسم الاختبارات. متابعة؟")){onClose();window._setSecP&&window._setSecP("assessments");}}} style={{ flex:1, padding:10, background:"var(--glass)", border:"1px solid var(--b)", borderRadius:8, textAlign:"center", cursor:"pointer" }}><span style={{ fontSize:12, fontWeight:700, color:"#4ade80" }}>▸ إضافة اختبار</span></div>
        </div>}

        {/* نموذج التقييم للمشرف/HR */}
        {!needsExamFirst && showForm && !isEmpEvaluator && <CandEvalFormInline cand={cand} onSubmit={handleEvalSubmit} onCancel={()=>setShowForm(false)} />}

        {/* نموذج التقييم للموظف المقيّم — يظهر مباشرة بدون زر */}
        {isEmpEvaluator && !hasSubmitted && (
          <div style={{ padding:"10px 16px", borderBottom:"1px solid var(--b)", background:"rgba(167,139,250,.03)" }}>
            {/* ── الترتيب الإجباري: لا تقييم مقابلة إلا بعد اعتماد الاختبار ── */}
            {needsExamFirst ? (
              <div style={{ padding:"14px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.2)", borderRadius:10, textAlign:"center" }}>
                <p style={{ fontSize:13, fontWeight:700, color:"#f87171", marginBottom:4 }}>⛔ لا يمكن بدء التقييم</p>
                <p style={{ fontSize:11, color:"var(--text3)" }}>{candAssessments.length === 0 ? "يجب تجهيز اختبار أولاً — تم إشعار مدير الموارد البشرية" : "يجب تصحيح واعتماد نتيجة الاختبار أولاً"}</p>
              </div>
            ) : (hasCompletedExam && !allExamsApproved) ? (
              <div style={{ padding:"14px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.2)", borderRadius:10, textAlign:"center" }}>
                <p style={{ fontSize:13, fontWeight:700, color:"#f87171", marginBottom:4 }}>⛔ لا يمكن بدء التقييم</p>
                <p style={{ fontSize:11, color:"var(--text3)" }}>يجب تصحيح واعتماد نتيجة الاختبار أولاً قبل البدء في تقييم المقابلة</p>
              </div>
            ) : (
              <>
                <p style={{ fontSize:12, color:"#a78bfa", fontWeight:700, marginBottom:8 }}>📋 أدخل تقييمك — تقييمات الإدارات الأخرى ستظهر بعد اعتماد تقييمك من المدير</p>
                <CandEvalFormInline cand={cand} onSubmit={async (evalData) => {
              const cu2 = window._currentUser || {};
              const result = { ...evalData, taskId: employeeTask.id };
              const updCand = { ...cand, evalTaskResults:[...(cand.evalTaskResults||[]), result] };
              if (onSave) await onSave(updCand);
              const updTask = { ...employeeTask, status:"pending_approval", completedAt:new Date().toISOString(),
                evalResult:{ score:evalData.totalScore, recommendation:evalData.recommendation, evaluatorName:cu2.displayName||"" },
                chat: employeeTask.chat||[] };
              await saveEvalTask(updTask);
              addPersonEvent(cand.uid||cand.email, { type:"eval", text:"📋 تقييم تكليف بواسطة "+(cu2.displayName||"")+" — "+evalData.totalScore+"/100 — التوصية: "+evalData.recommendation, by:cu2.displayName||"", byRole:"evaluator", private:false }).catch(()=>{});
              setHasSubmitted(true); setRefreshKey(k=>k+1);
              show("✅ تم إرسال التقييم — بانتظار موافقة المدير");
            }} onCancel={onClose} />
              </>
            )}
          </div>
        )}

        {isEmpEvaluator && hasSubmitted && !evalApproved && (
          <div style={{ padding:"10px 16px", background:"rgba(245,158,11,.04)", borderBottom:"1px solid var(--b)" }}>
            <p style={{ fontSize:12, color:"#f59e0b", fontWeight:700, margin:0 }}>⏳ تم إرسال تقييمك — بانتظار اعتماد المدير لعرض تقييمات الإدارات الأخرى</p>
          </div>
        )}

        {isEmpEvaluator && evalApproved && (
          <div style={{ padding:"10px 16px", background:"rgba(34,197,94,.04)", borderBottom:"1px solid var(--b)" }}>
            <p style={{ fontSize:12, color:"#4ade80", fontWeight:700, margin:0 }}>✅ تم اعتماد تقييمك — يمكنك الآن الإطلاع على تقييمات الإدارات الأخرى</p>
          </div>
        )}

        {/* Discussion - always open, orange color */}
        <div style={{ padding:"14px 16px", borderRight:"3px solid #FF8021", background:"rgba(255,128,33,.04)" }}>
          <p style={{ fontSize:13, fontWeight:900, color:"#FF8021", marginBottom:10 }}>💬 المناقشة</p>
          {allChats.length === 0 && <p style={{ fontSize:11, color:"var(--text3)", textAlign:"center", padding:12 }}>{hasAnyEval ? "لا توجد ردود بعد — كن أول من يعلق" : "لا توجد تقييمات بعد — أضف تقييماً أولاً"}</p>}
          {allChats.map((m,i) => <div key={i} style={{ marginBottom:6, padding:"8px 10px", borderRadius:8, background:m.role==="admin"?"rgba(59,130,246,.06)":m.role==="hr"?"rgba(34,197,94,.06)":"rgba(245,158,11,.06)" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:2 }}>
              <span style={{ fontSize:11, fontWeight:700, color:m.role==="admin"?"#60a5fa":m.role==="hr"?"#4ade80":"#f59e0b" }}>{m.by}</span>
              <span style={{ fontSize:9, color:"var(--text3)" }}>{m.at?new Date(m.at).toLocaleString("ar-SA"):""}</span>
            </div>
            <p style={{ fontSize:11, color:"var(--text2)", margin:0 }}>{m.text}</p>
          </div>)}
          {(liveTasks.length > 0 || hasAnyEval) && <div style={{ display:"flex", gap:6, margin:"10px 0" }}>
            <input value={chatMsg} onChange={e=>setChatMsg(e.target.value)} placeholder="أضف تعليقاً..." style={{ flex:1, padding:"8px 10px", borderRadius:8, border:"1px solid rgba(255,128,33,.3)", background:"rgba(255,128,33,.04)", color:"var(--text)", fontSize:12, fontFamily:"inherit", minWidth:0 }} onKeyDown={e=>{if(e.key==="Enter")doChat();}} />
            <button onClick={doChat} style={{ padding:"8px 14px", borderRadius:8, border:"1px solid rgba(255,128,33,.4)", background:"rgba(255,128,33,.12)", color:"#FF8021", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>إرسال</button>
          </div>}
          {canApprove && liveTasks.some(t=>t.status==="pending_approval") && <div style={{ display:"flex", gap:6 }}>
            <button onClick={doApprove} className="btn btn-gold" style={{ flex:1, padding:10, fontSize:12 }}>✅ موافقة ونقل</button>
            <button onClick={doReject} style={{ flex:1, padding:10, borderRadius:8, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.06)", color:"#f87171", cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700 }}>❌ رفض</button>
          </div>}
        </div>
      </div>
    </div>
  );
}

// ── CandEvalFormInline — inline eval form ────────────────────────────────────
function CandEvalFormInline({ cand, onSubmit, onCancel }) {
  const oC = v => v>=81?"#4ade80":v>=61?"#fbbf24":"#f87171";
  const [tech, setTech] = useState(50); const [adm, setAdm] = useState(50); const [lang, setLang] = useState(50);
  const [interviewDate, setInterviewDate] = useState(""); const [interviewTime, setInterviewTime] = useState(""); const [interviewLocation, setInterviewLocation] = useState("");
  const [interviewSaved, setInterviewSaved] = useState(false);
  const [techN, setTechN] = useState(""); const [admN, setAdmN] = useState(""); const [langN, setLangN] = useState("");
  const [genN, setGenN] = useState(""); const [rec, setRec] = useState(""); const [recT, setRecT] = useState("");
  const [sending, setSending] = useState(false); const { show, toastEl } = useToast();
  const RECS = ["لم يتم القبول","مرفوض من قبل المرشح","قائمة الانتظار","اختبار","مقابلة أولى","مقابلة ثانية","إرسال عرض وظيفي","إرسال مسودة عقد","يسجل متعاون","توقيع العقد","تدريب","يقبل كمتدرب"];
  const wc = s => (s||"").trim().split(/\s+/).filter(Boolean).length;
  const submit = async () => {
    if (wc(techN)<10) { show("⚠️ الفني: 10 كلمات على الأقل"); return; }
    if (wc(admN)<10) { show("⚠️ الإداري: 10 كلمات على الأقل"); return; }
    if (wc(langN)<3) { show("⚠️ اللغوي: 3 كلمات على الأقل"); return; }
    if (!rec) { show("⚠️ اختر التوصية"); return; }
    if (wc(recT)<10) { show("⚠️ شرح التوصية: 10 كلمات على الأقل"); return; }
    setSending(true);
    const tot = Math.round((+tech + +adm + +lang)/3);
    const cu = window._currentUser||{};
    await onSubmit({ technical:+tech, admin:+adm, language:+lang, technicalNotes:techN.trim(), adminNotes:admN.trim(), languageNotes:langN.trim(), generalNotes:genN.trim(), recommendation:rec, recommendationText:recT.trim(), totalScore:tot, evaluatorId:cu.username||"", evaluatorName:cu.displayName||"المشرف", at:new Date().toISOString() });
    setSending(false);
  };
  const field = (lbl, v, sv, min, n, sn) => (
    <div style={{ marginBottom:12 }}>
      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
        <span style={{ fontSize:12, fontWeight:700, minWidth:40 }}>{lbl}</span>
        <input type="number" min="0" max="100" value={v} onChange={e=>sv(Math.max(0,Math.min(100,+e.target.value||0)))} style={{ width:65, padding:"5px 6px", borderRadius:8, fontSize:14, fontWeight:700, textAlign:"center", fontFamily:"inherit", border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)" }} />
        <span style={{ fontSize:11, color:"var(--text3)" }}>/100</span>
      </div>
      <textarea value={n} onChange={e=>sn(e.target.value)} rows={2} placeholder={min+" كلمات على الأقل..."} style={{ width:"100%", fontSize:11, padding:"6px 8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", resize:"vertical", boxSizing:"border-box" }} />
      <p style={{ fontSize:9, color:wc(n)>=min?"#4ade80":"#f87171", margin:"2px 0 0" }}>{wc(n)}/{min}</p>
    </div>
  );
  return (
    <div style={{ padding:"14px 16px", borderBottom:"1px solid var(--b)" }}>
      {toastEl}
      {field("🔧 فني", tech, setTech, 10, techN, setTechN)}
      {field("📋 إداري", adm, setAdm, 10, admN, setAdmN)}
      {field("🗣️ لغوي", lang, setLang, 3, langN, setLangN)}
      <div style={{ textAlign:"center", margin:"8px 0 12px", padding:8, background:"var(--glass)", borderRadius:8 }}>
        <span style={{ fontSize:20, fontWeight:900, color:oC(Math.round((+tech+ +adm+ +lang)/3)) }}>{Math.round((+tech+ +adm+ +lang)/3)}<span style={{ fontSize:12, color:"var(--text3)" }}>/100</span></span>
      </div>
      <textarea value={genN} onChange={e=>setGenN(e.target.value)} rows={2} placeholder="ملاحظات عامة (اختياري)..." style={{ width:"100%", fontSize:11, padding:"6px 8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", marginBottom:10, boxSizing:"border-box" }} />
      <p style={{ fontSize:12, fontWeight:700, marginBottom:4 }}>التوصية</p>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:4, marginBottom:6 }}>
        {RECS.map(r => <button key={r} onClick={()=>setRec(r)} style={{ padding:"6px 3px", borderRadius:8, fontSize:10, fontFamily:"inherit", fontWeight:rec===r?700:400, border:"1px solid "+(rec===r?"var(--accent)":"var(--b)"), background:rec===r?"var(--accent-d)":"transparent", color:rec===r?"var(--accent)":"var(--text3)", cursor:"pointer" }}>{r}</button>)}
      </div>
      {rec && <><textarea value={recT} onChange={e=>setRecT(e.target.value)} rows={2} placeholder="شرح التوصية (10 كلمات)..." style={{ width:"100%", fontSize:11, padding:"6px 8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", boxSizing:"border-box" }} />
        <p style={{ fontSize:9, color:wc(recT)>=10?"#4ade80":"#f87171", margin:"2px 0 8px" }}>{wc(recT)}/10</p></>}
      <div style={{ display:"flex", gap:6 }}>
        <button onClick={submit} disabled={sending} className="btn btn-gold" style={{ flex:1, padding:10, fontSize:13 }}>{sending?"⏳...":"📤 حفظ وإرسال"}</button>
        <button onClick={onCancel} className="btn btn-ghost" style={{ padding:10, fontSize:13 }}>إلغاء</button>
      </div>
    </div>
  );
}
// ── AllEvalsPanel — shows all evaluations for a candidate ────────────────────
function AllEvalsPanel({ cand, onClose }) {
  const aiHistory = cand.aiEvalHistory || [];
  const stageEvals = cand.stageEvaluations || {};
  const examScore = cand.examScore || null;
  const evalTasks = cand.evalTaskResults || [];
  const [liveTasksMap, setLiveTasksMap] = useState({});
  // Load live tasks for chat data
  useEffect(() => {
    getEvalTasks().then(all => {
      const candId = cand.uid || cand.email;
      const map = {};
      all.filter(t => t.candidateId === candId).forEach(t => { map[t.id] = t; });
      setLiveTasksMap(map);
    }).catch(()=>{});
  }, [cand]);
  const aiScores = aiHistory.filter(h=>h.score).map(h=>h.score);
  const stageScores = Object.values(stageEvals).flatMap(ev=>(ev.evaluations||[ev]).filter(e=>e.total).map(e=>e.total));
  const taskScores = evalTasks.filter(t=>t.totalScore).map(t=>t.totalScore);
  const examScores = examScore ? [examScore] : [];
  const allScores = [];
  aiHistory.forEach(h => { if(h.score) allScores.push({ label:"🤖 AI: "+(h.by||""), val:h.score, at:h.at, type:"ai" }); });
  Object.entries(stageEvals).forEach(([stg, ev]) => {
    (ev.evaluations || [ev]).forEach(e => { if(e.total) allScores.push({ label:"📝 "+stg+": "+(e.by||""), val:e.total, at:e.at, type:"stage" }); });
  });
  evalTasks.forEach(t => { if(t.totalScore) allScores.push({ label:"📋 تكليف: "+(t.evaluatorName||""), val:t.totalScore, at:t.at, type:"task" }); });
  if (examScore) allScores.push({ label:"📝 اختبار", val:examScore, at:cand.examAt||"", type:"exam" });
  const avg = allScores.length > 0 ? Math.round(allScores.reduce((s,x)=>s+x.val,0)/allScores.length) : 0;
  const avgC = avg >= 75 ? "#4ade80" : avg >= 50 ? "#fbbf24" : "#f87171";
  const typeAvg = (arr) => arr.length ? Math.round(arr.reduce((a,b)=>a+b,0)/arr.length) : null;
  const aiAvg = typeAvg(aiScores); const stgAvg = typeAvg(stageScores); const tskAvg = typeAvg(taskScores); const exmAvg = typeAvg(examScores);
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:24, width:"100%", maxWidth:600, maxHeight:"90vh", overflowY:"auto" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <h3 style={{ color:"var(--gold)", fontWeight:900, fontSize:16, margin:0 }}>📊 نموذج التقييم الشامل — {cand.fullName}</h3>
          {cand.phone && <a href={"https://wa.me/"+cand.phone.replace(/^0/,"966").replace(/[^0-9]/g,"")+"?text="+encodeURIComponent("السلام عليكم "+cand.fullName+"،\nنود التنسيق معكم بخصوص موعد المقابلة.\n\nمع التحية،\nإدارة الموارد البشرية — كوادر HMA")} target="_blank" rel="noopener" style={{padding:"4px 12px",borderRadius:8,background:"rgba(37,211,102,.1)",border:"1px solid rgba(37,211,102,.3)",color:"#25d366",fontSize:11,fontWeight:700,textDecoration:"none",display:"inline-flex",alignItems:"center",gap:4}}>💬 واتساب</a>}
          <button onClick={onClose} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>
        <div style={{ textAlign:"center", padding:16, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:12, marginBottom:16 }}>
          <p style={{ fontSize:11, color:"var(--text3)", marginBottom:4 }}>المتوسط الإجمالي ({allScores.length} تقييم)</p>
          <p style={{ fontSize:36, fontWeight:900, color:avgC, margin:0 }}>{avg}<span style={{ fontSize:16, color:"var(--text3)" }}>/100</span></p>
          <div style={{ display:"flex", gap:8, justifyContent:"center", flexWrap:"wrap", marginTop:10 }}>
            {aiAvg!=null && <span style={{ fontSize:10, padding:"3px 8px", borderRadius:6, background:"rgba(167,139,250,.1)", border:"1px solid rgba(167,139,250,.25)", color:"#c4b5fd" }}>🤖 AI: {aiAvg} ({aiScores.length})</span>}
            {stgAvg!=null && <span style={{ fontSize:10, padding:"3px 8px", borderRadius:6, background:"rgba(59,130,246,.1)", border:"1px solid rgba(59,130,246,.25)", color:"#60a5fa" }}>📝 مراحل: {stgAvg} ({stageScores.length})</span>}
            {tskAvg!=null && <span style={{ fontSize:10, padding:"3px 8px", borderRadius:6, background:"rgba(245,158,11,.1)", border:"1px solid rgba(245,158,11,.25)", color:"#f59e0b" }}>📋 تكليفات: {tskAvg} ({taskScores.length})</span>}
            {exmAvg!=null && <span style={{ fontSize:10, padding:"3px 8px", borderRadius:6, background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.25)", color:"#4ade80" }}>📝 اختبارات: {exmAvg} ({examScores.length})</span>}
          </div>
        </div>
        {allScores.length > 0 && <div className="table-wrap" style={{ marginBottom:16 }}><table><thead><tr><th>المصدر</th><th>الدرجة</th><th>التاريخ</th></tr></thead><tbody>
          {allScores.map((s,i) => <tr key={i}><td>{s.label}</td><td style={{ fontWeight:700, color:s.val>=81?"#4ade80":s.val>=61?"#fbbf24":"#f87171" }}>{s.val}/100</td><td style={{ fontSize:11 }}>{s.at?new Date(s.at).toLocaleDateString("ar-SA"):"—"}</td></tr>)}
        </tbody></table></div>}
        {aiHistory.length > 0 && <div style={{ marginBottom:16 }}><p style={{ fontSize:13, fontWeight:700, color:"#c4b5fd", marginBottom:8 }}>🤖 تقييمات AI ({aiHistory.length})</p>
          {aiHistory.map((h,i) => <div key={i} style={{ padding:"8px 12px", background:"rgba(167,139,250,.06)", border:"1px solid rgba(167,139,250,.15)", borderRadius:10, marginBottom:4, fontSize:11, color:"var(--text2)" }}>
            <span style={{ fontWeight:700 }}>{h.by}</span> — {h.at?new Date(h.at).toLocaleDateString("ar-SA"):""} — <span style={{ color:"var(--gold)" }}>{h.score}/100</span> {h.level} — {h.recommendation}{h.summary && <p style={{ fontStyle:"italic", marginTop:2, fontSize:10 }}>"{h.summary}"</p>}
          </div>)}
        </div>}
        {Object.keys(stageEvals).length > 0 && <div style={{ marginBottom:16 }}><p style={{ fontSize:13, fontWeight:700, color:"#60a5fa", marginBottom:8 }}>📝 تقييمات المراحل</p>
          {Object.entries(stageEvals).map(([stg,ev]) => <div key={stg} style={{ padding:"8px 12px", background:"rgba(59,130,246,.06)", border:"1px solid rgba(59,130,246,.15)", borderRadius:10, marginBottom:4 }}>
            <p style={{ fontSize:12, fontWeight:700, color:"#60a5fa", marginBottom:2 }}>{stg}</p>
            {(ev.evaluations||[ev]).map((e,j) => <p key={j} style={{ fontSize:11, color:"var(--text2)" }}>{e.by} — فني:{e.technical} إداري:{e.admin} لغوي:{e.language} = <span style={{ color:"var(--gold)", fontWeight:700 }}>{e.total}/100</span> {e.notes&&"— "+e.notes}</p>)}
          </div>)}
        </div>}
        {evalTasks.length > 0 && <div style={{ marginBottom:16 }}><p style={{ fontSize:13, fontWeight:700, color:"#f59e0b", marginBottom:8 }}>📋 تقييمات التكليفات</p>
          {evalTasks.map((t,i) => { const live = liveTasksMap[t.taskId] || {}; const chat = live.chat || t.thread || []; return <div key={i} style={{ padding:"8px 12px", background:"rgba(245,158,11,.06)", border:"1px solid rgba(245,158,11,.15)", borderRadius:10, marginBottom:6 }}>
            <p style={{ fontSize:12, fontWeight:700, color:"#f59e0b" }}>{t.evaluatorName} — {t.at?new Date(t.at).toLocaleDateString("ar-SA"):""}</p>
            <p style={{ fontSize:11, color:"var(--text2)" }}>فني:{t.technical} إداري:{t.admin} لغوي:{t.language} = <span style={{ fontWeight:700, color:"var(--gold)" }}>{t.totalScore}/100</span></p>
            {t.technicalNotes && <p style={{ fontSize:10, color:"var(--text3)" }}>🔧 {t.technicalNotes}</p>}
            {t.adminNotes && <p style={{ fontSize:10, color:"var(--text3)" }}>📋 {t.adminNotes}</p>}
            {t.languageNotes && <p style={{ fontSize:10, color:"var(--text3)" }}>🗣️ {t.languageNotes}</p>}
            {t.generalNotes && <p style={{ fontSize:10, color:"var(--text3)" }}>📝 {t.generalNotes}</p>}
            {t.recommendation && <p style={{ fontSize:11, fontWeight:700, color:"#4ade80" }}>التوصية: {t.recommendation} {t.recommendationText&&" — "+t.recommendationText}</p>}
            {live.status && <p style={{ fontSize:10, color:live.status==="completed"?"#4ade80":live.status==="pending_approval"?"#f59e0b":"#f87171" }}>الحالة: {live.status==="completed"?"✅ تمت الموافقة":live.status==="pending_approval"?"⏳ بانتظار الموافقة":live.status==="rejected_eval"?"❌ مرفوض":"📋 معلّق"}</p>}
            {chat.length > 0 && <div style={{ marginTop:6, padding:"6px 8px", background:"rgba(255,255,255,.03)", borderRadius:8, borderRight:"2px solid rgba(245,158,11,.3)" }}>
              <p style={{ fontSize:10, fontWeight:700, color:"var(--text3)", marginBottom:4 }}>💬 المناقشة:</p>
              {chat.map((msg,mi) => <p key={mi} style={{ fontSize:10, marginBottom:2, color:msg.role==="admin"?"#60a5fa":"#fbbf24" }}><b>{msg.by}</b>: {msg.text} <span style={{ color:"var(--text3)", fontSize:9 }}>{msg.at?new Date(msg.at).toLocaleString("ar-SA"):""}</span></p>)}
            </div>}
          </div>; })}
        </div>}
        {allScores.length===0 && <p style={{ textAlign:"center", color:"var(--text3)", padding:20 }}>لا توجد تقييمات بعد</p>}
      </div>
    </div>
  );
}

// ── EvalAssignModal — admin/HR assigns eval task to employee ─────────────────
function EvalAssignModal({ cand, employees, onAssign, onClose }) {
  const [selEmp, setSelEmp] = useState(""); 
  const [allPeople, setAllPeople] = useState([]);
  const { show, toastEl } = useToast();
  useEffect(() => {
    const emps = (employees||[]).map(e => ({ id:e.uid||e.email, name:e.fullName||e.senderName, dept:e.department||"موظف", src:"emp", idNumber:e.idNumber, hrCode:e.hrCode, email:e.email, uid:e.uid }));
    getAllUsers().then(users => {
      const supervisors = users.filter(u => u.role === "admin" || u.role === "hr_manager" || u.role === "supervisor" || u.role === "assistant_supervisor").map(u => ({ id:u.linkedId||u.username, name:u.displayName||u.username, dept:({admin:"المدير العام",hr_manager:"مدير الموارد البشرية",supervisor:"مشرف"})[u.role]||u.role, src:"user", linkedId:u.linkedId }));
      const merged = [...emps];
      supervisors.forEach(u => {
        const nameWords = (u.name||"").split(" ").filter(w=>w.length>2);
        const dup = merged.find(m => m.id === u.id || m.id === u.linkedId || (nameWords.length>0 && nameWords.every(w => (m.name||"").includes(w))));
        if (!dup) merged.push(u);
      });
      setAllPeople(merged.filter(p => p.name));
    }).catch(()=>setAllPeople(emps.filter(p=>p.name)));
  }, [employees]);
  const assign = async () => {
    if (!selEmp) { show("⚠️ اختر موظف"); return; }
    const person = allPeople.find(p => p.id === selEmp);
    if (!person) { show("⚠️ لم يتم العثور على الموظف"); return; }
    try {
      // Check for duplicate assignment
      const existing = await getEvalTasks();
      const dup = existing.find(t => t.candidateId === (cand.uid||cand.email) && (t.evaluatorId === person.id || t.evaluatorName === person.name) && !["completed","rejected_eval"].includes(t.status));
      if (dup) { show("⚠️ "+person.name+" مكلّف بالفعل بتقييم "+cand.fullName); return; }
      const task = { id:Date.now().toString(), candidateId:cand.uid||cand.email, candidateName:cand.fullName, evaluatorId:person.id, evaluatorName:person.name, evaluatorIds:[person.id, person.uid, person.email, person.linkedId, person.idNumber, person.hrCode, person.name].filter(Boolean), status:"pending", assignedAt:new Date().toISOString(), assignedBy:window._currentUser?.displayName||"المشرف" };
      await saveEvalTask(task);
      addPersonEvent(cand.uid||cand.email, { type:"eval", text:"📋 تم تكليف "+person.name+" بتقييم "+cand.fullName, by:window._currentUser?.displayName||"المشرف", byRole:"admin", private:false }).catch(()=>{});
      // v37.84: إشعار بصمة بـ badge جديد للموظف المُكلَّف
      const empIdForBasma = person.idNumber || person.linkedId || person.id;
      if (empIdForBasma) syncEmpBadgesToBasma(empIdForBasma).catch(()=>{});
      if (onAssign) onAssign(task);
      show("✅ تم تكليف "+person.name);
      setTimeout(()=>onClose(), 500);
    } catch(err) { show("❌ خطأ: "+(err.message||"فشل الحفظ")); }
  };
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:24, width:"100%", maxWidth:420 }}>
        {toastEl}
        <h3 style={{ color:"var(--gold)", fontWeight:900, fontSize:16, marginBottom:12 }}>📋 تكليف موظف بتقييم {cand.fullName}</h3>
        <div className="field" style={{ marginBottom:14 }}><label className="label">اختر الموظف</label>
          <select value={selEmp} onChange={e=>setSelEmp(e.target.value)}><option value="">— اختر —</option>
            {allPeople.map(p => <option key={p.id} value={p.id}>{p.name} {p.dept?"— "+p.dept:""}</option>)}
          </select>
        </div>
        <div style={{ display:"flex", gap:8 }}><button onClick={assign} disabled={!selEmp} className="btn btn-gold" style={{ flex:1, opacity:selEmp?1:.5 }}>✅ تكليف</button><button onClick={onClose} className="btn btn-ghost">إلغاء</button></div>
      </div>
    </div>
  );
}

// ── FullEvalForm — detailed evaluation form ──────────────────────────────────
function FullEvalForm({ cand, task, onSubmit, onClose }) {
  const [tech, setTech] = useState(50); const [adm, setAdm] = useState(50); const [lang, setLang] = useState(50);
  const [interviewDate, setInterviewDate] = useState(""); const [interviewTime, setInterviewTime] = useState(""); const [interviewLocation, setInterviewLocation] = useState("");
  const [interviewSaved, setInterviewSaved] = useState(false);
  const [techN, setTechN] = useState(""); const [admN, setAdmN] = useState(""); const [langN, setLangN] = useState("");
  const [genN, setGenN] = useState(""); const [rec, setRec] = useState(""); const [recT, setRecT] = useState("");
  const [sending, setSending] = useState(false); const { show, toastEl } = useToast();
  const RECS = ["لم يتم القبول","مرفوض من قبل المرشح","قائمة الانتظار","اختبار","مقابلة أولى","مقابلة ثانية","إرسال عرض وظيفي","إرسال مسودة عقد","يسجل متعاون","توقيع العقد","تدريب"];
  const wc = s => (s||"").trim().split(/\s+/).filter(Boolean).length;
  const submit = async () => {
    if (wc(techN)<10) { show("⚠️ الفني: 10 كلمات على الأقل"); return; }
    if (wc(admN)<10) { show("⚠️ الإداري: 10 كلمات على الأقل"); return; }
    if (wc(langN)<3) { show("⚠️ اللغوي: 3 كلمات على الأقل"); return; }
    if (!rec) { show("⚠️ اختر التوصية"); return; }
    if (wc(recT)<10) { show("⚠️ شرح التوصية: 10 كلمات على الأقل"); return; }
    setSending(true);
    const tot = Math.round((+tech + +adm + +lang)/3);
    await onSubmit({ technical:+tech, admin:+adm, language:+lang, technicalNotes:techN.trim(), adminNotes:admN.trim(), languageNotes:langN.trim(), generalNotes:genN.trim(), recommendation:rec, recommendationText:recT.trim(), totalScore:tot, evaluatorId:task?.evaluatorId||"", evaluatorName:task?.evaluatorName||window._currentUser?.displayName||"", at:new Date().toISOString(), taskId:task?.id||"", thread:[] });
    setSending(false);
  };
  const slider = (lbl, v, sv, min, n, sn) => (
    <div style={{ marginBottom:12 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:3 }}>
        <label style={{ fontSize:12, fontWeight:700, color:"var(--text2)" }}>{lbl}</label>
        <span style={{ fontSize:18, fontWeight:900, color:v>=81?"#4ade80":v>=61?"#fbbf24":"#f87171" }}>{v}/100</span>
      </div>
      <input type="range" min="10" max="100" value={v} onChange={e=>sv(+e.target.value)} style={{ width:"100%", accentColor:v>=81?"#4ade80":v>=61?"#fbbf24":"#f87171" }} />
      <textarea value={n} onChange={e=>sn(e.target.value)} rows={2} placeholder={min+" كلمات على الأقل..."} style={{ marginTop:4, fontSize:11 }} />
      <p style={{ fontSize:9, color:wc(n)>=min?"#4ade80":"#f87171", margin:"2px 0 0" }}>{wc(n)}/{min}</p>
    </div>
  );
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:12 }} onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:22, width:"100%", maxWidth:520, maxHeight:"92vh", overflowY:"auto" }}>
        {toastEl}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
          <div><h3 style={{ color:"var(--gold)", fontWeight:900, fontSize:16, margin:0 }}>📋 تقييم {(cand||{}).fullName||task?.candidateName||""}</h3>
            {task && <p style={{ fontSize:11, color:"var(--text3)", margin:0 }}>تكليف من {task.assignedBy}</p>}
          </div>
          <button onClick={onClose} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>
        {/* ── تحديد موعد المقابلة ── */}
        <div style={{ marginBottom:14, padding:"10px 12px", background:"rgba(37,211,102,.06)", border:"1px solid rgba(37,211,102,.2)", borderRadius:10 }}>
          <p style={{ fontSize:12, fontWeight:700, color:"#25d366", marginBottom:8 }}>📅 تحديد موعد المقابلة والتنسيق</p>
          <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:8 }}>
            <input type="date" value={interviewDate} onChange={e=>setInterviewDate(e.target.value)} style={{ flex:"1 1 120px", fontSize:12, padding:"6px 8px" }} />
            <input type="time" value={interviewTime} onChange={e=>setInterviewTime(e.target.value)} style={{ flex:"1 1 80px", fontSize:12, padding:"6px 8px" }} />
            <input value={interviewLocation} onChange={e=>setInterviewLocation(e.target.value)} placeholder="المكان أو رابط الاجتماع" style={{ flex:"2 1 160px", fontSize:12, padding:"6px 8px" }} />
          </div>
          <div style={{ display:"flex", gap:6 }}>
            <button onClick={async()=>{
              if(!interviewDate){show("⚠️ حدد التاريخ");return;}
              const cid=(cand||{}).uid||(cand||{}).idNumber||(cand||{}).email||task?.candidateId;
              if(cid){
                const ivData={date:interviewDate,time:interviewTime,location:interviewLocation,scheduledBy:task?.evaluatorName||window._currentUser?.displayName||"",scheduledAt:new Date().toISOString()};
                await db.set("interview_schedule:"+cid, ivData);
                setInterviewSaved(true); show("✅ تم حفظ موعد المقابلة");
              }
            }} className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"#25d366", borderColor:"rgba(37,211,102,.3)" }}>
              {interviewSaved?"✅ تم الحفظ":"💾 حفظ الموعد"}
            </button>
            {(cand||{}).phone && interviewDate && (
              <a href={"https://wa.me/"+(cand.phone||"").replace(/^0/,"966").replace(/[^0-9]/g,"")+"?text="+encodeURIComponent("السلام عليكم "+(cand.fullName||task?.candidateName||"")+"،\nنود إبلاغكم بموعد المقابلة:\n📅 التاريخ: "+interviewDate+(interviewTime?" الساعة "+interviewTime:"")+"\n📍 المكان: "+(interviewLocation||"سيتم تحديده")+"\n\nنأمل الحضور في الموعد المحدد.\n\nمع التحية،\nإدارة الموارد البشرية — كوادر HMA")}
                target="_blank" rel="noopener" className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"#25d366", borderColor:"rgba(37,211,102,.3)", textDecoration:"none" }}>
                💬 إرسال واتساب بالموعد
              </a>
            )}
          </div>
        </div>
        {slider("🔧 فني", tech, setTech, 10, techN, setTechN)}
        {slider("📋 إداري", adm, setAdm, 10, admN, setAdmN)}
        {slider("🗣️ لغوي", lang, setLang, 3, langN, setLangN)}
        <div className="field" style={{ marginBottom:12 }}><label className="label">ملاحظات عامة</label><textarea value={genN} onChange={e=>setGenN(e.target.value)} rows={2} placeholder="ملاحظات..." /></div>
        <div style={{ marginBottom:12 }}>
          <p style={{ fontSize:12, fontWeight:700, color:"var(--text2)", marginBottom:6 }}>التوصية</p>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:5 }}>
            {RECS.map(r => <button key={r} onClick={()=>setRec(r)} style={{ padding:"7px 4px", borderRadius:8, fontSize:11, fontFamily:"inherit", fontWeight:rec===r?700:400, border:"1px solid "+(rec===r?"var(--accent)":"var(--b)"), background:rec===r?"var(--accent-d)":"transparent", color:rec===r?"var(--accent)":"var(--text2)", cursor:"pointer" }}>{r}</button>)}
          </div>
          {rec && <><textarea value={recT} onChange={e=>setRecT(e.target.value)} rows={2} placeholder="شرح التوصية (10 كلمات على الأقل)..." style={{ marginTop:6, fontSize:11 }} />
            <p style={{ fontSize:9, color:wc(recT)>=10?"#4ade80":"#f87171", margin:"2px 0 0" }}>{wc(recT)}/10</p></>}
        </div>
        <div style={{ textAlign:"center", marginBottom:8 }}><span style={{ fontSize:22, fontWeight:900, color:Math.round((tech+adm+lang)/3)>=75?"#4ade80":"#fbbf24" }}>{Math.round((+tech + +adm + +lang)/3)}/100</span></div>
        <button onClick={submit} disabled={sending} className="btn btn-gold" style={{ width:"100%", padding:"12px", fontSize:14 }}>{sending?"⏳...":"📤 إرسال التقييم"}</button>
      </div>
    </div>
  );
}

function CandProfile({ c, onEdit, isAdmin, libs, specsMap, onSave, lang="ar", isEmployee=false }) {
  const tCP = PORTAL_I18N[lang] || PORTAL_I18N.ar;
  const ev = c.evaluation || null;
  const [pane, setPane] = useState("profile");
  const [showLastEval, setShowLastEval] = useState(false);
  const [showMsg, setShowMsg] = useState(false);
  const { show, toastEl } = useToast();

  const initials = (c.fullName||"?").split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase();

  return (
    <div className="fade">
      {toastEl}

      {/* ── Last AI Eval Modal ── */}
      {showLastEval && ev && isAdmin && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid rgba(167,139,250,.4)", borderRadius:18, padding:26, width:"100%", maxWidth:480, maxHeight:"90vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
              <div>
                <p style={{ color:"#c4b5fd", fontWeight:900, fontSize:16 }}>🤖 آخر تقييم بالذكاء الاصطناعي</p>
                <p style={{ color:"var(--text3)", fontSize:12 }}>{c.fullName} — {c.evaluatedAt ? new Date(c.evaluatedAt).toLocaleDateString("ar-SA") : "—"}</p>
              </div>
              <button onClick={()=>setShowLastEval(false)} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit", lineHeight:1, flexShrink:0 }} title="إغلاق">✕</button>
            </div>
            <div style={{ display:"flex", gap:12, marginBottom:14, flexWrap:"wrap" }}>
              <div style={{ padding:"12px 18px", background:"rgba(167,139,250,.1)", border:"1px solid rgba(167,139,250,.3)", borderRadius:10, textAlign:"center" }}>
                <div style={{ fontSize:32, fontWeight:900, color:"#c4b5fd" }}>{ev.score||0}</div>
                <div style={{ fontSize:11, color:"var(--text3)" }}>/ 100</div>
              </div>
              <div style={{ flex:1 }}>
                {ev.level && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:6 }}>المستوى: <strong style={{ color:"var(--gold)" }}>{ev.level}</strong></p>}
                {ev.recommendation && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:6 }}>التوصية: <strong style={{ color:"#4ade80" }}>{ev.recommendation}</strong></p>}
              </div>
            </div>
            {ev.summary && <div style={{ padding:"10px 14px", background:"rgba(255,255,255,.03)", borderRadius:10, fontSize:13, color:"var(--text2)", lineHeight:1.7, fontStyle:"italic", marginBottom:12 }}>"{ev.summary}"</div>}
            <div className="g2" style={{ marginBottom:14 }}>
              {ev.strengths?.length > 0 && (
                <div style={{ padding:"10px 12px", background:"rgba(34,197,94,.06)", border:"1px solid rgba(34,197,94,.2)", borderRadius:9 }}>
                  <p style={{ color:"#4ade80", fontWeight:700, fontSize:11, marginBottom:6 }}>✅ نقاط القوة</p>
                  {ev.strengths.map((s,i)=><p key={i} style={{ fontSize:12, color:"var(--text2)", marginBottom:3 }}>• {s}</p>)}
                </div>
              )}
              {ev.weaknesses?.length > 0 && (
                <div style={{ padding:"10px 12px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.2)", borderRadius:9 }}>
                  <p style={{ color:"#f87171", fontWeight:700, fontSize:11, marginBottom:6 }}>⚠️ نقاط التطوير</p>
                  {ev.weaknesses.map((w,i)=><p key={i} style={{ fontSize:12, color:"var(--text2)", marginBottom:3 }}>• {w}</p>)}
                </div>
              )}
            </div>
            <button onClick={()=>setShowLastEval(false)} className="btn btn-ghost btn-sm" style={{ width:"100%" }}>إغلاق</button>
          </div>
        </div>
      )}

      {showMsg && <GlobalQuickMessage person={c} onClose={()=>setShowMsg(false)} />}

      {/* ── Hero Card — مدمج — مخفي للموظف لأن المعلومات في الهيدر ── */}
      {!isEmployee && (
      <div style={{ background:"linear-gradient(135deg,rgba(201,168,76,.12),rgba(201,168,76,.04))", border:"1px solid rgba(201,168,76,.25)", borderRadius:16, padding:"14px 16px", marginBottom:14 }}>
        {/* الصف الأول: أفاتار + اسم + رقم + أيقونات */}
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          {/* Avatar */}
          <div style={{ width:52, height:52, borderRadius:"50%", background:"linear-gradient(135deg,#c9a84c,#a8893a)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:18, fontWeight:900, color:"#0b0f1a", flexShrink:0, boxShadow:"0 4px 12px rgba(201,168,76,.35)" }}>
            {initials}
          </div>
          {/* الاسم والرقم */}
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ display:"flex", alignItems:"center", gap:6, flexWrap:"wrap" }}>
              <span style={{ fontSize:16, fontWeight:900, color:"var(--gold)", lineHeight:1.2 }}>{c.fullName||"—"}</span>
              {c.hrCode && <span style={{ fontSize:11, background:"rgba(201,168,76,.15)", color:"var(--gold)", padding:"2px 8px", borderRadius:10, border:"1px solid rgba(201,168,76,.35)", fontWeight:700 }}>{c.hrCode}</span>}
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:3, flexWrap:"wrap" }}>
              {c.email && <a href={"mailto:"+c.email} style={{ fontSize:11, color:"var(--text3)", display:"flex", alignItems:"center", gap:3, textDecoration:"none" }}>✉️ {c.email}</a>}
              {c.phone && <a href={"tel:"+c.phone} style={{ fontSize:11, color:"var(--text3)", display:"flex", alignItems:"center", gap:3, textDecoration:"none" }}>📞 {c.phone}</a>}
            </div>
          </div>
          {/* أيقونات اليمين */}
          <div style={{ display:"flex", gap:6, alignItems:"center", flexShrink:0 }}>
            {isAdmin && <button onClick={()=>setShowMsg(true)} style={{ width:36, height:36, borderRadius:10, background:"rgba(255,255,255,.04)", border:"1px solid var(--b)", color:"var(--text3)", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>💬</button>}
          </div>
        </div>

        {/* الصف الثاني: تفاصيل إضافية */}
        {(c.lastJob||c.city||c.yearsExperience||c.nationality||c.locationStatus||(ev&&isAdmin)) && (
          <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginTop:10, paddingTop:10, borderTop:"1px solid rgba(201,168,76,.12)", alignItems:"center" }}>
            {c.lastJob && <span style={S.txt3s11}>{c.lastJob}{c.lastCompany?" — "+c.lastCompany:""}</span>}
            {c.city && <span style={S.txt3s11}>📍 {c.city}</span>}
            {c.yearsExperience && <span style={S.txt3s11}>🗓️ {c.yearsExperience} سنوات</span>}
            {c.nationality && <span style={S.txt3s11}>🌍 {c.nationality}</span>}
            {c.locationStatus && <span style={{ fontSize:11, padding:"1px 7px", borderRadius:8, background:"rgba(96,165,250,.1)", color:"#93c5fd", border:"1px solid rgba(96,165,250,.2)" }}>{c.locationStatus}</span>}
            {ev && isAdmin && <Score score={ev.score} />}
            {ev && isAdmin && <Rec rec={ev.recommendation} />}
            {c.evaluation && isAdmin && <button onClick={()=>setShowLastEval(true)} className="btn btn-ghost btn-sm" style={{ color:"#c4b5fd", border:"1px solid rgba(167,139,250,.3)", fontSize:11, padding:"2px 8px" }}>🤖 آخر تقييم</button>}
            {onEdit && <button onClick={onEdit} className="btn btn-ghost btn-sm" style={{ fontSize:11, padding:"2px 8px" }}>✏️ تعديل</button>}
            {c._hasPendingTags && <span style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:"rgba(245,158,11,.15)", color:"#f59e0b", border:"1px solid rgba(245,158,11,.3)" }}>🔔 تصنيفات معلقة</span>}
            {c.linkedinUrl && <a href={c.linkedinUrl} target="_blank" rel="noreferrer" style={{ fontSize:11, color:"#60a5fa" }}>🔗 LinkedIn</a>}
          </div>
        )}
      </div>
      )}

      {/* ── Tabs ── */}
      <div style={{ display:"flex", gap:6, marginBottom:14, borderBottom:"1px solid var(--b)", paddingBottom:10 }}>
        {[["profile","📋 الملف"],["cv","📄 السيرة"],...(isEmployee?[["job_data","💼 البيانات الوظيفية"]]:[])].map(([id,label]) => (
          <button key={id} onClick={()=>setPane(id)}
            className={"tab-btn "+(pane===id?"tab-on":"tab-off")}>
            {label}
          </button>
        ))}
      </div>

      {/* ── Profile Tab ── */}
      {pane === "profile" && (
        <div>
          {/* Quick info grid */}
          <div className="g3" style={{ marginBottom:14 }}>
            {[
              ["🎓 المؤهل",       [c.education, c.university].filter(Boolean).join(" — ")],
              ["💰 الراتب المتوقع", c.expectedSalary ? Number(c.expectedSalary).toLocaleString()+" ريال" : ""],
              ["📅 تاريخ الالتحاق", c.availableDate ? new Date(c.availableDate).toLocaleDateString("ar-SA") : ""],
              ["🎂 سنة التخرج",   c.graduationYear ? String(c.graduationYear) : ""],
              ["👔 الجنس",        c.gender],
              ["📋 ملاحظات",      c.notes],
            ].filter(([,v])=>v&&String(v).trim()).map(([l,v]) => (
              <div key={l} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:9, padding:"10px 13px" }}>
                <p style={{ color:"var(--text3)", fontSize:10, marginBottom:3, fontWeight:600 }}>{l}</p>
                <p style={{ color:"var(--text)", fontWeight:700, fontSize:13 }}>{v}</p>
              </div>
            ))}
          </div>

          {/* Tags — improved display */}
          {[
            { title:"التخصصات", icon:"🏗️", tags:c.biSpec||(c.specializations||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.specs||[]).map(s=>s.label) },
            { title:"الإدارات",  icon:"🏢", tags:c.biDept||(c.departments||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.jobTypes||[]).filter(Boolean) },
            { title:"المهارات",  icon:"🛠️", tags:c.biSkill||(c.skills||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.skills||[]).filter(Boolean) },
            { title:"البرامج",   icon:"💻", tags:c.biSW||(c.software||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.software||[]).filter(Boolean) },
            { title:"المشاريع",  icon:"📋", tags:c.biProj||(c.projectTypes||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.projectTypes||[]).filter(Boolean) },
            { title:"الشهادات",  icon:"🏅", tags:c.biCert||(c.certifications||[]).map(s=>({ar:s,en:"",approved:true})), lib:(libs.certifications||[]).filter(l=>l!=null&&l!==undefined) },
          ].filter(b=>(b.tags||[]).length>0).map(b => (
            <div key={b.title} style={{ marginBottom:10 }}>
              <p style={{ fontSize:12, fontWeight:700, color:"var(--text2)", marginBottom:6 }}>{b.icon} {b.title}</p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
                {(b.tags||[]).map((t,i) => {
                  const label = t.ar || t.en || t.label || "";
                  const inLib = b.lib.some(l=>{
                const lStr = typeof l==="object" ? (l.ar||l.en||l.label||"") : (l||"");
                return lStr.toLowerCase()===label.toLowerCase();
              });
                  return label ? (
                    <span key={i} style={{ display:"inline-flex", alignItems:"center", gap:4,
                      padding:"4px 10px", borderRadius:20, fontSize:12, fontWeight:600,
                      background: inLib?"rgba(201,168,76,.1)":"rgba(255,255,255,.05)",
                      border:"1px solid "+(inLib?"rgba(201,168,76,.3)":"rgba(255,255,255,.1)"),
                      color: inLib?"var(--gold)":"var(--text3)" }}>
                      {label}
                      {t.en && t.ar && <span style={{ fontSize:10, opacity:.6 }}>({t.en})</span>}
                    </span>
                  ) : null;
                })}
              </div>
            </div>
          ))}

          <HayaBadge data={c} />

          {/* AI Evaluation */}
          {ev && (
            <div className="card-g" style={{ marginTop:14 }}>
              <div className="sec">🤖 تقييم الذكاء الاصطناعي</div>
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:7 }}>
                <span style={S.txt2s13}>الدرجة</span>
                <Score score={ev.score} />
              </div>
              <div className="pbar" style={{ marginBottom:12 }}><div className="pb-fill" style={{ width:ev.score+"%" }} /></div>
              <div className="g2">
                <div>
                  <p style={{ color:"var(--text2)", fontSize:12, marginBottom:5 }}>نقاط القوة</p>
                  {(ev.strengths||[]).map(s=><p key={s} style={{ color:"#4ade80", fontSize:12, margin:"2px 0" }}>✓ {s}</p>)}
                </div>
                <div>
                  <p style={{ color:"var(--text2)", fontSize:12, marginBottom:5 }}>نقاط الضعف</p>
                  {(ev.weaknesses||[]).map(w=><p key={w} style={{ color:"#fbbf24", fontSize:12, margin:"2px 0" }}>⚠ {w}</p>)}
                </div>
              </div>
              {ev.summary && <p style={{ color:"var(--text2)", fontSize:12, marginTop:9, lineHeight:1.7 }}>{ev.summary}</p>}
            </div>
          )}
        </div>
      )}

      {/* ── CV Tab ── */}
      {pane === "cv" && (
        <div className="card">
          {onSave
            ? <CVFilePane person={c} onSave={async (updates) => { await onSave({...c,...updates}); }} />
            : <p style={{ color:"var(--text3)", textAlign:"center", padding:20 }}>يتطلب صلاحية التعديل</p>
          }
        </div>
      )}

      {/* ── CV History Tab ── */}
      {pane === "history" && isAdmin && (
        <div>
          <EventsLog
            personId={c.uid || c.idNumber || c.email}
            currentUser={window._currentUser}
            isAdmin={isAdmin}
          />
        </div>
      )}
      {pane === "history" && !isAdmin && (
        <div className="card" style={{ textAlign:"center", padding:32 }}>
          <p style={{ fontSize:24, marginBottom:10 }}>🔒</p>
          <p style={{ color:"var(--text3)" }}>سجل الأحداث متاح للمشرفين فقط</p>
        </div>
      )}

      {/* ── البيانات الوظيفية — للموظفين ── */}
      {pane === "job_data" && isEmployee && (()=>{
        const myJT = (window._jobTitles||[]).find(jt => jt.title === c.jobTitle || jt.title === c.position);
        const fullCfg = window._kpiFullConfig;
        const myDept = c.department || myJT?.dept || "";
        const kpiTools = fullCfg?.tools || [];
        const deptKPI = fullCfg?.departments?.[myDept] || fullCfg?.departments?._default || [];
        return (
          <div>
            {/* المسمى الوظيفي */}
            <div className="card" style={{ marginBottom:14, border:"1px solid rgba(201,168,76,.2)" }}>
              <p style={{ fontWeight:900, fontSize:15, color:"var(--gold)", marginBottom:10 }}>💼 المسمى الوظيفي</p>
              <div style={{ display:"flex", gap:10, flexWrap:"wrap", marginBottom:10 }}>
                <div style={{ flex:"1 1 200px", padding:"10px 14px", background:"rgba(201,168,76,.06)", borderRadius:10, border:"1px solid rgba(201,168,76,.15)" }}>
                  <p style={{ fontSize:10, color:"var(--text3)" }}>المسمى</p>
                  <p style={{ fontWeight:700, fontSize:14, color:"var(--text)" }}>{c.jobTitle || c.position || "غير محدد"}</p>
                </div>
                <div style={{ flex:"1 1 200px", padding:"10px 14px", background:"rgba(201,168,76,.06)", borderRadius:10, border:"1px solid rgba(201,168,76,.15)" }}>
                  <p style={{ fontSize:10, color:"var(--text3)" }}>الإدارة</p>
                  <p style={{ fontWeight:700, fontSize:14, color:"var(--text)" }}>🏢 {myDept || "غير محدد"}</p>
                </div>
                {myJT?.gradeRef && <div style={{ flex:"1 1 120px", padding:"10px 14px", background:"rgba(201,168,76,.06)", borderRadius:10, border:"1px solid rgba(201,168,76,.15)" }}>
                  <p style={{ fontSize:10, color:"var(--text3)" }}>الدرجة</p>
                  <p style={{ fontWeight:700, fontSize:14, color:"var(--gold)" }}>{myJT.gradeRef}</p>
                </div>}
              </div>
            </div>

            {/* الوصف الوظيفي */}
            {myJT?.description && (
              <div className="card" style={{ marginBottom:14 }}>
                <p style={{ fontWeight:900, fontSize:14, color:"var(--text)", marginBottom:8 }}>📝 الوصف الوظيفي</p>
                <p style={{ fontSize:13, color:"var(--text2)", lineHeight:1.8 }}>{myJT.description}</p>
              </div>
            )}

            {/* المهام والمسؤوليات */}
            {myJT?.duties?.length > 0 && (
              <div className="card" style={{ marginBottom:14 }}>
                <p style={{ fontWeight:900, fontSize:14, color:"var(--text)", marginBottom:8 }}>📋 المهام والمسؤوليات</p>
                {myJT.duties.filter(d=>d.trim()).map((d,i) => (
                  <div key={i} style={{ display:"flex", gap:8, alignItems:"flex-start", marginBottom:6 }}>
                    <span style={{ color:"var(--gold)", fontWeight:900, fontSize:12, minWidth:20 }}>{i+1}.</span>
                    <p style={{ fontSize:13, color:"var(--text2)", lineHeight:1.6 }}>{d}</p>
                  </div>
                ))}
              </div>
            )}

            {/* معايير التقييم KPI */}
            <div className="card" style={{ marginBottom:14, border:"1px solid rgba(167,139,250,.2)" }}>
              <p style={{ fontWeight:900, fontSize:14, color:"#c4b5fd", marginBottom:10 }}>📊 معايير التقييم</p>
              {kpiTools.filter(t=>t.enabled).length > 0 ? (
                <div>
                  <p style={{ fontSize:11, color:"var(--text3)", marginBottom:8 }}>أدوات القياس الأساسية:</p>
                  {kpiTools.filter(t=>t.enabled).map(t => (
                    <div key={t.id} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 12px", marginBottom:4, background:"rgba(167,139,250,.04)", borderRadius:8, border:"1px solid rgba(167,139,250,.1)" }}>
                      <span style={{ fontSize:13, color:"var(--text)" }}>{t.icon} {t.label}</span>
                      <span style={{ fontSize:12, fontWeight:900, color:"#c4b5fd" }}>{t.weight}%</span>
                    </div>
                  ))}
                </div>
              ) : (
                <p style={{ fontSize:12, color:"var(--text3)", textAlign:"center", padding:8 }}>لم تُحدد معايير التقييم بعد</p>
              )}

              {/* معايير القسم */}
              {deptKPI.length > 0 && (
                <div style={{ marginTop:12 }}>
                  <p style={{ fontSize:11, color:"var(--text3)", marginBottom:6 }}>معايير القسم ({myDept}):</p>
                  {deptKPI.map((k,i) => (
                    <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"6px 10px", marginBottom:3, background:"rgba(245,158,11,.04)", borderRadius:6 }}>
                      <span style={{ fontSize:12, color:"var(--text2)" }}>{k.icon||"📊"} {k.label}</span>
                      <span style={{ fontSize:11, fontWeight:700, color:"#f59e0b" }}>{k.weight}%</span>
                    </div>
                  ))}
                </div>
              )}

              {/* معايير المسمى */}
              {myJT?.kpiCriteria?.length > 0 && (
                <div style={{ marginTop:12 }}>
                  <p style={{ fontSize:11, color:"var(--text3)", marginBottom:6 }}>معايير المسمى الوظيفي:</p>
                  {myJT.kpiCriteria.map((k,i) => (
                    <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"6px 10px", marginBottom:3, background:"rgba(34,197,94,.04)", borderRadius:6 }}>
                      <span style={{ fontSize:12, color:"var(--text2)" }}>{k.icon||"📊"} {k.label}</span>
                      <span style={{ fontSize:11, fontWeight:700, color:"#22c55e" }}>{k.weight}%</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {!myJT && (
              <div className="card" style={{ textAlign:"center", padding:30 }}>
                <p style={{ fontSize:28, marginBottom:8 }}>💼</p>
                <p style={{ color:"var(--text3)", fontSize:13 }}>لم يتم ربط مسمى وظيفي بحسابك بعد — تواصل مع الإدارة</p>
              </div>
            )}
          </div>
        );
      })()}

    </div>
  );
}

// ── SmartFileImport — multi-file smart classifier & importer ─────────────────
function SmartFileImport({ libs, onDone }) {
  const [files, setFiles]       = useState([]);
  const [step, setStep]         = useState(1);
  const [overrideType, setOverrideType] = useState("auto");   // 1=drop 2=analyzing 3=review 4=saving
  const [analyzed, setAnalyzed] = useState([]);  // [{file, type, person, personType, content, status, existing}]
  const [saving, setSaving]     = useState(false);
  const [progress, setProgress] = useState("");
  const [saveReport, setSaveReport] = useState(null); // {added, skipped, updated, duplicates}
  const fileRef = useRef(null);
  const { show, toastEl }       = useToast();

  const FILE_TYPES = {
    cv:          { icon:"📄", label:"سيرة ذاتية",      color:"#60a5fa" },
    portfolio:   { icon:"🗂️", label:"بروفايل / أعمال", color:"#a78bfa" },
    certificate: { icon:"🏅", label:"شهادة / وثيقة",   color:"#f59e0b" },
    exp_letter:  { icon:"💼", label:"شهادة خبرة",      color:"#e8eaf0" },
    excel:       { icon:"📊", label:"بيانات Excel",    color:"#34d399" },
    unknown:     { icon:"📎", label:"غير محدد",         color:"#94a3b8" },
  };

  const toB64 = (f) => new Promise((res,rej) => { const r=new FileReader(); r.onload=()=>res(r.result.split(",")[1]); r.onerror=rej; r.readAsDataURL(f); });
  const toArr = (f) => new Promise((res,rej) => { const r=new FileReader(); r.onload=()=>res(r.result); r.onerror=rej; r.readAsArrayBuffer(f); });
  const isXls = (f) => f.name.match(/\.(xlsx|xls|csv)$/i) || f.type.includes("spreadsheet") || f.type.includes("excel");

  const addFiles = (fs) => {
    const valid = Array.from(fs).filter(f =>
      f.type==="application/pdf" ||
      f.type.startsWith("image/") ||
      isXls(f) ||
      f.name.match(/\.(txt|doc|docx|rtf)$/i) ||
      f.type.includes("word") ||
      f.type.includes("document") ||
      f.type === "text/plain"
    );
    if (valid.length) setFiles(p => [...p, ...valid.filter(vf => !p.find(pf=>pf.name===vf.name))]);
  };

  const loadXLSX = () => new Promise((res,rej) => {
    if (window.XLSX) { res(window.XLSX); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
    s.onload = () => res(window.XLSX); s.onerror = rej;
    document.head.appendChild(s);
  });

  const classifyFile = async (f, b64, mime, rawText) => {
    const isImg = mime.startsWith("image/");
    const isPdf = mime === "application/pdf";
    // Use the same comprehensive prompt as buildPrompt
    const cvPrompt = buildPrompt(libs);
    const prompt = `You are an HR document analyzer. First determine the document type, then extract data if it is a CV.
Respond ONLY with valid JSON — no markdown, no explanation.

Step 1 — Classify the document:
{
  "fileType": "cv|portfolio|certificate|exp_letter|unknown",
  "personName": "full name as written",
  "personType": "candidate|employee|unknown",
  "language": "ar|en|both",
  "summary": "ملخص عربي 2-3 جمل",
  "cvData": null
}

Step 2 — If fileType is "cv", replace cvData with the full extracted JSON using these rules:
${cvPrompt}

For portfolio: summary should list project names and count.
For certificate: summary should include issuer, date, credential name.
For exp_letter: summary should include company, role, duration.

Respond ONLY with JSON.`;

    // ═══ Strategy: text first (callAIModel with fallback), binary as last resort ═══
    
    // Collect text from all sources
    let docText = rawText || "";
    if (!docText && (f.type === "text/plain" || f.name.endsWith(".txt"))) {
      try { docText = await f.text(); } catch {}
    }
    if (!docText && f.name.match(/\.(doc|docx|rtf)$/i)) {
      try { docText = atob(b64).replace(/[^\x20-\x7E\u0600-\u06FF\n\r\t]/g,"").trim(); } catch {}
    }

    // Method 1: If we have good text, use callAIModel (has full fallback)
    if (docText && docText.trim().length > 50) {
      try {
        const textPrompt = prompt + "\n\n=== DOCUMENT TEXT ===\n" + docText.slice(0, 8000);
        const result = await callAIModel([{role:"user",content:textPrompt}], "أنت محلل مستندات HR. أرجع JSON فقط بدون أي نص إضافي.", MODEL_GEMINI);
        if (result && !result._rawText) return result;
        if (result?._rawText) {
          const raw2 = result._rawText.replace(/```[\w]*/g,"").replace(/```/g,"").trim();
          const s2=raw2.indexOf("{"), e2=raw2.lastIndexOf("}");
          if (s2>-1&&e2>s2) return JSON.parse(raw2.slice(s2,e2+1));
        }
      } catch(textErr) {
        console.warn("classifyFile text method failed:", textErr.message);
      }
    }

    // Method 2: Binary content — try Claude first (best multimodal), then Gemini
    const isDoc = f.name.match(/\.(doc|docx|rtf|txt)$/i);
    let content;
    if (isDoc) {
      content = [{ type:"text", text: prompt + "\n\n=== DOCUMENT TEXT ===\n" + (docText||f.name).slice(0, 5000) }];
    } else if (isPdf) {
      content = [
        { type:"document", source:{ type:"base64", media_type:"application/pdf", data:b64 } },
        { type:"text", text:prompt }
      ];
    } else if (isImg) {
      content = [
        { type:"image", source:{ type:"base64", media_type:mime_c||mime, data:b64 } },
        { type:"text", text:prompt }
      ];
    } else {
      content = [{ type:"text", text:prompt }];
    }

    // For binary: Claude first (native multimodal), then Gemini, then Flash
    const models = [MODEL, MODEL_GEMINI, MODEL_FLASH];
    let lastErr = null;
    for (const tryModel of models) {
      for (let attempt = 0; attempt < 2; attempt++) {
        try {
          if (attempt > 0) await new Promise(r => setTimeout(r, 2000));
          const ep = AI;
          const res = await fetch(ep, {
            method:"POST", headers:{"Content-Type":"application/json"},
            body:JSON.stringify({ model:tryModel, max_tokens:4000,
              messages:[{ role:"user", content }] })
          });
          const d = await res.json();
          if (!res.ok) throw new Error(d?.error?.message || "API " + res.status);
          const raw = (d?.content?.[0]?.text || d?.candidates?.[0]?.content?.parts?.[0]?.text || "").replace(/```[\w]*/g,"").replace(/```/g,"").trim();
          if (!raw) throw new Error("empty response");
          console.log("⚡ classifyFile binary via " + tryModel);
          const s=raw.indexOf("{"), e=raw.lastIndexOf("}");
          try {
            return s>-1&&e>-1 ? JSON.parse(raw.slice(s,e+1)) : { fileType:"cv", personName:null, personType:"candidate", summary:raw.slice(0,200) };
          } catch {
            return { fileType:"cv", personName:null, personType:"candidate", summary:raw.slice(0,200) };
          }
        } catch(err) {
          lastErr = err;
          console.warn("classifyFile binary attempt (" + tryModel + " #" + (attempt+1) + "):", err.message);
        }
      }
    }
    throw lastErr || new Error("فشلت كل محاولات تحليل الملف")
  };

  const analyze = async () => {
    setStep(2);
    const allCands = await getAllCandidates();
    const allEmps  = await getAllEmployees();

    const xlsFiles  = files.filter(f => isXls(f));
    const aiFiles   = files.filter(f => !isXls(f));

    const tooBig = files.filter(f => f.size > 15 * 1024 * 1024);
    if (tooBig.length > 0) {
      setProgress(`⚠️ ${tooBig.length} ملف كبير جداً (>15MB) — قد يستغرق وقتاً أطول`);
    }

    let done = 0;
    const total = files.length;
    const tick = (name) => {
      done++;
      setProgress(`🔍 ${done}/${total} — ${name}`);
    };

    const xlsResults = [];
    for (const f of xlsFiles) {
      try {
        const XLSX = await loadXLSX();
        const buf  = await toArr(f);
        const wb   = XLSX.read(buf, { type:"array" });
        const ws   = wb.Sheets[wb.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(ws, { defval:"" });
        xlsResults.push({ file:f, name:f.name, fileType:"excel", personType:"multi", personName:null,
          summary:`ملف Excel يحتوي ${rows.length} صف`, rows, status:"ready", existing:null, save:true });
      } catch(e) {
        xlsResults.push({ file:f, name:f.name, fileType:"unknown", status:"error", error:e.message, save:false });
      }
      tick(f.name);
    }

    const BATCH = 3;
    const aiResults = [];
    for (let i = 0; i < aiFiles.length; i += BATCH) {
      const batch = aiFiles.slice(i, i + BATCH);
      const batchResults = await Promise.all(batch.map(async f => {
        try {
          const mime = f.type || "application/pdf";
          const _compressed = await compressImageB64(f);
          const b64  = _compressed.b64 || await toB64(f);
          const mime_c = _compressed.mime || mime;
          // Extract full raw text using pdf.js (no token limits)
          let rawText = "";
          try {
            if (mime === "application/pdf") {
              rawText = await extractTextFromPDF(f);
            } else if (f.name.endsWith(".txt")) {
              rawText = await f.text();
            }
          } catch(textErr) {
            console.warn("Text extraction failed:", textErr);
          }
          const cls  = await classifyFile(f, b64, mime, rawText);
          tick(f.name);

          const pname = cls.personName?.trim().toLowerCase();
          let existing = null;
          if (pname) {
            existing = allCands.find(c => (c.fullName||"").toLowerCase().includes(pname)||pname.includes((c.fullName||"").toLowerCase().split(" ")[0]||"_"))
                    || allEmps.find(e => (e.fullName||"").toLowerCase().includes(pname)||pname.includes((e.fullName||"").toLowerCase().split(" ")[0]||"_"));
          }
          const resolvedPersonType = overrideType === "auto" ? (cls.personType||"unknown")
            : (overrideType === "candidate" || overrideType === "candidates") ? "candidate"
            : "employee";
          return { file:f, name:f.name, b64, mime,
            fileType: cls.fileType||"unknown",
            personName: cls.personName || null,
            personType: resolvedPersonType,
            language: cls.language || "unknown",
            summary: cls.summary || "",
            cvData: cls.cvData || null,
            rawText: rawText || "",
            status: "ready", existing, save: true };
        } catch(e) {
          tick(f.name);
          return { file:f, name:f.name, fileType:"unknown", status:"error", error:e.message, save:false };
        }
      }));
      aiResults.push(...batchResults);
    }

    const results = [...xlsResults, ...aiResults];
    setAnalyzed(results);
    setProgress("");
    setStep(3);
  };

  const saveAll = async () => {
    setSaving(true); setStep(4);
    const actor = window._currentUser;
    const actorName = actor ? (actor.displayName||actor.username) : "المشرف";

    for (const r of analyzed) {
      if (!r.save) continue;
      setProgress(`💾 حفظ: ${r.name}`);

      if (r.fileType === "excel" && r.rows) {
        for (const row of r.rows) {
          const mapped = mapRowHelper(row);
          if (!mapped.fullName && !mapped.email) continue;
          const norm = await normalize(mapped, libs).catch(()=>mapped);
          const uid  = await saveCandidate(norm);
          await addPersonEvent(uid, { type:"data_check", text:`استيراد من Excel: ${r.name}`, by:actorName, byRole:"admin", private:false });
        }
        continue;
      }

      if (r.fileType !== "excel" && (r.personName || r.cvData || r.rawText)) {
        // Build cvData from whatever we have — save candidate/employee for ANY file type
        const cv = r.cvData || {};
        if (!cv.fullName && r.personName) cv.fullName = r.personName;
        // If still no name, try to extract from rawText first line
        if (!cv.fullName && r.rawText) {
          const firstLine = r.rawText.trim().split("\n")[0].trim();
          if (firstLine.length > 2 && firstLine.length < 60) cv.fullName = firstLine;
        }
        if (!cv.fullName) cv.fullName = r.name.replace(/\.(pdf|txt|doc|docx|rtf|jpg|jpeg|png)$/i,"").replace(/[_-]/g," ").trim() || "مرشح — " + r.name;
        // Save raw text as CV snapshot
        if (r.rawText && r.rawText.trim()) {
          const snap = makeCvSnapshot(r.rawText, "upload");
          cv.cvHistory = [snap];
          cv.cvFullText = r.rawText.slice(0, 50000);
        }
        // Add document info if not a CV
        if (r.fileType !== "cv" && r.summary) {
          if (!cv.notes) cv.notes = "";
          cv.notes = (cv.notes ? cv.notes + "\n" : "") + "📎 " + (FILE_TYPES[r.fileType]?.label||r.fileType) + ": " + r.summary;
        }
        const rawData = {
          ...cv,
          SPEC: cv.SPEC || cv.specializations || [],
          SKILL: cv.SKILL || cv.skills || [],
          SW: cv.SW || cv.software || [],
          CERT: cv.CERT || cv.certifications || [],
          DEPT: cv.DEPT || [],
          PROJ: cv.PROJ || [],
        };
        const norm = await normalize(rawData, libs).catch(()=>rawData);

        const allCands = await getAllCandidates();
        const allEmpsCheck = await getAllEmployees();
        const existing = allCands.find(c =>
          (norm.idNumber && c.idNumber && c.idNumber === norm.idNumber) ||
          (norm.email && c.email && (c.email||"").toLowerCase() === (norm.email||"").toLowerCase()) ||
          (norm.phone && c.phone && c.phone.replace(/\D/g,"").slice(-9) === norm.phone.replace(/\D/g,"").slice(-9)) ||
          (norm.fullName && c.fullName && (c.fullName||"").trim() === norm.fullName.trim())
        );
        const existingEmp = allEmpsCheck.find(e =>
          (norm.idNumber && e.idNumber && e.idNumber === norm.idNumber) ||
          (norm.email && e.email && (e.email||"").toLowerCase() === (norm.email||"").toLowerCase()) ||
          (norm.phone && e.phone && e.phone.replace(/\D/g,"").slice(-9) === norm.phone.replace(/\D/g,"").slice(-9)) ||
          (norm.fullName && e.fullName && (e.fullName||"").trim() === norm.fullName.trim())
        );
        if (existingEmp) {
          show("⚠️ تنبيه: " + norm.fullName + " موظف لديكم حالياً — رقم: " + (existingEmp.hrCode||"") + " الإدارة: " + (existingEmp.department||"غير محدد"), false);
        } else if (existing) {
          show("⚠️ " + norm.fullName + " مسجل مسبقاً — سيتم دمج البيانات الجديدة", false);
        }

        const toSave = existing
          ? { ...existing, ...norm, uid: existing.uid || norm.uid }
          : norm;

        // Only save raw text to history, not JSON summary
        const snap = { source:"upload", date:new Date().toISOString(), text:toSave.cvRawText||r.summary||"" };
        toSave.cvHistory = [...(toSave.cvHistory||[]), snap];
        toSave.cvFullText = toSave.cvRawText || r.summary || "";

        let uid;
        if (r.personType === "employee") uid = await saveEmployee(toSave);
        else uid = await saveCandidate(toSave);
        const resolvedUid = uid || toSave.uid || toSave.idNumber || toSave.email;
        if (resolvedUid) {
          await addPersonEvent(resolvedUid, {
            type:"cv_upload",
            text:`رفع سيرة ذاتية (${r.language==="ar"?"عربية":r.language==="en"?"إنجليزية":"عربية وإنجليزية"}) — ${r.name}`,
            by:actorName, byRole:"admin", private:false
          });
        }
        continue;
      }

      const pid = r.existing ? (r.existing.uid||r.existing.idNumber||r.existing.email) : null;
      if (pid) {
        const typeLabel = FILE_TYPES[r.fileType]?.label || r.fileType;
        const today = new Date().toLocaleDateString("ar-SA");
        await addPersonEvent(pid, {
          type: r.fileType === "exp_letter" ? "data_check" : "note",
          text: `أُرفق بتاريخ ${today} — ${typeLabel}:\n${r.summary}`,
          by: actorName, byRole:"admin", private:false
        });
      }
    }

    setSaving(false); setProgress("✅ اكتمل");
    show("✅ تم حفظ جميع الملفات");
    if (onDone) setTimeout(onDone, 800);
    setTimeout(() => { setFiles([]); setAnalyzed([]); setStep(1); setProgress(""); }, 1200);
  };

  const mapRowHelper = (row) => {
    const g = (...keys) => { for (const k of keys) { const fk=Object.keys(row).find(rk=>rk.trim().toLowerCase()===k.toLowerCase()); if(fk!==undefined&&row[fk]!=="") return String(row[fk]).trim(); } return ""; };
    const sp = (v) => v ? v.split(/[,،;]/).map(s=>s.trim()).filter(Boolean) : [];
    return { fullName:g("الاسم الكامل","الاسم","Name","Full Name"), email:g("البريد الإلكتروني","البريد","Email"),
      phone:g("الجوال","الهاتف","Phone"), idNumber:g("رقم الهوية","الهوية","ID"),
      nationality:g("الجنسية","Nationality"), city:g("المدينة","City"),
      yearsExperience:parseInt(g("سنوات الخبرة","الخبرة","Experience"))||0,
      lastJob:g("آخر مسمى","المسمى","Job Title"), lastCompany:g("آخر شركة","الشركة","Company"),
      education:g("المؤهل","Education"), expectedSalary:parseInt(g("الراتب المتوقع","الراتب","Salary"))||0,
      specializations:sp(g("التخصص","Specialization")), skills:sp(g("المهارات","Skills")), };
  };

  const toggleSave = (i) => setAnalyzed(p => p.map((r,j)=>j===i?{...r,save:!r.save}:r));
  const updateType = (i, t) => setAnalyzed(p => p.map((r,j)=>j===i?{...r,fileType:t}:r));
  const updatePType = (i, t) => setAnalyzed(p => p.map((r,j)=>j===i?{...r,personType:t}:r));

  const groups = {};
  analyzed.forEach((r,i) => {
    const key = r.personName?.trim() || `__${i}`;
    if (!groups[key]) groups[key] = [];
    groups[key].push({ ...r, _idx:i });
  });

  return (
    <div className="card-g" style={{ marginBottom:18 }}>
      {toastEl}
      <div className="sec">📂 رفع ملفات ذكي — تحليل تلقائي بالذكاء الاصطناعي</div>

      {/* Step 1 — Drop zone */}
      {step === 1 && (
        <div>
          <div onClick={()=>fileRef.current?.click()}
            onDragOver={e=>e.preventDefault()} onDrop={e=>{ e.preventDefault(); addFiles(e.dataTransfer.files); }}
            style={{ border:"2px dashed var(--b)", borderRadius:12, padding:"16px 14px", textAlign:"center", cursor:"pointer",
              transition:"border .2s", background:"rgba(255,255,255,.02)" }}
            onMouseEnter={e=>e.currentTarget.style.borderColor="rgba(201,168,76,.5)"}
            onMouseLeave={e=>e.currentTarget.style.borderColor="var(--b)"}>
            <input ref={fileRef} type="file" multiple style={{ display:"none" }}
              accept=".pdf,.jpg,.jpeg,.png,.txt,.xlsx,.xls,.csv,.doc,.docx,.rtf"
              onChange={e=>addFiles(e.target.files)} />
            <p style={{ fontSize:24, marginBottom:4 }}>📂</p>
            <p style={{ color:"var(--text2)", fontWeight:700, marginBottom:2, fontSize:13 }}>اسحب الملفات أو اضغط للرفع</p>
            <p style={{ fontSize:10, color:"var(--text3)" }}>PDF · صور · Word · TXT · Excel — سير ذاتية، شهادات، بروفايلات</p>
          </div>

          {files.length > 0 && (
            <div style={{ marginTop:12 }}>
              <div style={{ background:"var(--glass)", borderRadius:9, padding:"10px 12px", marginBottom:12 }}>
                {files.map((f,i) => (
                  <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"3px 0", fontSize:12 }}>
                    <span style={{ color:"var(--text2)" }}>📄 {f.name} <span style={{ color:"var(--text3)" }}>({(f.size/1024).toFixed(0)} KB)</span></span>
                    <button onClick={()=>setFiles(p=>p.filter((_,j)=>j!==i))} style={{ background:"none", border:"none", cursor:"pointer", color:"var(--text3)", fontSize:14 }}>✕</button>
                  </div>
                ))}
              </div>
              {/* personType override — prominent */}
              <div style={{ marginBottom:12, background:"rgba(201,168,76,.06)", border:"1px solid rgba(201,168,76,.2)", borderRadius:10, padding:"12px 14px" }}>
                <p style={{ fontSize:13, color:"var(--gold)", marginBottom:10, fontWeight:800 }}>
                  📋 هذه الملفات تخص:
                </p>
                <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                  {[
                    { v:"auto",      l:"🤖 تحديد تلقائي", d:"الذكاء الاصطناعي يحدد" },
                    { v:"candidate", l:"👤 مرشح واحد",     d:"ملفات لشخص واحد" },
                    { v:"candidates",l:"👥 مجموعة مرشحين", d:"ملفات لأكثر من شخص" },
                    { v:"employee",  l:"👨‍💼 موظف واحد",     d:"موظف حالي" },
                    { v:"employees", l:"👥 مجموعة موظفين",  d:"موظفون متعددون" },
                  ].map(o => (
                    <button key={o.v} onClick={()=>setOverrideType(o.v)}
                      style={{ padding:"8px 14px", borderRadius:10, cursor:"pointer", fontFamily:"inherit",
                        fontSize:12, fontWeight:700, textAlign:"right",
                        background:overrideType===o.v?"rgba(201,168,76,.2)":"rgba(255,255,255,.03)",
                        border:"2px solid "+(overrideType===o.v?"rgba(201,168,76,.6)":"rgba(255,255,255,.08)"),
                        color:overrideType===o.v?"var(--gold)":"var(--text3)" }}>
                      <div>{o.l}</div>
                      <div style={{ fontSize:10, opacity:.7, marginTop:2 }}>{o.d}</div>
                    </button>
                  ))}
                </div>
              </div>
              <button onClick={analyze} className="btn btn-gold" style={{ width:"100%" }}>
                🤖 تحليل {files.length} ملف تلقائياً
              </button>
            </div>
          )}
        </div>
      )}

      {/* Step 2 — Analyzing */}
      {step === 2 && (
        <div style={{ padding:"24px 0" }}>
          <div style={{ display:"flex", justifyContent:"space-between", marginBottom:8 }}>
            <p style={{ color:"var(--gold)", fontWeight:700, fontSize:14 }}>🤖 جاري التحليل بالذكاء الاصطناعي...</p>
            <p style={S.txt3s12}>
                  {progress.split("/").length > 1 ? progress.split("/")[0].split(" ").pop() + " من " + progress.split("/")[1].split(" ")[0] : ""}
            </p>
          </div>
          {/* Progress bar */}
          {progress.includes("/") && (() => {
            const parts = progress.split("/");
            const done = parseInt(parts[0].split(" ").pop()) || 0;
            const total = parseInt(parts[1].split(" ")[0]) || 1;
            const pct = Math.round(done/total*100);
            return (
              <div style={{ height:6, background:"rgba(255,255,255,.08)", borderRadius:4, marginBottom:12, overflow:"hidden" }}>
                <div style={{ height:"100%", width:pct+"%", background:"var(--gold)", borderRadius:4, transition:"width .3s" }} />
              </div>
            );
          })()}
          <p style={{ color:"var(--text3)", fontSize:12, marginBottom:16 }}>{progress.replace(/\d+[/]\d+ [—] /,"")}</p>
          <div style={S.flexWrap6}>
            {files.map((f,i) => {
              const fname = progress.includes(f.name);
              return (
                <span key={i} style={{ fontSize:11, padding:"3px 10px", borderRadius:8,
                  background:fname?"rgba(201,168,76,.12)":"rgba(255,255,255,.04)",
                  border:"1px solid "+(fname?"rgba(201,168,76,.4)":"var(--b)"),
                  color:fname?"var(--gold)":"var(--text3)" }}>
                  {fname?"🔍 ":""}{f.name.length>22?f.name.slice(0,22)+"...":f.name}
                </span>
              );
            })}
          </div>
        </div>
      )}

      {/* Step 3 — Review */}
      {step === 3 && (
        <div>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14, flexWrap:"wrap", gap:8 }}>
            <div>
              <p style={{ fontWeight:700, color:"var(--text)", marginBottom:3 }}>نتيجة التحليل — {analyzed.length} ملف</p>
              <p style={S.txt3s12}>راجع التصنيف وعدّل إذا لزم ثم احفظ</p>
            </div>
            <div style={S.flex8}>
              <button onClick={()=>{setFiles([]); setAnalyzed([]); setStep(1);}} className="btn btn-ghost btn-sm">إعادة</button>
              <button onClick={saveAll} className="btn btn-gold"
                disabled={!analyzed.some(r=>r.save)}>
                💾 حفظ {analyzed.filter(r=>r.save).length} ملف
              </button>
            </div>
          </div>

          {/* Grouped by person */}
          {Object.entries(groups).map(([person, items]) => (
            <div key={person} style={{ marginBottom:16 }}>
              {person && !person.startsWith("__") && (
                <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                  <div style={{ width:32, height:32, borderRadius:"50%", background:"linear-gradient(135deg,#c9a84c,#a8893a)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:900, color:"#0b0f1a" }}>
                    {person.split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase()}
                  </div>
                  <div>
                    <p style={{ fontWeight:900, fontSize:14, color:"var(--text)" }}>{person}</p>
                    {items[0].existing ? (
                      <div>
                        <p style={{ fontSize:11, color:"#f59e0b", fontWeight:700 }}>⚠️ موجود مسبقاً — {items[0].existing.fullName}</p>
                        <div style={{ display:"flex", gap:6, marginTop:4 }}>
                          <button onClick={()=>{
                            const updated = analyzed.map(r => items.find(x=>x._idx===r._idx) ? {...r, save:false} : r);
                            setAnalyzed(updated);
                          }} style={{ fontSize:10, padding:"2px 8px", borderRadius:6, border:"1px solid rgba(239,68,68,.4)", background:"rgba(239,68,68,.1)", color:"#f87171", cursor:"pointer", fontFamily:"inherit" }}>
                            🚫 تجاهل
                          </button>
                          <button onClick={()=>{
                            const updated = analyzed.map(r => items.find(x=>x._idx===r._idx) ? {...r, save:true} : r);
                            setAnalyzed(updated);
                          }} style={{ fontSize:10, padding:"2px 8px", borderRadius:6, border:"1px solid rgba(34,197,94,.4)", background:"rgba(34,197,94,.1)", color:"#4ade80", cursor:"pointer", fontFamily:"inherit" }}>
                            🔄 دمج وتحديث
                          </button>
                        </div>
                      </div>
                    ) : (
                      <p style={{ fontSize:11, color:"#4ade80" }}>🆕 مرشح/موظف جديد</p>
                    )}
                  </div>
                  {items.length > 1 && (
                    <span style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:"rgba(201,168,76,.1)", color:"var(--gold)", border:"1px solid rgba(201,168,76,.2)" }}>
                      {items.length} ملفات
                    </span>
                  )}
                </div>
              )}

              {items.map(r => {
                const ft = FILE_TYPES[r.fileType] || FILE_TYPES.unknown;
                return (
                  <div key={r._idx} style={{ marginBottom:8, padding:"12px 14px", background:"var(--glass)",
                    border:"1px solid "+(r.save?"rgba(201,168,76,.2)":"var(--b)"), borderRadius:10,
                    borderRight:"3px solid "+(r.save?ft.color:"var(--b)"), opacity:r.save?1:0.5 }}>
                    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:8 }}>
                      <div style={{ flex:1 }}>
                        <div style={{ display:"flex", gap:7, alignItems:"center", marginBottom:5, flexWrap:"wrap" }}>
                          <span style={{ fontSize:14 }}>{ft.icon}</span>
                          <span style={{ fontSize:12, fontWeight:700, color:ft.color, padding:"2px 9px", borderRadius:8,
                            background:ft.color+"15", border:"1px solid "+ft.color+"30" }}>{ft.label}</span>
                          {r.language && r.language!=="unknown" && (
                            <span style={{ fontSize:11, color:"var(--text3)", padding:"1px 7px", borderRadius:8, background:"rgba(255,255,255,.05)" }}>
                              {r.language==="ar"?"🇸🇦 عربية":r.language==="en"?"🇺🇸 إنجليزية":"🌐 ثنائية"}
                            </span>
                          )}
                          <span style={S.txt3s11}>{r.name}</span>
                        </div>
                        {r.summary && <p style={{ fontSize:12, color:"var(--text2)", lineHeight:1.7, marginBottom:6 }}>{r.summary}</p>}
                        {r.error && <p style={{ fontSize:12, color:"#f87171" }}>❌ {r.error}</p>}

                        {/* Correct file type */}
                        <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginTop:4 }}>
                          {Object.entries(FILE_TYPES).filter(([k])=>k!=="unknown").map(([k,v])=>(
                            <button key={k} onClick={()=>updateType(r._idx,k)}
                              style={{ padding:"2px 8px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:10, fontWeight:700,
                                background:r.fileType===k?v.color+"22":"none", border:"1px solid "+(r.fileType===k?v.color:"var(--b)"),
                                color:r.fileType===k?v.color:"var(--text3)" }}>
                              {v.icon} {v.label}
                            </button>
                          ))}
                          <span style={{ fontSize:10, color:"var(--text3)", alignSelf:"center", marginRight:4 }}>|</span>
                          {["candidate","employee"].map(pt=>(
                            <button key={pt} onClick={()=>updatePType(r._idx,pt)}
                              style={{ padding:"2px 8px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:10, fontWeight:700,
                                background:r.personType===pt?"rgba(96,165,250,.2)":"none",
                                border:"1px solid "+(r.personType===pt?"#60a5fa":"var(--b)"),
                                color:r.personType===pt?"#60a5fa":"var(--text3)" }}>
                              {pt==="candidate"?"👤 مرشح":"👨‍💼 موظف"}
                            </button>
                          ))}
                        </div>
                      </div>

                      {/* Toggle save */}
                      <button onClick={()=>toggleSave(r._idx)}
                        style={{ padding:"4px 10px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:11, fontWeight:700, flexShrink:0,
                          background:r.save?"rgba(34,197,94,.1)":"rgba(239,68,68,.1)",
                          border:"1px solid "+(r.save?"rgba(34,197,94,.3)":"rgba(239,68,68,.3)"),
                          color:r.save?"#4ade80":"#f87171" }}>
                        {r.save?"✅ يُحفظ":"⏭️ تجاوز"}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      )}

      {/* Step 4 — Saving */}
      {step === 4 && (
        <div>
          {saving ? (
            <div style={{ textAlign:"center", padding:"32px 0" }}>
              <div className="loader" style={{ margin:"0 auto 16px" }} />
              <p style={{ color:"var(--accent)", fontWeight:700 }}>جاري الحفظ...</p>
              <p style={S.txt3s12}>{progress}</p>
            </div>
          ) : saveReport ? (
            <div>
              <p style={{ fontWeight:700, color:"#4ade80", marginBottom:16, fontSize:16 }}>✅ اكتمل الحفظ</p>
              <div className="g2" style={{ marginBottom:16 }}>
                <div style={{ padding:"14px 16px", background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.2)", borderRadius:12, textAlign:"center" }}>
                  <p style={{ fontSize:28, fontWeight:900, color:"#4ade80" }}>{saveReport.newAdded}</p>
                  <p style={{ fontSize:12, color:"var(--text2)" }}>مرشح جديد أُضيف</p>
                </div>
                <div style={{ padding:"14px 16px", background:"rgba(59,130,246,.08)", border:"1px solid rgba(59,130,246,.2)", borderRadius:12, textAlign:"center" }}>
                  <p style={{ fontSize:28, fontWeight:900, color:"#60a5fa" }}>{saveReport.updated}</p>
                  <p style={{ fontSize:12, color:"var(--text2)" }}>ملف موجود حُدِّث</p>
                </div>
              </div>
              {saveReport.skipped > 0 && (
                <div style={{ padding:"12px 14px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.2)", borderRadius:12, marginBottom:12 }}>
                  <p style={{ fontSize:13, color:"#f87171", fontWeight:700, marginBottom:8 }}>
                    ⚠️ {saveReport.skipped} ملف تم تجاهله
                  </p>
                  <div style={{ display:"flex", flexDirection:"column", gap:4 }}>
                    {saveReport.skippedFiles.map((f,i)=>(
                      <div key={i} style={{ display:"flex", justifyContent:"space-between", fontSize:12 }}>
                        <span style={{ color:"var(--text2)" }}>📄 {f.name}</span>
                        <span style={{ color:"var(--text3)" }}>{f.existing?"موجود مسبقاً":f.error?"خطأ في القراءة":"مُتجاهَل"}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
              <button onClick={()=>{setFiles([]); setAnalyzed([]); setStep(1); setSaveReport(null); setProgress(""); if(onDone) onDone();}}
                className="btn btn-gold" style={{ width:"100%" }}>
                إغلاق ✓
              </button>
            </div>
          ) : null}
        </div>
      )}
    </div>
  );
}

function CandHeaderJobs({ onJobs, onShare }) {
  const [jobs, setJobs] = useState([]);
  useEffect(() => {
    getAllJobs().then(j => setJobs((j||[]).filter(x=>x.status==="مفتوحة"))).catch(()=>{});
  }, []);

  const fullTime = jobs.filter(j => !j.jobType || j.jobType === "دوام كامل").slice(0,2);
  const partTime = jobs.filter(j => j.jobType === "دوام جزئي" || j.jobType === "عقد مرن" || j.jobType === "بارت تايم").slice(0,2);

  const shareJobs = () => {
    const url = "https://hma.engineer";
    if(navigator.share){ navigator.share({ title:"📢 تصفّح الوظائف المتاحة", text:"نظام كوادر HMA – بوابة التوظيف والتدريب\n🔗 "+url }).catch(()=>{}); }
    else { navigator.clipboard?.writeText(url); }
  };

  if (!jobs.length) return (
    <p style={{ fontSize:12, color:"var(--text3)", textAlign:"center", padding:"16px 0" }}>لا توجد وظائف متاحة حالياً — تابع التحديثات</p>
  );

  const JobRow = ({j}) => (
    <div style={{ padding:"6px 8px", background:"rgba(255,255,255,.03)", borderRadius:7, border:"1px solid var(--b)", marginBottom:5 }}>
      <p style={{ fontWeight:700, fontSize:12, color:"var(--text)" }}>{j.title}</p>
      <p style={{ fontSize:10, color:"var(--text3)" }}>
        {[j.city, j.minExperience ? j.minExperience+" سنوات" : null].filter(Boolean).join(" · ")}
      </p>
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:0 }}>

      {/* ── قسم 1: إعلانات الوظائف ── */}
      <div style={{ marginBottom:10 }}>
        <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
          <span style={{ fontSize:13 }}>🏢</span>
          <span style={{ fontSize:12, fontWeight:900, color:"var(--text)" }}>إعلانات الوظائف</span>
          {fullTime.length > 0 && <span style={{ fontSize:10, padding:"1px 7px", borderRadius:8, background:"rgba(201,168,76,.12)", color:"var(--gold)", border:"1px solid rgba(201,168,76,.25)" }}>{fullTime.length}</span>}
        </div>
        {fullTime.length > 0
          ? fullTime.map(j => <JobRow key={j.id} j={j} />)
          : <p style={{ fontSize:11, color:"var(--text3)", padding:"8px 0" }}>لا توجد وظائف دوام كامل حالياً</p>
        }
      </div>

      {/* ── فاصل ── */}
      <div style={{ borderTop:"1px solid var(--b)", margin:"4px 0 10px" }} />

      {/* ── قسم 2: بارت تايم / عقد مرن ── */}
      <div style={{ marginBottom:10 }}>
        <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
          <span style={{ fontSize:13 }}>⏰</span>
          <span style={{ fontSize:12, fontWeight:900, color:"var(--text)" }}>عقد عمل مرن / بارت تايم</span>
          {partTime.length > 0 && <span style={{ fontSize:10, padding:"1px 7px", borderRadius:8, background:"rgba(96,165,250,.12)", color:"#60a5fa", border:"1px solid rgba(96,165,250,.25)" }}>{partTime.length}</span>}
        </div>
        {partTime.length > 0
          ? partTime.map(j => <JobRow key={j.id} j={j} />)
          : <p style={{ fontSize:11, color:"var(--text3)", padding:"8px 0" }}>لا توجد وظائف مرنة حالياً</p>
        }
      </div>

      {/* ── مشاركة + مزيد ── */}
      <div style={{ display:"flex", gap:6, paddingTop:6, borderTop:"1px solid var(--b)" }}>
        <button onClick={onShare} className="btn btn-ghost btn-sm" style={{ flex:1, fontSize:11 }}>🔗 مشاركة رابط الوظائف</button>
        {onJobs && <button onClick={onJobs} className="btn btn-ghost btn-sm" style={{ flex:1, fontSize:11, color:"#4ade80", border:"1px solid rgba(34,197,94,.3)" }}>مزيد من الإعلانات ←</button>}
      </div>
    </div>
  );
}

// ── GlobalSearch — searches all sections ─────────────────────────────────────
function GlobalSearch({ cands, emps, onSelectCand, onSelectEmp, globalSearch, setGlobalSearch, setSec }) {
  const [results, setResults] = useState([]);
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    if (!globalSearch.trim()) { setResults([]); setOpen(false); return; }
    const q = globalSearch.toLowerCase();

    const candResults = cands
      .filter(c => [c.fullName,c.email,c.phone,c.lastJob,c.lastCompany,c.city,...(c.specializations||[]),...(c.skills||[])].join(" ").toLowerCase().includes(q))
      .slice(0,5)
      .map(c => ({ type:"candidate", icon:"👤", label:c.fullName, sub:(c.specializations||[])[0]||c.lastJob||"", data:c }));

    const empResults = emps
      .filter(e => [e.fullName,e.email,e.phone,e.department,e.lastJob,...(e.specializations||[])].join(" ").toLowerCase().includes(q))
      .slice(0,3)
      .map(e => ({ type:"employee", icon:"👨‍💼", label:e.fullName, sub:e.department||e.lastJob||"", data:e }));

    setResults([...candResults, ...empResults]);
    setOpen(true);
  }, [globalSearch, cands, emps]);

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <div ref={ref} style={{ position:"relative", marginBottom:16 }}>
      <div style={{ position:"relative" }}>
        <span style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", color:"var(--text3)", fontSize:16 }}>🔍</span>
        <input
          value={globalSearch}
          onChange={e=>setGlobalSearch(e.target.value)}
          onFocus={()=>results.length&&setOpen(true)}
          placeholder="بحث شامل — مرشحين، موظفين، تصنيفات..."
          style={{ paddingRight:38, paddingLeft:40, width:"100%", fontSize:14, background:"rgba(255,255,255,.06)", border:"1px solid "+(globalSearch?"rgba(201,168,76,.4)":"var(--b)"), borderRadius:10, transition:"border .2s" }}
        />
        {globalSearch && (
          <button onClick={()=>{setGlobalSearch(""); setOpen(false);}}
            style={{ position:"absolute", left:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", cursor:"pointer", color:"var(--text3)", fontSize:16, lineHeight:1 }}>✕</button>
        )}
      </div>
      {open && results.length > 0 && (
        <div style={{ position:"absolute", top:"calc(100% + 6px)", right:0, left:0, background:"var(--dark2)", border:"1px solid rgba(201,168,76,.25)", borderRadius:12, zIndex:300, boxShadow:"0 8px 32px rgba(0,0,0,.5)", overflow:"hidden" }}>
          {results.length === 0 ? (
            <p style={{ padding:"14px 16px", color:"var(--text3)", fontSize:13 }}>لا توجد نتائج</p>
          ) : (
            <div>
              {results.map((r,i) => (
                <div key={i} onClick={()=>{
                  setGlobalSearch(""); setOpen(false);
                  if (r.type==="candidate") { setSec("candidates"); onSelectCand(r.data); }
                  else { setSec("employees"); onSelectEmp(r.data); }
                }}
                  style={{ display:"flex", alignItems:"center", gap:10, padding:"10px 16px", cursor:"pointer", borderBottom:"1px solid var(--b)", transition:"background .1s" }}
                  onMouseEnter={e=>e.currentTarget.style.background="rgba(201,168,76,.07)"}
                  onMouseLeave={e=>e.currentTarget.style.background=""}>
                  <span style={{ fontSize:20, flexShrink:0 }}>{r.icon}</span>
                  <div style={{ flex:1, minWidth:0 }}>
                    <p style={{ fontWeight:700, fontSize:13, color:"var(--text)", marginBottom:1 }}>{r.label}</p>
                    <p style={S.txt3s11}>{r.type==="candidate"?"مرشح":"موظف"}{r.sub?" — "+r.sub:""}</p>
                  </div>
                  <span style={{ fontSize:10, padding:"2px 8px", borderRadius:8, background:r.type==="candidate"?"rgba(96,165,250,.1)":"rgba(167,139,250,.1)", color:r.type==="candidate"?"#93c5fd":"#c4b5fd" }}>
                    {r.type==="candidate"?"👤 مرشح":"👨‍💼 موظف"}
                  </span>
                </div>
              ))}
              <div style={{ padding:"8px 16px", fontSize:11, color:"var(--text3)", textAlign:"center" }}>
                {results.length} نتيجة — اضغط للانتقال
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── CandPortalLoader — loads candidate data from storage by linkedId or email ─

// ── Duplicate check helper ─────────────────────────────────────────────────────
// ── PeriodicEvalForm — نموذج التقييم الدوري بالـ KPI المعتمد ──────────────────
function PeriodicEvalForm({ target, evaluatorName, onSubmit, onClose }) {
  const DEFAULT_KPI = [
    { id:"quality",    label:"جودة العمل",           icon:"✅", weight:25 },
    { id:"attendance", label:"الحضور والانضباط",     icon:"🕐", weight:20 },
    { id:"teamwork",   label:"التعاون وروح الفريق",  icon:"🤝", weight:20 },
    { id:"initiative", label:"المبادرة والإنجاز",    icon:"💡", weight:20 },
    { id:"leadership", label:"القيادة وحل المشكلات", icon:"🎯", weight:15 },
  ];

  const [kpiList, setKpiList] = useState([]);
  const [scores, setScores]   = useState({});
  const [notes, setNotes]     = useState("");
  const [saving, setSaving]   = useState(false);
  const { show, toastEl }     = useToast();
  const oC = v => v>=80?"#4ade80":v>=60?"#fbbf24":"#f87171";

  useEffect(() => {
    // بناء قائمة KPI من الإعدادات المعتمدة
    const fullCfg = window._kpiFullConfig || null;
    let list = [...DEFAULT_KPI];
    if (fullCfg) {
      const dept = target?.department || "";
      const global = (fullCfg.global||[]).filter(k => k.type==="manual" || !k.type);
      const deptK  = fullCfg.departments?.[dept] || fullCfg.departments?._default || [];
      const merged = [...global, ...deptK].filter(k=>k.id&&k.label);
      if (merged.length) list = merged.slice(0,8);
    }
    setKpiList(list);
    const init = {};
    list.forEach(k => { init[k.id] = 70; });
    setScores(init);
  }, [target]);

  const totalWeight = kpiList.reduce((s,k)=>s+(k.weight||20),0)||100;
  const total = Math.round(
    kpiList.reduce((s,k)=>s+(scores[k.id]||0)*((k.weight||20)/totalWeight),0)
  );

  const submit = async () => {
    setSaving(true);
    try { await onSubmit({ kpiScores:scores, kpiList, totalScore:total, notes:notes.trim() }); }
    catch { show("❌ خطأ في الحفظ"); }
    setSaving(false);
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:12, overflowY:"auto" }}
      onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:22, width:"100%", maxWidth:500, maxHeight:"92vh", overflowY:"auto" }}>
        {toastEl}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div>
            <h3 style={{ color:"var(--gold)", fontWeight:900, fontSize:15, margin:0 }}>⭐ تقييم أسبوعي</h3>
            <p style={{ fontSize:11, color:"var(--text3)", margin:"2px 0 0" }}>{target?.fullName} — {target?.type==="manager"?"مدير / مشرف":"موظف"}</p>
          </div>
          <button onClick={onClose} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>

        {kpiList.map(k => (
          <div key={k.id} style={{ marginBottom:14 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:4 }}>
              <span style={{ fontSize:12, fontWeight:700 }}>{k.icon||"📊"} {k.label}</span>
              <span style={{ fontSize:16, fontWeight:900, color:oC(scores[k.id]||0) }}>{scores[k.id]||0}<span style={{ fontSize:10, color:"var(--text3)" }}>/100</span></span>
            </div>
            <input type="range" min={0} max={100} step={5} value={scores[k.id]||0}
              onChange={e=>setScores(p=>({...p,[k.id]:+e.target.value}))}
              style={{ width:"100%", accentColor:oC(scores[k.id]||0) }} />
            <div style={{ display:"flex", justifyContent:"space-between", fontSize:9, color:"var(--text3)", marginTop:1 }}>
              <span>ضعيف</span><span>مقبول</span><span>جيد</span><span>ممتاز</span>
            </div>
          </div>
        ))}

        <div style={{ textAlign:"center", padding:"10px 0 14px", borderTop:"1px solid var(--b)", marginBottom:12 }}>
          <p style={{ fontSize:11, color:"var(--text3)", margin:"0 0 4px" }}>الدرجة الإجمالية المرجّحة</p>
          <p style={{ fontSize:28, fontWeight:900, color:oC(total), margin:0 }}>{total}<span style={{ fontSize:13, color:"var(--text3)" }}>/100</span></p>
        </div>

        <textarea value={notes} onChange={e=>setNotes(e.target.value)} rows={2}
          placeholder="ملاحظات (اختياري)..." style={{ width:"100%", marginBottom:12, resize:"vertical", boxSizing:"border-box" }} />

        <button onClick={submit} disabled={saving} className="btn btn-gold" style={{ width:"100%", padding:"12px", fontSize:14 }}>
          {saving?"⏳ جاري الإرسال...":"✅ إرسال التقييم الأسبوعي"}
        </button>
      </div>
    </div>
  );
}
function CandPortalLoader({ currentUser, isEmployee: isEmployeeProp, onBack, onJobs, libs, specsMap, initLang="ar", onLangChange }) {
  const isEmployee = isEmployeeProp || currentUser?.role === "employee";
  const [init, setInit] = useState(null);
  const [loading, setLoading] = useState(true);
  const [onboarding, setOnboarding] = useState(null); // null | "terms" | "screening" | "kpi_exam" | "done"
  const [kpiExamQs, setKpiExamQs] = useState([]);
  const [kpiExamAnswers, setKpiExamAnswers] = useState({});
  const [kpiExamSubmitting, setKpiExamSubmitting] = useState(false);
  const [screeningQs, setScreeningQs] = useState([]);
  const [answers, setAnswers] = useState({}); // qId -> true/false
  const [termsAccepted, setTermsAccepted] = useState(false);
  const { show, toastEl } = useToast();
  const screeningDoneRef = useRef(false);

  useEffect(() => {
    const load = async () => {
      let cand = null;

      // للموظف: ابحث في سجلات الموظفين أولاً
      if (isEmployee) {
        const emps = await getAllEmployees();
        const emp = emps.find(e =>
          (currentUser.linkedId && (e.uid === currentUser.linkedId || e.idNumber === currentUser.linkedId)) ||
          (currentUser.email && e.email && e.email.toLowerCase() === currentUser.email.toLowerCase()) ||
          (currentUser.username && (e.username === currentUser.username || e.idNumber === currentUser.username))
        );
        if (emp) cand = emp;
      }

      // إذا لم يُوجد — ابحث في المرشحين
      if (!cand) {
        if (currentUser.linkedId) cand = await db.get("c:" + currentUser.linkedId);
        if (!cand && currentUser.email) {
          const all = await getAllCandidates();
          cand = all.find(c => c.email && c.email.toLowerCase() === currentUser.email.toLowerCase()) || null;
        }
        if (!cand && currentUser.username) {
          const all = await getAllCandidates();
          cand = all.find(c => c.username === currentUser.username) || null;
        }
      }
      const candData = cand || { email: currentUser.email || "", username: currentUser.username };
      setInit(candData);

      // Skip onboarding if already completed in this session or if employee
      if (screeningDoneRef.current || isEmployee) { setLoading(false); return; }

      // Check if onboarding needed
      const pid = candData.uid || candData.email || currentUser.email;
      const existingAnswers = await getScreeningAnswers(pid);
      const sqs = await getAllScreeningQuestions();

      // Check for "forNewUsers" cycles not yet assigned to this user
      const cycleIdx = (await db.get("screening_cycle:idx")) || [];
      const assignedCycles = existingAnswers?.pendingCycles || [];
      const completedCycleIds = existingAnswers?.completedCycleIds || [];
      const allAssigned = new Set([...assignedCycles, ...completedCycleIds]);
      let addedNewUserCycles = false;
      for (const cid of cycleIdx) {
        if (allAssigned.has(cid)) continue;
        const cycle = await db.get("screening_cycle:" + cid).catch(()=>null);
        if (cycle && cycle.forNewUsers) {
          assignedCycles.push(cid);
          addedNewUserCycles = true;
        }
      }
      if (addedNewUserCycles) {
        await db.set("screening:" + pid, { ...(existingAnswers||{}), answers: existingAnswers?.answers || {}, pendingCycles: assignedCycles });
      }

      if (!existingAnswers && !existingAnswers?.completedAt) {
        // First time ever — show terms
        setScreeningQs(sqs);
        setOnboarding("terms");
      } else {
        // Check for pending cycles (sent by admin)
        const pendingCycles = existingAnswers?.pendingCycles || [];
        if (pendingCycles.length > 0) {
          // Load questions from pending cycles
          const cycleQIds = new Set();
          for (const cid of pendingCycles) {
            const cycle = await db.get("screening_cycle:" + cid).catch(()=>null);
            if (cycle) (cycle.questionIds||[]).forEach(qid => cycleQIds.add(qid));
          }
          const allQs = await getAllQuestions();
          const pendingQs = allQs.filter(q => cycleQIds.has(q.id) && existingAnswers?.answers?.[q.id] === undefined);
          if (pendingQs.length > 0) {
            setScreeningQs(pendingQs);
            setOnboarding("screening");
          }
        } else if (sqs.length > 0 && existingAnswers) {
          // Fallback: check for unanswered screening questions
          const answeredIds = new Set(Object.keys(existingAnswers.answers || {}));
          const unanswered = sqs.filter(q => !answeredIds.has(q.id));
          if (unanswered.length > 0) {
            setScreeningQs(unanswered);
            setOnboarding("screening");
          }
        }
      }
      setLoading(false);
    };
    load();
  }, [currentUser]);

  const acceptTerms = () => {
    if (!termsAccepted) { show("⚠️ يجب الموافقة على الشروط للمتابعة"); return; }
    if (screeningQs.length > 0) { setOnboarding("screening"); }
    else { screeningDoneRef.current = true; setOnboarding("done"); }
    // Check for pending KPI exam (monthly)
    if (isEmployee) {
      const month = new Date().toISOString().slice(0,7); // YYYY-MM
      const empId = c.uid || c.idNumber || c.email;
      getKPIExamResult(empId, month).then(r => {
        if (!r) {
          db.get("kpi_exam:active_month").then(active => {
            if (active && active.month === month && active.questionIds?.length) {
              Promise.all(active.questionIds.map(id => db.get("qn:"+id))).then(qs => {
                const valid = qs.filter(Boolean);
                if (valid.length > 0) { setKpiExamQs(valid); setOnboarding("kpi_exam"); }
              }).catch(()=>{});
            }
          }).catch(()=>{});
        }
      }).catch(()=>{});
    }
  };

  const submitScreening = async () => {
    const pid = init.uid || init.email || currentUser.email;
    const existingData = await getScreeningAnswers(pid);
    const existingAnswers = existingData?.answers || {};
    // Merge new answers with existing
    const mergedAnswers = { ...existingAnswers, ...answers };
    // Track completed cycle IDs so forNewUsers cycles don't re-appear
    const completedCycleIds = [...(existingData?.completedCycleIds || []), ...(existingData?.pendingCycles || [])];
    // Clear pending cycles
    await db.set("screening:" + pid, { answers: mergedAnswers, pendingCycles: [], completedCycleIds, completedAt: new Date().toISOString() });

    // Update stats.answered on each completed cycle
    for (const cid of (existingData?.pendingCycles || [])) {
      try {
        const cycle = await db.get("screening_cycle:" + cid);
        if (cycle && cycle.stats) {
          cycle.stats.answered = (cycle.stats.answered || 0) + 1;
          await db.set("screening_cycle:" + cid, cycle);
        }
      } catch(e) { console.warn("Failed to update cycle stats:", e); }
    }

    // Remove old screening tags, then apply new ones
    const existingTags = (init.biCert || []).filter(t => t.source !== "screening");
    const newTags = [];

    for (const q of screeningQs) {
      const ans = answers[q.id];
      if (ans === undefined) continue;
      if (q.type === "tf" && ans === true && q.tagLabel) {
        // TF: "yes" → add tagLabel
        const tag = q.tagLabel.trim();
        if (tag && !newTags.some(t => t.ar === tag)) {
          newTags.push({ ar: tag, en: "", approved: true, source: "screening" });
        }
      } else if (q.type === "mcq" && typeof ans === "number") {
        // MCQ: selected option index → get optionTag
        const optTag = (q.optionTags || [])[ans]?.trim();
        if (optTag && !newTags.some(t => t.ar === optTag)) {
          newTags.push({ ar: optTag, en: "", approved: true, source: "screening" });
        }
      }
    }

    // Also keep tags from previously answered screening questions (not in current batch)
    const allQs = await getAllQuestions();
    for (const [qid, ans] of Object.entries(mergedAnswers)) {
      if (answers[qid] !== undefined) continue; // Already handled above
      const q = allQs.find(x => x.id === qid);
      if (!q || !q.isScreening) continue;
      if (q.type === "tf" && ans === true && q.tagLabel) {
        const tag = q.tagLabel.trim();
        if (tag && !newTags.some(t => t.ar === tag)) {
          newTags.push({ ar: tag, en: "", approved: true, source: "screening" });
        }
      } else if (q.type === "mcq" && typeof ans === "number") {
        const optTag = (q.optionTags || [])[ans]?.trim();
        if (optTag && !newTags.some(t => t.ar === optTag)) {
          newTags.push({ ar: optTag, en: "", approved: true, source: "screening" });
        }
      }
    }

    const updated = { ...init, biCert: [...existingTags, ...newTags], activated: true };
    await saveCandidate(updated);
    setInit(updated);

    // Log to events
    addPersonEvent(pid, {
      type: "screening_answer",
      text: "أجاب على " + screeningQs.length + " سؤال ترشيح",
      by: init.fullName || "المستخدم",
      byRole: "candidate", private: false
    }).catch(()=>{});

    screeningDoneRef.current = true;
    setOnboarding("done");
  };

  if (loading) return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", minHeight:"100vh", flexDirection:"column", gap:12 }}>
      <div className="loader" style={{ width:36, height:36 }} />
      <p style={S.txt3s13}>جاري تحميل بياناتك...</p>
    </div>
  );

  // ── Terms Screen ──────────────────────────────────────────────────────────
  if (onboarding === "terms") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", padding:20, background:"var(--dark)" }}>
      {toastEl}
      <div style={{ background:"var(--card-bg)", border:"1px solid var(--b)", borderRadius:18, padding:28, width:"100%", maxWidth:560 }}>
        <div style={{ textAlign:"center", marginBottom:20 }}>
          <img src={HMA_LOGO_SM} alt="HMA" style={{ width:56, height:56, objectFit:"contain", marginBottom:8 }} />
          <h2 style={{ color:"var(--accent)", fontWeight:900, fontSize:18, marginBottom:4, lineHeight:1.4 }}>حساب المستخدم</h2>
          <p style={{ color:"var(--text3)", fontSize:11 }}>مكتب هاني محمد عسيري للاستشارات الهندسية</p>
        </div>
        <div style={{ background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:12, padding:16, marginBottom:18 }}>
          <p style={{ fontSize:13, color:"var(--text)", lineHeight:2, marginBottom:12 }}>
            <strong>١.</strong> تقوم إدارة الموارد البشرية بصفة مستمرة بتعبئة البيانات المرسلة من قبل المتقدمين عن طريق البريد الإلكتروني أو بالوسائل الأخرى. إذا كانت بياناتك مسجلة سابقاً نأمل منك مراجعتها بعناية وتأكيد صحة البيانات.
          </p>
          <p style={{ fontSize:13, color:"var(--text)", lineHeight:2 }}>
            <strong>٢.</strong> أوافق على أن يقوم المكتب بمراجعة وتدقيق صحة البيانات من الجهات الرسمية.
          </p>
        </div>
        <label style={{ display:"flex", alignItems:"flex-start", gap:10, cursor:"pointer", padding:"12px 14px", background: termsAccepted?"rgba(0,113,227,.08)":"rgba(255,255,255,.02)", border:"1px solid "+(termsAccepted?"rgba(0,113,227,.4)":"var(--b)"), borderRadius:10, marginBottom:20 }}>
          <input type="checkbox" checked={termsAccepted} onChange={e=>setTermsAccepted(e.target.checked)} style={{ width:18, height:18, accentColor:"var(--accent)", marginTop:2, flexShrink:0 }} />
          <span style={{ fontSize:13, color:termsAccepted?"var(--accent)":"var(--text2)", fontWeight:600 }}>أوافق على الشروط وأتفهم المحتوى أعلاه</span>
        </label>
        <button onClick={acceptTerms} className="btn btn-gold" style={{ width:"100%", fontSize:14, padding:"12px 0" }}>
          متابعة →
        </button>
      </div>
    </div>
  );

  // ── Screening Questions Screen ────────────────────────────────────────────
  if (onboarding === "screening") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", padding:20, background:"var(--dark)" }}>
      {toastEl}
      <div style={{ background:"var(--card-bg)", border:"1px solid var(--b)", borderRadius:18, padding:28, width:"100%", maxWidth:560 }}>
        <div style={{ textAlign:"center", marginBottom:20 }}>
          <p style={{ fontSize:24, marginBottom:8 }}>📋</p>
          <h2 style={{ color:"var(--accent)", fontWeight:900, fontSize:18, marginBottom:6 }}>أسئلة التقديم</h2>
          <p style={{ color:"var(--text2)", fontSize:13 }}>يرجى الإجابة بصدق — تساعدنا في مراجعة ملفك بشكل أفضل</p>
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:14, marginBottom:24 }}>
          {screeningQs.map((q, i) => (
            <div key={q.id} style={{ padding:"14px 16px", background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:12 }}>
              <p style={{ fontSize:14, color:"var(--text)", fontWeight:600, marginBottom:12, lineHeight:1.7 }}>
                <span style={{ color:"var(--accent)", marginLeft:6, fontWeight:900 }}>{i+1}.</span>
                {q.text}
              </p>
              {q.type === "tf" ? (
                <div style={{ display:"flex", gap:10 }}>
                  {[{val:true,label:"نعم ✓"},{val:false,label:"لا ✗"}].map(opt=>(
                    <button key={String(opt.val)} onClick={()=>setAnswers(p=>({...p,[q.id]:opt.val}))}
                      style={{ flex:1, padding:"10px 0", borderRadius:10, cursor:"pointer", fontFamily:"inherit", fontWeight:700, fontSize:14, border:"2px solid "+(answers[q.id]===opt.val?(opt.val?"rgba(34,197,94,.5)":"rgba(239,68,68,.5)"):"var(--b)"), background:answers[q.id]===opt.val?(opt.val?"rgba(34,197,94,.1)":"rgba(239,68,68,.1)"):"transparent", color:answers[q.id]===opt.val?(opt.val?"#4ade80":"#f87171"):"var(--text2)" }}>
                      {opt.label}
                    </button>
                  ))}
                </div>
              ) : q.type === "mcq" ? (
                <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
                  {(q.options||[]).filter(o=>o.trim()).map((opt, oi) => (
                    <button key={oi} onClick={()=>setAnswers(p=>({...p,[q.id]:oi}))}
                      style={{ padding:"10px 14px", borderRadius:10, cursor:"pointer", fontFamily:"inherit", fontWeight:600, fontSize:13, textAlign:"right",
                        border:"2px solid "+(answers[q.id]===oi?"rgba(59,130,246,.5)":"var(--b)"),
                        background:answers[q.id]===oi?"rgba(59,130,246,.1)":"transparent",
                        color:answers[q.id]===oi?"#93c5fd":"var(--text2)" }}>
                      {opt}
                    </button>
                  ))}
                </div>
              ) : null}
            </div>
          ))}
        </div>
        <button onClick={submitScreening}
          disabled={screeningQs.some(q => answers[q.id] === undefined)}
          className="btn btn-gold" style={{ width:"100%", fontSize:14, padding:"12px 0", opacity: screeningQs.some(q=>answers[q.id]===undefined)?0.5:1 }}>
          💾 حفظ الإجابات والمتابعة
        </button>
        {screeningQs.some(q=>answers[q.id]===undefined) && (
          <p style={{ textAlign:"center", fontSize:12, color:"var(--text3)", marginTop:8 }}>يجب الإجابة على جميع الأسئلة للمتابعة</p>
        )}
      </div>
    </div>
  );

  const isNew = !init.fullName || !init.phone; // New if missing key profile data

  // ── KPI Exam popup (monthly mandatory) ──
  if (onboarding === "kpi_exam" && kpiExamQs.length > 0) return (
    <div className="fade" style={{ maxWidth:500, margin:"0 auto", padding:16 }}>
      <div className="card" style={{ border:"1px solid rgba(167,139,250,.3)", padding:"20px" }}>
        <h3 style={{ color:"#c4b5fd", fontWeight:900, fontSize:17, marginBottom:6, textAlign:"center" }}>📚 اختبار قياس الأداء الشهري</h3>
        <p style={{ fontSize:12, color:"var(--text3)", textAlign:"center", marginBottom:16 }}>يجب إكمال الاختبار للمتابعة — {kpiExamQs.length} سؤال</p>
        {kpiExamQs.map((q, i) => (
          <div key={q.id} style={{ marginBottom:14, padding:"12px", background:"rgba(255,255,255,.02)", borderRadius:10, border:"1px solid var(--b)" }}>
            <p style={{ fontWeight:700, fontSize:13, color:"var(--text)", marginBottom:8 }}>{(i+1)+". "+q.text}</p>
            {q.type==="tf" && (
              <div style={{ display:"flex", gap:8 }}>
                {["صح","خطأ"].map(opt => (
                  <button key={opt} onClick={()=>setKpiExamAnswers(p=>({...p,[q.id]:opt==="صح"}))}
                    style={{ flex:1, padding:"10px", borderRadius:10, border:"2px solid "+(kpiExamAnswers[q.id]===(opt==="صح")?"#c4b5fd":"var(--b)"), background:kpiExamAnswers[q.id]===(opt==="صح")?"rgba(167,139,250,.1)":"var(--glass)", color:kpiExamAnswers[q.id]===(opt==="صح")?"#c4b5fd":"var(--text3)", fontWeight:700, fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>
                    {opt}
                  </button>
                ))}
              </div>
            )}
            {q.type==="mcq" && (q.options||[]).map((opt,oi) => (
              <button key={oi} onClick={()=>setKpiExamAnswers(p=>({...p,[q.id]:oi}))}
                style={{ display:"block", width:"100%", padding:"8px 12px", marginBottom:4, borderRadius:8, border:"2px solid "+(kpiExamAnswers[q.id]===oi?"#c4b5fd":"var(--b)"), background:kpiExamAnswers[q.id]===oi?"rgba(167,139,250,.1)":"var(--glass)", color:kpiExamAnswers[q.id]===oi?"#c4b5fd":"var(--text3)", fontWeight:600, fontSize:12, cursor:"pointer", fontFamily:"inherit", textAlign:"right" }}>
                {opt}
              </button>
            ))}
            {q.type==="written" && (
              <textarea value={kpiExamAnswers[q.id]||""} onChange={e=>setKpiExamAnswers(p=>({...p,[q.id]:e.target.value}))}
                rows={3} placeholder="اكتب إجابتك هنا..." style={{ width:"100%", fontSize:12, fontFamily:"inherit", padding:"8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", resize:"vertical" }} />
            )}
          </div>
        ))}
        <button onClick={async()=>{
          setKpiExamSubmitting(true);
          const empId = init?.uid || init?.idNumber || init?.email || "";
          const month = new Date().toISOString().slice(0,7);
          // Auto-grade
          let correct=0, total=0;
          kpiExamQs.forEach(q => {
            if (q.type==="tf") { total++; if(kpiExamAnswers[q.id]===q.correctTf) correct++; }
            else if (q.type==="mcq") { total++; if(kpiExamAnswers[q.id]===q.correctIdx) correct++; }
          });
          const score = total>0 ? Math.round(correct/total*100) : 0;
          await saveKPIExamResult(empId, month, { answers:kpiExamAnswers, score, questionsCount:kpiExamQs.length, correct, total });
          // Save to employee record
          try {
            const emp = await db.get("c:"+empId) || await db.get("emp:"+empId);
            if (emp) { emp._kpiExamScore = score; emp._kpiExamMonth = month; await saveCandidate(emp); }
          } catch{}
          setKpiExamSubmitting(false);
          setOnboarding(null);
          show("✅ تم إرسال الاختبار — نتيجتك: " + score + "%");
        }} disabled={kpiExamSubmitting || kpiExamQs.some(q=>kpiExamAnswers[q.id]===undefined&&kpiExamAnswers[q.id]!=="")}
          className="btn btn-gold" style={{ width:"100%", fontSize:14, padding:"12px 0", marginTop:8 }}>
          {kpiExamSubmitting ? "⏳ جاري الإرسال..." : "📤 إرسال الاختبار"}
        </button>
      </div>
    </div>
  );

  return (
    <CandPortal init={init} isNew={isNew} isEmployee={isEmployee} onBack={onBack} onJobs={onJobs} libs={libs} specsMap={specsMap} initLang={initLang} onLangChange={onLangChange} />
  );
}


// ── CandidatePipeline — مسار المرشح ──────────────────────────────────────────
function CandidatePipeline({ cand, onOpenSupport, onAcceptOffer }) {
  const rec = cand?.evaluation?.recommendation || "";
  const interview = cand?.interviewData || {};  // { link, location, date }
  const assessment = cand?.assessmentLink || "";

  const STAGES = [
    { key:"استلام",    label:"استلام السيرة", icon:"📄", recs:[""] },
    { key:"اختبار",    label:"اختبار",         icon:"📝", recs:["اختبار"] },
    { key:"مقابلة1",   label:"مقابلة أولى",   icon:"🗓️", recs:["مقابلة أولى"] },
    { key:"مقابلة2",   label:"مقابلة ثانية",  icon:"🤝", recs:["مقابلة ثانية"] },
    { key:"عرض",       label:"عرض وظيفي",     icon:"⭐", recs:["إرسال عرض وظيفي","توقيع العقد"] },
  ];

  // Determine current stage index
  const stageIdx = rec === "اختبار"        ? 1
    : rec === "مقابلة أولى"                  ? 2
    : rec === "مقابلة ثانية"               ? 3
    : (rec === "إرسال عرض وظيفي" || rec === "توقيع العقد") ? 4
    : rec === "لم يتم القبول"                         ? -1
    : cand?.fullName ? 0 : -2; // has data = stage 0, no data = nothing

  if (stageIdx === -2) return null;
  if (stageIdx === -1) return (
    <div style={{ background:"rgba(239,68,68,.07)", border:"1px solid rgba(239,68,68,.3)", borderRadius:12, padding:"14px 18px", marginBottom:16 }}>
      <p style={{ color:"#f87171", fontWeight:700, fontSize:14 }}>❌ تم إغلاق الطلب — للاستفسار يمكنك فتح تذكرة دعم</p>
    </div>
  );

  return (
    <div style={{ background:"rgba(59,130,246,.04)", border:"1px solid rgba(201,168,76,.2)", borderRadius:14, padding:"16px 18px", marginBottom:18 }}>
      <p style={{ fontSize:12, color:"var(--text3)", fontWeight:700, marginBottom:14 }}>📍 مرحلتك الحالية في عملية التوظيف</p>

      {/* Stage dots */}
      <div style={{ display:"flex", alignItems:"center", marginBottom:16, overflowX:"auto", paddingBottom:4 }}>
        {STAGES.map((s, i) => {
          const isDone    = i < stageIdx;
          const isCurrent = i === stageIdx;
          const isPending = i > stageIdx;
          return (
            <div key={s.key} style={{ display:"flex", alignItems:"center", flexShrink:0 }}>
              {i > 0 && (
                <div style={{ width:28, height:2, background: isDone?"var(--gold)":"rgba(255,255,255,.1)", flexShrink:0 }} />
              )}
              <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:5 }}>
                <div style={{
                  width: isCurrent?44:36, height: isCurrent?44:36,
                  borderRadius:"50%", display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize: isCurrent?20:16,
                  background: isDone?"rgba(201,168,76,.25)": isCurrent?"var(--gold)":"rgba(255,255,255,.06)",
                  border: isDone?"2px solid var(--gold)": isCurrent?"3px solid #a8893a":"2px solid rgba(255,255,255,.15)",
                  color: isDone?"var(--gold)": isCurrent?"#0b0f1a":"var(--text3)",
                  fontWeight: isCurrent?900:400,
                  boxShadow: isCurrent?"0 0 16px rgba(201,168,76,.4)":"none",
                  transition:"all .3s",
                }}>
                  {isDone ? "✓" : s.icon}
                </div>
                <span style={{ fontSize:10, fontWeight: isCurrent?900:400, color: isCurrent?"var(--gold)": isDone?"var(--text2)":"var(--text3)", textAlign:"center", maxWidth:60, lineHeight:1.3 }}>
                  {s.label}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Context info per stage */}
      {stageIdx === 1 && (interview.link || interview.location || interview.date) && (
        <div style={{ background:"rgba(34,197,94,.07)", border:"1px solid rgba(34,197,94,.25)", borderRadius:10, padding:"12px 14px" }}>
          <p style={{ color:"#4ade80", fontWeight:700, fontSize:13, marginBottom:8 }}>🗓️ تفاصيل المقابلة الأولى</p>
          {interview.date && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:4 }}>📅 {new Date(interview.date).toLocaleDateString("ar-SA", {weekday:"long", year:"numeric", month:"long", day:"numeric"})}</p>}
          {interview.location && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:4 }}>📍 {interview.location}</p>}
          {interview.link && <a href={interview.link} target="_blank" rel="noreferrer" style={{ fontSize:13, color:"#60a5fa", textDecoration:"none", display:"block" }}>🔗 رابط المقابلة الإلكترونية</a>}
        </div>
      )}
      {stageIdx === 2 && (
        <div style={{ background:"rgba(139,92,246,.07)", border:"1px solid rgba(139,92,246,.25)", borderRadius:10, padding:"12px 14px" }}>
          <p style={{ color:"#a78bfa", fontWeight:700, fontSize:13, marginBottom:8 }}>📝 تفاصيل الاختبار</p>
          {assessment ? (
            <a href={assessment} target="_blank" rel="noreferrer" style={{ fontSize:13, color:"#60a5fa", textDecoration:"none" }}>🔗 رابط الاختبار الإلكتروني</a>
          ) : (
            <p style={{ fontSize:13, color:"var(--text2)" }}>سيتم إرسال رابط الاختبار لاحقاً — تابع بريدك الإلكتروني</p>
          )}
        </div>
      )}
      {stageIdx === 3 && (interview.link2 || interview.location2 || interview.date2) && (
        <div style={{ background:"rgba(34,197,94,.07)", border:"1px solid rgba(34,197,94,.25)", borderRadius:10, padding:"12px 14px" }}>
          <p style={{ color:"#4ade80", fontWeight:700, fontSize:13, marginBottom:8 }}>🤝 تفاصيل المقابلة الثانية</p>
          {interview.date2 && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:4 }}>📅 {new Date(interview.date2).toLocaleDateString("ar-SA", {weekday:"long", year:"numeric", month:"long", day:"numeric"})}</p>}
          {interview.location2 && <p style={{ fontSize:13, color:"var(--text2)", marginBottom:4 }}>📍 {interview.location2}</p>}
          {interview.link2 && <a href={interview.link2} target="_blank" rel="noreferrer" style={{ fontSize:13, color:"#60a5fa", textDecoration:"none" }}>🔗 رابط المقابلة</a>}
        </div>
      )}
      {stageIdx === 4 && (()=>{
        const off = cand?.jobOffer;
        const accepted = off?.acceptedAt;
        return (
        <div style={{ background:"rgba(34,197,94,.08)", border:"1px solid rgba(34,197,94,.3)", borderRadius:12, padding:"16px" }}>
          <p style={{ color:"#4ade80", fontWeight:900, fontSize:15, marginBottom:12 }}>⭐ عرض وظيفي — Job Offer</p>
          {off ? (<>
            {/* ── تفاصيل العرض ── */}
            <div style={{ background:"rgba(255,255,255,.06)", border:"1px solid rgba(201,168,76,.25)", borderRadius:10, padding:"12px 14px", marginBottom:12 }}>
              <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
                <tbody>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700, width:"35%" }}>المسمى الوظيفي</td><td style={{ padding:"5px 8px", color:"var(--text)", fontWeight:700 }}>{off.position||"—"}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>الموقع</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.location||"—"}</td></tr>
                  <tr style={{ background:"rgba(201,168,76,.08)" }}><td style={{ padding:"5px 8px", color:"#c9a84c", fontWeight:900 }}>الراتب الإجمالي</td><td style={{ padding:"5px 8px", color:"#c9a84c", fontWeight:900, fontSize:16 }}>SAR {Number(off.totalSalary||0).toLocaleString()}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontSize:11 }}>الأساسي</td><td style={{ padding:"5px 8px", color:"var(--text2)", fontSize:11 }}>SAR {Number(off.basicSalary||0).toLocaleString()}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontSize:11 }}>بدل السكن</td><td style={{ padding:"5px 8px", color:"var(--text2)", fontSize:11 }}>SAR {Number(off.housing||0).toLocaleString()}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontSize:11 }}>بدل النقل</td><td style={{ padding:"5px 8px", color:"var(--text2)", fontSize:11 }}>SAR {Number(off.transport||0).toLocaleString()}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>الإجازة السنوية</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.annualLeave||21} يوم</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>فترة التجربة</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.probation||90} يوم</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>مدة العقد</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.contractDuration||"سنة واحدة"}</td></tr>
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>مواعيد العمل</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.workingHours||"8:30 - 5:00"} ({off.workingDays||6} أيام)</td></tr>
                  {off.startDate && <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>تاريخ البداية المتوقع</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.startDate}</td></tr>}
                  <tr><td style={{ padding:"5px 8px", color:"var(--text3)", fontWeight:700 }}>صلاحية العرض</td><td style={{ padding:"5px 8px", color:"var(--text)" }}>{off.validHours||24} ساعة</td></tr>
                </tbody>
              </table>
            </div>
            {off.jobDescription && <div style={{ background:"rgba(255,255,255,.04)", borderRadius:8, padding:"8px 12px", marginBottom:8, fontSize:12, color:"var(--text2)", lineHeight:1.7, borderRight:"3px solid #c9a84c" }}>📝 <strong>الوصف الوظيفي:</strong> {off.jobDescription}</div>}
            {(off.duties||[]).length>0 && <div style={{ background:"rgba(255,255,255,.04)", borderRadius:8, padding:"8px 12px", marginBottom:8, fontSize:12, color:"var(--text2)", lineHeight:1.7, borderRight:"3px solid #c9a84c" }}>📋 <strong>المهام:</strong><ul style={{ margin:"4px 0", paddingRight:16 }}>{(off.duties||[]).map((d,i)=><li key={i}>{d}</li>)}</ul></div>}
            {(off.kpiCriteria||[]).length>0 && <div style={{ background:"rgba(255,255,255,.04)", borderRadius:8, padding:"8px 12px", marginBottom:8, fontSize:12, color:"var(--text2)", lineHeight:1.7, borderRight:"3px solid #c9a84c" }}>📊 <strong>مؤشرات الأداء:</strong><ul style={{ margin:"4px 0", paddingRight:16 }}>{(off.kpiCriteria||[]).map((k,i)=><li key={i}>{k.label} ({k.weight}%)</li>)}</ul></div>}
            {/* ── حالة الموافقة ── */}
            {accepted ? (
              <div style={{ background:"rgba(74,222,128,.1)", border:"1px solid rgba(74,222,128,.3)", borderRadius:10, padding:"12px 14px", textAlign:"center" }}>
                <p style={{ color:"#4ade80", fontWeight:900, fontSize:14 }}>✅ تمت الموافقة على العرض</p>
                <p style={{ color:"var(--text2)", fontSize:12, marginTop:4 }}>بتاريخ: {new Date(off.acceptedAt).toLocaleDateString("ar-SA")}</p>
                {off.confirmedStartDate && <p style={{ color:"var(--text2)", fontSize:12 }}>تاريخ المباشرة: {off.confirmedStartDate}</p>}
              </div>
            ) : (
              <OfferAcceptForm cand={cand} onAccept={onAcceptOffer} />
            )}
            <div style={{ marginTop:10, textAlign:"center" }}>
              <button onClick={onOpenSupport} style={{ padding:"6px 14px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:11, fontWeight:700, background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.3)", color:"#4ade80" }}>💬 استفسار عن العرض الوظيفي</button>
            </div>
          </>) : (
            <p style={{ fontSize:13, color:"var(--text2)" }}>سيتم عرض تفاصيل العرض الوظيفي هنا قريباً — تابع بريدك الإلكتروني</p>
          )}
        </div>
        );
      })()}
      {stageIdx === 0 && (
        <div style={{ background:"rgba(96,165,250,.07)", border:"1px solid rgba(96,165,250,.2)", borderRadius:10, padding:"10px 14px" }}>
          <p style={{ fontSize:13, color:"#93c5fd" }}>
            {cand?.cvUploaded
              ? "✅ تم استلام سيرتك الذاتية — سيتم مراجعتها والتواصل معك قريباً"
              : "📝 يرجى استكمال بياناتك ورفع سيرتك الذاتية للتمكن من التقدم للوظائف"}
          </p>
        </div>
      )}
    </div>
  );
}

function OfferAcceptForm({ cand, onAccept }) {
  const [startDate, setStartDate] = useState("");
  const [confirmed, setConfirmed] = useState(false);
  const [saving, setSaving] = useState(false);
  const { show, toastEl } = useToast();
  const doAccept = async () => {
    if (!confirmed) { show("⚠️ يرجى تأكيد الموافقة أولاً"); return; }
    setSaving(true);
    await onAccept(startDate);
    setSaving(false);
    show("✅ تم تأكيد الموافقة على العرض الوظيفي");
  };
  return (
    <div style={{ background:"rgba(201,168,76,.08)", border:"1px solid rgba(201,168,76,.3)", borderRadius:10, padding:"14px" }}>
      {toastEl}
      <p style={{ color:"#c9a84c", fontWeight:800, fontSize:13, marginBottom:10 }}>📋 تأكيد الموافقة على العرض الوظيفي</p>
      <div style={{ marginBottom:10 }}>
        <label style={{ fontSize:12, color:"var(--text2)", fontWeight:700, display:"block", marginBottom:4 }}>📅 تاريخ المباشرة المقترح:</label>
        <input type="date" value={startDate} onChange={e=>setStartDate(e.target.value)} style={{ width:"100%", padding:"8px 10px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontSize:13, fontFamily:"inherit" }} />
      </div>
      <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer", fontSize:13, color:"var(--text)", marginBottom:12 }}>
        <input type="checkbox" checked={confirmed} onChange={e=>setConfirmed(e.target.checked)} style={{ width:18, height:18, accentColor:"#4ade80" }} />
        <span>أوافق على العرض الوظيفي المذكور أعلاه وأتعهد بالالتحاق في التاريخ المحدد</span>
      </label>
      <button onClick={doAccept} disabled={saving||!confirmed} style={{ width:"100%", padding:"12px", borderRadius:10, border:"none", cursor:confirmed?"pointer":"not-allowed", fontFamily:"inherit", fontSize:14, fontWeight:900, background:confirmed?"linear-gradient(135deg,#4ade80,#22c55e)":"rgba(255,255,255,.05)", color:confirmed?"#fff":"var(--text3)", opacity:confirmed?1:.5 }}>
        {saving ? "⏳ جاري التأكيد..." : "✅ تأكيد الموافقة على العرض"}
      </button>
    </div>
  );
}

function CandPortal({ init, isNew, isEmployee: isEmployeeProp, onBack, onJobs, libs, specsMap, initLang="ar", onLangChange }) {
  const [c, setC] = useState(init || {});
  const cu = window._currentUser || {};
  // الموظف: يُحدَّد من role المستخدم الحالي أو من الـ prop
  const isEmployee = isEmployeeProp || cu.role === "employee";
  // التعديل مقفل للموظف إلا إذا منحه المشرف canEdit
  const canEdit = !isEmployee || cu.canEdit === true;
  const [edit, setEdit] = useState(isNew && canEdit);
  const [editRequested, setEditRequested] = useState(false);
  const [showSupport, setShowSupport] = useState(false);
  const [lang, setLang] = useState(initLang || "ar");
  const changeLangCP = (l) => { setLang(l); if(onLangChange) onLangChange(l); };
  const { show, toastEl } = useToast();

  // تأكيد كلمة السر قبل طلب التعديل
  const [showEditConfirm, setShowEditConfirm] = useState(false);
  const [editPw, setEditPw] = useState("");
  const [editPwErr, setEditPwErr] = useState("");
  const [editPwLoading, setEditPwLoading] = useState(false);

  const requestEdit = () => {
    setEditPw(""); setEditPwErr(""); setShowEditConfirm(true);
  };

  const confirmRequestEdit = async () => {
    if (!editPw.trim()) { setEditPwErr("أدخل كلمة السر"); return; }
    setEditPwLoading(true);
    // التحقق من كلمة السر مقارنةً بكلمة سر المستخدم الحالي
    const storedPw = cu.password || cu.pw || "";
    if (storedPw && editPw !== storedPw) {
      setEditPwErr("كلمة السر غير صحيحة"); setEditPwLoading(false); return;
    }
    try {
      await saveNotification({ message:"✏️ "+(c.fullName||"موظف")+" يطلب صلاحية تعديل بياناته", type:"edit_request", targetId:"admin", sentBy:c.fullName||cu.displayName||"", read:false, createdAt:new Date().toISOString() });
      setEditRequested(true);
      setShowEditConfirm(false);
      show("✅ تم إرسال طلب التعديل — بانتظار موافقة المشرف");
    } catch { setEditPwErr("❌ فشل إرسال الطلب"); }
    setEditPwLoading(false);
  };

  const [notifs, setNotifs] = useState([]);
  const [showNotifsPage, setShowNotifsPage] = useState(false);
  useEffect(() => {
    const uid = c.uid || c.idNumber || c.email || cu.linkedId || cu.username;
    if (!uid) return;
    getNotifications(uid).then(ns => {
      const allNotifs = (ns||[]).filter(n=>!n.read).slice(0,20);
      // Add offer notification if pending
      const person = window._portalPerson;
      if (person?.jobOffer && !person.jobOffer.acceptedAt) {
        allNotifs.unshift({ id:"offer_pending", message:"⭐ لديك عرض وظيفي بانتظار موافقتك!", type:"offer", createdAt:person.jobOffer.sentAt||new Date().toISOString() });
      }
      setNotifs(allNotifs);
    }).catch(()=>{});
  }, [c.uid, c.email]);

  const dismissNotif = async (id) => {
    await markNotifRead(id).catch(()=>{});
    setNotifs(prev => prev.filter(n => n.id !== id));
  };
  const [evalTasks, setEvalTasks]       = useState([]);
  const [evalLoading, setEvalLoading]   = useState(false);
  const [empAllAsmts, setEmpAllAsmts]   = useState([]); // v37.39: اختبارات لعرض حالة المرحلة
  const [showTawasul, setShowTawasul]   = useState(false);
  const [twslNotifCount, setTwslNotifCount] = useState(0);
  const [twslEmps, setTwslEmps]         = useState([]);
  const [selTask, setSelTask]           = useState(null);
  const [showTaskCand, setShowTaskCand] = useState(false);
  const [showTaskEval, setShowTaskEval] = useState(false);
  const [taskChatMsg, setTaskChatMsg]   = useState("");

  useEffect(() => {
    if (isEmployee) {
      Promise.all([getAllEmployees(), getAllUsers()]).then(([emps, users]) => {
        // Add admin/HR/supervisor users who are NOT already in employee list
        const empIds = new Set(emps.map(e => e.uid || e.idNumber || e.email));
        const extraUsers = (users||[]).filter(u => u.role === "admin" || u.role === "hr_manager" || u.role === "supervisor" || u.role === "assistant_supervisor")
          .filter(u => !empIds.has(u.linkedId) && !empIds.has(u.email) && !empIds.has(u.username))
          .map(u => ({ fullName: u.displayName || u.username, email: u.email, uid: u.linkedId || u.username, idNumber: u.linkedId || "", department: u.role === "admin" ? "الإدارة العليا" : u.role === "hr_manager" ? "الموارد البشرية" : "الإشراف", _isUser: true, _username: u.username }));
        setTwslEmps([...emps, ...extraUsers]);
      }).catch(()=>{});
    }
    // Check tawasul notifications every 30 seconds
    if (isEmployee) {
      const myId = window._currentUser?.linkedId || window._currentUser?.username || "";
      const checkTwsl = async () => {
        try {
          const allReqs = await getAllTawasulReqs();
          const myPending = allReqs.filter(r => (r.assignees||[]).some(a => a.id === myId) && ["sent","received"].includes(r.status));
          if (myPending.length > twslNotifCount && twslNotifCount > 0) {
            // New task! Play sound
            try {
                const ctx = new AudioContext();
                const playNote = (freq, start, dur) => {
                  const o = ctx.createOscillator(); const g = ctx.createGain();
                  o.connect(g); g.connect(ctx.destination);
                  o.frequency.value = freq; o.type = "sine";
                  g.gain.setValueAtTime(0.2, ctx.currentTime+start);
                  g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime+start+dur);
                  o.start(ctx.currentTime+start); o.stop(ctx.currentTime+start+dur);
                };
                playNote(880,.0,.15); playNote(1100,.15,.15); playNote(1320,.3,.2);
              } catch{}
          }
          setTwslNotifCount(myPending.length);
        } catch{}
      };
      checkTwsl();
      const timer = setInterval(checkTwsl, 30000);
      return () => clearInterval(timer);
    }
  }, [isEmployee]);
  useEffect(() => {
    if (!isEmployee) return;
    setEvalLoading(true);
    (async () => {
      try {
        const all = await getEvalTasks();
        const cu2 = window._currentUser || {};
        // جمع كل المعرّفات الممكنة للموظف الحالي
        const myIds = [
          c.uid, c.idNumber, c.email, c.fullName, c.hrCode, c.username,
          cu2.username, cu2.linkedId, cu2.displayName, cu2.email, cu2.id,
          cu2.hrCode, cu2.fullName, cu2.phone
        ].filter(Boolean).map(x => String(x).trim().toLowerCase());

        const mine = all.filter(t => {
          if (["completed","rejected_eval"].includes(t.status)) return false;
          const tIds = [
            t.evaluatorId, t.evaluatorName,
            ...(t.evaluatorIds||[])
          ].filter(Boolean).map(x => String(x).trim().toLowerCase());
          // مطابقة مباشرة
          if (tIds.some(tid => myIds.includes(tid))) return true;
          // مطابقة احتياطية بالاسم الجزئي
          const myName = (c.fullName||cu2.displayName||"").toLowerCase();
          if (myName && t.evaluatorName && t.evaluatorName.toLowerCase().includes(myName.split(" ")[0]||"") && myName.length > 3) return true;
          return false;
        });
        const [cands, emps] = await Promise.all([getAllCandidates().catch(()=>[]), getAllEmployees().catch(()=>[])]);
        const everyone = [...cands, ...emps];
        setEvalTasks(mine.map(t => {
          const found = everyone.find(p => p.uid===t.candidateId || p.email===t.candidateId || p.idNumber===t.candidateId || p.fullName===t.candidateName);
          return { ...t, _cand: found || { uid:t.candidateId, fullName:t.candidateName } };
        }).filter(t => {
          // v37.44: إخفاء المرشح بعد المقابلة الثانية
          const candRec = (t._cand?.evaluation||{}).recommendation||"";
          const visibleStages = ["اختبار","مقابلة أولى","مقابلة ثانية",""];
          return visibleStages.includes(candRec) || !candRec;
        }));
        // v37.39: تحميل الاختبارات
        getAllAssessments().then(a => setEmpAllAsmts(a)).catch(()=>{});
      } catch(e) { console.error("[evalTasks]", e); }
      setEvalLoading(false);
    })();
  }, [isEmployee]);

  // إشعار تذكير أسبوعي بالتقييم
  useEffect(() => {
    if (!isEmployee || !c.uid) return;
    const lastKey = "hma_periodic_reminder_" + (c.uid||c.email||"");
    const last = localStorage.getItem(lastKey);
    const now = Date.now();
    const week = 7*24*60*60*1000;
    if (!last || now - +last > week) {
      saveNotification({
        message: "⭐ تذكير: حان وقت التقييم الأسبوعي — قيّم مديرك والموظفين تحت إشرافك",
        type: "periodic_reminder", targetId: c.uid||c.email,
        sentBy: "النظام", read: false, createdAt: new Date().toISOString()
      }).catch(()=>{});
      localStorage.setItem(lastKey, String(now));
      setNotifs(prev => prev.some(n=>n.type==="periodic_reminder") ? prev : [
        { id:"remind_"+now, message:"⭐ تذكير: حان وقت التقييم الأسبوعي", type:"periodic_reminder", createdAt:new Date().toISOString() },
        ...prev
      ]);
    }
  }, [isEmployee, c.uid]);

  const submitEvalTask = async (evalData) => {
    if (!selTask) return;
    const cu = window._currentUser || {};
    const updTask = { ...selTask, status:"pending_approval", completedAt:new Date().toISOString(),
      evalResult:{ score:evalData.totalScore, recommendation:evalData.recommendation, evaluatorName:cu.displayName||c.fullName||"" },
      chat: selTask.chat||[] };
    delete updTask._cand;
    await saveEvalTask(updTask);
    if (selTask._cand?.uid||selTask._cand?.email) {
      await saveCandidate({ ...selTask._cand, evalTaskResults:[...(selTask._cand.evalTaskResults||[]), { ...evalData, taskId:selTask.id }] }).catch(()=>{});
      addPersonEvent(selTask._cand.uid||selTask._cand.email, { type:"eval", text:"📋 تقييم تكليف بواسطة "+(c.fullName||"")+" — "+evalData.totalScore+"/100", by:c.fullName||"", byRole:"evaluator", private:false }).catch(()=>{});
    }
    setEvalTasks(prev => prev.map(t => t.id===selTask.id ? { ...t, ...updTask, _cand:t._cand } : t));
    setShowTaskEval(false); setSelTask(null);
    show("✅ تم إرسال التقييم — بانتظار موافقة المدير");
  };

  const sendTaskChat = async (task) => {
    if (!taskChatMsg.trim()) return;
    const msg = { by:c.fullName||"", role:"evaluator", text:taskChatMsg.trim(), at:new Date().toISOString() };
    const updTask = { ...task, chat:[...(task.chat||[]), msg] };
    delete updTask._cand;
    await saveEvalTask(updTask);
    setEvalTasks(prev => prev.map(t => t.id===task.id ? { ...t, chat:updTask.chat } : t));
    setTaskChatMsg("");
  };

  // ── التقييم الدوري — يستخدم FullEvalForm الموحد ──
  const [periodicEvals, setPeriodicEvals] = useState([]);
  const [periodicLoading, setPeriodicLoading] = useState(false);
  const [showPeriodicSel, setShowPeriodicSel] = useState(false);
  const [periodicSel, setPeriodicSel]       = useState(null);
  const [periodicPeople, setPeriodicPeople] = useState([]);
  const [showPeriodicForm, setShowPeriodicForm] = useState(false);

  useEffect(() => {
    if (!isEmployee) return;
    setPeriodicLoading(true);
    (async () => {
      try {
        const cu2 = window._currentUser || {};
        // الموظف يرى فقط ما كتبه هو — evaluatorId هو المعيار
        const myIds = [c.uid, c.idNumber, c.email, c.fullName, cu2.linkedId, cu2.username]
          .filter(Boolean).map(x => String(x).trim());
        const all = (await db.get("periodic_evals")) || [];
        const mine = all.filter(r => myIds.includes(String(r.evaluatorId||"").trim()) || myIds.includes(String(r.evaluatorName||"").trim()));
        setPeriodicEvals(mine.sort((a,b) => new Date(b.createdAt) - new Date(a.createdAt)));
      } catch {}
      setPeriodicLoading(false);
    })();
  }, [isEmployee]);

  useEffect(() => {
    if (!isEmployee || !showPeriodicSel) return;
    (async () => {
      try {
        const [allEmps, allUsers] = await Promise.all([getAllEmployees().catch(()=>[]), getAllUsers().catch(()=>[])]);
        const managers = allUsers
          .filter(u => (u.role==="admin"||u.role==="hr_manager"||u.role==="supervisor") && u.displayName && u.username !== cu.username)
          .map(u => ({ uid:u.linkedId||u.username, fullName:u.displayName, type:"manager" }));
        const subordinates = allEmps
          .filter(e => e.uid !== c.uid && e.email !== c.email)
          .map(e => ({ ...e, type:"subordinate" }));
        setPeriodicPeople([...managers, ...subordinates]);
      } catch {}
    })();
  }, [isEmployee, showPeriodicSel]);

  const submitPeriodicEval = async (evalData) => {
    if (!periodicSel) return;
    const rec = {
      id:"pev_"+Date.now(),
      evaluatorId:c.uid||c.email, evaluatorName:c.fullName||"",
      targetId:periodicSel.uid||periodicSel.email, targetName:periodicSel.fullName, targetType:periodicSel.type,
      kpiScores:evalData.kpiScores, kpiList:evalData.kpiList,
      totalScore:evalData.totalScore, notes:evalData.notes||"",
      createdAt:new Date().toISOString()
    };
    const existing = (await db.get("periodic_evals")) || [];
    await db.set("periodic_evals", [...existing, rec]);
    await saveNotification({ message:"⭐ "+(c.fullName||"موظف")+" قيّم "+periodicSel.fullName+" ("+evalData.totalScore+"/100)", type:"periodic_eval", targetId:"admin", sentBy:c.fullName||"", read:false, createdAt:new Date().toISOString() });
    setPeriodicEvals(prev => [rec, ...prev]);
    setShowPeriodicForm(false); setShowPeriodicSel(false); setPeriodicSel(null);
    show("✅ تم إرسال التقييم الدوري بنجاح");
  };

  const save = async (data) => {
    try {
      const hasProfile = !!(data.fullName && (data.phone || data.email));
      // ── Track changes: compare old (c) vs new (data) ──
      const trackFields = ["fullName","fullNameEn","phone","email","idNumber","nationality","gender","city","locationStatus","education","university","university2","major","graduationYear","yearsExperience","lastJob","lastCompany","expectedSalary","linkedinUrl","availabilityStatus","trainingType","primarySpecId","secondarySpecId","notes","hayaMemberNo","hayaRank","hayaExpiry"];
      const trackArrays = ["specializations","skills","software","certifications","companies","biSpec","biDept","biSkill","biSW","biProj","biCert"];
      const oldChanges = c._pendingChanges || {};
      const newChanges = { ...oldChanges };
      const changedFields = [];
      trackFields.forEach(f => {
        const oldVal = c[f] || "";
        const newVal = data[f] || "";
        if (String(oldVal).trim() !== String(newVal).trim() && !oldChanges[f]) {
          newChanges[f] = { old: oldVal, at: new Date().toISOString() };
          changedFields.push(f);
        }
      });
      trackArrays.forEach(f => {
        const oldArr = JSON.stringify(c[f] || []);
        const newArr = JSON.stringify(data[f] || []);
        if (oldArr !== newArr && !oldChanges[f]) {
          newChanges[f] = { old: c[f] || [], at: new Date().toISOString() };
          changedFields.push(f);
        }
      });
      const hasPending = Object.keys(newChanges).length > 0;
      const merged = { ...c, ...data, uid: c.uid || data.uid, cvUploaded: hasProfile, accountStatus: "قيد المراجعة", _pendingChanges: hasPending ? newChanges : undefined, _hasReview: hasPending };
      const uid = await saveCandidate(merged);
      setC({ ...merged, uid });
      setEdit(false);
      show(changedFields.length > 0 ? "✅ تم حفظ "+changedFields.length+" تعديل — بانتظار مراجعة المشرف" : "✅ تم حفظ البيانات");
      // Log changes
      if (changedFields.length > 0) {
        const fieldLabels = { fullName:"الاسم",phone:"الجوال",email:"البريد",city:"المدينة",nationality:"الجنسية",education:"المؤهل",university:"الجامعة",yearsExperience:"الخبرة",lastJob:"آخر وظيفة",lastCompany:"آخر شركة",expectedSalary:"الراتب المتوقع",biSpec:"التخصصات",biSkill:"المهارات",biSW:"البرامج",biCert:"الشهادات",biProj:"المشاريع",biDept:"جهات العمل",specializations:"التخصصات",skills:"المهارات",software:"البرامج",certifications:"الشهادات" };
        const names = changedFields.map(f=>fieldLabels[f]||f).join("، ");
        addPersonEvent(c.uid||c.idNumber||c.email, { type:"edit", text:"المرشح عدّل: "+names, by:c.fullName||"المرشح", byRole:"candidate", private:false }).catch(()=>{});
      }
      saveNotification({
        message: "📝 " + (merged.fullName||"مرشح") + " قام بتحديث بياناته" + (changedFields.length ? " ("+changedFields.length+" حقل)" : "") + " — يحتاج مراجعة",
        type: "data_review", targetId: "admin",
        sentBy: "النظام", read: false,
        createdAt: new Date().toISOString(),
      }).catch(()=>{});
    } catch(e) {
      show("❌ خطأ في الحفظ: " + (e.message||"غير معروف"));
      console.error("Save error:", e);
    }
  };

  const onSaveCV = async (updates) => {
    const updated = { ...c, ...updates, uid: c.uid };
    const uid = await saveCandidate(updated);
    setC({ ...updated, uid });
    show("✅ تم الحفظ");
  };

  const t = PORTAL_I18N[lang] || PORTAL_I18N.ar;
  return (
    <div dir={t.dir} style={{ maxWidth:900, margin:"0 auto", padding:"16px 14px 160px" }} className="content-with-footer">
      {toastEl}

      {/* ── نافذة تأكيد طلب التعديل ── */}
      {showEditConfirm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.75)", backdropFilter:"blur(6px)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}
          onClick={e=>{ if(e.target===e.currentTarget){ setShowEditConfirm(false); } }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid rgba(201,168,76,.35)", borderRadius:18, padding:28, width:"100%", maxWidth:360, textAlign:"center" }}>
            <div style={{ fontSize:36, marginBottom:10 }}>🔒</div>
            <p style={{ fontWeight:900, fontSize:16, color:"var(--gold)", marginBottom:6 }}>تأكيد طلب التعديل</p>
            <p style={{ fontSize:12, color:"var(--text3)", marginBottom:18, lineHeight:1.6 }}>أدخل كلمة السر لتأكيد إرسال طلب التعديل إلى المشرف</p>
            <input
              type="password"
              value={editPw}
              onChange={e=>{ setEditPw(e.target.value); setEditPwErr(""); }}
              onKeyDown={e=>{ if(e.key==="Enter") confirmRequestEdit(); }}
              placeholder="كلمة السر"
              autoFocus
              style={{ width:"100%", padding:"10px 14px", borderRadius:10, border:"1px solid "+(editPwErr?"rgba(239,68,68,.6)":"var(--b)"), background:"var(--input-bg)", color:"var(--text)", fontSize:14, fontFamily:"inherit", textAlign:"center", marginBottom:6, boxSizing:"border-box" }}
            />
            {editPwErr && <p style={{ fontSize:12, color:"#f87171", marginBottom:10 }}>{editPwErr}</p>}
            <div style={{ display:"flex", gap:8, marginTop:14 }}>
              <button onClick={()=>setShowEditConfirm(false)} style={{ flex:1, padding:"10px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", fontWeight:700, fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>إلغاء</button>
              <button onClick={confirmRequestEdit} disabled={editPwLoading} style={{ flex:1, padding:"10px", borderRadius:10, border:"none", background:"linear-gradient(135deg,#c9a84c,#a8893a)", color:"#0b0f1a", fontWeight:900, fontSize:13, cursor:"pointer", fontFamily:"inherit", opacity:editPwLoading?0.7:1 }}>
                {editPwLoading ? "⏳ جاري..." : "✅ تأكيد الطلب"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── عنوان الصفحة ── */}
      <div style={{ marginBottom:12, textAlign:"center" }}>
        <p style={{ fontSize:11, color:"var(--text3)", margin:0 }}>
          {isEmployee ? "👨‍💼 حساب الموظفين" : "👤 حساب المرشحين"}
        </p>
      </div>

      {/* ── هيدر الموظف: بدون وظائف ── */}
      {isEmployee ? (
        <div className="card" style={{ padding:"16px", marginBottom:16, display:"flex", flexDirection:"column", alignItems:"center", textAlign:"center", gap:8, background:"linear-gradient(135deg,rgba(201,168,76,.08),rgba(201,168,76,.02))", border:"1px solid rgba(201,168,76,.2)" }}>
          <p style={{ fontWeight:900, fontSize:19, color:"var(--gold)", margin:"0 0 6px" }}>
            {(t.welcome||"مرحباً") + " " + (c.fullName ? c.fullName.split(" ").slice(0,2).join(" ") : "بك")}
          </p>
          <img src={HMA_LOGO_USER} alt="HMA" style={{ width:72, height:72, objectFit:"contain", marginBottom:6, borderRadius:8 }} />
          {c.jobTitle && <p style={{ fontSize:13, color:"var(--text2)", fontWeight:700, margin:"0 0 4px" }}>{c.jobTitle}</p>}
          {c.department && <p style={{ fontSize:11, color:"var(--text3)", margin:"0 0 10px" }}>{c.department}</p>}
          <div style={{ display:"flex", gap:8, width:"100%", marginBottom:8 }}>
            <div style={{ flex:1, background:"rgba(201,168,76,.06)", borderRadius:8, padding:"6px 8px", textAlign:"center" }}>
              <p style={{ fontSize:9, color:"var(--text3)", margin:0 }}>🗓️ اليوم</p>
              <p style={{ fontSize:11, color:"var(--gold)", fontWeight:900, margin:0 }}>{new Date().toLocaleDateString("ar-SA", {weekday:"long"})}</p>
            </div>
            <div style={{ flex:1, background:"rgba(201,168,76,.06)", borderRadius:8, padding:"6px 8px", textAlign:"center" }}>
              <p style={{ fontSize:9, color:"var(--text3)", margin:0 }}>🕐 الوقت</p>
              <p style={{ fontSize:13, color:"var(--text)", fontWeight:900, margin:0 }}>{new Date().toLocaleTimeString("ar-SA", {hour:"2-digit", minute:"2-digit"})}</p>
            </div>
          </div>
          <button onClick={()=>setShowNotifsPage(true)} style={{ width:"100%", padding:"11px", borderRadius:10, background:notifs.length>0?"rgba(239,68,68,.12)":"rgba(255,128,33,.06)", color:notifs.length>0?"#f87171":"#FF8021", fontSize:13, fontWeight:700, border:"1px solid "+(notifs.length>0?"rgba(239,68,68,.3)":"rgba(255,128,33,.25)"), cursor:"pointer", fontFamily:"inherit", minHeight:44, display:"flex", alignItems:"center", justifyContent:"center", gap:10, position:"relative" }}>
            <span style={{ fontSize:20 }}>🔔</span>
            <span>{notifs.length>0 ? "لديك "+notifs.length+" إشعار"+(notifs.length>1?"ات":"") : "لا توجد إشعارات جديدة"}</span>
            {notifs.length>0 && <span style={{ position:"absolute", top:8, left:12, background:"#ef4444", color:"#fff", borderRadius:"50%", width:22, height:22, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:900 }}>{notifs.length}</span>}
          </button>
          {/* v37.86: بنر بصمة مع SSO — تسجيل دخول تلقائي */}
          <a href="https://b.hma.engineer" onClick={async(e)=>{
            e.preventDefault();
            const el = e.currentTarget;
            el.style.opacity = "0.6";
            try {
              const cu = window._currentUser || {};
              const res = await fetch("/api/sso?action=create", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  username: cu.username,
                  empIdNumber: c.idNumber || cu.linkedId || "",
                }),
                signal: AbortSignal.timeout(5000),
              });
              const data = await res.json();
              if (data && data.ok && data.redirectUrl) {
                window.open(data.redirectUrl, "_blank", "noopener,noreferrer");
              } else {
                // fallback: افتح بصمة بدون SSO
                window.open("https://b.hma.engineer", "_blank", "noopener,noreferrer");
              }
            } catch (err) {
              console.warn("SSO token failed:", err);
              window.open("https://b.hma.engineer", "_blank", "noopener,noreferrer");
            } finally {
              el.style.opacity = "1";
            }
          }} style={{ display:"block", textDecoration:"none", width:"100%", cursor:"pointer" }}>
            <div style={{ background:"linear-gradient(135deg, #0f1e3c 0%, #1a3a6e 40%, #2b5ea7 100%)", borderRadius:14, padding:"14px 18px", display:"flex", alignItems:"center", justifyContent:"space-between", position:"relative", overflow:"hidden", direction:"rtl", gap:10 }}>
              <div style={{ position:"absolute", top:0, right:0, width:180, height:"100%", background:"radial-gradient(ellipse at right, rgba(252,211,77,0.15) 0%, transparent 70%)", pointerEvents:"none" }}/>
              <div style={{ display:"flex", alignItems:"center", gap:12, position:"relative", zIndex:1, minWidth:0 }}>
                <div style={{ width:44, height:44, borderRadius:11, background:"linear-gradient(135deg, #FCD34D, #F59E0B)", display:"flex", alignItems:"center", justifyContent:"center", boxShadow:"0 2px 8px rgba(252,211,77,0.3)", flexShrink:0 }}>
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#1a3a6e" strokeWidth="2.5" strokeLinecap="round"><circle cx="12" cy="12" r="10"/><polyline points="12,6 12,12 16,14"/></svg>
                </div>
                <div style={{ minWidth:0 }}>
                  <div style={{ color:"#fff", fontSize:14, fontWeight:800, marginBottom:2 }}>بصمة HMA</div>
                  <div style={{ color:"#FCD34D", fontSize:10, fontWeight:600 }}>الحضور · الانصراف · المخالفات</div>
                </div>
              </div>
              <div style={{ position:"relative", background:"rgba(255,255,255,0.1)", border:"1px solid rgba(252,211,77,0.4)", padding:"7px 14px", borderRadius:10, color:"#FCD34D", fontSize:11, fontWeight:700, display:"flex", alignItems:"center", gap:6, zIndex:1, flexShrink:0 }}>
                فتح
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#FCD34D" strokeWidth="3" strokeLinecap="round"><polyline points="15,18 9,12 15,6"/></svg>
              </div>
            </div>
          </a>
          {/* v37.100: زر الرجوع لحساب المشرف — استخدام cu بدل currentUser */}
          {(window._adminViewingAsEmployee || cu?.role === "admin" || cu?.username === "admin" || cu?.role === "hr_manager" || cu?.role === "supervisor" || cu?.role === "assistant_supervisor") && (
            <button onClick={()=>{
              window._adminViewingAsEmployee = false;
              if (window._setMainView) window._setMainView("admin");
              else if (onBack) onBack();
            }}
              style={{ width:"100%", padding:"13px", borderRadius:10, background:"rgba(201,168,76,.12)", color:"var(--gold)", fontSize:15, fontWeight:900, border:"1px solid rgba(201,168,76,.4)", cursor:"pointer", fontFamily:"inherit", minHeight:48, display:"flex", alignItems:"center", justifyContent:"center", gap:10 }}>
              <span style={{ fontSize:22 }}>🛡️</span>
              <span>الرجوع لحساب المشرف</span>
            </button>
          )}
          {/* زر تواصل — للموظفين فقط */}
          <button onClick={()=>setShowTawasul(true)}
            style={{ width:"100%", padding:"13px", borderRadius:10, background:twslNotifCount>0?"rgba(239,68,68,.12)":"rgba(16,185,129,.12)", color:twslNotifCount>0?"#f87171":"#10b981", fontSize:15, fontWeight:900, border:"1px solid "+(twslNotifCount>0?"rgba(239,68,68,.4)":"rgba(16,185,129,.4)"), cursor:"pointer", fontFamily:"inherit", minHeight:48, display:"flex", alignItems:"center", justifyContent:"center", gap:10, position:"relative" }}>
            <span style={{ fontSize:22 }}>🤝</span>
            <span>تواصل — طلبات العمل الداخلية</span>
            {twslNotifCount>0 && <span style={{ position:"absolute", top:8, left:12, background:"#ef4444", color:"#fff", borderRadius:"50%", width:22, height:22, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:900 }}>{twslNotifCount}</span>}
          </button>
          {/* صف: إيميل + كود + طباعة */}
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", width:"100%", padding:"8px 12px", background:"rgba(255,255,255,.03)", borderRadius:10, border:"1px solid var(--b)", boxSizing:"border-box" }}>
            {c.email && <a href={"mailto:"+c.email} style={{ fontSize:11, color:"var(--text3)", textDecoration:"none" }}>✉️ {c.email}</a>}
            {c.hrCode && <span style={{ fontSize:11, background:"rgba(201,168,76,.15)", color:"var(--gold)", padding:"2px 8px", borderRadius:8, border:"1px solid rgba(201,168,76,.3)", fontWeight:700 }}>{c.hrCode}</span>}
            <button onClick={()=>exportProfileToPDF(c,"موظف")} style={{ width:30, height:30, borderRadius:8, background:"rgba(147,197,253,.06)", border:"1px solid rgba(147,197,253,.2)", color:"#93c5fd", fontSize:15, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }} title="طباعة">🖨️</button>
          </div>
          <div className="desktop-only" style={{ display:"none", width:"100%", gap:8, marginTop:4 }}>
            <button onClick={onJobs} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>💼 وظائف</button>
            <button onClick={()=>setShowSupport(true)} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(255,128,33,.4)", background:"rgba(255,128,33,.08)", color:"#FF8021", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>🎫 دعم</button>
            <button onClick={canEdit?()=>setEdit(p=>!p):editRequested?undefined:requestEdit} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(201,168,76,.4)", background:"rgba(201,168,76,.08)", color:"var(--gold)", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>{canEdit?(edit?"👁️ عرض":"✏️ تعديل"):editRequested?"⏳ انتظار":"🔒 تعديل"}</button>
            <button onClick={onBack} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.06)", color:"#f87171", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>🚪 خروج</button>
          </div>
        </div>
      ) : (
        /* ── هيدر المرشح — مطابق لهيدر الموظف ── */
        <div className="card" style={{ padding:"16px", marginBottom:16, display:"flex", flexDirection:"column", alignItems:"center", textAlign:"center", background:"linear-gradient(135deg,rgba(201,168,76,.08),rgba(201,168,76,.02))", border:"1px solid rgba(201,168,76,.2)" }}>
          <p style={{ fontWeight:900, fontSize:19, color:"var(--gold)", margin:"0 0 6px" }}>
            {(t.welcome||"مرحباً") + " " + (c.fullName ? c.fullName.split(" ").slice(0,2).join(" ") : "بك")}
          </p>
          <img src={HMA_LOGO_USER} alt="HMA" style={{ width:72, height:72, objectFit:"contain", marginBottom:6, borderRadius:8 }} />
          {c.jobTitle && <p style={{ fontSize:13, color:"var(--text2)", fontWeight:700, margin:"0 0 4px" }}>{c.jobTitle}</p>}
          {(!c.jobTitle && (c.specializations||[])[0]) && <p style={{ fontSize:13, color:"var(--text2)", fontWeight:700, margin:"0 0 4px" }}>{(c.specializations||[])[0]}</p>}
          <div style={{ display:"flex", gap:8, width:"100%", marginBottom:8 }}>
            <div style={{ flex:1, background:"rgba(201,168,76,.06)", borderRadius:8, padding:"6px 8px", textAlign:"center" }}>
              <p style={{ fontSize:9, color:"var(--text3)", margin:0 }}>🗓️ اليوم</p>
              <p style={{ fontSize:11, color:"var(--gold)", fontWeight:900, margin:0 }}>{new Date().toLocaleDateString("ar-SA", {weekday:"long"})}</p>
            </div>
            <div style={{ flex:1, background:"rgba(201,168,76,.06)", borderRadius:8, padding:"6px 8px", textAlign:"center" }}>
              <p style={{ fontSize:9, color:"var(--text3)", margin:0 }}>🕐 الوقت</p>
              <p style={{ fontSize:13, color:"var(--text)", fontWeight:900, margin:0 }}>{new Date().toLocaleTimeString("ar-SA", {hour:"2-digit", minute:"2-digit"})}</p>
            </div>
          </div>
          {/* صف: إيميل + كود + طباعة */}
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", width:"100%", padding:"8px 12px", background:"rgba(255,255,255,.03)", borderRadius:10, border:"1px solid var(--b)", boxSizing:"border-box", marginBottom:8 }}>
            {c.email && <a href={"mailto:"+c.email} style={{ fontSize:11, color:"var(--text3)", textDecoration:"none" }}>✉️ {c.email}</a>}
            {c.hrCode && <span style={{ fontSize:11, background:"rgba(201,168,76,.15)", color:"var(--gold)", padding:"2px 8px", borderRadius:8, border:"1px solid rgba(201,168,76,.3)", fontWeight:700 }}>{c.hrCode}</span>}
          </div>
          <button onClick={()=>setShowNotifsPage(true)} style={{ width:"100%", padding:"11px", borderRadius:10, background:notifs.length>0?"rgba(239,68,68,.12)":"rgba(255,128,33,.06)", color:notifs.length>0?"#f87171":"#FF8021", fontSize:13, fontWeight:700, border:"1px solid "+(notifs.length>0?"rgba(239,68,68,.3)":"rgba(255,128,33,.25)"), cursor:"pointer", fontFamily:"inherit", minHeight:44, display:"flex", alignItems:"center", justifyContent:"center", gap:10, position:"relative" }}>
            <span style={{ fontSize:20 }}>🔔</span>
            <span>{notifs.length>0 ? "لديك "+notifs.length+" إشعار"+(notifs.length>1?"ات":"") : "لا توجد إشعارات جديدة"}</span>
            {notifs.length>0 && <span style={{ position:"absolute", top:8, left:12, background:"#ef4444", color:"#fff", borderRadius:"50%", width:22, height:22, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:900 }}>{notifs.length}</span>}
          </button>
          {/* أزرار ديسكتوب */}
          <div className="desktop-only" style={{ display:"none", width:"100%", gap:8, marginTop:4 }}>
            <button onClick={onJobs} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>💼 وظائف</button>
            <button onClick={()=>setShowSupport(true)} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(255,128,33,.4)", background:"rgba(255,128,33,.08)", color:"#FF8021", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>🎫 دعم</button>
            <button onClick={()=>setEdit(p=>!p)} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(201,168,76,.4)", background:"rgba(201,168,76,.08)", color:"var(--gold)", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>{edit?"👁️ عرض":"✏️ تعديل"}</button>
            <button onClick={onBack} style={{ flex:1, padding:"9px", borderRadius:10, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.06)", color:"#f87171", fontWeight:700, fontSize:12, cursor:"pointer", fontFamily:"inherit" }}>🚪 خروج</button>
          </div>
        </div>
      )}

      
{/* ── Pipeline — للمرشحين فقط ── */}
      {!isEmployee && !edit && c.fullName && (
        <CandidatePipeline cand={c} onAcceptOffer={async(startDate)=>{
          const off = c.jobOffer;
          if(!off) return;
          const updated = {...c, jobOffer:{...off, acceptedAt:new Date().toISOString(), status:"accepted", confirmedStartDate:startDate}};
          await saveCandidate(updated);
          const pid = c.uid||c.idNumber||c.email;
          if(pid) addPersonEvent(pid,{type:"offer",text:"✅ المرشح وافق على العرض الوظيفي — تاريخ المباشرة: "+(startDate||"يحدد لاحقاً"),by:c.fullName||"",byRole:"candidate",private:false}).catch(()=>{});
          setC(updated);
        }} onOpenSupport={()=>{
          window._autoSupportType = "hr_offer";
          setShowSupport(true);
        }} />
      )}

      {/* ── تواصل — Full Screen ── */}
      {isEmployee && showTawasul && (
        <div style={{ position:"fixed", inset:0, background:"var(--dark)", zIndex:9998, overflowY:"auto", padding:16 }}>
          <div style={{ maxWidth:700, margin:"0 auto", paddingTop:16 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
              <h2 style={{ color:"var(--gold)", fontWeight:900, fontSize:18, margin:0 }}>🤝 تواصل</h2>
              <button onClick={()=>setShowTawasul(false)} style={{ width:36, height:36, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:18, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit" }}>✕</button>
            </div>
            <TawasulSection employees={twslEmps} currentUser={window._currentUser} />
          </div>
        </div>
      )}

      {/* ── صفحة الإشعارات ── */}
      {showNotifsPage && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"flex-start", justifyContent:"center", padding:16, overflowY:"auto" }}
          onClick={e=>{ if(e.target===e.currentTarget) setShowNotifsPage(false); }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:20, width:"100%", maxWidth:500, marginTop:20 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16, margin:0 }}>🔔 الإشعارات</p>
              <button onClick={()=>setShowNotifsPage(false)} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
            </div>
            {notifs.length===0 && <p style={{ fontSize:12, color:"var(--text3)", textAlign:"center", padding:24 }}>لا توجد إشعارات جديدة</p>}
            {notifs.map(n => (
              <div key={n.id} style={{ display:"flex", alignItems:"flex-start", gap:10, padding:"12px 14px", marginBottom:8, background:"rgba(201,168,76,.06)", border:"1px solid rgba(201,168,76,.2)", borderRadius:10 }}>
                <div style={{ flex:1 }}>
                  <p style={{ fontSize:13, fontWeight:700, color:"var(--text)", margin:"0 0 3px" }}>{n.message||n.text||""}</p>
                  {n.createdAt && <p style={{ fontSize:10, color:"var(--text3)", margin:0 }}>{new Date(n.createdAt).toLocaleDateString("ar-SA", {weekday:"short", day:"numeric", month:"long", hour:"2-digit", minute:"2-digit"})}</p>}
                </div>
                <button onClick={()=>dismissNotif(n.id)} style={{ background:"none", border:"none", color:"var(--text3)", cursor:"pointer", fontSize:18, padding:"0 4px", lineHeight:1, flexShrink:0 }}>✕</button>
              </div>
            ))}
            {notifs.length>0 && (
              <button onClick={async()=>{ await Promise.all(notifs.map(n=>markNotifRead(n.id).catch(()=>{}))); setNotifs([]); setShowNotifsPage(false); show("✅ تم تعليم الكل كمقروء"); }}
                className="btn btn-ghost btn-sm" style={{ width:"100%", marginTop:8 }}>✓ تعليم الكل كمقروء</button>
            )}
          </div>
        </div>
      )}

      {/* ── تكليفات + دوري في صف واحد ── */}
      {isEmployee && (
        <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:16 }}>
        <div className="card" style={{ border:"1px solid rgba(167,139,250,.3)", background:"rgba(167,139,250,.04)", padding:"14px 16px" }}>
          <p style={{ fontWeight:900, fontSize:13, color:"#a78bfa", marginBottom:10 }}>📋 تكليفات التقييم</p>
          {evalLoading && <div style={{ textAlign:"center", padding:8 }}><div className="loader" style={{ width:20, height:20 }}/></div>}
          {!evalLoading && evalTasks.length===0 && <p style={{ fontSize:11, color:"var(--text3)", textAlign:"center", padding:8 }}>لا توجد تكليفات حالياً</p>}
          {/* كل التكليفات — بطاقة موحّدة */}
          {evalTasks.map(t => t._cand ? (
            <UnifiedCandCard key={t.id} cand={t._cand} allAssessments={empAllAsmts} evTasks={evalTasks} onOpen={()=>{ setSelTask(t); setShowTaskCand(true); }} />
          ) : (
            <div key={t.id} onClick={()=>{ setSelTask(t); setShowTaskCand(true); }}
              style={{ padding:"10px 12px", marginBottom:6, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:10, cursor:"pointer" }}>
              <p style={{ fontWeight:700, fontSize:13, color:"var(--gold)" }}>{t.candidateName}</p>
              <p style={{ fontSize:10, color:"var(--text3)" }}>كُلِّفت من: {t.assignedBy}</p>
            </div>
          ))}
        </div>
        <div className="card" style={{ border:"1px solid rgba(96,165,250,.3)", background:"rgba(96,165,250,.03)", padding:"14px 16px" }}>
          <p style={{ fontWeight:900, fontSize:13, color:"#60a5fa", margin:"0 0 10px" }}>⭐ التقييم الدوري</p>
          {periodicLoading && <div style={{ textAlign:"center", padding:8 }}><div className="loader" style={{ width:20, height:20 }}/></div>}
          {!periodicLoading && (<>
            {/* مدراء / مشرفون */}
            {periodicPeople.filter(p=>p.type==="manager").length>0 && (
              <div style={{ marginBottom:8 }}>
                <p style={{ fontSize:10, color:"var(--text3)", fontWeight:700, marginBottom:5 }}>👔 مديرك / مشرفك</p>
                {periodicPeople.filter(p=>p.type==="manager").map(p=>(
                  <div key={p.uid||p.fullName} onClick={()=>{ setPeriodicSel(p); setShowPeriodicForm(true); }}
                    style={{ padding:"8px 10px", marginBottom:4, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:9, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                    <p style={{ fontWeight:700, fontSize:12, margin:0 }}>{p.fullName}</p>
                    <span style={{ fontSize:10, color:"#60a5fa" }}>تقييم ←</span>
                  </div>
                ))}
              </div>
            )}
            {/* موظفون تحت الإدارة */}
            {periodicPeople.filter(p=>p.type==="subordinate").length>0 && (
              <div>
                <p style={{ fontSize:10, color:"var(--text3)", fontWeight:700, marginBottom:5 }}>👥 تحت إدارتك</p>
                {periodicPeople.filter(p=>p.type==="subordinate").map(p=>(
                  <div key={p.uid||p.fullName} onClick={()=>{ setPeriodicSel(p); setShowPeriodicForm(true); }}
                    style={{ padding:"8px 10px", marginBottom:4, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:9, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                    <div>
                      <p style={{ fontWeight:700, fontSize:12, margin:0 }}>{p.fullName}</p>
                      {p.department && <p style={{ fontSize:10, color:"var(--text3)", margin:0 }}>{p.department}</p>}
                    </div>
                    <span style={{ fontSize:10, color:"#60a5fa" }}>تقييم ←</span>
                  </div>
                ))}
              </div>
            )}
            {periodicPeople.length===0 && (
              <p style={{ fontSize:11, color:"var(--text3)", textAlign:"center", padding:8 }}>لا يوجد أشخاص للتقييم</p>
            )}
          </>)}
        </div>
        </div>
      )}

      {/* ── اختيار شخص للتقييم الدوري ── */}
      {showPeriodicSel && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}
          onClick={e=>{ if(e.target===e.currentTarget){ setShowPeriodicSel(false); setPeriodicSel(null); } }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--b)", borderRadius:16, padding:22, width:"100%", maxWidth:420, maxHeight:"80vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:15, margin:0 }}>⭐ اختر الشخص للتقييم</p>
              <button onClick={()=>{ setShowPeriodicSel(false); setPeriodicSel(null); }} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
            </div>
            {periodicPeople.length===0 && <p style={{ color:"var(--text3)", fontSize:12, textAlign:"center" }}>جاري التحميل...</p>}
            {periodicPeople.filter(p=>p.type==="manager").length>0 && <p style={{ fontSize:11, color:"var(--text3)", fontWeight:700, marginBottom:6 }}>👔 المدراء / المشرفون</p>}
            {periodicPeople.filter(p=>p.type==="manager").map(p=>(
              <div key={p.uid||p.fullName} onClick={()=>{ setPeriodicSel(p); setShowPeriodicSel(false); setShowPeriodicForm(true); }}
                style={{ padding:"10px 12px", marginBottom:5, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:10, cursor:"pointer" }}>
                <p style={{ fontWeight:700, fontSize:13, margin:0 }}>{p.fullName}</p>
              </div>
            ))}
            {periodicPeople.filter(p=>p.type==="subordinate").length>0 && <p style={{ fontSize:11, color:"var(--text3)", fontWeight:700, margin:"10px 0 6px" }}>👥 الموظفون</p>}
            {periodicPeople.filter(p=>p.type==="subordinate").map(p=>(
              <div key={p.uid||p.fullName} onClick={()=>{ setPeriodicSel(p); setShowPeriodicSel(false); setShowPeriodicForm(true); }}
                style={{ padding:"10px 12px", marginBottom:5, background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:10, cursor:"pointer" }}>
                <p style={{ fontWeight:700, fontSize:13, margin:0 }}>{p.fullName}</p>
                {p.department && <p style={{ fontSize:10, color:"var(--text3)", margin:0 }}>{p.department}</p>}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── النموذج الموحد للتقييم الدوري (KPI المعتمد) ── */}
      {showPeriodicForm && periodicSel && (
        <PeriodicEvalForm
          target={periodicSel}
          evaluatorName={c.fullName||""}
          onSubmit={submitPeriodicEval}
          onClose={()=>{ setShowPeriodicForm(false); setPeriodicSel(null); }}
        />
      )}
      {/* ── عرض ملف المرشح (قراءة فقط) ── */}
      {/* ── عرض ملف المرشح للموظف المكلّف عبر CandEvalPage ── */}
      {showTaskCand && selTask?._cand && selTask._cand.fullName && (
        <CandEvalPage
          cand={selTask._cand}
          employeeTask={selTask}
          onClose={()=>{ setShowTaskCand(false); setSelTask(null); }}
          onSave={async (updCand) => {
            await saveCandidate(updCand).catch(()=>{});
            setEvalTasks(prev => prev.map(t => t.id===selTask.id ? { ...t, status:"pending_approval", _cand:updCand } : t));
          }}
        />
      )}

      {/* ── نموذج التقييم الموحد (CandEvalPage) ── */}
      {showTaskEval && selTask && selTask._cand && selTask._cand.fullName && (
        <CandEvalPage
          cand={selTask._cand}
          employeeTask={selTask}
          onClose={()=>{ setShowTaskEval(false); setSelTask(null); }}
          onSave={async (updCand) => {
            await saveCandidate(updCand).catch(()=>{});
            setEvalTasks(prev => prev.map(t => t.id===selTask.id ? { ...t, status:"pending_approval", _cand:updCand } : t));
          }}
        />
      )}
      {showTaskEval && selTask && selTask._cand && !selTask._cand.fullName && (
        <FullEvalForm
          cand={selTask._cand}
          task={selTask}
          onSubmit={submitEvalTask}
          onClose={()=>{ setShowTaskEval(false); setSelTask(null); }}
        />
      )}

      {/* ── Support MODAL ── */}
      {showSupport && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.6)", backdropFilter:"blur(6px)", zIndex:9998, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}
          onClick={e=>{ if(e.target===e.currentTarget) setShowSupport(false); }}>
          <div className="card" style={{ maxWidth:500, width:"100%", padding:24, maxHeight:"85vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
              <div className="sec" style={{ marginBottom:0 }}>🎫 تذكرة دعم فني</div>
              <button onClick={()=>{ setShowSupport(false); delete window._autoSupportType; }} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit" }}>✕</button>
            </div>
            <CandSupportForm
              key={showSupport ? "open" : "closed"}
              candidateId={c.uid || c.idNumber || c.email}
              candidateName={c.fullName}
              hrCode={c.hrCode}
              onSent={()=>{ setTimeout(()=>setShowSupport(false), 2000); delete window._autoSupportType; }}
            />
          </div>
        </div>
      )}

      {/* ── Old page below header ── */}
      {edit
        ? <CandForm initial={c} onSave={save} isNew={isNew} libs={libs} sessionEmail={c.email} lang={lang} />
        : <CandProfile c={c} onEdit={isEmployee?(canEdit?()=>setEdit(true):null):()=>setEdit(true)} libs={libs} specsMap={specsMap} onSave={isEmployee?(canEdit?onSaveCV:null):onSaveCV} lang={lang} isEmployee={isEmployee} />
      }

      {/* Mobile footer */}
      <div className="mobile-footer-bar" style={{ justifyContent:"space-around", padding:"6px 8px", gap:4 }}>
        {isEmployee ? (<>
          {/* 4 أزرار للموظف */}
          <button onClick={onJobs} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>
            <span style={{ fontSize:20 }}>💼</span>
            <span style={{ fontSize:9, fontWeight:700 }}>وظائف</span>
          </button>
          <button onClick={()=>setShowNotifsPage(true)} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid "+(notifs.length>0?"rgba(239,68,68,.4)":"rgba(255,128,33,.2)"), background:notifs.length>0?"rgba(239,68,68,.08)":"rgba(255,128,33,.04)", color:notifs.length>0?"#f87171":"#FF8021", cursor:"pointer", fontFamily:"inherit", position:"relative" }}>
            <span style={{ fontSize:20 }}>🔔</span>
            <span style={{ fontSize:9, fontWeight:700 }}>إشعارات</span>
            {notifs.length>0 && <span style={{ position:"absolute", top:4, left:"50%", marginLeft:6, background:"#ef4444", color:"#fff", borderRadius:"50%", width:16, height:16, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, fontWeight:900 }}>{notifs.length}</span>}
          </button>
          <button onClick={canEdit ? ()=>setEdit(p=>!p) : editRequested ? undefined : requestEdit}
            disabled={editRequested && !canEdit}
            style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid "+(canEdit?"rgba(201,168,76,.4)":"rgba(251,191,36,.3)"), background:canEdit?"rgba(201,168,76,.08)":"rgba(251,191,36,.05)", color:canEdit?"var(--gold)":editRequested?"var(--text3)":"#fbbf24", cursor:editRequested&&!canEdit?"not-allowed":"pointer", fontFamily:"inherit", opacity:editRequested&&!canEdit?0.6:1 }}>
            <span style={{ fontSize:20 }}>{canEdit?(edit?"👁️":"✏️"):editRequested?"⏳":"🔒"}</span>
            <span style={{ fontSize:9, fontWeight:700 }}>{canEdit?(edit?"عرض":"تعديل"):editRequested?"انتظار":"طلب تعديل"}</span>
          </button>
          <button onClick={onBack} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.06)", color:"#f87171", cursor:"pointer", fontFamily:"inherit" }}>
            <span style={{ fontSize:20 }}>🚪</span>
            <span style={{ fontSize:9, fontWeight:700 }}>خروج</span>
          </button>
        </>) : (<>
          {/* 4 أزرار للمرشح — تعديل دائماً متاح */}
          <button onClick={onJobs} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>
            <span style={{ fontSize:20 }}>💼</span>
            <span style={{ fontSize:9, fontWeight:700 }}>وظائف</span>
          </button>
          <button onClick={()=>setShowNotifsPage(true)} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid "+(notifs.length>0?"rgba(239,68,68,.4)":"rgba(255,128,33,.2)"), background:notifs.length>0?"rgba(239,68,68,.08)":"rgba(255,128,33,.04)", color:notifs.length>0?"#f87171":"#FF8021", cursor:"pointer", fontFamily:"inherit", position:"relative" }}>
            <span style={{ fontSize:20 }}>🔔</span>
            <span style={{ fontSize:9, fontWeight:700 }}>إشعارات</span>
            {notifs.length>0 && <span style={{ position:"absolute", top:4, left:"50%", marginLeft:6, background:"#ef4444", color:"#fff", borderRadius:"50%", width:16, height:16, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, fontWeight:900 }}>{notifs.length}</span>}
          </button>
          <button onClick={()=>setEdit(p=>!p)} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid rgba(201,168,76,.4)", background:"rgba(201,168,76,.08)", color:"var(--gold)", cursor:"pointer", fontFamily:"inherit" }}>
            <span style={{ fontSize:20 }}>{edit?"👁️":"✏️"}</span>
            <span style={{ fontSize:9, fontWeight:700 }}>{edit?"عرض":"تعديل"}</span>
          </button>
          <button onClick={onBack} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.06)", color:"#f87171", cursor:"pointer", fontFamily:"inherit" }}>
            <span style={{ fontSize:20 }}>🚪</span>
            <span style={{ fontSize:9, fontWeight:700 }}>خروج</span>
          </button>
        </>)}
      </div>
    </div>
  );
}

// ── EventsLog — admin-only activity log with comments ────────────────────────
function EventsLog({ personId, currentUser, isAdmin=true }) {
  const [events, setEvents]     = useState([]);
  const [loading, setLoading]   = useState(true);
  const [tab, setTab]           = useState("all");
  const [comment, setComment]   = useState("");
  const [noteType, setNoteType] = useState("note");       // note | recommendation
  const [directedTo, setDirectedTo] = useState("");       // who to direct it to
  const [admins, setAdmins]     = useState([]);
  const [saving, setSaving]     = useState(false);
  const { show, toastEl }       = useToast();

  useEffect(() => {
    if (!personId) { setLoading(false); return; }
    getPersonEvents(personId).then(e => { setEvents(e); setLoading(false); });
    getAllUsers().then(users => setAdmins(users.filter(u => u.role === "admin" || u.role === "hr_manager" || u.role === "supervisor" || u.role === "assistant_supervisor")));
  }, [personId]);

  const actor = currentUser || window._currentUser;

  const addComment = async () => {
    if (!comment.trim()) return;
    setSaving(true);
    const entry = await addPersonEvent(personId, {
      type: noteType,
      text: comment.trim(),
      by: actor?.displayName || actor?.username || "المشرف",
      byRole: actor?.role || "admin",
      private: true,
      meta: directedTo ? { directedTo } : {},
    });
    setEvents(p => [entry, ...p]);
    if (directedTo) {
      try {
        const cached = JSON.parse(sessionStorage.getItem("_directed_events_cache") || "[]");
        cached.unshift({ ...entry, directedTo, personId, personName: "" });
        sessionStorage.setItem("_directed_events_cache", JSON.stringify(cached.slice(0,50)));
      } catch {}
    }
    setComment(""); setDirectedTo("");
    setSaving(false);
    show("✅ تم الحفظ");
  };

  const TYPE_ICONS = {
    note:          { icon:"💬", label:"تعليق داخلي",    color:"#a78bfa" },
    recommendation:{ icon:"⭐", label:"توصية",          color:"#f59e0b" },
    cv_upload:     { icon:"📄", label:"رفع سيرة ذاتية", color:"#60a5fa" },
    interview:     { icon:"🗓️", label:"مقابلة",         color:"#e8eaf0" },
    eval:          { icon:"🤖", label:"تقييم",          color:"#e8eaf0" },
    ticket:        { icon:"🎫", label:"تذكرة دعم",      color:"#fb923c" },
    data_check:    { icon:"✅", label:"تدقيق بيانات",   color:"#4ade80" },
    status_change: { icon:"🔄", label:"تغيير حالة",     color:"#94a3b8" },
  };

  const filtered = tab === "recs"
    ? events.filter(e => e.type === "recommendation" || e.type === "eval")
    : events;
  const [showAllEvents, setShowAllEvents] = useState(false);
  const displayed = showAllEvents ? filtered : filtered.slice(0, 2);
  const hasMore = filtered.length > 2;

  if (loading) return <div style={{ textAlign:"center", padding:32 }}><div className="loader"/></div>;

  return (
    <div>
      {toastEl}

      {/* ── Add note/recommendation (admin only) ── */}
      {isAdmin && (
        <div style={{ marginBottom:16, background:"rgba(167,139,250,.05)", border:"1px solid rgba(167,139,250,.2)", borderRadius:10, padding:"14px 16px" }}>
          <p style={{ fontSize:12, color:"#c4b5fd", fontWeight:700, marginBottom:10 }}>🔒 تعليق داخلي — لا يراه المرشح/الموظف</p>

          {/* Note type selector */}
          <div style={{ display:"flex", gap:8, marginBottom:10 }}>
            {[["note","💬 تعليق"],["recommendation","⭐ توصية"]].map(([v,l])=>(
              <button key={v} onClick={()=>setNoteType(v)}
                style={{ padding:"5px 14px", borderRadius:20, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700,
                  background:noteType===v?"rgba(201,168,76,.15)":"none",
                  border:"1px solid "+(noteType===v?"rgba(201,168,76,.5)":"var(--b)"),
                  color:noteType===v?"var(--gold)":"var(--text3)" }}>
                {l}
              </button>
            ))}
          </div>

          <textarea value={comment} onChange={e=>setComment(e.target.value)} rows={3}
            placeholder={noteType==="recommendation"
              ? "اكتب توصيتك... مثال: يطلب 11,000 والسلم يحدد 10,000 ريال"
              : "اكتب ملاحظة داخلية..."}
            style={{ marginBottom:10, resize:"vertical" }} />

          {/* Direction field */}
          <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
            <select value={directedTo} onChange={e=>setDirectedTo(e.target.value)}
              style={{ flex:"1 1 180px", fontSize:12 }}>
              <option value="">↩️ يوجَّه إلى (اختياري)</option>
              <option value="all">📢 كل المشرفين والمدير العام</option>
              {admins.map(a=>(
                <option key={a.id} value={a.username}>{a.displayName||a.username}</option>
              ))}
            </select>
            <button onClick={addComment} disabled={saving||!comment.trim()} className="btn btn-gold btn-sm">
              {saving?"⏳ جاري الحفظ...":"💾 حفظ"}
            </button>
          </div>
        </div>
      )}

      {/* ── Filter tabs ── */}
      <div style={{ display:"flex", gap:6, marginBottom:14 }}>
        <button onClick={()=>setTab("all")} className={"tab-btn "+(tab==="all"?"tab-on":"tab-off")}>📋 كل الأحداث</button>
        <button onClick={()=>setTab("recs")} className={"tab-btn "+(tab==="recs"?"tab-on":"tab-off")}>⭐ التوصيات والتقييمات</button>
      </div>

      {/* ── Events list ── */}
      {filtered.length === 0 ? (
        <div style={{ textAlign:"center", padding:32 }}>
          <p style={{ fontSize:28, marginBottom:8 }}>{tab==="recs"?"⭐":"📋"}</p>
          <p style={S.txt3s13}>
            {tab==="recs" ? "لا توجد توصيات أو تقييمات بعد" : "لا توجد أحداث — ستُسجَّل تلقائياً عند رفع السيرة والتقييم..."}
          </p>
        </div>
      ) : (
        <div style={S.flexCol8}>
          {displayed.map(ev => {
            const t = TYPE_ICONS[ev.type] || TYPE_ICONS.note;
            return (
              <div key={ev.id} style={{ display:"flex", gap:12, padding:"12px 14px",
                background: ev.type==="note"||ev.type==="recommendation" ? "rgba(167,139,250,.05)" : "var(--glass)",
                border:"1px solid "+(ev.type==="note"||ev.type==="recommendation"?"rgba(167,139,250,.2)":"var(--b)"),
                borderRadius:10, borderRight:"3px solid "+t.color }}>
                <span style={{ fontSize:20, flexShrink:0, lineHeight:1.4 }}>{t.icon}</span>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:4, marginBottom:5 }}>
                    <span style={{ fontSize:11, fontWeight:700, color:t.color, padding:"2px 9px", borderRadius:8,
                      background:t.color+"15", border:"1px solid "+t.color+"30" }}>{t.label}</span>
                    <span style={{ fontSize:10, color:"var(--text3)" }}>
                      {new Date(ev.at).toLocaleDateString("ar-SA",{year:"numeric",month:"short",day:"numeric"})}
                      {" · "}
                      {new Date(ev.at).toLocaleTimeString("ar-SA",{hour:"2-digit",minute:"2-digit"})}
                    </span>
                  </div>
                  <p style={{ fontSize:13, color:"var(--text)", lineHeight:1.7, marginBottom:5 }}>{ev.text}</p>
                  <div style={{ display:"flex", gap:10, flexWrap:"wrap", fontSize:11, color:"var(--text3)" }}>
                    {ev.by && <span>👤 {ev.by}</span>}
                    {ev.meta?.score && <span>• درجة: <strong style={{ color:"var(--gold)" }}>{ev.meta.score}/100</strong></span>}
                    {ev.meta?.rec && <span>• توصية: <strong style={{ color:"#f59e0b" }}>{ev.meta.rec}</strong></span>}
                    {ev.meta?.directedTo && (
                      <span style={{ color:"#60a5fa" }}>
                        ↩️ يوجَّه إلى: {ev.meta.directedTo === "all" ? "كل المشرفين" : ev.meta.directedTo}
                      </span>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
          {hasMore && !showAllEvents && <button onClick={()=>setShowAllEvents(true)} style={{ width:"100%", padding:"8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--gold)", cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700 }}>▾ المزيد ({filtered.length - 2} حدث)</button>}
          {showAllEvents && filtered.length > 2 && <button onClick={()=>setShowAllEvents(false)} style={{ width:"100%", padding:"8px", borderRadius:8, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700 }}>▴ عرض أقل</button>}
        </div>
      )}
    </div>
  );
}

// ── InlinePendingTags — shows + approves pending tags from inside InlineViewer ─
function InlinePendingTags({ personId, libs, saveLibs, setCands, candidates }) {
  const [pending, setPending]   = useState(null); // null=loading, []=none
  const { show, toastEl }       = useToast();

  useEffect(() => {
    if (!personId) { setPending([]); return; }
    getPendingTags(personId).then(r => {
      const tags = r?.tags || [];
      setPending(tags);
      // 🔧 Auto-clear stale _hasPendingTags flag
      if (tags.length === 0) {
        const cand = (candidates||[]).find(c => (c.uid||c.idNumber||c.email) === personId);
        if (cand && cand._hasPendingTags) {
          const upd = { ...cand, _hasPendingTags: false };
          saveCandidate(upd).catch(()=>{});
          if (setCands) setCands(p => p.map(x => (x.uid||x.idNumber||x.email) === personId ? upd : x));
        }
      }
    }).catch(()=>setPending([]));
  }, [personId]);

  if (!pending || pending.length === 0) return null;

  const approveTag = async (tag, enVal, arVal, parentSpecLabel) => {
    const finalAr = arVal || tag.ar || tag.label;
    const finalEn = enVal || tag.en || "";

    if (saveLibs && libs) {
      const libKey = { biSpec:"specs", biDept:"jobTypes", biSkill:"skills", biSW:"software", biProj:"projectTypes", biCert:"certifications" }[tag.field];
      if (libKey) {
        // 🔒 Load fresh libs from Redis to prevent stale overwrite
        const freshLibs = await db.get("libs") || libs;
        const updated = { ...freshLibs };
        if (libKey === "specs") {
          if (parentSpecLabel) {
            updated.specs = (updated.specs||[]).map(s =>
              s.label === parentSpecLabel
                ? { ...s, subs: [...(s.subs||[]).filter(sub=>(typeof sub==="object"?sub.ar:sub).toLowerCase()!==finalAr.toLowerCase()), { ar:finalAr, en:finalEn }] }
                : s
            );
          } else {
            if (!(updated.specs||[]).some(s=>s.label.toLowerCase()===finalAr.toLowerCase())) {
              updated.specs = [...(updated.specs||[]), { id:"spec_"+Date.now(), label:finalAr, icon:"🏗️", aliases:[finalEn], subs:[] }];
            }
          }
        } else {
          const objFields = ["software","certifications","skills","projectTypes","jobTypes"];
          const isObj = objFields.includes(libKey);
          if (!(updated[libKey]||[]).some(l=>(typeof l==="object"?(l.ar||l.label||""):(l||"")).toLowerCase()===finalAr.toLowerCase())) {
            updated[libKey] = [...(updated[libKey]||[]), isObj ? { ar:finalAr, en:finalEn } : finalAr];
          }
        }
        // ✅ حفظ التصنيفات عند اعتماد المشرف — هذا إجراء يدوي وليس تلقائي
        await saveLibs(updated).catch(()=>{});
      }
    }

    const cand = (candidates||[]).find(x=>(x.idNumber||x.email)===personId||x.email===personId);
    if (cand) {
      const bf = tag.field;
      const existing = cand[bf]||[];
      if (!existing.some(t=>(t.ar||t.en||"").toLowerCase()===finalAr.toLowerCase())) {
        const upd = { ...cand, [bf]: [...existing, { ar:finalAr, en:finalEn, approved:true }] };
        await saveCandidate(upd).catch(()=>{});
        if (setCands) setCands(p=>p.map(x=>(x.idNumber||x.email)===(upd.idNumber||upd.email)?upd:x));
      }
    }

    const tagKey = (tag.label||"") + "|" + (tag.field||"");
    const remaining = pending.filter(t=>((t.label||"") + "|" + (t.field||"")) !== tagKey);
    setPending(remaining);
    if (remaining.length === 0) {
      await deletePendingTags(personId).catch(()=>{});
      // clear _hasPendingTags
      const c2 = cand || (candidates||[]).find(x=>(x.idNumber||x.email)===personId||x.email===personId);
      if (c2 && setCands) {
        const cleared = { ...c2, _hasPendingTags: false };
        await saveCandidate(cleared).catch(()=>{});
        setCands(p=>p.map(x=>(x.idNumber||x.email)===(cleared.idNumber||cleared.email)?cleared:x));
      }
    } else {
      await replacePendingTags(personId, remaining).catch(()=>{});
    }
    show("✅ تم الاعتماد وتحديث الملف");
  };

  const rejectTag = async (tag) => {
    const tagKey = (tag.label||"") + "|" + (tag.field||"");
    const remaining = pending.filter(t=>((t.label||"") + "|" + (t.field||"")) !== tagKey);
    setPending(remaining);
    if (remaining.length === 0) {
      await deletePendingTags(personId).catch(()=>{});
      const cand = (candidates||[]).find(x=>(x.idNumber||x.email)===personId||x.email===personId);
      if (cand && setCands) {
        const cleared = { ...cand, _hasPendingTags: false };
        await saveCandidate(cleared).catch(()=>{});
        setCands(p=>p.map(x=>(x.idNumber||x.email)===(cleared.idNumber||cleared.email)?cleared:x));
      }
    }
    else await replacePendingTags(personId, remaining).catch(()=>{});
  };

  const replaceTag = async (tag, rep) => {
    const cand = (candidates||[]).find(x=>(x.idNumber||x.email)===personId||x.email===personId);
    if (cand) {
      const bf = tag.field;
      const existing = cand[bf]||[];
      if (!existing.some(t=>(t.ar||t.en||"").toLowerCase()===rep.toLowerCase())) {
        const upd = { ...cand, [bf]: [...existing, { ar:rep, en:"", approved:true }] };
        await saveCandidate(upd).catch(()=>{});
        if (setCands) setCands(p=>p.map(x=>(x.idNumber||x.email)===(upd.idNumber||upd.email)?upd:x));
      }
    }
    await rejectTag(tag);
    show("✅ تم الاستبدال");
  };

  return (
    <div style={{ marginBottom:14, border:"2px solid rgba(251,146,60,.3)", borderRadius:12, overflow:"hidden" }}>
      {toastEl}
      <div style={{ background:"rgba(251,146,60,.08)", padding:"10px 14px", borderBottom:"1px solid rgba(251,146,60,.2)" }}>
        <p style={{ fontWeight:800, color:"#fb923c", fontSize:13 }}>
          🏷️ {pending.length} تصنيف يحتاج مراجعة
        </p>
        <p style={{ fontSize:11, color:"var(--text3)", marginTop:2 }}>استخرجها الذكاء الاصطناعي — غير موجودة في المكتبة</p>
      </div>
      <div style={{ padding:"10px 14px", display:"flex", flexDirection:"column", gap:8 }}>
        {pending.map((tag, i) => (
          <PendingTagRow key={(tag.label||"")+"_"+(tag.field||"")+"_"+i} tag={tag} libs={libs}
            onApprove={(en,ar,parent)=>approveTag(tag,en,ar,parent)}
            onReject={()=>rejectTag(tag)}
            onReplace={(rep)=>replaceTag(tag,rep)} />
        ))}
      </div>
    </div>
  );
}

// ── InlineViewer — unified inline view/edit panel for candidates & employees ──
function InlineViewer({ record, type, libs, specsMap, onSave, onDelete, onEval, evalLoad, onClose }) {
  const isNew = !record.fullName && !record.uid && !record.idNumber;
  const [editMode, setEditMode] = useState(isNew);
  const [tab, setTab] = useState("info");
  const [showLastEval, setShowLastEval] = useState(false);
  const [showMsg, setShowMsg] = useState(false);
  const [showAllEvals, setShowAllEvals] = useState(false);
  const [showAssignEval, setShowAssignEval] = useState(false);
  const [showFullEval, setShowFullEval] = useState(false);
  const [showCandEvalPage, setShowCandEvalPage] = useState(false);
  const { show, toastEl } = useToast();
  const isEmp = type === "employee";
  const isAdmin = window._currentUser?.username === "admin" || window._currentUser?.role === "hr_manager";

  const save = async (data) => {
    await onSave(data);
    setEditMode(false);
    show("✅ تم الحفظ");
  };

  const VIEW_TABS = [
    { id:"info",    icon:"👤", label:"البيانات الأساسية" },
    { id:"exp",     icon:"💼", label:"الخبرة" },
    { id:"tags",    icon:"🏷️", label:"التصنيفات" },
    { id:"cv",      icon:"📄", label:"ملفات السيرة الذاتية" },
    { id:"history", icon:"📋", label:"سجل الأحداث" },
    ...(isEmp ? [{ id:"eval", icon:"⭐", label:"التقييم" }] : []),
    ...(isEmp ? [{ id:"dev", icon:"🔬", label:"التطوير والابتكار" }] : []),
  ];

  const EDIT_TABS = [
    { id:"info",    icon:"👤", label:"البيانات الأساسية" },
    { id:"exp",     icon:"💼", label:"الخبرة" },
    { id:"tags",    icon:"🏷️", label:"التصنيفات" },
    { id:"cv",      icon:"📄", label:"ملفات السيرة الذاتية" },
    { id:"history", icon:"📋", label:"سجل الأحداث" },
    ...(isEmp ? [{ id:"eval", icon:"⭐", label:"التقييم" }] : []),
    ...(isEmp ? [{ id:"dev", icon:"🔬", label:"التطوير والابتكار" }] : []),
  ];

  const TABS = editMode ? EDIT_TABS : VIEW_TABS;
  const ev = record.evaluation || record.empEvaluation || null;
  const _allScores = [...(record.aiEvalHistory||[]).filter(h=>h.score).map(h=>h.score), ...Object.values(record.stageEvaluations||{}).flatMap(ev2=>(ev2.evaluations||[ev2]).filter(e=>e.total).map(e=>e.total)), ...(record.evalTaskResults||[]).filter(t=>t.totalScore).map(t=>t.totalScore), ...(record.examScore?[record.examScore]:[])];
  const overallScore = _allScores.length ? Math.round(_allScores.reduce((a,b)=>a+b,0)/_allScores.length) : (ev?.score || 0);
  const initials = (record.fullName||"?").split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase();

  const today = new Date();
  const daysLeft = record.contractEnd ? Math.floor((new Date(record.contractEnd)-today)/86400000) : null;

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.5)", backdropFilter:"blur(6px)", zIndex:8888, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}
      onClick={e=>{ if(e.target===e.currentTarget && onClose) onClose(); }}>
      {toastEl}
      <div className="fade" style={{ width:"100%", maxWidth:900, maxHeight:"92vh", overflowY:"auto", overflowX:"hidden", background:"var(--dark2,#2c2c2e)", border:"1px solid rgba(255,255,255,.1)", borderRadius:18, boxShadow:"0 24px 80px rgba(0,0,0,.7)", WebkitOverflowScrolling:"touch", position:"relative" }}>
      {showMsg && <GlobalQuickMessage person={record} onClose={()=>setShowMsg(false)} />}
      {showLastEval && record.evaluation && (
        <EvalEditor
          cand={record}
          preload={record.evaluation}
          onSave={async (ev) => {
            const upd = { ...record, evaluation: ev, evaluatedAt: new Date().toISOString() };
            await saveCandidate(upd);
            onSave(upd);
            setShowLastEval(false);
          }}
          onClose={() => setShowLastEval(false)}
        />
      )}

      {/* ── Hero header ── */}
      {isNew ? (
        <div style={{ padding:"16px 20px", background:"linear-gradient(135deg,rgba(34,197,94,.08),rgba(34,197,94,.02))", borderBottom:"1px solid rgba(34,197,94,.2)", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div>
            <p style={{ fontSize:18, fontWeight:900, color:"#4ade80" }}>{type==="employee"?"➕ إضافة موظف جديد":"➕ إضافة مرشح جديد"}</p>
            <p style={{ fontSize:12, color:"var(--text3)", marginTop:4 }}>عبّئ البيانات في التبويبات أدناه ثم اضغط حفظ</p>
          </div>
          {onClose && <button onClick={onClose} className="btn btn-sm" style={{ width:32, height:32, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.4)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit", padding:0 }} title="إغلاق">✕</button>}
        </div>
      ) : (
      <div style={{ padding:"12px 16px", background:"linear-gradient(135deg,rgba(201,168,76,.1),rgba(201,168,76,.03))", borderBottom:"1px solid rgba(201,168,76,.15)", position:"relative" }}>
        {/* Close button — fixed top-left */}
        {onClose && <button onClick={onClose} style={{ position:"absolute", top:10, left:10, width:28, height:28, borderRadius:"50%", background:"rgba(239,68,68,.15)", border:"1px solid rgba(239,68,68,.4)", color:"#f87171", fontSize:14, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit", padding:0, zIndex:5 }} title="إغلاق">✕</button>}
        <div style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
          {/* Avatar */}
          <div style={{ width:44, height:44, borderRadius:"50%", background:"linear-gradient(135deg,#c9a84c,#a8893a)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, fontWeight:900, color:"#0b0f1a", flexShrink:0, boxShadow:"0 4px 14px rgba(201,168,76,.3)" }}>
            {initials}
          </div>
          {/* Info */}
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:2, flexWrap:"wrap" }}>
              <h3 style={{ fontSize:15, fontWeight:900, color:"var(--gold)", margin:0 }}>{record.fullName||"—"}</h3>
              {!isEmp && overallScore > 0 && (
                <span onClick={()=>setShowCandEvalPage(true)} style={{ fontSize:11, fontWeight:700, padding:"1px 6px", borderRadius:8, cursor:"pointer",
                  background:overallScore>=81?"rgba(34,197,94,.15)":overallScore>=61?"rgba(245,158,11,.15)":"rgba(239,68,68,.15)",
                  color:overallScore>=81?"#4ade80":overallScore>=61?"#f59e0b":"#f87171",
                  border:"1px solid "+(overallScore>=81?"rgba(34,197,94,.3)":overallScore>=61?"rgba(245,158,11,.3)":"rgba(239,68,68,.3)") }}>
                  📊 {overallScore}/100
                </span>
              )}
              {!isEmp && overallScore === 0 && (
                <span onClick={()=>setShowCandEvalPage(true)} style={{ fontSize:11, fontWeight:700, padding:"1px 6px", borderRadius:8, cursor:"pointer", background:"rgba(167,139,250,.12)", color:"#a78bfa", border:"1px solid rgba(167,139,250,.3)" }}>
                  📊 تقييم
                </span>
              )}
            </div>
            {ev?.recommendation && <p style={{ fontSize:11, color:"var(--text2)", marginBottom:3 }}>
              المرحلة: <span style={{ fontWeight:700, color:"var(--accent)" }}>{ev.recommendation}</span>
            </p>}
            <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
              {record.city && <span style={{ fontSize:10, color:"var(--text3)" }}>📍 {record.city}</span>}
              {daysLeft !== null && daysLeft < 90 && <span style={{ fontSize:10, padding:"1px 5px", borderRadius:6, background:"rgba(234,179,8,.1)", color:"#fbbf24" }}>⚠️ {daysLeft} يوم</span>}
            </div>
          </div>
        </div>
        {/* ── Action buttons — compact grid ── */}
        <div style={{ display:"flex", gap:4, flexWrap:"wrap", alignItems:"center", marginTop:8, paddingTop:8, borderTop:"1px solid rgba(255,255,255,.06)" }}>
          {!isEmp && (isAdmin || window._hasPerm?.("eval_interview")) && <button title="إسناد تقييم لموظف" onClick={()=>setShowAssignEval(true)} style={{ padding:"3px 8px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:10, fontWeight:700, border:"1px solid rgba(34,197,94,.3)", background:"rgba(34,197,94,.08)", color:"#4ade80" }}>📋 إسناد</button>}
          {isEmp && (() => { const ce = record.evalCumulative || (record.weeklyEvals?.length ? Math.round(record.weeklyEvals.reduce((s,e)=>s+(e.finalAverage||0),0)/record.weeklyEvals.length) : null); return ce ? <span title="المتوسط التراكمي" style={{ padding:"3px 8px", borderRadius:8, fontSize:10, fontWeight:900, border:"1px solid "+(ce>=80?"rgba(34,197,94,.3)":ce>=60?"rgba(245,158,11,.3)":"rgba(239,68,68,.3)"), background:ce>=80?"rgba(34,197,94,.08)":ce>=60?"rgba(245,158,11,.08)":"rgba(239,68,68,.08)", color:ce>=80?"#4ade80":ce>=60?"#f59e0b":"#f87171", cursor:"pointer" }} onClick={()=>setTab("eval")}>⭐ {ce}/100</span> : (window._hasPerm?.("eval_interview")) ? <button title="تقييم" onClick={()=>setTab("eval")} className="btn btn-gold btn-sm" style={{ fontSize:10, padding:"4px 8px" }}>⭐ تقييم</button> : null; })()}
          {!isEmp && (window._hasPerm?.("change_stage")) && <StageChangeBtn record={record} onSave={async(upd)=>{ await saveCandidate(upd); await onSave(upd); }} />}
          {(window._hasPerm?.("send_message")) && <button title="رسالة" onClick={()=>setShowMsg(true)} className="btn btn-ghost btn-sm" style={{ fontSize:10, padding:"4px 8px" }}>💬 رسالة</button>}
          {/* زر إرسال موعد/رابط — لمساعد المشرف في المراحل الثلاث */}
          {window._effectiveRole === "assistant_supervisor" && !isEmp && ["interview1","interview2","assessment"].includes(record.stage) && (
            <button title={record.stage === "assessment" ? "إرسال رابط اختبار" : "إرسال موعد مقابلة"} onClick={()=>{
              window._asstSendModal = { cand: record, stageId: record.stage };
              window.dispatchEvent(new CustomEvent("openAsstSendModal"));
            }} className="btn btn-ghost btn-sm" style={{ fontSize:10, padding:"4px 8px", color:"#25d366", border:"1px solid rgba(37,211,102,.3)" }}>
              {record.stage === "assessment" ? "📝 إرسال اختبار" : "📅 إرسال موعد"}
            </button>
          )}
          {(window._hasPerm?.("edit_record")) && <button title={editMode?"عرض":"تعديل"} onClick={()=>setEditMode(p=>!p)} className={"btn btn-sm "+(editMode?"btn-ghost":"btn-gold")} style={{ fontSize:10, padding:"4px 8px" }}>
            {editMode ? "👁️ عرض" : "✏️ تعديل"}
          </button>}
          {!isEmp && (window._hasPerm?.("convert_employee")) && (
            <button title="تحويل لموظف" onClick={()=>{
              window._convertCand = record;
              window.dispatchEvent(new CustomEvent("openConvertModal"));
            }} className="btn btn-ghost btn-sm" style={{ color:"#4ade80", border:"1px solid rgba(34,197,94,.3)", fontSize:10, padding:"4px 8px" }}>
              👨‍💼 تحويل لموظف
            </button>
          )}
          {(window._hasPerm?.("delete_record")) && <button title="حذف" onClick={()=>onDelete(record)} className="btn btn-danger btn-sm" style={{ fontSize:10, padding:"4px 8px" }}>🗑️</button>}
          {isEmp && window._currentUser?.username === "admin" && (
            <button title="إرجاع إلى مرشح — المدير العام فقط" onClick={async()=>{
              if(!window.confirm("هل تريد إرجاع "+record.fullName+" من موظف إلى مرشح؟\n\nسيتم حفظ كل السجلات والتقييمات والمقابلات.")) return;
              const empId=record.uid||record.idNumber||record.email;
              const actor=window._currentUser?.displayName||"المشرف";
              const candData={...record}; delete candData.employmentType; delete candData.joinDate; delete candData.branch;
              candData.role="candidate"; candData.revertedFromEmployee=true; candData.revertedAt=new Date().toISOString();
              await saveCandidate(candData);
              await delEmployee(empId).catch(()=>{});
              if(record.email){const u=await getUserByEmail(record.email).catch(()=>null);if(u)await saveUser({...u,role:"candidate"}).catch(()=>{});}
              await addPersonEvent(empId,{type:"revert",text:"↩️ تم إرجاع من موظف إلى مرشح بواسطة "+actor,by:actor,byRole:"admin",private:false}).catch(()=>{});
              await db._sync();
              if(window._showToast) window._showToast("✅ تم إرجاع "+record.fullName+" إلى مرشح");
              else alert("✅ تم إرجاع "+record.fullName+" إلى مرشح");
              setTimeout(()=>window.location.reload(),1500);
            }} className="btn btn-ghost btn-sm" style={{ fontSize:10, padding:"4px 8px", color:"#f59e0b", border:"1px solid rgba(245,158,11,.3)" }}>↩️ إرجاع لمرشح</button>
          )}
          {(window._hasPerm?.("access_code")) && record.email && (
            <button title="إرسال رمز دخول — المدير العام فقط" onClick={async()=>{
              const sendOk = await confirm("⚠️ إرسال رمز دخول جديد لـ "+record.fullName+"؟\n\nسيتم إنشاء كلمة مرور مؤقتة وإرسالها بالبريد.");
              if(!sendOk) return;
              
              const tempPw = Math.random().toString(36).slice(2,8);
              const hash = await hashPassword(tempPw);
              const user = await getUserByEmail(record.email);
              if (user) { await saveUser({...user, passwordHash:hash, emailVerified:true}); }
              const upd = {...record, activated:true, accountStatus:"مفعّل", activatedAt:record.activatedAt||new Date().toISOString()};
              await saveCandidate(upd);
              if (record.email) {
                sendEmail({to:record.email, subject:"رمز الدخول — نظام كوادر HMA", html:"<div dir='rtl'><h2>مرحباً "+(record.fullName||"")+"</h2><p>رمز الدخول المؤقت: <strong style='font-size:20px;color:#c9a84c'>"+tempPw+"</strong></p><p>يرجى تغيير كلمة المرور بعد تسجيل الدخول.</p><p><a href='https://hma.engineer'>hma.engineer</a></p></div>"}).catch(()=>{});
              }
              if (window._showToast) window._showToast("✅ تم إرسال رمز الدخول: " + tempPw);
              else alert("✅ رمز الدخول: " + tempPw);
            }} className="btn btn-ghost btn-sm" style={{ color:"#e8eaf0", border:"1px solid rgba(34,197,94,.3)", fontSize:10, padding:"4px 8px" }}>🔓 رمز دخول</button>
          )}
        </div>
      </div>
      )}

      {/* ── Action Required Bar ── */}
      {!isNew && (()=>{
        const actions = [];
        if (record._hasPendingTags) actions.push({ icon:"🔖", text:"تصنيفات جديدة تنتظر الاعتماد", tab:"tags" });
        if (record.accountStatus === "قيد المراجعة" && record.cvUploaded) actions.push({ icon:"📄", text:"المرشح رفع سيرة ذاتية جديدة — تحتاج مراجعة", tab:"cv", confirmable:true });
        if (!record.activated) actions.push({ icon:"🔓", text:"الحساب غير مفعّل", tab:"info" });
        if (!record.cvUploaded && !isEmp) actions.push({ icon:"⚠️", text:"الملف غير مكتمل — لم يرفع سيرة ذاتية", tab:"info" });
        // Check for unapproved auto-translations
        const biFields = ["biSpec","biDept","biSkill","biSW","biProj","biCert"];
        let pendingCount = 0;
        biFields.forEach(f => { (record[f]||[]).forEach(t => { if (t && t.arSource === "auto" && !t.approved) pendingCount++; }); });
        if (pendingCount > 0) actions.push({ icon:"🏷️", text:pendingCount + " ترجمة تلقائية تنتظر الاعتماد", tab:"tags" });
        if (actions.length === 0) return null;
        return (
          <div style={{ margin:"0 16px", marginTop:8, padding:"10px 14px", background:"rgba(253,224,71,.08)", border:"1px solid rgba(253,224,71,.25)", borderRadius:10 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:actions.length > 1 ? 6 : 0 }}>
              <p style={{ fontSize:12, fontWeight:900, color:"#f59e0b" }}>⚡ إجراءات مطلوبة:</p>
            </div>
            {actions.map((a, ai) => (
              <div key={ai} style={{ fontSize:11, color:"#fbbf24", padding:"3px 0", display:"flex", alignItems:"center", gap:6 }}>
                <span onClick={()=>setTab(a.tab)} style={{ cursor:"pointer", display:"flex", alignItems:"center", gap:4, flex:1 }}>
                  <span>{a.icon}</span>
                  <span style={{ textDecoration:"underline", textUnderlineOffset:2 }}>{a.text}</span>
                </span>
                {a.confirmable && (
                  <button onClick={async()=>{
                    const upd={...record, accountStatus:"معتمد", _hasReview:false, cvReviewedAt:new Date().toISOString(), cvReviewedBy:window._currentUser?.displayName||"المشرف"};
                    await onSave(upd);
                    const actor=window._currentUser?.displayName||"المشرف";
                    const pid=record.uid||record.idNumber||record.email;
                    if(pid) addPersonEvent(pid,{type:"review",text:"✅ تم مراجعة السيرة الذاتية بواسطة "+actor,by:actor,byRole:"admin",private:true}).catch(()=>{});
                  }} style={{ padding:"3px 10px", borderRadius:6, border:"1px solid rgba(34,197,94,.4)", background:"rgba(34,197,94,.12)", color:"#4ade80", fontSize:10, cursor:"pointer", fontFamily:"inherit", fontWeight:700, whiteSpace:"nowrap" }}>✅ تم المراجعة</button>
                )}
              </div>
            ))}
          </div>
        );
      })()}

      {/* ── Tabs ── */}
      <div style={{ display:"flex", gap:4, padding:"10px 16px 0", borderBottom:"1px solid var(--b)", overflowX:"auto", flexWrap:"nowrap" }}>
        {TABS.map(t => (
          <button key={t.id} onClick={()=>setTab(t.id)}
            className={"tab-btn "+(tab===t.id?"tab-on":"tab-off")}
            style={{ whiteSpace:"nowrap", flexShrink:0 }}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>

      {/* ── Tab content ── */}
      <div style={{ padding:"16px 20px" }}>
        {/* Pending tags — show when in tags tab or any tab if exist */}
        {!editMode && type === "candidate" && (tab === "tags" || tab === "info") && (
          <InlinePendingTags
            personId={record.uid || record.idNumber || record.email}
            libs={libs}
            saveLibs={window._saveLibs}
            candidates={window._allCands || []}
            setCands={window._setCands}
          />
        )}
        {editMode ? (
          <InlineEditContent record={record} tab={tab} type={type} libs={libs} specsMap={specsMap} onSave={save} />
        ) : (
          <ErrorBoundary>
            <InlineViewContent record={record} tab={tab} type={type} libs={libs} specsMap={specsMap} onSave={onSave} ev={ev} />
          </ErrorBoundary>
        )}
      </div>
      {showAllEvals && <AllEvalsPanel cand={record} onClose={()=>setShowAllEvals(false)} />}
      {showAssignEval && <EvalAssignModal cand={record} employees={window._allEmps||[]} onAssign={async(task)=>{ const upd={...record, evalTaskResults:[...(record.evalTaskResults||[])]}; await onSave(upd); }} onClose={()=>setShowAssignEval(false)} />}
      {showFullEval && <FullEvalForm cand={record} onSubmit={async(result)=>{ const upd={...record, evalTaskResults:[...(record.evalTaskResults||[]),result]}; await onSave(upd); setShowFullEval(false); show("✅ تم حفظ التقييم"); const pid=record.uid||record.idNumber||record.email; if(pid) addPersonEvent(pid,{type:"eval",text:"📋 تقييم مفصّل: "+result.totalScore+"/100 — "+result.evaluatorName+" — التوصية: "+result.recommendation, by:result.evaluatorName, byRole:"admin", private:false}).catch(()=>{}); }} onClose={()=>setShowFullEval(false)} />}
      {showCandEvalPage && <CandEvalPage cand={record} onClose={()=>setShowCandEvalPage(false)} onSave={async(upd)=>{ await onSave(upd); }} />}
      </div>
    </div>
  );
}

// ── InlineViewContent — read-only content per tab ────────────────────────────
function InlineViewContent({ record, tab, type, libs, specsMap, onSave, ev }) {
  const isEmp = type === "employee";
  const pc = record._pendingChanges || {};
  const hasPending = Object.keys(pc).length > 0;
  const [hovField, setHovField] = useState(null);
  const [evalForm, setEvalForm] = useState({ performance:70, attendance:70, commitment:70, quality:70, teamwork:70, initiative:70, notes:"" });
  const [savingEval, setSavingEval] = useState(false);

  const approveField = async (f) => {
    const upd = { ...record, _pendingChanges: { ...pc } };
    delete upd._pendingChanges[f];
    if (Object.keys(upd._pendingChanges).length === 0) { delete upd._pendingChanges; upd._hasReview = false; upd.accountStatus = "معتمد"; }
    if (onSave) await onSave(upd);
  };
  const revertField = async (f) => {
    const old = pc[f]?.old;
    const upd = { ...record, [f]: old, _pendingChanges: { ...pc } };
    delete upd._pendingChanges[f];
    if (Object.keys(upd._pendingChanges).length === 0) { delete upd._pendingChanges; upd._hasReview = false; upd.accountStatus = "معتمد"; }
    if (onSave) await onSave(upd);
  };
  const approveAll = async () => {
    const upd = { ...record };
    delete upd._pendingChanges; upd._hasReview = false; upd._hasPendingTags = false; upd.accountStatus = "معتمد";
    if (onSave) await onSave(upd);
  };

  const fieldLabel = (f) => ({ fullName:"الاسم",fullNameEn:"الاسم EN",phone:"الجوال",email:"البريد",idNumber:"الهوية",nationality:"الجنسية",gender:"الجنس",city:"المدينة",locationStatus:"الموقع",education:"المؤهل",university:"الجامعة",university2:"الجامعة 2",major:"التخصص",primarySpecId:"التخصص الرئيسي",secondarySpecId:"التخصص الإضافي",graduationYear:"سنة التخرج",yearsExperience:"الخبرة",lastJob:"آخر وظيفة",lastCompany:"آخر شركة",expectedSalary:"الراتب المتوقع",linkedinUrl:"LinkedIn",availabilityStatus:"الإتاحة",trainingType:"خاص بطالبي التدريب والتدريب المنتهي بالتوظيف",notes:"ملاحظات",biSpec:"التخصصات",biSkill:"المهارات",biSW:"البرامج",biCert:"الشهادات",biProj:"المشاريع",biDept:"جهات العمل" }[f] || f);

  const FieldStar = ({ field }) => {
    if (!pc[field]) return null;
    const oldVal = pc[field].old;
    const oldStr = Array.isArray(oldVal) ? (oldVal.length?oldVal.map(t=>typeof t==="object"?(t.ar||t.en||t.label||""):t).join("، "):"فارغ") : (oldVal||"فارغ");
    return (
      <span style={{ position:"relative", display:"inline-block" }}
        onMouseEnter={()=>setHovField(field)} onMouseLeave={()=>setHovField(null)}>
        <span style={{ color:"#f59e0b", cursor:"help", fontSize:12, marginRight:3 }}>⭐</span>
        {hovField === field && (
          <div style={{ position:"absolute", bottom:"100%", right:0, zIndex:99999, paddingBottom:8 }}
            onMouseEnter={()=>setHovField(field)} onMouseLeave={()=>setHovField(null)}>
            <div style={{ background:"var(--dark2)", border:"1px solid var(--b)", borderRadius:8, padding:"8px 12px", minWidth:180, boxShadow:"0 4px 16px rgba(0,0,0,.5)", fontSize:11 }}>
              <p style={{ color:"var(--text3)", marginBottom:4 }}>القيمة السابقة:</p>
              <p style={{ color:"#f87171", fontWeight:700, marginBottom:6 }}>{oldStr}</p>
              <div style={{ display:"flex", gap:4 }}>
                <button onClick={()=>approveField(field)} style={{ flex:1, padding:"3px 6px", borderRadius:6, border:"1px solid rgba(74,222,128,.3)", background:"rgba(74,222,128,.1)", color:"#4ade80", fontSize:10, cursor:"pointer", fontFamily:"inherit", fontWeight:700 }}>✅ اعتماد الجديد</button>
                <button onClick={()=>revertField(field)} style={{ flex:1, padding:"3px 6px", borderRadius:6, border:"1px solid rgba(239,68,68,.3)", background:"rgba(239,68,68,.1)", color:"#f87171", fontSize:10, cursor:"pointer", fontFamily:"inherit", fontWeight:700 }}>↩️ استرجاع القديم</button>
              </div>
            </div>
          </div>
        )}
      </span>
    );
  };

  if (tab === "info") return (
    <div>
      {/* Review banner */}
      {hasPending && (
        <div style={{ padding:"10px 14px", background:"rgba(245,158,11,.08)", border:"1px solid rgba(245,158,11,.3)", borderRadius:10, marginBottom:14, display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:8 }}>
          <div>
            <p style={{ color:"#f59e0b", fontWeight:700, fontSize:13 }}>⭐ {Object.keys(pc).length} تعديل بانتظار المراجعة</p>
            <p style={{ color:"var(--text3)", fontSize:11 }}>حرّك الماوس على ⭐ لرؤية القيمة السابقة</p>
          </div>
          <button onClick={approveAll} style={{ padding:"6px 14px", borderRadius:8, border:"1px solid rgba(74,222,128,.3)", background:"rgba(74,222,128,.1)", color:"#4ade80", fontSize:12, cursor:"pointer", fontFamily:"inherit", fontWeight:700 }}>✅ اعتماد الكل</button>
        </div>
      )}

      <div className="g3" style={{ marginBottom:14 }}>
        {[
          ["📞 الجوال",        record.phone, "phone"],
          ["✉️ البريد",        record.email, "email"],
          ["🆔 رقم الهوية",    record.idNumber, "idNumber"],
          ["🌍 الجنسية",       record.nationality, "nationality"],
          ["👤 الجنس",         record.gender, "gender"],
          ["📍 المدينة",       record.city, "city"],
          ["🌐 الموقع",        record.locationStatus, "locationStatus"],
          ["🔤 الاسم بالإنجليزية", record.fullNameEn, "fullNameEn"],
          ["🎓 المؤهل",        [record.education, record.university].filter(Boolean).join(" — "), "education"],
          ["📚 التخصص الدراسي", record.major, "major"],
          ["💰 " + (isEmp?"الراتب":"الراتب المتوقع"), record.salary||record.expectedSalary ? Number(record.salary||record.expectedSalary).toLocaleString()+" ريال" : "", "expectedSalary"],
          ...(isEmp ? [
            ["📅 الالتحاق",   record.joinDate ? new Date(record.joinDate).toLocaleDateString("ar-SA") : "", "joinDate"],
            ["🔚 انتهاء العقد", record.contractEnd ? new Date(record.contractEnd).toLocaleDateString("ar-SA") : "", "contractEnd"],
            ["🏢 الإدارة",    record.department, "department"],
          ] : [
            ["📅 الإتاحة",    record.availabilityStatus, "availabilityStatus"],
            ["🎓 نوع التدريب", record.trainingType, "trainingType"],
            ["🔗 LinkedIn",    record.linkedinUrl, "linkedinUrl"],
          ]),
          ["💼 آخر مسمى",     record.lastJob, "lastJob"],
          ["🏢 آخر شركة",     record.lastCompany, "lastCompany"],
          ["🎂 سنة التخرج",   record.graduationYear ? String(record.graduationYear) : "", "graduationYear"],
          ["📊 سنوات الخبرة",  record.yearsExperience ? record.yearsExperience+" سنة" : "", "yearsExperience"],
        ].filter(([,v])=>v&&String(v).trim()).map(([l,v,f])=>(
          <div key={l} style={{ background: pc[f] ? "rgba(245,158,11,.05)" : "var(--glass)", border:"1px solid "+(pc[f]?"rgba(245,158,11,.25)":"var(--b)"), borderRadius:9, padding:"10px 13px", overflow:pc[f]?"visible":"hidden", minWidth:0, position:pc[f]?"relative":"static" }}>
            <p style={{ color:"var(--text3)", fontSize:10, marginBottom:3, fontWeight:600 }}>{l} <FieldStar field={f} /></p>
            <p style={{ color:"var(--text)", fontWeight:700, fontSize:13, wordBreak:"break-word", overflowWrap:"anywhere" }}>{v}</p>
          </div>
        ))}
      </div>
      {record.notes && (
        <div style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:9, padding:"10px 13px" }}>
          <p style={{ fontSize:11, color:"var(--text3)", marginBottom:4 }}>📝 ملاحظات</p>
          <p style={{ fontSize:13, color:"var(--text2)", lineHeight:1.7 }}>{record.notes}</p>
        </div>
      )}
      {record && <HayaBadge data={record} />}
    </div>
  );

  if (tab === "exp") return (
    <div className="g3">
      {[
        ["💼 آخر مسمى",    record.lastJob],
        ["🏢 آخر شركة",    record.lastCompany],
        ["🎂 سنة التخرج",  record.graduationYear ? String(record.graduationYear) : ""],
        ["📊 سنوات الخبرة", record.yearsExperience ? record.yearsExperience+" سنة" : ""],
      ].filter(([,v])=>v&&String(v).trim()).map(([l,v])=>(
        <div key={l} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:9, padding:"10px 13px", overflow:"hidden", minWidth:0 }}>
          <p style={{ color:"var(--text3)", fontSize:10, marginBottom:3, fontWeight:600 }}>{l}</p>
          <p style={{ color:"var(--text)", fontWeight:700, fontSize:13, wordBreak:"break-word", overflowWrap:"anywhere" }}>{v}</p>
        </div>
      ))}
      {(record.companies||[]).length > 0 && (
        <div style={{ gridColumn:"1/-1", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:9, padding:"10px 13px" }}>
          <p style={{ color:"var(--text3)", fontSize:10, marginBottom:6, fontWeight:600 }}>🏛️ الشركات السابقة</p>
          <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
            {(record.companies||[]).map((c,i)=><span key={i} style={{ fontSize:12, padding:"3px 10px", borderRadius:16, background:"rgba(255,255,255,.06)", color:"var(--text2)", border:"1px solid var(--b)" }}>{c}</span>)}
          </div>
        </div>
      )}
      {/* v37.84: كارت بصمة — للموظفين فقط */}
      {isEmp && <div style={{ gridColumn:"1/-1" }}><EmployeeBasmaCard idNumber={record.idNumber} /></div>}
    </div>
  );

  if (tab === "tags") {
    if (!libs) return <div style={{ textAlign:"center",padding:40 }}><div className="loader"/></div>;
    const toStr = (x) => typeof x === "string" ? x : (x?.ar || x?.label || x?.en || "");
    const safeLibs = {
      specs:         ((libs.specs||[]).map(s=>toStr(s)).filter(Boolean)),
      jobTypes:      (libs.jobTypes||[]).map(toStr).filter(Boolean),
      skills:        (libs.skills||[]).map(toStr).filter(Boolean),
      software:      (libs.software||[]).map(toStr).filter(Boolean),
      projectTypes:  (libs.projectTypes||[]).map(toStr).filter(Boolean),
      certifications:(libs.certifications||[]).map(toStr).filter(Boolean),
    };
    // Map bi fields to pending changes
    const biFields = { biSpec:"التخصصات", biDept:"الإدارات", biSkill:"المهارات", biSW:"البرامج", biProj:"المشاريع", biCert:"الشهادات" };
    const getOldTags = (field) => {
      if (!pc[field]) return null;
      return (pc[field].old || []).map(t => (typeof t==="string"?t:(t.ar||t.en||t.label||"")).toLowerCase().trim());
    };
    const filterScreening = (tags) => (tags||[]).filter(t => !(t && typeof t === "object" && t.source === "screening"));
    const tagBlocks = [
      { title:"التخصصات", icon:"🏗️", field:"biSpec", tags:filterScreening(record.biSpec)||(record.specializations||[]).map(s=>({ar:s,en:"",approved:true})), lib:safeLibs.specs },
      { title:"الإدارات",  icon:"🏢", field:"biDept", tags:filterScreening(record.biDept)||(record.departments||[]).map(s=>({ar:s,en:"",approved:true})),    lib:safeLibs.jobTypes },
      { title:"المهارات",  icon:"🛠️", field:"biSkill", tags:filterScreening(record.biSkill)||(record.skills||[]).map(s=>({ar:s,en:"",approved:true})),        lib:safeLibs.skills },
      { title:"البرامج",   icon:"💻", field:"biSW", tags:filterScreening(record.biSW)||(record.software||[]).map(s=>({ar:s,en:"",approved:true})),         lib:safeLibs.software },
      { title:"المشاريع",  icon:"📋", field:"biProj", tags:filterScreening(record.biProj)||(record.projectTypes||[]).map(s=>({ar:s,en:"",approved:true})),   lib:safeLibs.projectTypes },
      { title:"الشهادات",  icon:"🏅", field:"biCert", tags:filterScreening(record.biCert)||(record.certifications||[]).map(s=>({ar:typeof s==="string"?s:(s.ar||s.name||""),en:"",approved:true})), lib:safeLibs.certifications },
    ].filter(b=>(b.tags||[]).length>0);
    const hasTagChanges = Object.keys(biFields).some(f => pc[f]);
    return (
    <div>
      {/* Review banner for tags */}
      {(hasPending || hasTagChanges) && (
        <div style={{ padding:"10px 14px", background:"rgba(245,158,11,.08)", border:"1px solid rgba(245,158,11,.3)", borderRadius:10, marginBottom:14, display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:8 }}>
          <div>
            <p style={{ color:"#f59e0b", fontWeight:700, fontSize:13 }}>⭐ تصنيفات بانتظار المراجعة</p>
            <p style={{ color:"var(--text3)", fontSize:11 }}>🟢 مطابق للمكتبة · ⚪ غير مطابق · ⭐ جديد من المرشح</p>
          </div>
          <button onClick={approveAll} style={{ padding:"6px 14px", borderRadius:8, border:"1px solid rgba(74,222,128,.3)", background:"rgba(74,222,128,.1)", color:"#4ade80", fontSize:12, cursor:"pointer", fontFamily:"inherit", fontWeight:700 }}>✅ اعتماد الكل</button>
        </div>
      )}
      {tagBlocks.map(b=>{
        const oldTags = getOldTags(b.field);
        return (
        <div key={b.title} style={{ marginBottom:10 }}>
          <p style={{ fontSize:12, fontWeight:700, color:"var(--text2)", marginBottom:6 }}>
            {b.icon} {b.title}
            {pc[b.field] && <span style={{ color:"#f59e0b", fontSize:10, marginRight:4 }}>⭐ معدّل</span>}
          </p>
          <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
            {(b.tags||[]).map((t,i)=>{
              const label = (typeof t==="string"?t:(t.ar||t.en||t.label||"")).trim();
              const inLib = b.lib.some(l=>{ try { return l && label && String(l).toLowerCase()===String(label).toLowerCase(); } catch { return false; } });
              const isNew = oldTags && !oldTags.includes(label.toLowerCase().trim());
              return label?(
                <span key={i} style={{ display:"inline-flex", alignItems:"center", gap:4, padding:"4px 10px", borderRadius:20, fontSize:12, fontWeight:600,
                  background: isNew ? "rgba(245,158,11,.12)" : inLib ? "rgba(34,197,94,.1)" : "rgba(148,163,184,.08)",
                  border:"1px solid "+(isNew ? "rgba(245,158,11,.4)" : inLib ? "rgba(34,197,94,.3)" : "rgba(148,163,184,.2)"),
                  color: isNew ? "#f59e0b" : inLib ? "#4ade80" : "#94a3b8" }}>
                  {isNew && "⭐ "}{label}{t&&t.en&&t.ar&&<span style={{ fontSize:10, opacity:.6 }}>({t.en})</span>}
                </span>
              ):null;
            })}
          </div>
        </div>
      );})}
      {record && <HayaBadge data={record} />}
    </div>
  );
  }

  if (tab === "cv") return (
    <div className="card">
      <CVFilePane person={record} onSave={onSave ? async (updates)=>await onSave({...record,...updates}) : null} />
    </div>
  );

  if (tab === "history") return (
    <EventsLog
      personId={record.uid || record.idNumber || record.email}
      currentUser={null}
      isAdmin={true}
    />
  );

  if (tab === "eval" && isEmp) {
    const cUser = window._currentUser || {};
    const isAdminEval = cUser.username === "admin" || cUser.role === "hr_manager";
    const evals = record.weeklyEvals || [];
    const cumAvg = evals.length > 0 ? Math.round(evals.reduce((s,e) => s + (e.finalAverage||0), 0) / evals.length) : null;
    const hayaRankStr = typeof record.hayaRank==="object"?(record.hayaRank?.ar||""):record.hayaRank||"";
    const hayaNotRequired = hayaRankStr === "غير مطلوب";
    const hayaDaysLeft = record.hayaExpiry ? Math.floor((new Date(record.hayaExpiry) - new Date()) / 86400000) : null;
    const hayaExpired = !hayaNotRequired && hayaDaysLeft !== null && hayaDaysLeft < 0;
    const hayaMissing = !hayaNotRequired && !record.hayaMemberNo;
    const CRITERIA = [
      { key:"performance", label:"الأداء الوظيفي", icon:"📊", weight:20 },
      { key:"attendance", label:"الحضور والانصراف", icon:"🕐", weight:20 },
      { key:"commitment", label:"الالتزام بالمواعيد", icon:"⏰", weight:15 },
      { key:"quality", label:"جودة العمل", icon:"✅", weight:20 },
      { key:"teamwork", label:"التعاون مع الفريق", icon:"🤝", weight:15 },
      { key:"initiative", label:"المبادرة والابتكار", icon:"💡", weight:10 },
    ];
    const now = new Date();
    const evalCycle = localStorage.getItem("hma_eval_cycle") || "weekly";
    let periodStart, periodEnd, periodLabel;
    if (evalCycle === "monthly") {
      const first = new Date(now.getFullYear(), now.getMonth(), 1);
      const last = new Date(now.getFullYear(), now.getMonth() + 1, 0);
      periodStart = first.toISOString().split("T")[0];
      periodEnd = last.toISOString().split("T")[0];
      periodLabel = first.toLocaleDateString("ar-SA",{month:"long",year:"numeric"});
    } else {
      const day = now.getDay();
      const sun = new Date(now); sun.setDate(now.getDate() - day);
      const sat = new Date(sun); sat.setDate(sun.getDate() + 6);
      periodStart = sun.toISOString().split("T")[0];
      periodEnd = sat.toISOString().split("T")[0];
      periodLabel = periodStart + " إلى " + periodEnd;
    }
    const thisWeek = { start: periodStart, end: periodEnd };
    const alreadyThisWeek = evals.some(e => e.weekStart === thisWeek.start);

    const setEF = (k,v) => setEvalForm(p=>({...p,[k]:v}));

    const saveWeeklyEval = async () => {
      setSavingEval(true);
      const avg = Math.round(CRITERIA.reduce((s,c) => s + (evalForm[c.key]||0) * (c.weight/100), 0));
      const entry = {
        weekStart: thisWeek.start, weekEnd: thisWeek.end,
        evaluatorId: cUser.linkedId || cUser.username,
        ...Object.fromEntries(CRITERIA.map(c => [c.key, evalForm[c.key]||0])),
        average: avg, finalAverage: avg,
        notes: evalForm.notes, createdAt: new Date().toISOString(),
      };
      const updated = { ...record, weeklyEvals: [...evals, entry], evalCumulative: Math.round([...evals, entry].reduce((s,e) => s + (e.finalAverage||0), 0) / (evals.length + 1)) };
      await saveEmployee(updated);
      await onSave(updated);
      setSavingEval(false);
      show("✅ تم حفظ التقييم");
    };

    return (
      <div>
        {/* ── KPI Dashboard ── */}
        {(()=>{
          // Load KPI config: centralized from eval:kpi_full_config
          const fullCfg = window._kpiFullConfig || null;
          const GLOBAL_KPI = fullCfg?.global || window._kpiConfig || [
            { id:"profile", label:"إكمال الملف الشخصي", icon:"📋", weight:15, type:"auto_profile", scope:"عام" },
            { id:"haya", label:"عضوية الهيئة", icon:"🏛️", weight:10, type:"auto_haya", scope:"عام" },
            { id:"init", label:"المبادرات المنجزة", icon:"💡", weight:10, type:"auto_initiatives", scope:"عام" },
          ];
          // Department-specific KPI
          const empDept = record.department || "";
          const deptKPI = fullCfg?.departments?.[empDept] || fullCfg?.departments?._default || [
            { id:"quality", label:"جودة العمل", icon:"✅", weight:25, source:"مدير" },
            { id:"attendance", label:"الحضور والانصراف", icon:"🕐", weight:25, source:"HR" },
            { id:"teamwork", label:"التعاون", icon:"🤝", weight:15, source:"مدير" },
          ];
          // Individual KPI
          const indivKPI = (record._kpiIndividual||[]).map(k=>({...k, scope:"فردي", type:"manual"}));
          // Merge all layers
          const globalWithScope = GLOBAL_KPI.map(k=>({...k, scope:"عام"}));
          const deptWithScope = deptKPI.map(k=>({...k, scope:empDept?"مسمى: "+empDept:"افتراضي", type:"manual"}));
          const kpiConfig = [...globalWithScope, ...deptWithScope, ...indivKPI];

          // Auto-calculate scores based on type
          const calcScore = (item) => {
            if (item.type === "auto_profile") {
              const fields = ["fullName","phone","email","idNumber","nationality","city","education","jobTitle"];
              return Math.round(fields.filter(f=>record[f]&&String(record[f]).trim()).length/fields.length*100);
            }
            if (item.type === "auto_haya") return hayaNotRequired ? 100 : (record.hayaMemberNo && !hayaExpired) ? 100 : hayaExpired ? 20 : 0;
            if (item.type === "auto_certs") return Math.min(100, ((record.certifications||[]).length + (record.biCert||[]).length) * 25);
            if (item.type === "auto_initiatives") return Math.min(100, (record.initiatives||[]).filter(i=>i.status==="مكتمل"||i.status==="completed").length * 20);
            if (item.type === "excel") return record._kpiDiscipline?.ratio || 0;
            if (item.type === "auto_tawasul") { try { return calcTawasulRating(window._twslReqs||[], record.uid||record.idNumber||record.email).score; } catch{ return 0; } }
            if (item.type === "exam") return record._kpiExamScore || 0;
            if (item.type === "peer_eval") { const evals = record.mgrEvalsByEmp||[]; return evals.length ? Math.round(evals.reduce((s,e)=>s+(e.average||0),0)/evals.length) : 0; }
            if (item.type === "manual") return record._kpiManual?.[item.id] || 0;
            return 0;
          };

          // ── KPI 40/60 Split: عام (40%) + خاص (60%) ──
          const kpiSplit = fullCfg?.split || { general: 40, specific: 60 };
          const generalScores = scores.filter(i => i.scope === "عام");
          const specificScores = scores.filter(i => i.scope !== "عام");
          const hasSpecific = specificScores.length > 0;

          // Calculate general score
          const genTotalW = generalScores.reduce((s,i)=>s+i.weight,0) || 100;
          const generalScore = Math.round(generalScores.reduce((s,i)=>s+i.score*(i.weight/genTotalW),0));

          // Calculate specific score
          let specificScore = 0;
          if (hasSpecific) {
            const specTotalW = specificScores.reduce((s,i)=>s+i.weight,0) || 100;
            specificScore = Math.round(specificScores.reduce((s,i)=>s+i.score*(i.weight/specTotalW),0));
          }

          // Combined: general × weight% + specific × weight%
          const autoKPI = hasSpecific
            ? Math.round(generalScore * (kpiSplit.general/100) + specificScore * (kpiSplit.specific/100))
            : generalScore; // No specific criteria → 100% from general

          // Alert: no specific criteria
          const noSpecificAlert = !hasSpecific;

          const mgrEvals = record.mgrEvalsByEmp || [];
          const mgrAvg = mgrEvals.length > 0 ? Math.round(mgrEvals.reduce((s,e)=>s+(e.average||0),0)/mgrEvals.length) : null;
          const hasData = cumAvg || mgrAvg || autoKPI;
          const weights = { mgr: cumAvg?50:0, auto: autoKPI?30:0, emp: mgrAvg?20:0 };
          const wTotal = weights.mgr+weights.auto+weights.emp || 100;
          const combinedKPI = hasData ? Math.round(((cumAvg||0)*weights.mgr + autoKPI*weights.auto + (mgrAvg||0)*weights.emp) / wTotal) : null;

          // Alert: no specific criteria for this employee
          const NoSpecificAlert = () => noSpecificAlert ? (
            <div style={{ padding:"8px 12px", background:"rgba(245,158,11,.06)", border:"1px solid rgba(245,158,11,.2)", borderRadius:8, marginBottom:10, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <p style={{ fontSize:11, color:"#f59e0b" }}>⚠️ لا توجد معايير خاصة لهذا الموظف — يُحسب KPI من المعايير العامة فقط</p>
              {isAdminEval && <button onClick={()=>{if(window._setSecP) window._setSecP("kpi_settings");}} className="btn btn-ghost btn-sm" style={{ fontSize:9, color:"#f59e0b", border:"1px solid rgba(245,158,11,.3)" }}>⚙️ إضافة</button>}
            </div>
          ) : null;

          const last12 = evals.slice(-12);

          // KPI Settings — redirect to centralized page
          const KPISettings = () => {
            if (!isAdminEval) return null;
            return <button onClick={()=>{if(window._setSecP) window._setSecP("kpi_settings");}} style={{ background:"none", border:"1px solid var(--b)", color:"var(--text3)", cursor:"pointer", fontSize:10, padding:"2px 8px", borderRadius:6, fontFamily:"inherit" }}>⚙️ إعدادات KPI</button>;
          };

          return (
            <div style={{ marginBottom:20 }}>
              {/* Score circles row */}
              <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12, marginBottom:16 }}>
                {[
                  { label:"تقييم المدير", score:cumAvg, color:cumAvg>=80?"#4ade80":cumAvg>=60?"#f59e0b":"#f87171", sub:evals.length+" تقييم" },
                  { label:"تقييم الموظف لمديره", score:mgrAvg, color:mgrAvg>=80?"#4ade80":mgrAvg>=60?"#f59e0b":"#f87171", sub:mgrEvals.length+" تقييم" },
                  { label:"KPI تلقائي", score:autoKPI, color:autoKPI>=80?"#4ade80":autoKPI>=60?"#f59e0b":"#f87171", sub:"من النظام" },
                  { label:"المعدل العام", score:combinedKPI, color:combinedKPI>=80?"#4ade80":combinedKPI>=60?"#f59e0b":"#f87171", sub:"مُركّب" },
                ].map((item,i)=>(
                  <div key={i} style={{ textAlign:"center", padding:"14px 8px", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12 }}>
                    <div style={{ display:"inline-flex", alignItems:"center", justifyContent:"center", width:52, height:52, borderRadius:"50%", border:"3px solid "+(item.score?item.color:"#64748b"), background:item.score?item.color+"18":"rgba(148,163,184,.08)" }}>
                      <span style={{ fontSize:18, fontWeight:900, color:item.score?item.color:"#64748b" }}>{item.score||"—"}</span>
                    </div>
                    <p style={{ fontSize:11, fontWeight:700, color:"var(--text2)", marginTop:6 }}>{item.label}</p>
                    <p style={{ fontSize:9, color:"var(--text3)" }}>{item.sub}</p>
                  </div>
                ))}
              </div>

              {/* Auto KPI breakdown */}
              <div className="card" style={{ marginBottom:16, padding:"12px 14px" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10, flexWrap:"wrap", gap:6 }}>
                  <p style={{ fontSize:12, fontWeight:700, color:"var(--text2)" }}>📊 مؤشرات KPI ({scores.reduce((s,i)=>s+i.weight,0)}%)</p>
                  <div style={{ display:"flex", gap:6 }}>
                    {isAdminEval && <button onClick={async()=>{
                      const label = window.prompt("اسم المعيار الفردي:");
                      if(!label) return;
                      const w = parseInt(window.prompt("الوزن (%):","10"))||10;
                      const upd = {...record, _kpiIndividual:[...(record._kpiIndividual||[]),{id:"ind_"+Date.now(),label,icon:"👤",weight:w,source:"مدير"}]};
                      if(onSave) await onSave(upd);
                    }} style={{ background:"none", border:"1px solid rgba(167,139,250,.3)", color:"#a78bfa", cursor:"pointer", borderRadius:6, padding:"2px 8px", fontSize:10, fontFamily:"inherit" }}>👤 معيار فردي</button>}
                    <KPISettings />
              <NoSpecificAlert />
                  </div>
                </div>
                {/* ── KPI Accordion: عام + خاص ── */}
                {[
                  { title:"🟢 المعايير العامة", color:"#0f766e", bg:"rgba(15,118,110,.06)", items:generalScores, totalScore:generalScore, weight:kpiSplit.general },
                  ...(hasSpecific ? [{ title:"🟡 المعايير الخاصة", color:"#d97706", bg:"rgba(217,119,6,.06)", items:specificScores, totalScore:specificScore, weight:kpiSplit.specific }] : [])
                ].map((sec,si) => (
                  <details key={si} style={{ marginBottom:8, border:"1px solid "+sec.color+"33", borderRadius:10, overflow:"hidden" }}>
                    <summary style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 12px", background:sec.bg, cursor:"pointer", listStyle:"none" }}>
                      <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                        <span style={{ fontSize:12, fontWeight:700, color:sec.color }}>{sec.title}</span>
                        <span style={{ fontSize:10, color:"var(--text3)" }}>({sec.items.length} معايير · وزن {sec.weight}%)</span>
                      </div>
                      <span style={{ fontSize:14, fontWeight:900, color:sec.totalScore>=80?"#4ade80":sec.totalScore>=60?"#f59e0b":"#f87171" }}>{sec.totalScore}/100</span>
                    </summary>
                    <div style={{ padding:"8px 12px" }}>
                      {sec.items.map((item,i)=>(
                        <div key={i} style={{ display:"flex", alignItems:"center", gap:8, marginBottom:5 }}>
                          <span style={{ fontSize:11, fontWeight:700, color:"var(--text3)", minWidth:130 }}>
                            {item.icon} {item.label} <span style={{ fontSize:9 }}>({item.weight}%)</span>
                          </span>
                          <div style={{ flex:1, height:7, background:"var(--glass2)", borderRadius:4, overflow:"hidden" }}>
                            <div style={{ width:item.score+"%", height:"100%", borderRadius:4, background:item.score>=80?"#4ade80":item.score>=60?"#f59e0b":"#f87171", transition:"width .5s" }} />
                          </div>
                          <span style={{ fontSize:11, fontWeight:900, color:item.score>=80?"#4ade80":item.score>=60?"#f59e0b":"#f87171", minWidth:28, textAlign:"center" }}>{item.score}</span>
                        </div>
                      ))}
                    </div>
                  </details>
                ))}
              </div>

              {/* Bar chart — last 12 evaluations */}
              {last12.length > 1 && (
                <div className="card" style={{ marginBottom:16, padding:"12px 14px" }}>
                  <p style={{ fontSize:12, fontWeight:700, color:"var(--text2)", marginBottom:10 }}>📈 آخر {last12.length} تقييم</p>
                  <div style={{ display:"flex", alignItems:"flex-end", gap:4, height:100 }}>
                    {last12.map((ev,i)=>{
                      const h = Math.max(8, (ev.finalAverage/100)*100);
                      const c = ev.finalAverage>=80?"#4ade80":ev.finalAverage>=60?"#f59e0b":"#f87171";
                      return (
                        <div key={i} title={ev.weekStart+": "+ev.finalAverage+"/100"} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2 }}>
                          <span style={{ fontSize:8, color:"var(--text3)" }}>{ev.finalAverage}</span>
                          <div style={{ width:"100%", height:h+"%", background:c, borderRadius:3, minHeight:6, transition:"height .3s" }} />
                        </div>
                      );
                    })}
                  </div>
                  <div style={{ display:"flex", justifyContent:"space-between", marginTop:4 }}>
                    <span style={{ fontSize:8, color:"var(--text3)" }}>{last12[0]?.weekStart}</span>
                    <span style={{ fontSize:8, color:"var(--text3)" }}>{last12[last12.length-1]?.weekStart}</span>
                  </div>
                </div>
              )}
            </div>
          );
        })()}

        {/* New evaluation form — admin/hr only */}
        {isAdminEval && !alreadyThisWeek && (
          <div className="card" style={{ marginBottom:16, border:"1px solid rgba(201,168,76,.2)" }}>
            <div className="sec" style={{ marginBottom:12 }}>⭐ تقييم جديد — {periodLabel}</div>
            <div style={{ display:"grid", gap:12 }}>
              {CRITERIA.filter(c=>c.key!=="attendance").map(c => (
                <div key={c.key} style={{ display:"flex", alignItems:"center", gap:10 }}>
                  <span style={{ fontSize:12, fontWeight:700, color:"var(--text2)", minWidth:150 }}>{c.icon} {c.label} <span style={{ fontSize:9, color:"var(--text3)" }}>({c.weight}%)</span></span>
                  <input type="range" min={0} max={100} step={5} value={evalForm[c.key]} onChange={e=>setEF(c.key, parseInt(e.target.value))} style={{ flex:1, accentColor:"#c9a84c" }} />
                  <span style={{ fontSize:14, fontWeight:900, color:evalForm[c.key]>=80?"#4ade80":evalForm[c.key]>=60?"#f59e0b":"#f87171", minWidth:35, textAlign:"center" }}>{evalForm[c.key]}</span>
                </div>
              ))}
              {/* Attendance — HR enters from external system */}
              <div style={{ display:"flex", alignItems:"center", gap:10, padding:"8px 12px", background:"rgba(96,165,250,.06)", border:"1px solid rgba(96,165,250,.15)", borderRadius:8 }}>
                <span style={{ fontSize:12, fontWeight:700, color:"#60a5fa", minWidth:150 }}>🕐 الحضور والانصراف <span style={{ fontSize:9, color:"var(--text3)" }}>(20%)</span></span>
                <input type="number" min={0} max={100} value={evalForm.attendance} onChange={e=>setEF("attendance", Math.min(100,Math.max(0,parseInt(e.target.value)||0)))} style={{ width:65, textAlign:"center", padding:"4px 8px", borderRadius:6, border:"1px solid rgba(96,165,250,.3)", background:"var(--glass)", color:"var(--text)", fontWeight:700, fontSize:14, fontFamily:"inherit" }} />
                <span style={{ fontSize:10, color:"var(--text3)" }}>% من برنامج الحضور</span>
              </div>
              <div className="field">
                <label className="label" style={{ fontSize:11 }}>📝 ملاحظات</label>
                <textarea value={evalForm.notes} onChange={e=>setEF("notes",e.target.value)} rows={2} style={{ fontFamily:"inherit", fontSize:12 }} />
              </div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <span style={{ fontSize:13, fontWeight:900, color:"var(--gold)" }}>المتوسط المرجّح: {Math.round(CRITERIA.reduce((s,c)=>s+(evalForm[c.key]||0)*(c.weight/100),0))}/100</span>
                <button onClick={saveWeeklyEval} disabled={savingEval} className="btn btn-gold">{savingEval?"⏳":"💾 حفظ التقييم"}</button>
              </div>
            </div>
          </div>
        )}
        {isAdminEval && alreadyThisWeek && (
          <div style={{ textAlign:"center", padding:"10px 14px", background:"rgba(34,197,94,.06)", border:"1px solid rgba(34,197,94,.2)", borderRadius:10, marginBottom:16 }}>
            <p style={{ fontSize:12, color:"#4ade80", fontWeight:700 }}>✅ تم تقييم هذا الأسبوع</p>
          </div>
        )}
        {!isAdminEval && (
          <div style={{ textAlign:"center", padding:"14px", background:"rgba(148,163,184,.06)", border:"1px solid rgba(148,163,184,.15)", borderRadius:10, marginBottom:16 }}>
            <p style={{ fontSize:12, color:"var(--text3)" }}>🔒 التقييم مخفي — متاح للمدير العام ومدير الموارد البشرية فقط</p>
          </div>
        )}

        {/* History */}
        {evals.length > 0 && (
          <div>
            <div className="sec" style={{ marginBottom:10 }}>📊 سجل تقييمات المدير للموظف ({evals.length})</div>
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {[...evals].reverse().map((ev,i) => (
                <div key={i} style={{ padding:"10px 14px", background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:10 }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                    <span style={{ fontSize:12, color:"var(--text3)" }}>📅 {ev.weekStart}</span>
                    {isAdminEval ? (
                      <span style={{ fontSize:14, fontWeight:900, color:ev.finalAverage>=80?"#4ade80":ev.finalAverage>=60?"#f59e0b":"#f87171" }}>⭐ {ev.finalAverage}/100</span>
                    ) : (
                      <span style={{ fontSize:12, color:"var(--text3)", fontStyle:"italic" }}>🔒 التقييم مخفي</span>
                    )}
                  </div>
                  {isAdminEval && (
                    <div style={{ display:"flex", gap:12, flexWrap:"wrap", fontSize:11, color:"var(--text3)" }}>
                      {CRITERIA.map(c => <span key={c.key}>{c.icon} {ev[c.key]||0}</span>)}
                      {ev.notes && <span style={{ color:"var(--text2)" }}>📝 {ev.notes}</span>}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Manager evaluation BY employee */}
        {(()=>{
          const MGR_CRITERIA = [
            { key:"clarity", label:"وضوح التوجيهات", icon:"📋" },
            { key:"support", label:"الدعم والتوجيه", icon:"🤲" },
            { key:"fairness", label:"العدالة في التعامل", icon:"⚖️" },
            { key:"communication", label:"التواصل الفعّال", icon:"💬" },
            { key:"development", label:"تطوير الفريق", icon:"📈" },
          ];
          const mgrEvals = record.mgrEvalsByEmp || [];
          const mgrAvg = mgrEvals.length > 0 ? Math.round(mgrEvals.reduce((s,e)=>s+(e.average||0),0)/mgrEvals.length) : null;
          return (
            <div style={{ marginTop:20 }}>
              <div className="sec" style={{ marginBottom:10, borderColor:"rgba(167,139,250,.3)" }}>
                🔄 تقييم الموظف لمديره {mgrAvg !== null && <span style={{ color:mgrAvg>=80?"#4ade80":mgrAvg>=60?"#f59e0b":"#f87171", fontSize:14 }}>({mgrAvg}/100)</span>}
              </div>
              {mgrEvals.length === 0 ? (
                <p style={{ fontSize:12, color:"var(--text3)", textAlign:"center", padding:14 }}>لم يقم الموظف بتقييم مديره بعد</p>
              ) : (
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {[...mgrEvals].reverse().map((ev,i) => (
                    <div key={i} style={{ padding:"10px 14px", background:"rgba(167,139,250,.04)", border:"1px solid rgba(167,139,250,.15)", borderRadius:10 }}>
                      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                        <span style={{ fontSize:12, color:"var(--text3)" }}>📅 {ev.weekStart}</span>
                        <span style={{ fontSize:14, fontWeight:900, color:ev.average>=80?"#4ade80":ev.average>=60?"#f59e0b":"#f87171" }}>⭐ {ev.average}/100</span>
                      </div>
                      <div style={{ display:"flex", gap:12, flexWrap:"wrap", fontSize:11, color:"var(--text3)" }}>
                        {MGR_CRITERIA.map(c => <span key={c.key}>{c.icon} {ev[c.key]||0}</span>)}
                        {ev.notes && <span style={{ color:"var(--text2)" }}>📝 {ev.notes}</span>}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })()}
      </div>
    );
  }

  if (tab === "dev") return (
    <DevViewPane employees={[record]} />
  );

  return null;
}

// ── InlineEditContent — editable content per tab ─────────────────────────────

// ── StageChangeBtn — manually change candidate stage ─────────────────────────
function StageChangeBtn({ record, onSave }) {
  const [open, setOpen] = useState(false);
  const [postponeData, setPostponeData] = useState(null);
  const currentUser = window._currentUser;
  const isHR = currentUser?.role === "hr_manager" || currentUser?.username === "admin";

  const STAGE_ORDER = ["assessment","interview1","interview2","offer","contract","waiting","rejected"];
  const REC_TO_STAGE = {
    "مقابلة أولى":"interview1", "اختبار":"assessment", "مقابلة ثانية":"interview2",
    "إرسال عرض وظيفي":"offer", "توقيع العقد":"contract",
    "تدريب":"training","قائمة الانتظار":"waiting", "لم يتم القبول":"rejected"
  };
  const STAGE_TO_REC = Object.fromEntries(Object.entries(REC_TO_STAGE).map(([k,v])=>[v,k]));

  const STAGES = [
    { rec:"اختبار",             icon:"📝", color:"#e8eaf0" },
    { rec:"مقابلة أولى",       icon:"🗓️", color:"#e8eaf0" },
    { rec:"مقابلة ثانية",      icon:"🤝", color:"#e8eaf0" },
    { rec:"إرسال عرض وظيفي",  icon:"⭐", color:"#e8eaf0" },
    { rec:"توقيع العقد",        icon:"✅", color:"#e8eaf0" },
    { rec:"تدريب",              icon:"🎓", color:"#e8eaf0" },
    { rec:"قائمة الانتظار",    icon:"⏳", color:"#94a3b8" },
    { rec:"لم يتم القبول",      icon:"❌", color:"#f87171" },
  ];

  const current = record?.evaluation?.recommendation || "";
  const currentStageId = REC_TO_STAGE[current] || "";
  const currentIdx = STAGE_ORDER.indexOf(currentStageId);

  // hasEval: true if current stage has been evaluated OR candidate has no current stage yet
  const hasEval = !currentStageId || // No stage = first time, no eval needed
    record.stageEvaluations?.[currentStageId] ||
    (["مقابلة أولى","مقابلة ثانية"].includes(current) && (record.evaluation?.score || 0) > 0);

  const doChange = async (targetRec) => {
    const targetStageId = REC_TO_STAGE[targetRec] || "";
    const targetIdx = STAGE_ORDER.indexOf(targetStageId);
    const movingForward = targetIdx > currentIdx;
    const movingBackward = targetIdx < currentIdx;
    const steps = Math.abs(targetIdx - currentIdx);

    // Backward: HR only
    if (movingBackward && !isHR) {
      alert("⚠️ الرجوع للخلف متاح لمدير الموارد البشرية والمدير العام فقط");
      return;
    }
    // Non-HR: 1 step forward only
    if (movingForward && !isHR && steps > 1) {
      alert("⚠️ يمكنك نقل المرشح خطوة واحدة للأمام فقط");
      return;
    }
    // Eval check when moving forward — always required
    if (movingForward && !hasEval) {
      if (!isHR) {
        alert("⚠️ يجب تقييم المرحلة الحالية أو كتابة سبب الانتقال قبل المتابعة");
        return;
      } else {
        // HR: show postpone modal to write reason
        setPostponeData({ targetRec, targetStageId });
        return;
      }
    }
    // Proceed with change
    await executeChange(targetRec, currentStageId, null);
  };

  const executeChange = async (targetRec, fromStageId, postponeReason) => {
    const actor = currentUser?.displayName || "المشرف";
    const upd = { ...record, evaluation:{ ...(record.evaluation||{}), recommendation:targetRec, score:(record.evaluation?.score||0) } };
    await onSave(upd);
    // Log to commlog
    const pid = record.uid || record.idNumber || record.email;
    const eventText = (postponeReason ? "تأجيل تقييم — " : "") + "تغيير المرحلة إلى: " + targetRec;
    if (pid) {
      addPersonEvent(pid, { type:"stage", text:eventText, by:actor, byRole:"admin", private:false }).catch(()=>{});
      saveCommLog({ type:"stage_change", candidateId:pid, candidateName:record.fullName,
        notes:eventText, outcome:"تم النقل", by:actor, createdAt:new Date().toISOString() }).catch(()=>{});
      if (postponeReason) {
        addPersonEvent(pid, { type:"note", text:"تأجيل تقييم مرحلة "+fromStageId+" — السبب: "+postponeReason,
          by:actor, byRole:"admin", private:true }).catch(()=>{});
      }
    }
    setOpen(false); setPostponeData(null);
  };

  if (!open && !postponeData) return (
    <button onClick={()=>setOpen(true)} className="btn btn-ghost btn-sm"
      style={{ border:"1px solid var(--modal-border)", color:"var(--gold)", fontSize:11 }}>
      📍 تغيير المرحلة
    </button>
  );

  if (postponeData) return (
    <PostponeEvalModal
      cand={record}
      stageId={postponeData.targetStageId}
      currentStageId={currentStageId}
      onConfirm={async(reason)=>{ await executeChange(postponeData.targetRec, currentStageId, reason); }}
      onClose={()=>setPostponeData(null)}
    />
  );

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:16, padding:22, width:"100%", maxWidth:420 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <div>
            <p style={{ color:"var(--gold)", fontWeight:900, fontSize:15 }}>📍 تغيير مرحلة — {record.fullName}</p>
            {!hasEval && current && <p style={{ fontSize:11, color:"#f87171", marginTop:3 }}>⚠️ لم يتم تقييم المرحلة الحالية بعد</p>}
          </div>
          <button onClick={()=>setOpen(false)} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit", lineHeight:1, flexShrink:0 }} title="إغلاق">✕</button>
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          {STAGES.map(s => {
            const targetStageId = REC_TO_STAGE[s.rec] || "";
            const targetIdx2 = STAGE_ORDER.indexOf(targetStageId);
            const isForward = targetIdx2 > currentIdx;
            const isBackward = targetIdx2 < currentIdx;
            const steps2 = Math.abs(targetIdx2 - currentIdx);
            const disabled = current === s.rec ||
              (isBackward && !isHR) ||
              (isForward && !isHR && steps2 > 1);
            return (
              <button key={s.rec} onClick={()=>doChange(s.rec)}
                disabled={disabled}
                style={{ padding:"10px 16px", borderRadius:10, cursor:disabled?"not-allowed":"pointer",
                  fontFamily:"inherit", fontSize:13, fontWeight:700, textAlign:"right", opacity:disabled?0.4:1,
                  background: current===s.rec ? s.color+"22" : "rgba(255,255,255,.04)",
                  border:"2px solid "+(current===s.rec ? s.color : "rgba(255,255,255,.1)"),
                  color: current===s.rec ? s.color : "var(--text2)" }}>
                {s.icon} {s.rec}
                {current===s.rec && " ← الحالية"}
                {isForward && !isHR && steps2 > 1 && " (يتطلب HR)"}
                {isBackward && !isHR && " (يتطلب HR)"}
              </button>
            );
          })}
        </div>
        <p style={{ fontSize:11, color:"var(--text3)", marginTop:12, textAlign:"center" }}>
          {isHR ? "صلاحيات المدير العام / HR — يمكن التنقل بحرية" : "مشرف — خطوة واحدة للأمام فقط"}
        </p>
      </div>
    </div>
  );
}


function InlineEditContent({ record, tab, type, libs, specsMap, onSave, hideFooter }) {
  const [data, setData] = useState({ ...record });
  const set = (k,v) => setData(p=>({...p,[k]:v}));
  const [saving, setSaving] = useState(false);
  const isEmp = type === "employee";
  const EDUC = ["ثانوية","دبلوم","بكالوريوس","ماجستير","دكتوراه"];
  const AVAIL = ["متاح فوراً","نقل كفالة","خلال أسبوع","خلال شهر","بعد أكثر من شهر"];

  const save = async () => {
    setSaving(true);
    if (isEmp) await saveEmployee(data); else await saveCandidate(data);
    const pid = data.uid || data.idNumber || data.email;
    const actor = window._currentUser;
    if (pid && actor && actor.role === "admin") {
      addPersonEvent(pid, {
        type: "data_check",
        text: "تم تحديث بيانات " + (tab==="info"?"الأساسية":tab==="exp"?"الخبرة":"التصنيفات"),
        by: actor.displayName||actor.username,
        byRole: "admin",
        private: false,
        personName: data.fullName||"",
      }).catch(()=>{});
    }
    await onSave(data);
    setSaving(false);
  };

  const Footer = () => hideFooter ? null : (
    <div style={{ display:"flex", justifyContent:"flex-end", marginTop:16 }}>
      <button onClick={save} disabled={saving} className="btn btn-gold">
        {saving?"⏳ جاري الحفظ...":"💾 حفظ"}
      </button>
    </div>
  );

  if (tab === "info") return (
    <div>
      <div className="g2" style={{ marginBottom:12 }}>
        <div className="field"><label className="label">الاسم الكامل</label><input value={data.fullName||""} onChange={e=>set("fullName",e.target.value)} /></div>
        <div className="field"><label className="label">الاسم بالإنجليزية</label><input value={data.fullNameEn||""} onChange={e=>set("fullNameEn",e.target.value)} style={{ direction:"ltr", textAlign:"left" }} /></div>
        <div className="field"><label className="label">الجوال</label><input value={data.phone||""} onChange={e=>set("phone",e.target.value)} /></div>
        <div className="field"><label className="label">البريد الرسمي</label><input value={data.email||""} onChange={e=>set("email",e.target.value)} placeholder="name@hma.sa" /></div>
        <div className="field"><label className="label">البريد الشخصي</label><input value={data.personalEmail||""} onChange={e=>set("personalEmail",e.target.value)} placeholder="name@gmail.com" /></div>
        <div className="field"><label className="label">رقم الهوية</label><input value={data.idNumber||""} onChange={e=>set("idNumber",e.target.value)} /></div>
        <div className="field"><label className="label">الجنسية</label><input value={data.nationality||""} onChange={e=>set("nationality",e.target.value)} /></div>
        <div className="field"><label className="label">المدينة</label><input value={data.city||""} onChange={e=>set("city",e.target.value)} /></div>
        <div className="field"><label className="label">الموقع</label>
          <select value={data.locationStatus||""} onChange={e=>set("locationStatus",e.target.value)}>
            <option value="">--</option><option>داخل السعودية</option><option>خارج السعودية</option>
          </select>
        </div>
        {isEmp ? <>
          <div className="field"><label className="label">نوع التوظيف</label>
            <select value={data.employmentType||"موظف دوام كامل"} onChange={e=>set("employmentType",e.target.value)}>
              <option>موظف دوام كامل</option><option>عقد مرن</option><option>موظف دوام كامل ومرن</option><option>متدرب</option><option>موظف سابق</option>
            </select>
          </div>
          <div className="field"><label className="label">الإدارة</label>
            <select value={data.department||""} onChange={e=>set("department",e.target.value)}>
              <option value="">--</option>{(libs.jobTypes||[]).map((j,ji)=>{const jl=typeof j==="string"?j:(j&&(j.ar||j.label||j.en))||"";return jl?<option key={jl+ji} value={jl}>{jl}</option>:null;})}
            </select>
          </div>
          <div className="field"><label className="label">🏢 الفرع</label>
            <select value={data.branch||""} onChange={e=>set("branch",e.target.value)}>
              <option value="">--</option>
              {((libs||{}).branches||DEFAULT_LIBS.branches).map(b=><option key={b} value={b}>{b}</option>)}
            </select>
          </div>
          <div className="field"><label className="label">الراتب (ريال)</label><input type="number" value={data.salary||""} onChange={e=>set("salary",e.target.value)} /></div>
          <div className="field"><label className="label">تاريخ الالتحاق</label><input type="date" value={data.joinDate||""} onChange={e=>set("joinDate",e.target.value)} /></div>
          <div className="field"><label className="label">المسمى الوظيفي</label>
            <select value={data.jobTitleId||""} onChange={e=>{
              const id = e.target.value;
              const jt = (window._jobTitles||[]).find(j=>j.id===id);
              if (jt) {
                set("jobTitleId", id);
                set("jobTitle", jt.title);
                if (jt.dept) set("department", jt.dept);
                if (jt.gradeRef) set("gradeCode", jt.gradeRef);
              } else {
                set("jobTitleId", "");
                set("jobTitle", "");
              }
            }} style={{ fontSize:13 }}>
              <option value="">-- اختر المسمى الوظيفي --</option>
              {(() => {
                const allJTs = (window._jobTitles||[]).filter(j=>j.title);
                const allEmps = (window._allEmps||[]);
                const orgCfg = window._orgChartConfig || { positions:{} };
                const myId = data.idNumber || data.email || data.uid;
                // حساب الشواغر لكل مسمى
                return allJTs.map(jt => {
                  const headcount = (orgCfg?.positions?.[jt.id]?.headcount) || 1;
                  // عدد الموظفين على هذا المسمى (باستثناء الموظف الحالي)
                  const assigned = allEmps.filter(e => 
                    e.jobTitleId === jt.id && 
                    (e.idNumber||e.email||e.uid) !== myId
                  ).length;
                  const vacancies = headcount - assigned;
                  // أظهر فقط لو فيه شاغر، أو لو هذا المسمى الحالي للموظف
                  const isCurrent = data.jobTitleId === jt.id;
                  if (vacancies <= 0 && !isCurrent) return null;
                  const label = jt.title + 
                    (jt.dept ? " — " + jt.dept : "") + 
                    " (" + vacancies + "/" + headcount + " شاغر)";
                  return <option key={jt.id} value={jt.id}>{label}</option>;
                }).filter(Boolean);
              })()}
            </select>
            {data.jobTitle && !data.jobTitleId && <p style={{ fontSize:10, color:"#f59e0b", marginTop:4 }}>⚠️ المسمى الحالي: "{data.jobTitle}" غير مرتبط بالهيكل التنظيمي — اختر من القائمة</p>}
          </div>
          <div className="field"><label className="label">رمز الدرجة</label>
            <input value={data.gradeCode||""} onChange={e=>set("gradeCode",e.target.value)} placeholder="E5" /></div>
          <div className="field"><label className="label">المدير المباشر</label>
            <select value={data.managerId||""} onChange={e=>set("managerId",e.target.value)}>
              <option value="">-- اختر</option>
              {(window._allEmps||[]).filter(x=>(x.idNumber||x.email)!==(data.idNumber||data.email)).map(x=>(
                <option key={x.idNumber||x.email} value={x.idNumber||x.email}>{x.fullName}{x.jobTitle?" ("+x.jobTitle+")":""}</option>
              ))}
            </select>
          </div>
          <div className="field"><label className="label">المدير الثاني (Matrix)</label>
            <select value={data.managerId2||""} onChange={e=>set("managerId2",e.target.value)}>
              <option value="">-- لا يوجد</option>
              {(window._allEmps||[]).filter(x=>(x.idNumber||x.email)!==(data.idNumber||data.email)).map(x=>(
                <option key={x.idNumber||x.email} value={x.idNumber||x.email}>{x.fullName}{x.jobTitle?" ("+x.jobTitle+")":""}</option>
              ))}
            </select>
          </div>
          <div className="field"><label className="label">انتهاء العقد</label><input type="date" value={data.contractEnd||""} onChange={e=>set("contractEnd",e.target.value)} /></div>
        </> : <>
          <div className="field"><label className="label">حالة الإتاحة</label>
            <select value={data.availabilityStatus||""} onChange={e=>set("availabilityStatus",e.target.value)}>
              <option value="">--</option>{AVAIL.map(a=><option key={a}>{a}</option>)}
            </select>
          </div>
          <div className="field"><label className="label">خاص بطالبي التدريب والتدريب المنتهي بالتوظيف</label>
            <select value={data.trainingType||""} onChange={e=>set("trainingType",e.target.value)}>
              <option value="">-- لا ينطبق</option>
              <option>طلب تدريب جامعي</option>
              <option>طلب تدريب منتهي بالتوظيف</option>
              <option>طلب تدريب</option>
            </select>
          </div>
          <div className="field"><label className="label">الراتب المتوقع</label><input type="number" value={data.expectedSalary||""} onChange={e=>set("expectedSalary",e.target.value)} /></div>
        </>}
        <div className="field" style={{ gridColumn:"1/-1" }}><label className="label">ملاحظات</label>
          <textarea value={data.notes||""} onChange={e=>set("notes",e.target.value)} style={{ minHeight:60 }} />
        </div>

      </div>
      <Footer/>
    </div>
  );

  if (tab === "exp") return (
    <div>
      <div className="g2" style={{ marginBottom:12 }}>
        <div className="field"><label className="label">سنوات الخبرة</label><input type="number" value={data.yearsExperience||""} onChange={e=>set("yearsExperience",e.target.value)} /></div>
        <div className="field"><label className="label">آخر مسمى وظيفي</label><input value={data.lastJob||""} onChange={e=>set("lastJob",e.target.value)} /></div>
        <div className="field"><label className="label">آخر شركة</label><input value={data.lastCompany||""} onChange={e=>set("lastCompany",e.target.value)} /></div>
        <div className="field"><label className="label">المؤهل</label>
          <select value={data.education||""} onChange={e=>set("education",e.target.value)}>
            <option value="">--</option>{EDUC.map(e=><option key={e}>{e}</option>)}
          </select>
        </div>
        <div className="field"><label className="label">الجامعة</label><input value={data.university||""} onChange={e=>set("university",e.target.value)} /></div>
        <div className="field"><label className="label">سنة التخرج</label>
          <input type="number" value={data.graduationYear||""} onChange={e=>{ set("graduationYear",e.target.value); set("yearsFromGraduation",2026-parseInt(e.target.value||0)); }} />
        </div>
        <div className="field"><label className="label">التخصص الرئيسي</label>
          <select value={data.primarySpecId||""} onChange={e=>set("primarySpecId",e.target.value)}>
            <option value="">-- اختر تخصص رئيسي</option>
            {((libs||{}).specs||[]).map(s=><option key={s.id} value={s.id}>{s.icon} {s.label}</option>)}
          </select>
        </div>
        <div className="field"><label className="label">الجامعة 2 (ماجستير / دكتوراه)</label><input value={data.university2||""} onChange={e=>set("university2",e.target.value)} placeholder="اختياري" /></div>
        <div className="field"><label className="label">سنة التخرج 2</label>
          <input type="number" value={data.graduationYear2||""} onChange={e=>set("graduationYear2",e.target.value)} placeholder="اختياري" />
        </div>
        <div className="field"><label className="label">التخصص الإضافي (ماجستير / دكتوراه)</label>
          <select value={data.secondarySpecId||""} onChange={e=>set("secondarySpecId",e.target.value)}>
            <option value="">-- اختياري</option>
            {((libs||{}).specs||[]).map(s=><option key={s.id} value={s.id}>{s.icon} {s.label}</option>)}
          </select>
        </div>
        {!isEmp && <div className="field"><label className="label">الراتب المتوقع</label><input type="number" value={data.expectedSalary||""} onChange={e=>set("expectedSalary",e.target.value)} /></div>}
        <div className="field" style={{ gridColumn:"1/-1" }}><label className="label">الشركات السابقة</label>
          <input value={(data.companies||[]).join("، ")} onChange={e=>set("companies",e.target.value.split(/[,،]/).map(s=>s.trim()).filter(Boolean))} placeholder="افصل بفاصلة" />
        </div>
      </div>
      <Footer/>
    </div>
  );

  if (tab === "tags") {
    if (!libs) return <div style={{ textAlign:"center",padding:40 }}><div className="loader"/></div>;
    try {
    return (
    <div>
      <EmpBiBlock title="التخصصات" icon="🏗️" field="biSpec" data={data} set={set} libItems={((libs||{}).specs||[]).map(s=>typeof s==="string"?s:(s&&s.label)||"").filter(Boolean)} isSpecs={true} specs={(libs||{}).specs||[]} />
      <EmpBiBlock title="الإدارات"       icon="🏢" field="biDept"  data={data} set={set} libItems={(libs||{}).jobTypes||[]} />
      <EmpBiBlock title="المهارات"       icon="🛠️" field="biSkill" data={data} set={set} libItems={(libs||{}).skills||[]} />
      <EmpBiBlock title="البرامج"        icon="💻" field="biSW"    data={data} set={set} libItems={(libs||{}).software||[]} />
      <EmpBiBlock title="أنواع المشاريع" icon="📋" field="biProj"  data={data} set={set} libItems={(libs||{}).projectTypes||[]} />
      <EmpBiBlock title="الشهادات"       icon="🏅" field="biCert"  data={data} set={set} libItems={(libs||{}).certifications||[]} />
      {/* Haya rank as classification */}
      <div className="card" style={{ marginBottom:10 }}>
        <div className="sec" style={{ marginBottom:8 }}>🏛️ الدرجة المهنية للهيئة السعودية للمهندسين</div>
        <div className="g2">
          <div className="field">
            <label className="label">الدرجة المهنية</label>
            <select value={typeof data.hayaRank==="object"?(data.hayaRank?.ar||""):data.hayaRank||""} onChange={e=>set("hayaRank", e.target.value)}>
              <option value="">-- اختر</option>
              {((libs||{}).hayaGrades||[]).map((g,i)=><option key={i} value={typeof g==="object"?g.ar:g}>{typeof g==="object"?g.ar:g}</option>)}
            </select>
          </div>
          <div className="field">
            <label className="label">رقم العضوية</label>
            <input value={data.hayaMemberNo||""} onChange={e=>set("hayaMemberNo",e.target.value)} placeholder="SCE-XXXXX" />
          </div>
          <div className="field">
            <label className="label">تاريخ الانتهاء</label>
            <input type="date" value={data.hayaExpiry||""} onChange={e=>set("hayaExpiry",e.target.value)} />
          </div>
        </div>
      </div>
      <Footer/>
    </div>
  );
    } catch(e) {
      return <div style={{ padding:20, color:"var(--text3)", fontSize:13 }}>⚠️ خطأ في التصنيفات — {e?.message||"unknown"}</div>;
    }
  }

  if (tab === "cv") return (
    <div className="card">
      <CVExtractor
        onExtract={async (extracted) => {
          if (!extracted) return;
          const fieldMap = {
            fullName:1, fullNameEn:1, phone:1, email:1, idNumber:1,
            nationality:1, gender:1, city:1, locationStatus:1,
            education:1, university:1, major:1, graduationYear:1,
            yearsExperience:1, lastJob:1, lastCompany:1, expectedSalary:1,
            linkedinUrl:1, companies:1, availabilityStatus:1, trainingType:1, notes:1,
            hayaMemberNo:1, hayaRank:1, hayaExpiry:1,
            biSpec:1, biDept:1, biSkill:1, biSW:1, biProj:1, biCert:1,
            specId:1, primarySpecId:1, secondarySpecId:1, university2:1, specializations:1, skills:1, software:1, certifications:1,
            cvHistory:1, cvFullText:1, _hasPendingTags:1,
          };
          const merged = { ...data };
          Object.entries(extracted).forEach(([k,v]) => {
            if (!fieldMap[k]) return;
            if (v===null||v===undefined||v==="") return;
            if (Array.isArray(v)&&v.length===0) return;
            merged[k] = v;
          });
          merged.uid = data.uid;
          if (isEmp) await saveEmployee(merged); else await saveCandidate(merged);
          await onSave(merged);
        }}
        libs={libs}
        sessionEmail={data.email}
        candidateId={data.uid||data.idNumber||data.email}
        isAdmin={true}
      />
    </div>
  );

  if (tab === "history") return (
    <EventsLog
      personId={data.uid || data.idNumber || data.email}
      currentUser={window._currentUser || null}
      isAdmin={true}
    />
  );

  if (tab === "dev") return (
    <DevEditPane employees={[data]} />
  );

  return null;
}


// ── AI Permission check ───────────────────────────────────────────────────────
function hasAIAccess(user) {
  if (!user) return false;
  if (user.username === "admin") return true;
  if (user.role === "hr_manager") return !!(user.aiAccess);
  return !!(user.aiAccess);
}

function isHRManager(user) {
  return user?.role === "hr_manager" || user?.username === "admin";
}

function canSeeSalary(user) {
  // Only HR Manager and System Admin (GM) can see salary details
  return user?.role === "hr_manager" || user?.username === "admin";
}


