// ── StageActionModal — unified: fields + message + channels + queue ──
function StageActionModal({ candidate, stageId, interviews, onClose, onSend, onSaveInterview, onQueue }) {
  const STAGE_CFG = {
    interview1: { title:"💬 جدولة مقابلة أولى", fields:["date","time","location","interviewer"], required:["date","time","location"] },
    interview2: { title:"🤝 جدولة مقابلة ثانية", fields:["date","time","location","interviewer"], required:["date","time","location"] },
    assessment: { title:"📝 إرسال رابط اختبار", fields:["date","time","link"], required:["link"] },
    offer:      { title:"⭐ إعداد عرض وظيفي", fields:["jobTitle","salary","date"], required:["date"] },
    contract:   { title:"✍️ موعد توقيع العقد", fields:["date","time","location"], required:["date","location"] },
    welcome:    { title:"🎉 ترحيب بموظف جديد", fields:["date"], required:["date"] },
    waiting:    { title:"⏳ إشعار قائمة الانتظار", fields:[], required:[] },
    rejected:   { title:"❌ إشعار عدم القبول", fields:[], required:[] },
    draft_contract: { title:"📑 إرسال مسودة عقد", fields:["date"], required:[] },
    candidate_rejected: { title:"🚫 رفض المرشح العرض", fields:[], required:[] },
    training:   { title:"🎓 بدء التدريب", fields:["date","location"], required:["date"] },
  };
  const cfg = STAGE_CFG[stageId] || STAGE_CFG.waiting;
  const tpls = STAGE_TEMPLATES[stageId] || STAGE_TEMPLATES.waiting;

  const existingInt = (interviews||[]).find(iv => (iv.candidateId===candidate.uid||iv.candidateId===candidate.email) && (
    (stageId==="interview1" && iv.type==="مقابلة أولى") || (stageId==="interview2" && iv.type==="مقابلة ثانية")
  ));

  const [form, setForm] = useState({
    date: existingInt?.date || new Date().toISOString().split("T")[0],
    time: existingInt?.time || "10:00",
    location: existingInt?.location || "",
    link: "", interviewer: existingInt?.interviewer || "",
    jobTitle: candidate.lastJob || candidate.jobTitle || "",
    salary: candidate.expectedSalary || "",
  });
  const [useTemplate, setUseTemplate] = useState(true);
  const [msgText, setMsgText] = useState("");
  const [channels, setChannels] = useState({ email:true, whatsapp:false, system:false });
  const [err, setErr] = useState("");
  const { show, toastEl } = useToast();
  const set = (k,v) => setForm(p=>({...p,[k]:v}));
  const toggleCh = (k) => setChannels(p=>({...p,[k]:!p[k]}));

  const FIELD_UI = {
    date:        { label:"📅 التاريخ", type:"date" },
    time:        { label:"🕐 الوقت", type:"time" },
    location:    { label:"📍 المكان / رابط الاجتماع", type:"text", placeholder:"رابط Zoom أو عنوان المكتب" },
    link:        { label:"🔗 رابط الاختبار", type:"url", placeholder:"https://..." },
    interviewer: { label:"👤 المقابِل", type:"text", placeholder:"اسم المقابِل" },
    jobTitle:    { label:"💼 المسمى الوظيفي", type:"text", placeholder:"مهندس مدني أول" },
    salary:      { label:"💰 الراتب (ريال)", type:"number", placeholder:"الراتب الشهري" },
  };

  // Build message from template with actual data
  const buildFromTemplate = (channel) => {
    const tpl = channel === "whatsapp" ? tpls.whatsapp : tpls.email;
    return tpl
      .split("{name}").join(candidate.fullName || "")
      .split("{date}").join(form.date || "")
      .split("{time}").join(form.time ? " الساعة " + form.time : "")
      .split("{location}").join(form.location || "")
      .split("{link}").join(form.link || "")
      .split("{interviewer}").join(form.interviewer ? "\nالمقابِل: " + form.interviewer : "")
      .split("{jobTitle}").join(form.jobTitle || "")
      .split("{salary}").join(form.salary ? Number(form.salary).toLocaleString() : "يُحدد لاحقاً");
  };

  // Get the displayed message
  const getMessage = (channel) => {
    if (useTemplate) return buildFromTemplate(channel || "email");
    return msgText;
  };

  // Displayed preview — use email template for preview
  const previewMsg = getMessage("email");

  const validate = () => {
    const missing = cfg.required.filter(f => !form[f]?.toString().trim());
    if (missing.length > 0) {
      setErr("يرجى تعبئة: " + missing.map(f => (FIELD_UI[f]?.label||f).replace(/^[^\s]+\s/,"")).join("، "));
      return false;
    }
    if (!useTemplate && !msgText.trim()) { setErr("يرجى كتابة نص الرسالة أو تفعيل النموذج المعتمد"); return false; }
    if (!Object.values(channels).some(Boolean)) { setErr("اختر قناة إرسال واحدة على الأقل"); return false; }
    return true;
  };

  const handleSend = async () => {
    if (!validate()) return;
    // Save interview if applicable
    if (["interview1","interview2"].includes(stageId) && onSaveInterview) {
      await onSaveInterview({
        candidateId: candidate.uid || candidate.email,
        candidateName: candidate.fullName || "",
        type: stageId === "interview1" ? "مقابلة أولى" : "مقابلة ثانية",
        date: form.date, time: form.time, location: form.location,
        interviewer: form.interviewer, status: "مجدولة",
      });
    }
    // Build per-channel messages
    const emailMsg = getMessage("email");
    const waMsg = getMessage("whatsapp");
    onSend({ emailMsg, waMsg, channels, form });
  };

  const handleQueue = async () => {
    if (!validate()) return;
    if (["interview1","interview2"].includes(stageId) && onSaveInterview) {
      await onSaveInterview({
        candidateId: candidate.uid || candidate.email,
        candidateName: candidate.fullName || "",
        type: stageId === "interview1" ? "مقابلة أولى" : "مقابلة ثانية",
        date: form.date, time: form.time, location: form.location,
        interviewer: form.interviewer, status: "مجدولة",
      });
    }
    const emailMsg = getMessage("email");
    const waMsg = getMessage("whatsapp");
    if (onQueue) onQueue({ emailMsg, waMsg, channels, form, candidate, stageId });
    else {
      // Fallback: save to email queue in localStorage
      const queue = JSON.parse(localStorage.getItem("hma_email_queue") || "[]");
      queue.push({
        id: "q_" + Date.now(),
        to: candidate.email, toName: candidate.fullName, phone: candidate.phone,
        emailBody: emailMsg, waBody: waMsg, channels,
        stageId, createdAt: new Date().toISOString(), status: "pending",
      });
      localStorage.setItem("hma_email_queue", JSON.stringify(queue));
      show("📬 تم حفظ الرسالة في قائمة الانتظار");
      onClose();
    }
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.6)", backdropFilter:"blur(6px)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}
      onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      {toastEl}
      <div className="fade" style={{ background:"var(--dark2)", border:"1px solid rgba(201,168,76,.2)", borderRadius:18, width:"100%", maxWidth:560, maxHeight:"92vh", overflowY:"auto" }}>
        {/* Header */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"16px 20px", borderBottom:"1px solid rgba(201,168,76,.15)", background:"linear-gradient(135deg,rgba(201,168,76,.08),rgba(201,168,76,.02))" }}>
          <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16 }}>{cfg.title}</p>
          <button onClick={onClose} style={{ width:30, height:30, borderRadius:"50%", background:"rgba(239,68,68,.12)", border:"1px solid rgba(239,68,68,.35)", color:"#f87171", fontSize:16, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"inherit" }}>✕</button>
        </div>

        <div style={{ padding:"16px 20px" }}>
        {/* Candidate info */}
        <div style={{ display:"flex", alignItems:"center", gap:10, padding:"10px 14px", background:"rgba(201,168,76,.06)", border:"1px solid rgba(201,168,76,.15)", borderRadius:10, marginBottom:16 }}>
          <div style={{ width:36, height:36, borderRadius:"50%", background:"linear-gradient(135deg,#c9a84c,#a8893a)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:900, color:"#0b0f1a", flexShrink:0 }}>
            {(candidate.fullName||"?").split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase()}
          </div>
          <div style={{ flex:1, minWidth:0 }}>
            <p style={{ fontWeight:700, fontSize:14, color:"var(--text)" }}>{candidate.fullName}</p>
            <p style={{ fontSize:11, color:"var(--text3)" }}>{[candidate.email, candidate.phone].filter(Boolean).join(" • ")}</p>
          </div>
        </div>

        {/* Stage fields */}
        {cfg.fields.length > 0 && (
          <div style={{ display:"grid", gridTemplateColumns:cfg.fields.length>1?"1fr 1fr":"1fr", gap:10, marginBottom:16 }}>
            {cfg.fields.map(f => {
              const ui = FIELD_UI[f];
              if (!ui) return null;
              const isReq = cfg.required.includes(f);
              return (
                <div key={f} className="field">
                  <label className="label" style={{ fontSize:11 }}>{ui.label}{isReq?" *":""}</label>
                  <input type={ui.type||"text"} value={form[f]||""} onChange={e=>set(f,e.target.value)} placeholder={ui.placeholder||""}
                    style={{ fontSize:13, padding:"8px 10px" }} />
                </div>
              );
            })}
          </div>
        )}

        {/* Message section */}
        <div style={{ marginBottom:14 }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
            <span style={{ fontSize:13, fontWeight:700, color:"var(--text2)" }}>✉️ نص الرسالة</span>
            <label style={{ display:"flex", alignItems:"center", gap:6, cursor:"pointer", fontSize:12, color:useTemplate?"var(--gold)":"var(--text3)" }}>
              <input type="checkbox" checked={useTemplate} onChange={()=>setUseTemplate(p=>!p)}
                style={{ accentColor:"#c9a84c", width:16, height:16 }} />
              إرسال وفق النموذج المعتمد
            </label>
          </div>
          <textarea
            value={useTemplate ? previewMsg : msgText}
            onChange={e => { if(!useTemplate) setMsgText(e.target.value); }}
            readOnly={useTemplate}
            rows={8}
            placeholder={useTemplate ? "" : "اكتب رسالتك هنا..."}
            style={{ width:"100%", background:useTemplate?"rgba(201,168,76,.04)":"rgba(255,255,255,.05)", border:"1px solid "+(useTemplate?"rgba(201,168,76,.2)":"var(--b)"), borderRadius:10, outline:"none", color:"var(--text)", fontSize:13, fontFamily:"inherit", lineHeight:1.8, padding:"10px 12px", resize:"none", direction:"rtl" }} />
          {useTemplate && channels.whatsapp && (
            <details style={{ marginTop:6 }}>
              <summary style={{ fontSize:11, color:"var(--text3)", cursor:"pointer" }}>👁️ معاينة رسالة الواتساب</summary>
              <pre style={{ fontSize:11, color:"var(--text2)", background:"rgba(37,211,102,.05)", border:"1px solid rgba(37,211,102,.15)", borderRadius:8, padding:10, marginTop:4, whiteSpace:"pre-wrap", direction:"rtl", fontFamily:"inherit", lineHeight:1.7 }}>{buildFromTemplate("whatsapp")}</pre>
            </details>
          )}
        </div>

        {/* Channel buttons */}
        <div style={{ display:"flex", gap:8, marginBottom:16, flexWrap:"wrap" }}>
          {[
            { key:"email", icon:"✉️", label:"بريد إلكتروني", disabled:!candidate.email, color:"#0a84ff" },
            { key:"whatsapp", icon:"📱", label:"واتساب", disabled:!candidate.phone, color:"#25d366" },
            { key:"system", icon:"🔔", label:"إشعار نظام", disabled:false, color:"#a78bfa" },
          ].map(ch=>(
            <button key={ch.key} onClick={()=>{ if(!ch.disabled) toggleCh(ch.key); }} disabled={ch.disabled}
              style={{ display:"flex", alignItems:"center", gap:5, padding:"6px 14px", borderRadius:20, cursor:ch.disabled?"not-allowed":"pointer", fontFamily:"inherit", fontSize:12, fontWeight:600,
                border:"1px solid "+(channels[ch.key]?ch.color+"66":"rgba(255,255,255,.1)"),
                background:channels[ch.key]?ch.color+"18":"rgba(255,255,255,.04)",
                color:channels[ch.key]?ch.color:"var(--text3)", opacity:ch.disabled?.4:1 }}>
              {ch.icon} {ch.label}
            </button>
          ))}
        </div>

        {err && <p style={{ color:"var(--red)", fontSize:12, marginBottom:12, padding:"7px 12px", background:"rgba(239,68,68,.08)", borderRadius:7, border:"1px solid rgba(239,68,68,.2)" }}>{err}</p>}

        {/* Action buttons */}
        <div style={{ display:"flex", gap:8, justifyContent:"flex-end", flexWrap:"wrap" }}>
          <button onClick={onClose} className="btn btn-ghost" style={{ fontSize:12 }}>تخطي</button>
          <button onClick={handleQueue} className="btn btn-ghost" style={{ fontSize:12, color:"#f59e0b", border:"1px solid rgba(245,158,11,.3)" }}>📬 حفظ وإرسال لاحقاً</button>
          <button onClick={handleSend} className="btn btn-gold" style={{ fontSize:13 }}>✉️ إرسال الآن</button>
        </div>
        </div>
      </div>
    </div>
  );
}

function HiringStagesSection({ candidates, employees, libs, currentUser }) {
  const [cands, setCands]         = useState(candidates);
  const [selCand, setSelCand]     = useState(null);
  const [stage, setStage]         = useState(null);
  const [search, setSearch]       = useState("");
  const [showOffer, setShowOffer] = useState(false);
  const [showDraftContract, setShowDraftContract] = useState(false);
  const [quickMsgCand, setQuickMsgCand] = useState(null);
  const [stageActionCand, setStageActionCand] = useState(null); // { cand, stageId }
  const [qMsg, setQMsg] = useState({ text:"", channels:{ email:true, system:false, whatsapp:false }, sendEmailCopy:false });
  const [view, setView]           = useState("tree");
  const [openStages, setOpenStages] = useState({}); // v37.47: شجرة المراحل — مغلقة بالافتراض
  const [interviews, setInterviews] = useState([]);
  const [showIntForm, setShowIntForm] = useState(false);
  const [intForm, setIntForm]     = useState({ candidateId:"", candidateName:"", type:"مقابلة أولى", date:new Date().toISOString().split("T")[0], time:"10:00", location:"", interviewer:"", notes:"", result:"", score:"", status:"مجدولة", evalTechnical:"", evalAdmin:"", evalLanguage:"", evalGeneral:"", evalNotes:"" });
  const [allJobs, setAllJobs]     = useState([]);
  const [evalForm, setEvalForm]   = useState(null);
  const [kanbanEvalCand, setKanbanEvalCand] = useState(null);
  const { show, toastEl }         = useToast();
  const { confirm, dlg }          = useConfirm();

  // Role checks
  const isHR = currentUser?.role === "hr_manager" || currentUser?.username === "admin";

  useEffect(()=>{ getAllInterviews().then(setInterviews); getAllJobs().then(setAllJobs); },[]);
  // Sync candidates when prop changes
  useEffect(()=>{ setCands(candidates); },[candidates]);

  const STAGES = [
    { id:"assessment",          label:"اختبار",               icon:"📝", color:"#3b82f6" },
    { id:"interview1",          label:"مقابلة أولى",           icon:"🤝", color:"#22c55e" },
    { id:"interview2",          label:"مقابلة ثانية",          icon:"💬", color:"#8b5cf6" },
    { id:"offer",               label:"إرسال عرض وظيفي",      icon:"⭐", color:"#f59e0b" },
    { id:"draft_contract",      label:"إرسال مسودة عقد",      icon:"📑", color:"#06b6d4" },
    { id:"contract",            label:"توقيع العقد",           icon:"📋", color:"#10b981" },
    { id:"training",            label:"تدريب",                 icon:"🎓", color:"#e879f9" },
    { id:"waiting",             label:"قائمة الانتظار",        icon:"⏸️", color:"#94a3b8" },
    { id:"rejected",            label:"لم يتم القبول",         icon:"❌", color:"#ef4444" },
    { id:"candidate_rejected",  label:"رفض المرشح العرض",     icon:"🚫", color:"#fb923c" },
  ];

  const STAGE_ORDER = ["assessment","interview1","interview2","offer","draft_contract","contract","training","waiting","rejected","candidate_rejected"];

  const STAGE_TO_REC = {
    interview1:"مقابلة أولى", assessment:"اختبار", interview2:"مقابلة ثانية",
    offer:"إرسال عرض وظيفي", draft_contract:"إرسال مسودة عقد", contract:"توقيع العقد",
    training:"تدريب", waiting:"قائمة الانتظار", rejected:"لم يتم القبول",
    candidate_rejected:"مرفوض من قبل المرشح"
  };

  const getCandStage = (c) => {
    const rec = c.evaluation?.recommendation || "";
    return Object.entries(STAGE_TO_REC).find(([,v])=>v===rec)?.[0] || null;
  };

  const hasEvalForStage = (cand, stageId) => {
    // Check if candidate has been evaluated for current stage
    const stageEvals = cand.stageEvaluations || {};
    return !!stageEvals[stageId];
  };

  const changeStage = async (cand, stageId) => {
    const currentStageId = getCandStage(cand);
    const currentIdx = STAGE_ORDER.indexOf(currentStageId);
    const targetIdx  = STAGE_ORDER.indexOf(stageId);
    const movingForward = targetIdx > currentIdx;
    const movingBackward = targetIdx < currentIdx;
    const steps = Math.abs(targetIdx - currentIdx);
    const alreadyEval = hasEvalForStage(cand, currentStageId);

    // Backward: HR/Admin only
    if (movingBackward && !isHR) {
      show("⚠️ الرجوع للخلف متاح للمدير العام أو مدير الموارد البشرية فقط"); return;
    }

    // Non-HR: only 1 step forward
    if (movingForward && !isHR && steps > 1) {
      show("⚠️ يمكنك نقل المرشح خطوة واحدة للأمام فقط"); return;
    }

    // Eval check when moving forward
    if (movingForward && currentStageId && !alreadyEval) {
      if (!isHR) {
        // Non-HR: must evaluate first, no exceptions
        show("⚠️ يجب تقييم المرحلة الحالية أولاً قبل الانتقال"); return;
      } else {
        // HR/Admin: can postpone with mandatory note
        setPostponeModal({ cand, stageId, currentStageId }); return;
      }
    }

    await doChangeStage(cand, stageId, currentStageId);
  };

  const [postponeModal, setPostponeModal] = useState(null);

  const doChangeStage = async (cand, stageId, fromStageId) => {

    const rec = STAGE_TO_REC[stageId];
    const movBack = STAGE_ORDER.indexOf(stageId) < STAGE_ORDER.indexOf(fromStageId||stageId);
    // Preserve previous evals when moving backward
    const stageEvals = cand.stageEvaluations || {};
    const upd = { ...cand,
      evaluation: { ...(cand.evaluation||{}), recommendation: rec },
      stageEvaluations: stageEvals,
      updatedAt: new Date().toISOString()
    };
    await saveCandidate(upd);
    setCands(p => p.map(x => (x.uid||x.idNumber||x.email)===(cand.uid||cand.idNumber||cand.email) ? upd : x));
    const pid = cand.uid||cand.idNumber||cand.email;
    const actor = currentUser?.displayName||"المشرف";
    const fromLabel = STAGE_TO_REC[fromStageId||""] || fromStageId || "";
    const eventText = movBack
      ? "رجوع من مرحلة "+fromLabel+" إلى: "+rec
      : "تغيير المرحلة إلى: "+rec;
    await addPersonEvent(pid, { type:"stage", text:eventText, by:actor, byRole:"admin", private:false }).catch(()=>{});
    // Log to interview log
    await saveCommLog({ type:"stage_change", candidateId:pid, candidateName:cand.fullName,
      notes:eventText, outcome:"تم النقل", by:actor, createdAt:new Date().toISOString() }).catch(()=>{});
    // After stage change — open StageActionModal for the new stage
    show("✅ تم تغيير مرحلة " + cand.fullName + " إلى " + rec);
    setSelCand(null); setStage(null); show("✅ تم تغيير المرحلة");
    // Trigger the unified stage action modal for sending message
    setTimeout(() => setStageActionCand({ cand: upd, stageId }), 300);
  };

  const saveEval = async () => {
    if (!evalForm) return;
    const wordCount = (evalForm.evalNotes||"").trim().split(/\s+/).filter(Boolean).length;
    if (wordCount < 10) { show("⚠️ الملاحظات يجب أن لا تقل عن 10 كلمات"); return; }
    const stageId = getCandStage(evalForm);
    const thisTotal = Math.round(([evalForm.evalTechnical,evalForm.evalAdmin,evalForm.evalLanguage,evalForm.evalGeneral].map(Number).reduce((a,b)=>a+b,0))/4);
    const newEvalEntry = {
      technical: evalForm.evalTechnical, admin: evalForm.evalAdmin,
      language: evalForm.evalLanguage, general: evalForm.evalGeneral,
      notes: evalForm.evalNotes, total: thisTotal,
      by: evalForm._evalOnBehalf || window._currentUser?.displayName || "المشرف",
      byId: window._currentUser?.username || "",
      at: new Date().toISOString(),
    };
    const stageEvals = { ...(evalForm.stageEvaluations||{}) };
    const existing = stageEvals[stageId] || {};
    const evalList = [...(existing.evaluations || [])];
    // If editing an existing eval by same person, replace it
    const sameIdx = evalList.findIndex(e => e.byId === newEvalEntry.byId);
    if (sameIdx >= 0 && !evalForm._evalOnBehalf) evalList[sameIdx] = newEvalEntry;
    else evalList.push(newEvalEntry);
    // Calculate average from all evaluators
    const avgTotal = evalList.length > 0 ? Math.round(evalList.reduce((s,e) => s+(e.total||0), 0) / evalList.length) : thisTotal;
    stageEvals[stageId] = { ...newEvalEntry, evaluations: evalList, score: avgTotal, total: avgTotal };
    // Average across all stages
    const allTotals = Object.values(stageEvals).map(e => e.score || e.total || 0).filter(t => t > 0);
    const avgScore = allTotals.length > 0 ? Math.round(allTotals.reduce((a,b)=>a+b,0) / allTotals.length) : thisTotal;
    const upd = { ...evalForm,
      stageEvaluations: stageEvals,
      evaluation: { ...(evalForm.evaluation||{}), stageAvgScore: avgScore },
    };
    delete upd._evalOnBehalf;
    if (!upd.evaluation.score || upd.evaluation.score === 0) upd.evaluation.score = avgScore;
    await saveCandidate(upd);
    setCands(p => p.map(x => (x.uid||x.idNumber||x.email)===(upd.uid||upd.idNumber||upd.email) ? upd : x));
    // Log evaluation event
    const pid = upd.uid||upd.idNumber||upd.email;
    const evalBy = newEvalEntry.by;
    if(pid) addPersonEvent(pid, {type:"eval", text:"📊 تقييم مقابلة: "+thisTotal+"/100 — المقيّم: "+evalBy, by:evalBy, byRole:"admin", private:false}).catch(()=>{});
    show("✅ تم حفظ التقييم — المتوسط: " + avgTotal + "/100 (" + evalList.length + " مقيّم)");
    setEvalForm(null);
  };

  const saveInt = async (data) => {
    const rec = await saveInterview(data);
    setInterviews(p => { const n=p.filter(x=>x.id!==rec.id); return [...n,rec].sort((a,b)=>a.date>b.date?1:-1); });
    show("✅ تم حفظ المقابلة"); setShowIntForm(false);
  };

  const [candPage, setCandPage] = useState(0);
  const PAGE_SIZE = 100;

  const filtered = cands.filter(c => {
    const q = search.toLowerCase();
    return !q || [c.fullName,c.email,c.hrCode].join(" ").toLowerCase().includes(q);
  });

  const grouped = {};
  STAGES.forEach(s => { grouped[s.id] = []; });
  filtered.forEach(c => {
    const stg = getCandStage(c);
    if (stg) grouped[stg].push(c);
  });

  return (
    <div className="fade">
      {toastEl}{dlg}
      {showOffer && selCand && (
        <JobOfferModal candidate={selCand} onClose={()=>setShowOffer(false)}
          onSent={(upd)=>{ setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x)); setShowOffer(false); setSelCand(null); }} />
      )}

      {showDraftContract && selCand && (
        <DraftContractModal candidate={selCand} onClose={()=>setShowDraftContract(false)}
          onSent={(upd)=>{ setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x)); setShowDraftContract(false); setSelCand(null); }} />
      )}

      {/* Evaluation Modal */}
      {evalForm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.85)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:560, maxHeight:"92vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:16 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16 }}>📊 تقييم المقابلة — {evalForm.fullName}</p>
              <button onClick={()=>setEvalForm(null)} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:20 }}>✕</button>
            </div>
            <p style={{ fontSize:12, color:"var(--text3)", marginBottom:14 }}>كل محور من 10 إلى 100 — الرقم الأحادي (مثل 7) يتحول تلقائياً إلى (70)</p>
            {window._currentUser?.username === "admin" && (
              <div className="field" style={{ marginBottom:12 }}>
                <label className="label">📝 تقييم نيابة عن (المدير العام فقط)</label>
                <input value={evalForm._evalOnBehalf||""} onChange={e=>setEvalForm(p=>({...p,_evalOnBehalf:e.target.value}))} placeholder="اتركه فارغاً للتقييم باسمك" />
              </div>
            )}
            <div className="g2" style={{ marginBottom:12 }}>
              {[["evalTechnical","🔧 الجانب الفني"],["evalAdmin","🏢 الجانب الإداري"],["evalLanguage","🗣️ الجانب اللغوي"]].map(([k,l])=>(
                <div key={k} className="field">
                  <label className="label">{l} (10-100)</label>
                  <input type="number" min="10" max="100" value={evalForm[k]||""} onChange={e=>{
                    let val = Math.min(100, Math.max(0, parseInt(e.target.value)||0));
                    setEvalForm(p=>{
                      const upd = {...p, [k]:val||""};
                      const t = [upd.evalTechnical, upd.evalAdmin, upd.evalLanguage].map(Number).filter(n=>n>0);
                      upd.evalGeneral = t.length > 0 ? Math.round(t.reduce((a,b)=>a+b,0)/t.length) : "";
                      return upd;
                    });
                  }} onBlur={e=>{
                    let v=parseInt(e.target.value)||0;
                    if(v>0&&v<10) v=v*10; // 7 → 70
                    if(v>100) v=100;
                    setEvalForm(p=>{const upd={...p,[k]:v||""};const t=[upd.evalTechnical,upd.evalAdmin,upd.evalLanguage].map(Number).filter(n=>n>0);upd.evalGeneral=t.length>0?Math.round(t.reduce((a,b)=>a+b,0)/t.length):"";return upd;});
                  }} />
                </div>
              ))}
              <div className="field">
                <label className="label">⭐ التقييم العام (تلقائي)</label>
                <input type="number" value={evalForm.evalGeneral||""} readOnly style={{ background:"rgba(201,168,76,.08)", color:"var(--gold)", fontWeight:900, fontSize:18, textAlign:"center" }} />
              </div>
            </div>
            <div className="field" style={{ marginBottom:14 }}>
              <label className="label">الملاحظات (10 كلمات على الأقل) *</label>
              <textarea value={evalForm.evalNotes||""} onChange={e=>setEvalForm(p=>({...p,evalNotes:e.target.value}))}
                rows={4} style={{ fontFamily:"inherit" }} placeholder="اكتب ملاحظاتك التفصيلية عن المقابلة..." />
              <p style={{ fontSize:11, color:(evalForm.evalNotes||"").trim().split(/\s+/).filter(Boolean).length>=10?"#4ade80":"#f87171" }}>
                {(evalForm.evalNotes||"").trim().split(/\s+/).filter(Boolean).length} كلمة
              </p>
            </div>
            <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
              <button onClick={()=>setEvalForm(null)} className="btn btn-ghost btn-sm">إلغاء</button>
              <button onClick={saveEval} className="btn btn-gold">💾 حفظ التقييم</button>
            </div>
          </div>
        </div>
      )}

      {/* Interview Form */}
      {showIntForm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:520, maxHeight:"90vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:16 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16 }}>🎯 تسجيل مقابلة</p>
              <button onClick={()=>setShowIntForm(false)} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:20 }}>✕</button>
            </div>
            <div className="g2">
              <div className="field"><label className="label">المرشح</label>
                <select value={intForm.candidateId} onChange={e=>{
                  const c=cands.find(x=>(x.uid||x.idNumber||x.email)===e.target.value);
                  setIntForm(p=>({...p,candidateId:e.target.value,candidateName:c?.fullName||""}));
                }}>
                  <option value="">-- اختر</option>
                  {cands.map(c=><option key={c.uid||c.email} value={c.uid||c.idNumber||c.email}>{c.fullName}</option>)}
                </select>
              </div>
              <div className="field"><label className="label">نوع المقابلة</label>
                <select value={intForm.type} onChange={e=>setIntForm(p=>({...p,type:e.target.value}))}>
                  {["مقابلة أولى","مقابلة ثانية","اختبار تقني","اختبار إداري","مقابلة نهائية"].map(t=><option key={t}>{t}</option>)}
                </select>
              </div>
              <div className="field"><label className="label">التاريخ</label>
                <input type="date" value={intForm.date} onChange={e=>setIntForm(p=>({...p,date:e.target.value}))} /></div>
              <div className="field"><label className="label">الوقت</label>
                <input type="time" value={intForm.time} onChange={e=>setIntForm(p=>({...p,time:e.target.value}))} /></div>
              <div className="field"><label className="label">الموقع/الرابط</label>
                <input value={intForm.location} onChange={e=>setIntForm(p=>({...p,location:e.target.value}))} /></div>
              <div className="field"><label className="label">المسؤول</label>
                <input value={intForm.interviewer} onChange={e=>setIntForm(p=>({...p,interviewer:e.target.value}))} /></div>
              <div className="field"><label className="label">النتيجة</label>
                <select value={intForm.result} onChange={e=>setIntForm(p=>({...p,result:e.target.value}))}>
                  <option value="">-- اختر</option>
                  {["ناجح","راسب","مقبول مشروط","بانتظار القرار"].map(r=><option key={r}>{r}</option>)}
                </select>
              </div>
              <div className="field"><label className="label">الدرجة (من 100)</label>
                <input type="number" min="0" max="100" value={intForm.score} onChange={e=>setIntForm(p=>({...p,score:e.target.value}))} /></div>
            </div>
            <div className="field"><label className="label">ملاحظات</label>
              <textarea value={intForm.notes} onChange={e=>setIntForm(p=>({...p,notes:e.target.value}))} rows={3} style={{ fontFamily:"inherit" }} /></div>
            <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:14 }}>
              <button onClick={()=>setShowIntForm(false)} className="btn btn-ghost btn-sm">إلغاء</button>
              <button onClick={()=>saveInt({...intForm,id:undefined})} disabled={!intForm.candidateName} className="btn btn-gold">💾 حفظ</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16, flexWrap:"wrap", gap:10 }}>
        <h2 style={S.gold900s20}>🔄 مراحل التوظيف</h2>
        <div style={{ display:"flex", gap:4, flexWrap:"wrap", alignItems:"center" }}>
          {[{id:"tree",label:"🌳 مراحل التوظيف"},{id:"log",label:"📋 سجل المقابلات"}].map(t=>(
            <button key={t.id} onClick={()=>setView(t.id)}
              style={{ padding:"6px 14px", borderRadius:20, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700,
                background:view===t.id?"rgba(201,168,76,.2)":"none",
                border:"1px solid "+(view===t.id?"rgba(201,168,76,.5)":"var(--b)"),
                color:view===t.id?"var(--gold)":"var(--text3)" }}>
              {t.label}
            </button>
          ))}
          {view==="log" && <button onClick={()=>setShowIntForm(true)} className="btn btn-gold btn-sm">➕ مقابلة</button>}
        </div>
      </div>
      {view==="kanban" && <input value={search} onChange={e=>setSearch(e.target.value)}
        placeholder="🔍 بحث في المرشحين..." style={{ width:"100%", padding:"8px 14px", borderRadius:10, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", fontSize:13, marginBottom:14 }} />}

      {/* Interview Log */}
      {view === "log" && (
        <div>
          {interviews.length === 0
            ? <div className="card" style={{ textAlign:"center", padding:40 }}><p style={{ fontSize:32 }}>🎯</p><p style={{ color:"var(--text3)" }}>لا توجد مقابلات</p><button onClick={()=>setShowIntForm(true)} className="btn btn-gold" style={{ marginTop:14 }}>➕ أضف مقابلة</button></div>
            : <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {[...interviews].sort((a,b)=>b.date>a.date?1:-1).map(iv=>{
                  const SC = {"مجدولة":"#3b82f6","جارية":"#f59e0b","مكتملة":"#22c55e","ملغاة":"#ef4444","غائب":"#9ca3af"};
                  return (
                    <div key={iv.id} style={{ padding:"12px 16px", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12 }}>
                      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:8 }}>
                        <div>
                          <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                            <span style={{ fontWeight:700, fontSize:14 }}>{iv.candidateName}</span>
                            <span style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:(SC[iv.status]||"#94a3b8")+"22", color:SC[iv.status]||"#94a3b8" }}>{iv.status}</span>
                            <span style={{ fontSize:11, color:"var(--gold)", fontWeight:700 }}>{iv.type}</span>
                          </div>
                          <p style={{ fontSize:12, color:"var(--text3)" }}>📅 {iv.date} {iv.time&&"— "+iv.time} {iv.location&&"| 📍 "+iv.location}</p>
                          {iv.result && <p style={{ fontSize:12, color:iv.result==="ناجح"?"#4ade80":"#f87171", marginTop:4 }}>النتيجة: {iv.result} {iv.score&&"("+iv.score+"/100)"}</p>}
                        </div>
                        <div style={{ display:"flex", gap:6 }}>
                          <button onClick={()=>{setIntForm({...iv});setShowIntForm(true);}} className="btn btn-ghost btn-sm">✏️</button>
                          <button onClick={async()=>{ await delInterview(iv.id); setInterviews(p=>p.filter(x=>x.id!==iv.id)); }} className="btn btn-ghost btn-sm" style={{ color:"var(--red)" }}>🗑️</button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
          }
        </div>
      )}

      {/* ═══ مراحل التوظيف — شجرة + لوحة مدمجة ═══ */}
      {view === "tree" && (
        <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 بحث في المرشحين..." style={{ width:"100%", padding:"8px 14px", borderRadius:10, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", fontSize:13, marginBottom:8 }} />
          {STAGES.map(s => {
            const list = (grouped[s.id]||[]).filter(c => !search || (c.fullName||"").includes(search) || (c.hrCode||"").includes(search));
            const isOpen = openStages[s.id];
            return (
              <div key={s.id} style={{ border:"1px solid var(--b)", borderRadius:12, overflow:"hidden", borderRight:"4px solid "+s.color }}>
                <div onClick={()=>setOpenStages(p=>({...p,[s.id]:!p[s.id]}))} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"12px 16px", cursor:"pointer", background:isOpen?s.color+"08":"transparent", transition:"background .15s" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <div style={{ width:36, height:36, borderRadius:"50%", background:s.color+"20", border:"2px solid "+s.color, display:"flex", alignItems:"center", justifyContent:"center", fontSize:16 }}>{s.icon}</div>
                    <div>
                      <p style={{ fontWeight:800, fontSize:14, color:s.color, margin:0 }}>{s.label}</p>
                      <p style={{ fontSize:10, color:"var(--text3)", margin:0 }}>{list.length} مرشح</p>
                    </div>
                  </div>
                  <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                    <span style={{ fontSize:20, fontWeight:900, color:s.color }}>{list.length}</span>
                    <span style={{ fontSize:14, color:"var(--text3)", transition:"transform .2s", transform:isOpen?"rotate(90deg)":"rotate(0)" }}>▸</span>
                  </div>
                </div>
                {isOpen && <div style={{ padding:"10px 12px", borderTop:"1px solid var(--b)" }}>
                  {list.length === 0 ? <p style={{ textAlign:"center", color:"var(--text3)", padding:16, fontSize:12 }}>لا يوجد مرشحون</p> :
                    <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:8 }}>
                      {list.map(c => {
                        const _ks = [...(c.aiEvalHistory||[]).filter(h=>h.score).map(h=>h.score), ...Object.values(c.stageEvaluations||{}).flatMap(ev2=>(ev2.evaluations||[ev2]).filter(e=>e.total).map(e=>e.total)), ...(c.evalTaskResults||[]).filter(t=>t.totalScore).map(t=>t.totalScore), ...(c.examScore?[c.examScore]:[])];
                        const sc = _ks.length ? Math.round(_ks.reduce((a,b)=>a+b,0)/_ks.length) : (c.evaluation?.score||0);
                        const scClr = sc >= 81 ? "#4ade80" : sc >= 61 ? "#fbbf24" : sc > 0 ? "#f87171" : "#94a3b8";
                        const spec = c.lastJob || c.specialization || (window._jobTitles||[]).find(t=>t.id===c.jobTitleId)?.title || "";
                        return (
                          <div key={c.uid||c.email} onClick={()=>{setSelCand(c);setStage(s.id);}}
                            style={{ padding:"10px 12px", border:"1px solid var(--b)", borderRadius:10, cursor:"pointer", background:"rgba(255,255,255,.03)", transition:".15s" }}
                            onMouseEnter={e=>{e.currentTarget.style.borderColor="rgba(255,255,255,.2)";e.currentTarget.style.background="rgba(255,255,255,.05)";}}
                            onMouseLeave={e=>{e.currentTarget.style.borderColor="var(--b)";e.currentTarget.style.background="rgba(255,255,255,.03)";}}>
                            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                              <span style={{ fontWeight:800, fontSize:12, color:scClr, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", flex:1 }}>{c.fullName||"—"}</span>
                              {sc > 0 ? <span style={{ fontSize:15, fontWeight:900, color:scClr, flexShrink:0, marginRight:6 }}>{sc}</span> : <span style={{ fontSize:11, color:"#475569" }}>—</span>}
                            </div>
                            <div style={{ height:5, borderRadius:3, background:"rgba(255,255,255,.06)", overflow:"hidden", margin:"6px 0 8px" }}>
                              <div style={{ width:Math.max(sc,0)+"%", height:"100%", borderRadius:3, background:sc>0?scClr:"transparent" }} />
                            </div>
                            <div style={{ display:"flex", gap:4, alignItems:"center" }}>
                              <span style={{ fontSize:9, color:"#64748b" }}>{c.hrCode||""}</span>
                              {spec && <><span style={{ fontSize:9, color:"#475569" }}>—</span><span style={{ fontSize:9, color:"#94a3b8", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{spec}</span></>}
                            </div>
                            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginTop:7 }}>
                              <button onClick={e=>{e.stopPropagation();setStageActionCand({cand:c,stageId:s.id});}} style={{ padding:"3px 10px", borderRadius:6, border:"1px solid var(--b)", background:"transparent", color:"#94a3b8", fontSize:9, cursor:"pointer", fontFamily:"inherit" }}>💬 رسالة</button>
                              {c.trainingType && <span style={{ fontSize:8, padding:"2px 6px", borderRadius:4, background:"rgba(167,139,250,.12)", color:"#a78bfa", border:"1px solid rgba(167,139,250,.2)", fontWeight:700 }}>🎓 {c.trainingType}</span>}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  }
                </div>}
              </div>
            );
          })}
        </div>
      )}

      {/* Kanban */}
      {view === "kanban" && (
        <div>
          <div className="stages-grid" style={{ display:"grid", gridTemplateColumns:"repeat(4, 1fr)", gap:12, paddingBottom:16 }}>
            {STAGES.map(s => (
              <div key={s.id} style={{ minWidth:0 }}>
                <div style={{ padding:"8px 12px", borderRadius:"10px 10px 0 0", background:"rgba(255,255,255,.04)", border:"1px solid var(--b)", borderBottom:"none", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                  <span style={{ fontWeight:700, fontSize:13, color:s.color }}>{s.icon} {s.label}</span>
                  <span style={{ fontSize:11, background:"rgba(255,255,255,.08)", padding:"1px 8px", borderRadius:10, color:"var(--text3)" }}>{grouped[s.id]?.length||0}</span>
                </div>
                <div style={{ border:"1px solid var(--b)", borderTop:"none", borderRadius:"0 0 10px 10px", minHeight:180, background:"rgba(255,255,255,.02)", padding:8, display:"flex", flexDirection:"column", gap:6 }}>
                  {(grouped[s.id]||[]).map((c, ci) => (
                    <div key={c.uid||c.email} onClick={()=>{ setSelCand(c); setStage(s.id); }}
                      style={{ padding:"8px 10px", background:ci%2===1?"rgba(59,130,246,.025)":"transparent", border:"1px solid var(--b)", borderRadius:8, cursor:"pointer" }}
                      onMouseEnter={e=>e.currentTarget.style.borderColor=s.color+"66"}
                      onMouseLeave={e=>e.currentTarget.style.borderColor="var(--b)"}>
                      <p style={{ fontSize:12, fontWeight:700, color:"var(--text)" }}>{c.fullName}</p>
                      {c.hrCode && <p style={{ fontSize:10, color:"var(--gold)" }}>{c.hrCode}</p>}
                      <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginTop:2 }}>
                        {c.trainingType && <span style={{ fontSize:9, padding:"1px 6px", borderRadius:5, background:"rgba(167,139,250,.15)", color:"#a78bfa", border:"1px solid rgba(167,139,250,.3)" }}>🎓 {c.trainingType}</span>}
                        {c.jobTitleId && <span style={{ fontSize:9, padding:"1px 6px", borderRadius:5, background:"rgba(201,168,76,.1)", color:"var(--gold)", border:"1px solid rgba(201,168,76,.25)" }}>💼 {(window._jobTitles||[]).find(t=>t.id===c.jobTitleId)?.title||c.jobTitleId}</span>}
                      </div>
                      {(() => {
                        const _ks = [...(c.aiEvalHistory||[]).filter(h=>h.score).map(h=>h.score), ...Object.values(c.stageEvaluations||{}).flatMap(ev2=>(ev2.evaluations||[ev2]).filter(e=>e.total).map(e=>e.total)), ...(c.evalTaskResults||[]).filter(t=>t.totalScore).map(t=>t.totalScore), ...(c.examScore?[c.examScore]:[])];
                        const kov = _ks.length ? Math.round(_ks.reduce((a,b)=>a+b,0)/_ks.length) : (c.evaluation?.score||0);
                        return kov > 0 ? <div style={{ marginTop:3 }}><span onClick={e=>{e.stopPropagation();setKanbanEvalCand(c);}} style={{ fontSize:10, fontWeight:900, padding:"2px 8px", borderRadius:6, cursor:"pointer", color:kov>=81?"#4ade80":kov>=61?"#fbbf24":"#f87171", background:(kov>=81?"rgba(34,197,94,.12)":kov>=61?"rgba(245,158,11,.12)":"rgba(239,68,68,.12)"), border:"1px solid "+(kov>=81?"rgba(34,197,94,.3)":kov>=61?"rgba(245,158,11,.3)":"rgba(239,68,68,.3)") }}>📊 التقييم {kov}/100</span></div> : null;
                      })()}
                      {hasEvalForStage(c, s.id) && <p style={{ fontSize:10, color:"#4ade80" }}>✅ مُقيَّم</p>}
                      <button title="إرسال رسالة للمرشح عبر البريد أو واتساب" onClick={e=>{e.stopPropagation();setStageActionCand({cand:c,stageId:s.id});}} className="btn btn-ghost btn-sm" style={{ marginTop:4, fontSize:10, padding:"2px 8px" }}>💬 رسالة</button>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>

        </div>
      )}

      {/* ── Postpone Eval Modal ── */}
      {postponeModal && (
        <PostponeEvalModal
          cand={postponeModal.cand}
          stageId={postponeModal.stageId}
          currentStageId={postponeModal.currentStageId}
          onConfirm={async(reason)=>{
            const {cand,stageId,currentStageId} = postponeModal;
            const pid = cand.uid||cand.idNumber||cand.email;
            addPersonEvent(pid, { type:"note", text:"تأجيل تقييم مرحلة "+currentStageId+" — السبب: "+reason,
              by:currentUser?.displayName||"المشرف", byRole:"admin", private:true }).catch(()=>{});
            setPostponeModal(null);
            await doChangeStage(cand, stageId, currentStageId);
          }}
          onClose={()=>setPostponeModal(null)}
        />
      )}

      {/* ── Quick Message & Stage Action Modals ── */}
          {stageActionCand && (
            <StageActionModal
              candidate={stageActionCand.cand}
              stageId={stageActionCand.stageId}
              interviews={interviews}
              onClose={()=>setStageActionCand(null)}
              onSend={async ({ emailMsg, waMsg, channels: ch }) => {
                const c = stageActionCand.cand;
                const pid = c.uid || c.idNumber || c.email || "";
                const actor = currentUser?.displayName || "المشرف";
                // Email
                if (ch.email && c.email) {
                  sendEmail({ to:c.email, subject:"رسالة من نظام كوادر HMA", html:emailTemplate("رسالة",("<p>" + emailMsg.split("\n").join("<br>") + "</p>"),actor), _logOpts:{ candidateId:pid, name:c.fullName||"" } }).catch(()=>{});
                }
                // WhatsApp
                if (ch.whatsapp && c.phone) {
                  const waNum = formatPhoneForWA(c.phone);
                  window.open("https://wa.me/" + waNum + "?text=" + encodeURIComponent(waMsg || emailMsg), "_blank");
                }
                // System notification
                if (ch.system) {
                  await saveNotification({ message: emailMsg.slice(0,200), type:"general", targetId:pid, targetName:c.fullName||"", sentBy:actor, read:false }).catch(()=>{});
                }
                // Log event
                await addPersonEvent(pid, { type:"message", text:"رسالة مرحلة: " + (stageActionCand.stageId||"") + " — " + emailMsg.slice(0,60), by:actor, byRole:"admin", private:false }).catch(()=>{});
                show("✅ تم الإرسال");
                setStageActionCand(null);
              }}
              onSaveInterview={async (intData) => {
                await saveInterview({ ...intData, id: "int_" + Date.now(), createdAt: new Date().toISOString() });
                setInterviews(await getAllInterviews());
                show("✅ تم حفظ المقابلة");
              }}
            />
          )}

          {quickMsgCand && (() => {
            // If composed message from StageActionModal, use it directly
            if (quickMsgCand._composedMsg) {
              return <GlobalQuickMessage person={quickMsgCand} onClose={()=>setQuickMsgCand(null)} stageTemplate={{ label:"رسالة جاهزة", body:quickMsgCand._composedMsg }} />;
            }
            const cStage = getCandStage(quickMsgCand);
            const stageTemplateMap = { interview1:"interview1", assessment:"assessment", interview2:"interview2", offer:"offer", contract:"welcome", reject:"reject", waiting:"waiting" };
            const tplId = stageTemplateMap[cStage];
            const tpl = DEFAULT_MSG_TEMPLATES.find(t=>t.id===tplId);
            const stgTpl = tpl ? { label:tpl.label, body:(tpl.body||"").split("{name}").join(quickMsgCand.fullName||"").split("{job}").join(quickMsgCand.jobTitle||quickMsgCand.lastJob||"") } : null;
            return <GlobalQuickMessage person={quickMsgCand} onClose={()=>setQuickMsgCand(null)} stageTemplate={stgTpl} />;
          })()}

          {/* Action Panel */}
          {selCand && stage && (
            <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", zIndex:999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
              <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:500, maxHeight:"90vh", overflowY:"auto" }}>
                <div style={{ display:"flex", justifyContent:"space-between", marginBottom:16 }}>
                  <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16 }}>⚡ {selCand.fullName}</p>
                  <button onClick={()=>{setSelCand(null);setStage(null);}} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:20 }}>✕</button>
                </div>
                <p style={{ fontSize:13, color:"var(--text3)", marginBottom:14 }}>المرحلة الحالية: <span style={{ color:STAGES.find(s=>s.id===stage)?.color, fontWeight:700 }}>{STAGES.find(s=>s.id===stage)?.label}</span></p>

                {/* Job title + Job posting + Training badge — unified design */}
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:14 }}>
                  <div className="field"><label className="label">💼 ربط بمسمى وظيفي</label>
                    <select value={selCand?.jobTitleId||""} onChange={async(e)=>{
                      const jt=(window._jobTitles||[]).find(t=>t.id===e.target.value);
                      const upd={...selCand, jobTitleId:e.target.value, jobGradeCode:jt?.gradeRef||""};
                      await saveCandidate(upd);
                      setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x));
                      setSelCand(upd); show("✅ تم ربط المسمى الوظيفي");
                    }}>
                      <option value="">-- اختر مسمى وظيفي --</option>
                      {(window._jobTitles||[]).map(jt=><option key={jt.id} value={jt.id}>{jt.title}{jt.gradeRef?" ("+jt.gradeRef+")":""}{jt.dept?" — "+jt.dept:""}</option>)}
                    </select>
                  </div>
                  <div className="field"><label className="label">📢 ربط بإعلان وظيفي</label>
                    <select value={selCand?.linkedJobId||""} onChange={async(e)=>{
                      const job = allJobs.find(j=>j.id===e.target.value);
                      const upd = {...selCand, linkedJobId:e.target.value,
                        jobGradeCode:job?.gradeCode||"", jobBonusCode:job?.bonusCode||"", jobTitleId:job?.titleId||""};
                      await saveCandidate(upd);
                      setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x));
                      setSelCand(upd); show("✅ تم الربط");
                    }}>
                      <option value="">-- اختر إعلاناً</option>
                      {allJobs.filter(j=>j.status==="مفتوحة").map(j=><option key={j.id} value={j.id}>{j.title}{j.gradeCode?" ("+j.gradeCode+")":""}</option>)}
                    </select>
                  </div>
                  <div className="field"><label className="label">📍 تغيير المرحلة</label>
                    <select value={stage} onChange={e=>changeStage(selCand, e.target.value)}>
                      {STAGES.map(s=><option key={s.id} value={s.id}>{s.icon} {s.label}</option>)}
                    </select>
                  </div>
                  {(() => {
                    const _es = [...(selCand.aiEvalHistory||[]).filter(h=>h.score).map(h=>h.score), ...Object.values(selCand.stageEvaluations||{}).flatMap(ev2=>(ev2.evaluations||[ev2]).filter(e=>e.total).map(e=>e.total)), ...(selCand.evalTaskResults||[]).filter(t=>t.totalScore).map(t=>t.totalScore), ...(selCand.examScore?[selCand.examScore]:[])];
                    const _ov = _es.length ? Math.round(_es.reduce((a,b)=>a+b,0)/_es.length) : (selCand.evaluation?.score||0);
                    const _c = _ov>=81?"#4ade80":_ov>=61?"#fbbf24":"#f87171";
                    return <div className="field"><label className="label" style={{ color:_c }}>📊 التقييم</label>
                      <button onClick={()=>setKanbanEvalCand(selCand)} style={{ width:"100%", padding:"8px 10px", borderRadius:8, border:"1px solid "+_c+"50", background:_c+"12", color:_c, cursor:"pointer", fontFamily:"inherit", fontSize:13, fontWeight:900, minHeight:38 }}>{_ov}/100</button>
                    </div>;
                  })()}
                </div>
                {selCand?.trainingType && <div style={{ marginBottom:10 }}><span style={{ fontSize:11, padding:"3px 10px", borderRadius:6, background:"rgba(167,139,250,.15)", color:"#a78bfa", border:"1px solid rgba(167,139,250,.3)" }}>🎓 {selCand.trainingType}</span></div>}

                {/* Stage actions */}
                {stage === "offer" && (
                  <div style={{ marginBottom:14 }}>
                    <button onClick={()=>setShowOffer(true)} className="btn btn-gold" style={{ width:"100%", marginTop:8 }}>📋 إعداد العرض الوظيفي</button>
                  </div>
                )}
                {stage === "draft_contract" && (
                  <div style={{ marginBottom:14 }}>
                    <button onClick={()=>setShowDraftContract(true)} className="btn" style={{ width:"100%", marginTop:8, background:"linear-gradient(135deg,#06b6d4,#0891b2)", color:"#fff", fontWeight:900, border:"none" }}>📑 إعداد مسودة عقد</button>
                    {selCand?.jobOffer && <p style={{ fontSize:10, color:"#06b6d4", marginTop:4, textAlign:"center" }}>💰 بيانات العرض: {Number(selCand.jobOffer.totalSalary||0).toLocaleString()} ريال — {selCand.jobOffer.position||""}</p>}
                  </div>
                )}
                {stage === "contract" && (
                  <div className="g2" style={{ marginBottom:14 }}>
                    <div className="field"><label className="label">تاريخ البدء</label>
                      <input type="date" onBlur={async(e)=>{if(!e.target.value)return;const upd={...selCand,contractStartDate:e.target.value};await saveCandidate(upd);setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x));setSelCand(upd);show("✅ تم الحفظ");}} /></div>
                    <div className="field"><label className="label">رقم العقد</label>
                      <input onBlur={async(e)=>{if(!e.target.value)return;const upd={...selCand,contractNo:e.target.value};await saveCandidate(upd);setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x));setSelCand(upd);show("✅ تم الحفظ");}} /></div>
                  </div>
                )}

                <button onClick={()=>{setSelCand(null);setStage(null);}} className="btn btn-ghost btn-sm" style={{ width:"100%" }}>إغلاق</button>
              </div>
            </div>
          )}

      {kanbanEvalCand && <CandEvalPage cand={kanbanEvalCand} onClose={()=>setKanbanEvalCand(null)} onSave={async(upd)=>{ await saveCandidate(upd); setCands(p=>p.map(x=>(x.uid||x.email)===(upd.uid||upd.email)?upd:x)); setKanbanEvalCand(upd); if(selCand && (selCand.uid||selCand.email)===(upd.uid||upd.email)) setSelCand(upd); }} />}
    </div>
  );
}


function SalaryScaleManager({ readOnly=false }) {
  const [scale, setScale]     = useState(null);
  const [tab, setTab]         = useState("engineers");
  const [saving, setSaving]   = useState(false);
  const { show, toastEl }     = useToast();

  useEffect(() => { getSalaryScale().then(setScale); }, []);

  if (!scale) return <div style={{ textAlign:"center", padding:40 }}><div className="loader"/></div>;

  const TABS = [
    { id:"engineers", label:"👷 مهندسون" },
    { id:"admin",     label:"🏢 إداريون" },
    { id:"technical", label:"🔧 تقنيون/مراقبون" },
    { id:"design",    label:"🎨 تصميم داخلي" },
    { id:"bonuses",   label:"⭐ علاوات" },
  ];

  const setRow = (tableKey, idx, field, val) => {
    const updated = { ...scale };
    updated[tableKey] = updated[tableKey].map((r, i) => {
      if (i !== idx) return r;
      const newRow = { ...r, [field]: field==="grade"||field==="note"||field==="label" ? val : Number(val)||0 };
      // Auto-calc total for salary rows
      if (["basic","housing","transport"].includes(field)) {
        const b = field==="basic" ? Number(val)||0 : newRow.basic;
        const h = field==="housing" ? Number(val)||0 : newRow.housing;
        const t = field==="transport" ? Number(val)||0 : newRow.transport;
        newRow.total = b + h + t;
      }
      return newRow;
    });
    setScale(updated);
  };

  const save = async () => {
    setSaving(true);
    await saveSalaryScale(scale);
    show("✅ تم حفظ سلم الرواتب");
    setSaving(false);
  };

  const reset = async () => {
    setScale(JSON.parse(JSON.stringify(DEFAULT_SALARY_SCALE)));
    show("↩️ تم إعادة تعيين السلم للقيم الافتراضية");
  };

  const TH = { padding:"8px 10px", textAlign:"right", color:"var(--gold)", fontWeight:700, fontSize:12, borderBottom:"1px solid var(--b)" };
  const TD = { padding:"6px 8px", color:"var(--text2)" };
  const INPUT = { background:"rgba(255,255,255,.05)", border:"1px solid var(--b)", borderRadius:6, padding:"4px 8px", color:"var(--text)", fontFamily:"inherit", fontSize:12, width:"100%" };

  const renderTable = (tableKey) => {
    const rows = scale[tableKey] || [];
    const isBonuses = tableKey === "bonuses";
    return (
      <div style={{ overflowX:"auto" }}>
        <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
          <thead>
            <tr style={{ background:"rgba(201,168,76,.1)" }}>
              {isBonuses ? (
                <>
                  <th style={TH}>الفئة</th>
                  <th style={TH}>نسبة الزيادة %</th>
                  <th style={TH}>ملاحظة</th>
                </>
              ) : (
                <>
                  <th style={TH}>الدرجة</th>
                  <th style={TH}>خبرة من</th>
                  <th style={TH}>خبرة حتى</th>
                  <th style={TH}>الأساسي</th>
                  <th style={TH}>السكن (25%)</th>
                  <th style={TH}>النقل</th>
                  <th style={TH}>الإجمالي</th>
                </>
              )}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, i) => (
              <tr key={i} style={{ borderBottom:"1px solid var(--b)" }}>
                {isBonuses ? (
                  <>
                    <td style={TD}><input value={row.label} onChange={e=>setRow(tableKey,i,"label",e.target.value)} style={INPUT}/></td>
                    <td style={TD}><input type="number" value={row.pct} onChange={e=>setRow(tableKey,i,"pct",e.target.value)} style={{...INPUT,width:70,textAlign:"center"}}/></td>
                    <td style={TD}><input value={row.note} onChange={e=>setRow(tableKey,i,"note",e.target.value)} style={INPUT}/></td>
                  </>
                ) : (
                  <>
                    <td style={TD}><input value={row.grade} onChange={e=>setRow(tableKey,i,"grade",e.target.value)} style={{...INPUT,width:60,textAlign:"center",fontWeight:700,color:"var(--gold)"}}/></td>
                    <td style={TD}><input type="number" value={row.expMin} onChange={e=>setRow(tableKey,i,"expMin",e.target.value)} style={{...INPUT,width:60,textAlign:"center"}}/></td>
                    <td style={TD}><input type="number" value={row.expMax} onChange={e=>setRow(tableKey,i,"expMax",e.target.value)} style={{...INPUT,width:60,textAlign:"center"}}/></td>
                    <td style={TD}><input type="number" value={row.basic} onChange={e=>setRow(tableKey,i,"basic",e.target.value)} style={{...INPUT,width:80,textAlign:"center"}}/></td>
                    <td style={{...TD,color:"var(--text3)"}}>{row.housing.toLocaleString()}</td>
                    <td style={TD}><input type="number" value={row.transport} onChange={e=>setRow(tableKey,i,"transport",e.target.value)} style={{...INPUT,width:70,textAlign:"center"}}/></td>
                    <td style={{...TD,fontWeight:700,color:"#4ade80"}}>{row.total.toLocaleString()} ريال</td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };


  return (
    <div className="fade">
      {toastEl}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20, flexWrap:"wrap", gap:10 }}>
        <div>
          <h2 style={S.gold900s20}>💰 سلم الرواتب</h2>
          <p style={S.txt3s12}>{readOnly ? "عرض فقط — التعديل للمدير العام" : "قابل للتعديل — المدير العام فقط"}</p>
        </div>
        {!readOnly && <div style={S.flex8}>
          <button onClick={reset} className="btn btn-ghost btn-sm">↩️ استعادة الافتراضي</button>
          <button onClick={save} disabled={saving} className="btn btn-gold">{saving?"⏳ جاري الحفظ...":"💾 حفظ التعديلات"}</button>
        </div>}
      </div>

      <div style={{ display:"flex", gap:6, marginBottom:16, flexWrap:"wrap" }}>
        {TABS.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{ padding:"6px 14px", borderRadius:20, cursor:"pointer", fontFamily:"inherit", fontSize:13, fontWeight:700,
              background:tab===t.id?"rgba(201,168,76,.2)":"none",
              border:"1px solid "+(tab===t.id?"rgba(201,168,76,.5)":"var(--b)"),
              color:tab===t.id?"var(--gold)":"var(--text3)" }}>
            {t.label}
          </button>
        ))}
      </div>

      <div className="card">
        <p style={{ fontSize:12, color:"var(--text3)", marginBottom:12 }}>
          {tab==="engineers" && "بدل السكن = 25% من الأساسي تلقائياً"}
          {tab==="bonuses" && "النسبة تُضاف على الراتب الأساسي"}
        </p>
        {renderTable(tab)}
      </div>
    </div>
  );
}


