// ── Send Email via API ────────────────────────────────────────────────────────
async function sendEmail({ to, subject, html, text, _logOpts }) {
  const settings = await getEmailSettings();
  if (!settings.enabled || !settings.user || !settings.pass) {
    const reason = !settings.enabled ? "البريد غير مُفعّل — فعّله من إعدادات البريد"
      : !settings.user ? "اسم المستخدم فارغ في إعدادات البريد"
      : "كلمة مرور البريد فارغة في إعدادات البريد";
    console.warn("Email not configured:", reason);
    if (html || text) {
      await addToEmailQueue({
        to, subject, html: html||"",
        label: subject + " → " + to,
      }).catch(()=>{});
    }
    return { skipped: true, queued: !!(html||text), reason };
  }
  try {
    const res = await fetch("/api/send-email", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        to, subject, html, text,
        provider: settings.provider,
        user: settings.user,
        pass: settings.pass,
      })
    });
    const result = await res.json();
    // Auto-log to commlog if logOpts provided
    if (result.success && _logOpts?.candidateId) {
      const actor = window._currentUser?.displayName || "المشرف";
      saveCommLog({
        type: "email",
        candidateId: _logOpts.candidateId,
        candidateName: _logOpts.name || "",
        notes: subject,
        outcome: "تم الإرسال",
        by: actor,
        createdAt: new Date().toISOString(),
      }).catch(()=>{});
      addPersonEvent(_logOpts.candidateId, {
        type: "email",
        text: "بريد إلكتروني: " + subject,
        by: actor,
        byRole: "admin",
        private: false,
      }).catch(()=>{});
    }
    return result;
  } catch(e) {
    console.error("Email send error:", e);
    // Add to queue for retry
    await addToEmailQueue({
      to, subject, html: html||"",
      label: subject + " → " + to,
    }).catch(()=>{});
    return { error: e.message, queued: true };
  }
}

