async function getJobTitles() {
  try {
    const saved = await db.get("job_titles");
    // null/undefined = first ever load → seed with defaults
    if (saved === null || saved === undefined) {
      await db.set("job_titles", DEFAULT_JOB_TITLES);
      return DEFAULT_JOB_TITLES;
    }
    // saved exists (even if empty array) → respect user's deletions, no merge
    return Array.isArray(saved) ? saved : DEFAULT_JOB_TITLES;
  } catch { return DEFAULT_JOB_TITLES; }
}
async function saveJobTitles(data) { await db.set("job_titles", data); }


// ── JobTitlesManager ──────────────────────────────────────────────────────────

// ── Notifications Storage ─────────────────────────────────────────────────────
async function saveNotification(data) {
  const id = data.id || "notif_"+Date.now();
  const record = { ...data, id, createdAt: data.createdAt || new Date().toISOString(), read:false };
  await db.set("notif:"+id, record);
  const idx = (await db.get("notif:idx")) || [];
  if (!idx.includes(id)) await db.set("notif:idx", [...idx, id]);
  return record;
}
async function getNotifications(userId) {
  const idx = (await db.get("notif:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("notif:"+id)));
  return all.filter(x => x && (!userId || x.targetId === userId || x.targetId === "all"));
}
async function markNotifRead(id) {
  const n = await db.get("notif:"+id);
  if (n) await db.set("notif:"+id, { ...n, read:true });
}

function JobTitlesManager({ onClose, onSelect, currentUser }) {
  const [titles, setTitles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editItem, setEditItem] = useState(null);
  const [printJT, setPrintJT] = useState(null);
  const [printEmpName, setPrintEmpName] = useState("");
    const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ title:"", titleEn:"", dept:"", gradeRef:"", description:"", duties:[""], skills:[], software:[], certifications:[], kpiCriteria:[] });
  const [titleSearch, setTitleSearch] = useState("");
  const { show, toastEl } = useToast();
  const canEdit = isHRManager(currentUser);

  useEffect(() => { getJobTitles().then(t=>{ setTitles(t); setLoading(false); }); }, []);
  const [scale, setScale] = useState(null);
  useEffect(() => { getSalaryScale().then(setScale); }, []);
  const uniqueDepts = [...new Set((titles||[]).map(t=>t.dept).filter(Boolean))].sort();
  const gradeOptions = scale ? [...new Set([...(scale.engineers||[]).map(g=>g.grade),...(scale.admin||[]).map(g=>g.grade),...(scale.technicians||[]).map(g=>g.grade)])].sort() : [];

  const [pendingNotif, setPendingNotif] = useState(null);

  const save = async () => {
    if (!form.title.trim()) { show("⚠️ عنوان المسمى مطلوب"); return; }
    const item = { ...form, id: editItem?.id || "jt_"+Date.now(), duties: form.duties.filter(d=>d.trim()) };
    const isUpdate = !!editItem;
    const updated = isUpdate ? titles.map(t=>t.id===item.id?item:t) : [...titles, item];
    await saveJobTitles(updated);
    setTitles(updated);

    // ── Sync KPI criteria to KPI config ──
    if ((item.kpiCriteria||[]).length > 0 && item.dept) {
      try {
        const fullCfg = await db.get("eval:kpi_full_config") || { global:[], departments:{} };
        const deptKey = item.dept;
        const existing = fullCfg.departments?.[deptKey] || [];
        const existingIds = new Set(existing.map(k => k.id));
        const newItems = (item.kpiCriteria||[]).filter(k => k.label && !existingIds.has(k.id)).map(k => ({
          ...k, id: k.id || "kpi_"+Date.now()+"_"+Math.random().toString(36).slice(2,5),
          jobTitleRef: item.id, jobTitleName: item.title
        }));
        if (newItems.length > 0) {
          fullCfg.departments = { ...fullCfg.departments, [deptKey]: [...existing, ...newItems] };
          await db.set("eval:kpi_full_config", fullCfg);
          window._kpiFullConfig = fullCfg;
          window._kpiConfig = fullCfg.global;
          show("📊 تم مزامنة " + newItems.length + " معيار KPI مع إعدادات القسم");
        }
      } catch(e) { console.error("KPI sync error:", e); }
    }

    show("✅ تم الحفظ"); setShowForm(false); setEditItem(null);
    setForm({ title:"", titleEn:"", dept:"", gradeRef:"", description:"", duties:[""], skills:[], software:[], certifications:[], kpiCriteria:[] }); 
    // Prepare notification draft for updates
    if (isUpdate) {
      setPendingNotif({ titleId:item.id, titleName:item.title,
        message:"تم تحديث المسمى الوظيفي: "+item.title+". يرجى مراجعة المتطلبات الجديدة.",
        targetId:"all" });
    }
  };

  const sendTitleNotif = async () => {
    if (!pendingNotif) return;
    await saveNotification({ ...pendingNotif, type:"title_update", sentBy:window._currentUser?.displayName||"الإدارة" });
    show("✅ تم إرسال الإشعار للموظفين"); setPendingNotif(null);
  };

  const canDelete = currentUser && (currentUser.role === "admin" || currentUser.username === "admin" || isHRManager(currentUser));

  const del = async (id) => {
    const t = titles.find(x=>x.id===id);
    if (!window.confirm("⚠️ هل أنت متأكد من حذف المسمى الوظيفي \"" + (t?.title||"") + "\"؟\n\nسيتم حذفه نهائياً من المكتبة.")) return;
    const updated = titles.filter(t=>t.id!==id);
    await saveJobTitles(updated);
    setTitles(updated);
    if (editItem?.id === id) { setEditItem(null); setShowForm(false); setForm({ title:"", titleEn:"", dept:"", gradeRef:"", description:"", duties:[""], skills:[], software:[], certifications:[], kpiCriteria:[] }); }
    show("✅ تم حذف \"" + (t?.title||"المسمى") + "\"");
  };

  const openEdit = (item) => {
    setForm({ ...item, duties: item.duties?.length ? item.duties : [""] });
    setEditItem(item); setShowForm(true);
  };

  if (loading) return <div style={{ textAlign:"center", padding:40 }}><div className="loader"/></div>;

  return (
    <div className="fade">
      {toastEl}

      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16, flexWrap:"wrap", gap:10 }}>
        <div>
          <h2 style={S.gold900s20}>💼 مكتبة المسميات الوظيفية</h2>
          <p style={{ fontSize:12, color:"var(--text3)", marginTop:2 }}>{titles.length} مسمى وظيفي</p>
        </div>
        <div style={{ display:"flex", gap:8 }}>
          {onClose && <button onClick={onClose} className="btn btn-ghost btn-sm">← رجوع</button>}
          {canEdit && <button onClick={()=>{setEditItem(null);setForm({ title:"", titleEn:"", dept:"", gradeRef:"", description:"", duties:[""], skills:[], software:[], certifications:[] });setShowForm(true);}} className="btn btn-gold btn-sm">➕ مسمى جديد</button>}
          {canEdit && <button onClick={()=>{
            const src = titles.length > 0 ? window.prompt("أدخل اسم المسمى الوظيفي المراد نسخه:") : null;
            if (!src) return;
            const found = titles.find(t=>t.title.includes(src) || (t.titleEn||"").toLowerCase().includes(src.toLowerCase()));
            if (!found) { alert("لم يتم العثور على المسمى"); return; }
            setForm({ ...found, id:"", title:found.title+" (نسخة)", titleEn:found.titleEn?(found.titleEn+" (copy)"):"", duties:found.duties||[""] });
            setEditItem(null); setShowForm(true);
          }} className="btn btn-ghost btn-sm">📋 نسخ مسمى</button>}
        </div>
      </div>

      {/* Search */}
      <input value={titleSearch} onChange={e=>setTitleSearch(e.target.value)} placeholder="🔍 بحث في المسميات..." style={{ width:"100%", padding:"8px 14px", borderRadius:10, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", fontSize:13, marginBottom:14 }} />

      {/* Form */}
      {showForm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:600, maxHeight:"90vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:16 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:16 }}>{editItem?"✏️ تعديل":"➕ مسمى جديد"}</p>
              <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                <button onClick={async()=>{
                  if(!form.title.trim()){show("⚠️ أدخل المسمى الوظيفي أولاً");return;}
                  show("⏳ جاري توليد الوصف بـ Gemini...");
                  try {
                    const prompt = `أنت خبير موارد بشرية في مجال الهندسة.
للمسمى الوظيفي: "${form.title}" في قسم "${form.dept||"الهندسة"}".
أنتج JSON فقط:
{
  "description": "وصف وظيفي دقيق مختصر (3-4 جمل)",
  "duties": ["مهمة 1","مهمة 2","مهمة 3","مهمة 4","مهمة 5"],
  "requirements": "متطلبات الوظيفة من مؤهل وخبرة وشهادات"
}`;
                    const res = await callAIModel([{role:"user",content:prompt}],"أنت خبير موارد بشرية. أرجع JSON فقط.",MODEL_GEMINI);
                    if(res?.description) setForm(p=>({...p, description:res.description, duties:res.duties||p.duties, requirements:res.requirements||p.requirements||""}));
                    show("✅ تم توليد الوصف بـ Gemini");
                  } catch(e){show("❌ "+e.message);}
                }} style={{ padding:"6px 12px", borderRadius:8, border:"1px solid rgba(96,165,250,.4)", background:"rgba(96,165,250,.08)", color:"#60a5fa", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
                  ✨ توليد بـ Gemini
                </button>
                <button onClick={()=>{setShowForm(false);setEditItem(null);}} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:20 }}>✕</button>
              </div>
            </div>
            <div className="g2" style={{ marginBottom:12 }}>
              <div className="field"><label className="label">المسمى الوظيفي (عربي) *</label>
                <input value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))} placeholder="مهندس مدني" /></div>
              <div className="field"><label className="label">المسمى الوظيفي (إنجليزي)</label>
                <input value={form.titleEn} onChange={e=>setForm(p=>({...p,titleEn:e.target.value}))} placeholder="Civil Engineer" /></div>
              <div className="field"><label className="label">الإدارة / القسم</label>
                <select value={form.dept||""} onChange={e=>setForm(p=>({...p,dept:e.target.value}))}>
                  <option value="">-- اختر القسم --</option>
                  {uniqueDepts.map(d=><option key={d} value={d}>{d}</option>)}
                </select></div>
              <div className="field"><label className="label">درجة السلم</label>
                <select value={form.gradeRef||""} onChange={e=>setForm(p=>({...p,gradeRef:e.target.value}))}>
                  <option value="">-- اختر الدرجة --</option>
                  {gradeOptions.map(g=><option key={g} value={g}>{g}</option>)}
                  {form.gradeRef && !gradeOptions.includes(form.gradeRef) && <option value={form.gradeRef}>{form.gradeRef}</option>}
                </select></div>
            </div>
            <div className="field" style={{ marginBottom:12 }}>
              <label className="label">الوصف الوظيفي</label>
              <textarea value={form.description} onChange={e=>setForm(p=>({...p,description:e.target.value}))} rows={3} style={{ fontFamily:"inherit", fontSize:13 }} placeholder="وصف مختصر للوظيفة ودورها في المكتب..." />
            </div>
            <div style={{ marginBottom:14 }}>
              <label className="label">المهام والمسؤوليات</label>
              {form.duties.map((d,i)=>(
                <div key={i} style={{ display:"flex", gap:6, marginBottom:6 }}>
                  <input value={d} onChange={e=>setForm(p=>({...p,duties:p.duties.map((x,j)=>j===i?e.target.value:x)}))}
                    placeholder={"المهمة "+(i+1)} style={{ flex:1 }} />
                  {form.duties.length > 1 && <button onClick={()=>setForm(p=>({...p,duties:p.duties.filter((_,j)=>j!==i)}))}
                    style={{ background:"none",border:"1px solid var(--b)",color:"var(--red)",cursor:"pointer",borderRadius:6,padding:"4px 8px" }}>✕</button>}
                </div>
              ))}
              <button onClick={()=>setForm(p=>({...p,duties:[...p.duties,""]}))} className="btn btn-ghost btn-sm">+ إضافة مهمة</button>
            </div>
            {/* KPI Criteria for this job title */}
            <div style={{ marginBottom:14, padding:"12px 14px", background:"rgba(201,168,76,.04)", border:"1px solid rgba(201,168,76,.15)", borderRadius:10 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
                <label className="label" style={{ marginBottom:0 }}>📊 معايير KPI الخاصة بالمسمى</label>
                <div style={{ display:"flex", gap:6 }}>
                  <button onClick={async()=>{
                    if(!form.title.trim()){show("⚠️ أدخل المسمى أولاً");return;}
                    show("⏳ Gemini يقترح معايير KPI...");
                    try {
                      const prompt = `أنت خبير موارد بشرية. اقترح معايير KPI مناسبة للمسمى الوظيفي التالي.
المسمى: ${form.title}
القسم: ${form.dept||"الهندسة"}
الوصف: ${form.description||""}

أرجع JSON فقط:
{"kpi": [
  {"label": "اسم المعيار", "icon": "📊", "weight": 20, "source": "مدير"},
  {"label": "اسم المعيار 2", "icon": "⏱️", "weight": 15, "source": "hr"}
]}
أضف 4-6 معايير مناسبة. المصادر: مدير أو hr أو موظف. مجموع الأوزان 100.`;
                      const res = await callAIModel([{role:"user",content:prompt}],"أنت خبير موارد بشرية. أرجع JSON فقط.",MODEL_GEMINI);
                      if(res?.kpi?.length){
                        const newKpis = res.kpi.map(k=>({id:"kpi_"+Date.now()+Math.random(),label:k.label||"",icon:k.icon||"📊",weight:k.weight||10,source:k.source||"مدير"}));
                        setForm(p=>({...p,kpiCriteria:[...(p.kpiCriteria||[]),...newKpis]}));
                        show("✅ Gemini اقترح "+newKpis.length+" معيار KPI");
                      }
                    } catch(e){show("❌ "+e.message);}
                  }} style={{ background:"none", border:"1px solid rgba(96,165,250,.3)", color:"#60a5fa", cursor:"pointer", borderRadius:6, padding:"3px 10px", fontSize:11, fontFamily:"inherit", fontWeight:700 }}>✨ Gemini</button>
                  <button onClick={()=>setForm(p=>({...p,kpiCriteria:[...(p.kpiCriteria||[]),{id:"kpi_"+Date.now(),label:"",icon:"📊",weight:10,source:"مدير"}]}))}
                    style={{ background:"none", border:"1px solid rgba(201,168,76,.3)", color:"var(--gold)", cursor:"pointer", borderRadius:6, padding:"3px 10px", fontSize:11, fontFamily:"inherit", fontWeight:700 }}>+ معيار</button>
                </div>
              </div>
              <p style={{ fontSize:10, color:"var(--text3)", marginBottom:8 }}>تُضاف بجانب المعايير العامة — المصدر: 👨‍💼 المدير يقيّم · 🏢 HR تدخل نسبة · 👤 الموظف يقيّم نفسه</p>
              {(form.kpiCriteria||[]).length === 0 && <p style={{ fontSize:11, color:"var(--text3)", textAlign:"center", padding:8 }}>لا توجد معايير خاصة — سيُطبّق المعايير العامة فقط</p>}
              {(form.kpiCriteria||[]).map((kpi,i)=>(
                <div key={i} style={{ display:"flex", gap:6, alignItems:"center", marginBottom:6 }}>
                  <input value={kpi.icon} onChange={e=>setForm(p=>({...p,kpiCriteria:p.kpiCriteria.map((x,j)=>j===i?{...x,icon:e.target.value}:x)}))}
                    style={{ width:32, textAlign:"center", padding:"4px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", fontSize:14 }} />
                  <input value={kpi.label} onChange={e=>setForm(p=>({...p,kpiCriteria:p.kpiCriteria.map((x,j)=>j===i?{...x,label:e.target.value}:x)}))}
                    placeholder="اسم المعيار" style={{ flex:1, padding:"4px 8px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontSize:12, fontFamily:"inherit" }} />
                  <select value={kpi.source||"مدير"} onChange={e=>setForm(p=>({...p,kpiCriteria:p.kpiCriteria.map((x,j)=>j===i?{...x,source:e.target.value}:x)}))}
                    style={{ width:80, padding:"4px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text2)", fontSize:10, fontFamily:"inherit" }}>
                    <option value="مدير">👨‍💼 مدير</option><option value="HR">🏢 HR</option><option value="ذاتي">👤 ذاتي</option>
                  </select>
                  <input type="number" min={0} max={100} value={kpi.weight} onChange={e=>setForm(p=>({...p,kpiCriteria:p.kpiCriteria.map((x,j)=>j===i?{...x,weight:parseInt(e.target.value)||0}:x)}))}
                    style={{ width:45, textAlign:"center", padding:"4px", borderRadius:6, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontWeight:700, fontSize:12 }} />
                  <span style={{ fontSize:10, color:"var(--text3)" }}>%</span>
                  <button onClick={()=>setForm(p=>({...p,kpiCriteria:p.kpiCriteria.filter((_,j)=>j!==i)}))}
                    style={{ background:"none", border:"none", color:"#f87171", cursor:"pointer", fontSize:14 }}>✕</button>
                </div>
              ))}
            </div>
            <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
              <button onClick={()=>{setShowForm(false);setEditItem(null);}} className="btn btn-ghost btn-sm">إلغاء</button>
              <button onClick={save} className="btn btn-gold">💾 حفظ</button>
            </div>
          </div>
        </div>
      )}

      {/* Pending Notification */}
      {pendingNotif && (
        <div style={{ padding:"12px 16px", background:"rgba(245,158,11,.08)", border:"1px solid rgba(245,158,11,.3)", borderRadius:12, marginBottom:16 }}>
          <p style={{ fontSize:13, color:"#f59e0b", fontWeight:700, marginBottom:6 }}>📢 إشعار جاهز للإرسال</p>
          <p style={{ fontSize:12, color:"var(--text2)", marginBottom:10 }}>{pendingNotif.message}</p>
          <div style={{ display:"flex", gap:8 }}>
            <button onClick={sendTitleNotif} className="btn btn-gold btn-sm">📨 إرسال للموظفين</button>
            <button onClick={()=>setPendingNotif(null)} className="btn btn-ghost btn-sm">تجاهل</button>
          </div>
        </div>
      )}

      {/* Grid */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))", gap:10 }}>

        {/* ── Print Job Description Card ── */}
        {printJT && (
          <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.75)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={e=>{if(e.target===e.currentTarget)setPrintJT(null);}}>
            <div style={{ background:"var(--modal-bg,#1a1a2e)", border:"1px solid var(--b)", borderRadius:16, padding:22, maxWidth:500, width:"100%", maxHeight:"90vh", overflowY:"auto" }}>
              <h3 style={{ color:"var(--gold)", fontWeight:900, fontSize:16, marginBottom:12 }}>🖨️ طباعة بطاقة الوصف الوظيفي</h3>
              <div className="field" style={{ marginBottom:12 }}>
                <label className="label">اسم الموظف (اختياري)</label>
                <input value={printEmpName} onChange={e=>setPrintEmpName(e.target.value)} placeholder="اكتب اسم الموظف..." style={{ fontSize:13 }} />
              </div>
              <div style={{ display:"flex", gap:8 }}>
                <button onClick={()=>{
                  const t = printJT;
                  const empName = printEmpName.trim();
                  const kpiCfg = window._kpiFullConfig || {};
                  const deptKPI = kpiCfg?.departments?.[t.dept] || kpiCfg?.departments?._default || [];
                  const globalTools = (kpiCfg?.tools||[]).filter(x=>x.enabled);
                  const sp = kpiCfg?.split || { general:40, specific:60 };
                  const w = window.open("","_blank");
                  var h = "<!DOCTYPE html><html dir=\'rtl\' lang=\'ar\'><head><meta charset=\'UTF-8\'><title>بطاقة وصف وظيفي</title>";
                  h += "<style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Tahoma,sans-serif;padding:40px;color:#1a1a1a;font-size:13px;line-height:1.8}";
                  h += ".hdr{display:flex;justify-content:space-between;align-items:center;border-bottom:3px solid #0f766e;padding-bottom:16px;margin-bottom:20px}";
                  h += ".bx{border:1px solid #ddd;border-radius:8px;padding:14px 16px;margin-bottom:14px}";
                  h += ".bx h3{color:#0f766e;font-size:14px;margin-bottom:8px;border-bottom:1px solid #eee;padding-bottom:6px}";
                  h += "table{width:100%;border-collapse:collapse;margin-bottom:14px}td,th{border:1px solid #ddd;padding:8px 10px;text-align:right;font-size:12px}";
                  h += "th{background:#f0f9ff;font-weight:700;color:#0f766e}";
                  h += ".sig{margin-top:40px;display:flex;justify-content:space-between}.sig-bx{width:45%;border-top:2px solid #333;padding-top:8px;text-align:center;font-size:12px}";
                  h += ".ft{margin-top:30px;text-align:center;border-top:2px solid #0f766e;padding-top:12px}";
                  h += "@media print{body{padding:10px 20px!important}table,.bx,.sig{page-break-inside:avoid;break-inside:avoid}.page-num{position:fixed;bottom:10px;left:0;right:0;text-align:center;font-size:9px;color:#999}}@page{size:A4 portrait;margin:20mm 15mm 25mm 15mm}</style></head><body>";
                  h += "<div class=\'hdr\'><div><h1 style=\'font-size:20px;color:#0f766e\'>بطاقة الوصف الوظيفي</h1>";
                  h += "<p style=\'font-size:11px;color:#666\'>تاريخ الإصدار: " + new Date().toLocaleDateString("ar-SA") + "</p></div>";
                  h += "<div style=\'text-align:left\'><img src=\'" + HMA_LOGO_PRINT + "\' style=\'width:100px;object-fit:contain\' />";
                  h += "</div></div>";
                  h += "<table><tr><th>المسمى الوظيفي</th><td style=\'font-weight:700;font-size:14px\'>" + t.title + (t.titleEn?" — "+t.titleEn:"") + "</td></tr>";
                  if (empName) h += "<tr><th>اسم الموظف</th><td style=\'font-weight:700;font-size:14px\'>" + empName + "</td></tr>";
                  h += "<tr><th>الإدارة</th><td>" + (t.dept||"—") + "</td></tr>";
                  h += "<tr><th>الدرجة الوظيفية</th><td>" + (t.gradeRef||"—") + "</td></tr></table>";
                  if (t.description) h += "<div class=\'bx\'><h3>📝 الوصف الوظيفي</h3><p>" + t.description + "</p></div>";
                  var duties = (t.duties||[]).filter(function(d){return d.trim();});
                  if (duties.length) { h += "<div class=\'bx\'><h3>📋 المهام والمسؤوليات</h3><ol>"; duties.forEach(function(d){h+="<li>"+d+"</li>";}); h += "</ol></div>"; }
                  h += "<div class=\'bx\'><h3>📊 معايير التقييم — KPI</h3>";
                  h += "<p style=\'font-size:11px;color:#666;margin-bottom:12px\'>التوزيع: المعايير العامة <b>" + sp.general + "%</b> + المعايير الخاصة <b>" + sp.specific + "%</b></p>";
                  h += "<h4 style=\'color:#0f766e;font-size:13px;margin-bottom:6px;background:#f0fdf4;padding:6px 10px;border-radius:6px\'>🟢 المعايير العامة (الوزن " + sp.general + "% — كل معيار من 100%)</h4>";
                  h += "<table><tr><th>المعيار</th><th>الوزن</th></tr>";
                  globalTools.forEach(function(g){h+="<tr><td>"+g.icon+" "+g.label+"</td><td style=\'text-align:center;font-weight:700\'>"+g.weight+"%</td></tr>";});
                  h += "</table>";
                  var specKPI = (t.kpiCriteria||[]).length > 0 ? (t.kpiCriteria||[]) : deptKPI;
                  if (specKPI.length > 0) {
                    h += "<h4 style=\'color:#d97706;font-size:13px;margin:12px 0 6px;background:#fffbeb;padding:6px 10px;border-radius:6px\'>🟡 المعايير الخاصة (الوزن " + sp.specific + "% — كل معيار من 100%)</h4>";
                    h += "<table><tr><th>المعيار</th><th>الوزن</th></tr>";
                    specKPI.forEach(function(k){h+="<tr><td>"+(k.icon||"📊")+" "+k.label+"</td><td style=\'text-align:center;font-weight:700\'>"+k.weight+"%</td></tr>";});
                    h += "</table>";
                  }
                  h += "</div>";
                  h += "<div class=\'sig\'><div class=\'sig-bx\'><p>توقيع الموظف</p><p style=\'margin-top:30px\'>" + (empName||"________________") + "</p><p style=\'color:#999;font-size:10px\'>التاريخ: ___/___/______</p></div>";
                  h += "<div class=\'sig-bx\'><p>توقيع المدير المباشر</p><p style=\'margin-top:30px\'>________________</p><p style=\'color:#999;font-size:10px\'>التاريخ: ___/___/______</p></div></div>";
                  h += "<div class=\'ft\'>";
                  h += "<div style=\'margin-top:8px;padding:6px 16px;background:#fef3c7;border:1px solid #f59e0b;border-radius:6px;display:inline-block\'>";
                  h += "<p style=\'font-size:10px;color:#92400e;font-weight:700\'>⚠️ وثيقة داخلية سرية — للاستخدام الداخلي فقط</p>";
                  h += "<p style=\'font-size:9px;color:#92400e\'>يُمنع نسخ أو تداول محتويات هذه الوثيقة خارج نطاق المكتب دون إذن كتابي مسبق من الإدارة</p>";
                  h += "</div></div><div class='page-num'>صفحة <span class='pagenum'></span></div><script>document.querySelectorAll('.pagenum').forEach(e=>e.textContent='1')</script></body></html>";
                  w.document.write(h);
                  w.document.close();
                  setTimeout(function(){w.print();}, 500);
                  setPrintJT(null); setPrintEmpName("");
                }} className="btn btn-gold" style={{ flex:1 }}>🖨️ طباعة</button>
                <button onClick={()=>{setPrintJT(null);setPrintEmpName("");}} className="btn btn-ghost btn-sm">إلغاء</button>
              </div>
            </div>
          </div>
        )}


        {titles.filter(t=>!titleSearch.trim()||[t.title,t.titleEn,t.description,t.dept,(t.duties||[]).join(" ")].join(" ").toLowerCase().includes(titleSearch.toLowerCase())).map(t=>(
          <div key={t.id} onClick={()=>openEdit(t)} style={{ padding:"14px 16px", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12, cursor:"pointer", transition:"border-color .2s" }}
            onMouseEnter={e=>e.currentTarget.style.borderColor="rgba(201,168,76,.4)"}
            onMouseLeave={e=>e.currentTarget.style.borderColor="var(--b)"}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:6 }}>
              <span style={{ fontWeight:800, fontSize:14, color:"var(--text)" }}>{t.title}</span>
              <div style={{ display:"flex", gap:4, flexShrink:0 }}>
                <button onClick={e=>{e.stopPropagation();setPrintJT(t);}} className="btn btn-ghost btn-sm" style={{ fontSize:10, padding:"0 8px", height:26, color:"#60a5fa", borderColor:"rgba(96,165,250,.3)" }} title="طباعة بطاقة وصف وظيفي">🖨️</button>
                {onSelect && <button onClick={e=>{e.stopPropagation();onSelect(t);}} className="btn btn-gold btn-sm" style={{ fontSize:10, padding:"0 8px", height:26 }}>اختيار</button>}
                {canDelete && <button onClick={e=>{e.stopPropagation();del(t.id);}} style={{ background:"none", border:"none", color:"var(--red)", cursor:"pointer", fontSize:12, padding:0 }}>🗑️</button>}
              </div>
            </div>
            {t.titleEn && <p style={{ fontSize:11, color:"var(--text3)", marginBottom:4 }}>{t.titleEn}</p>}
            {t.dept && <span style={{ fontSize:10, color:"var(--gold)", background:"rgba(201,168,76,.08)", padding:"2px 8px", borderRadius:6, border:"1px solid rgba(201,168,76,.15)" }}>{t.dept}</span>}
            {t.description && <p style={{ fontSize:12, color:"var(--text2)", marginTop:6, lineHeight:1.6, display:"-webkit-box", WebkitLineClamp:2, WebkitBoxOrient:"vertical", overflow:"hidden" }}>{t.description}</p>}
          </div>
        ))}
      </div>
    </div>
  );
}


// ── Job-Candidate Linking ─────────────────────────────────────────────────────
async function linkCandidatesToJob(jobId, candidateIds) {
  const job = await db.get("job:" + jobId);
  if (!job) return;
  const current = job.linkedCandidates || [];
  const merged = [...new Set([...current, ...candidateIds])];
  await saveJob({ ...job, linkedCandidates: merged });
}
async function unlinkCandidateFromJob(jobId, candidateId) {
  const job = await db.get("job:" + jobId);
  if (!job) return;
  await saveJob({ ...job, linkedCandidates: (job.linkedCandidates||[]).filter(id=>id!==candidateId) });
}

function JobPostingsSection({ candidates, employees, libs, currentUser }) {
  const [tab, setTab]           = useState("jobs"); // jobs | titles
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editJob, setEditJob] = useState(null);
  const [selJob, setSelJob] = useState(null);
  const [selected, setSelected] = useState([]);
  const [matchingJob, setMatchingJob] = useState(null);
  const [jobTitles,   setJobTitles]   = useState([]);
  const [jobSearch, setJobSearch] = useState("");
  useEffect(()=>{ getJobTitles().then(setJobTitles); },[]);
  const { confirm, dlg } = useConfirm();
  const { show, toastEl } = useToast();

  useEffect(() => { getAllJobs().then(j => { setJobs(j); setLoading(false); }); }, []);

  const save = async (data) => {
    const saved = await saveJob(data);
    await db._sync(); // Force immediate sync so visitor page gets latest
    setJobs(p => { const n=p.filter(x=>x.id!==saved.id); return [...n,saved]; });
    await addAudit("job", (data.id?"تحديث":"إضافة")+" وظيفة: "+data.title);
    show("✅ تم الحفظ"); setShowForm(false); setEditJob(null);
  };

  const del = async (j) => {
    const ok = await confirm("حذف وظيفة "+j.title+"؟");
    if (!ok) return;
    await delJob(j.id);
    await db._sync();
    setJobs(p=>p.filter(x=>x.id!==j.id));
    if (selJob?.id===j.id) setSelJob(null);
    setSelected(p=>p.filter(x=>x!==j.id));
    show("✅ تم الحذف");
  };

  const delSelected = async () => {
    const ok = await confirm("حذف "+selected.length+" إعلان؟");
    if (!ok) return;
    for (const id of selected) await delJob(id);
    setJobs(p=>p.filter(x=>!selected.includes(x.id)));
    setSelected([]);
    show("✅ تم الحذف");
  };

  const toggleSel = (id) => setSelected(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);

  if ((showForm||editJob) && !selJob) return (
    <div className="fade">
      {toastEl}
      <button onClick={()=>{setShowForm(false);setEditJob(null);}} className="btn btn-ghost btn-sm" style={{ marginBottom:14 }}>← رجوع</button>
      <JobForm initial={editJob} libs={libs} jobTitles={jobTitles} onSave={save} onClose={()=>{setShowForm(false);setEditJob(null);}} />
    </div>
  );

  if (selJob) return (
    <ErrorBoundary>
    <JobDetail job={selJob} candidates={candidates} employees={employees} libs={libs}
      onBack={()=>setSelJob(null)} onEdit={j=>{setEditJob(j);setSelJob(null);setShowForm(true);}} onDelete={del} />
    </ErrorBoundary>
  );

  const today = new Date().toISOString().split("T")[0];
  const filteredJobs = jobSearch.trim() ? jobs.filter(j => [j.title,j.department,j.city,j.description,(j.requiredSkills||[]).join(" ")].join(" ").toLowerCase().includes(jobSearch.toLowerCase())) : jobs;
  const open = filteredJobs.filter(j=>j.status==="مفتوحة"&&(!j.openDate||j.openDate<=today));
  const upcoming = filteredJobs.filter(j=>j.status==="مفتوحة"&&j.openDate&&j.openDate>today);
  const closed = filteredJobs.filter(j=>j.status!=="مفتوحة");

  return (
    <div className="fade">
      {dlg}{toastEl}
      {matchingJob && <JobMatchingModal job={matchingJob} candidates={candidates} onClose={()=>setMatchingJob(null)} />}

      {tab === "jobs" && <>

      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10, flexWrap:"wrap", gap:8 }}>
        <h2 style={{ color:"var(--gold)", fontWeight:900, fontSize:20, margin:0 }}>📢 إعلانات الوظائف</h2>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
          {selected.length > 0 && (
            <button onClick={delSelected} className="btn btn-danger btn-sm">{"🗑️ حذف ("+selected.length+")"}</button>
          )}
          <button onClick={()=>setShowForm(true)} className="btn btn-gold">➕ وظيفة جديدة</button>
        </div>
      </div>
      <div style={{ marginBottom:12 }}>
        <input value={jobSearch} onChange={e=>setJobSearch(e.target.value)} placeholder="🔍 بحث في الإعلانات..." style={{ width:"100%", padding:"8px 14px", borderRadius:10, border:"1px solid var(--b)", background:"var(--glass)", color:"var(--text)", fontFamily:"inherit", fontSize:13 }} />
      </div>

      {selected.length > 0 && (
        <div style={{ padding:"8px 14px", background:"rgba(239,68,68,.08)", border:"1px solid rgba(239,68,68,.2)", borderRadius:10, marginBottom:12, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <span style={{ color:"#f87171", fontSize:13, fontWeight:700 }}>{selected.length+" إعلان محدد"}</span>
          <button onClick={()=>setSelected([])} className="btn btn-ghost btn-sm" style={{ fontSize:11 }}>إلغاء</button>
        </div>
      )}

      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:18 }}>
        {[{l:"مفتوحة",v:open.length,c:"#e8eaf0"},{l:"قادمة",v:upcoming.length,c:"#e8eaf0"},{l:"مغلقة",v:closed.length,c:"#6b7280"},{l:"الكل",v:jobs.length,c:"var(--gold)"}].map(s=>(
          <div key={s.l} className="card" style={{ textAlign:"center" }}>
            <div style={{ fontSize:26,fontWeight:900,color:s.c }}>{s.v}</div>
            <div style={{ fontSize:11,color:"var(--text2)" }}>{s.l}</div>
          </div>
        ))}
      </div>

      {loading ? <div style={{ textAlign:"center",padding:40 }}><div className="loader"/></div>
      : jobs.length===0 ? (
        <div className="card" style={{ textAlign:"center",padding:44 }}>
          <p style={{ fontSize:36,marginBottom:10 }}>📢</p>
          <p style={{ color:"var(--text3)" }}>لا توجد وظائف — اضغط "وظيفة جديدة"</p>
        </div>
      ) : (
        <div style={{ display:"flex",flexDirection:"column",gap:9 }}>
          {/* Select all */}
          <div style={{ display:"flex", alignItems:"center", gap:10, padding:"4px 4px" }}>
            <input type="checkbox"
              checked={selected.length === jobs.length && jobs.length > 0}
              onChange={() => setSelected(p => p.length===jobs.length ? [] : jobs.map(j=>j.id))}
              style={{ cursor:"pointer", width:15, height:15 }} />
            <span style={S.txt3s12}>تحديد الكل</span>
          </div>

          {filteredJobs.sort((a,b)=>b.updatedAt>a.updatedAt?1:-1).map(j => {
            const isSel = selected.includes(j.id);
            const isOpen = j.status==="مفتوحة" && (!j.openDate||j.openDate<=today);
            const isFuture = j.status==="مفتوحة" && j.openDate && j.openDate>today;
            const daysLeft = j.openDate && isFuture ? Math.ceil((new Date(j.openDate)-new Date())/86400000) : null;
            return (
              <div key={j.id} style={{ background:"var(--glass)", border:"1px solid "+(isSel?"rgba(239,68,68,.3)":isOpen?"rgba(34,197,94,.25)":isFuture?"rgba(59,130,246,.25)":"var(--b)"), borderRadius:12, padding:"13px 16px" }}>
                <div style={{ display:"flex", alignItems:"flex-start", gap:12 }}>
                  <input type="checkbox" checked={isSel}
                    onChange={e=>{e.stopPropagation();toggleSel(j.id);}}
                    onClick={e=>e.stopPropagation()}
                    style={{ cursor:"pointer", width:15, height:15, flexShrink:0, marginTop:3 }} />
                  <div style={{ flex:1, cursor:"pointer" }} onClick={()=>setSelJob(j)}>
                    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:5, flexWrap:"wrap" }}>
                      <span style={{ fontWeight:700, fontSize:15 }}>{j.title}</span>
                      <span style={{ fontSize:12, padding:"2px 9px", borderRadius:12, background:isOpen?"rgba(34,197,94,.12)":isFuture?"rgba(59,130,246,.12)":"rgba(107,114,128,.12)", color:isOpen?"#4ade80":isFuture?"#93c5fd":"#9ca3af", border:"1px solid "+(isOpen?"rgba(34,197,94,.3)":isFuture?"rgba(59,130,246,.3)":"rgba(107,114,128,.3)") }}>
                        {isOpen?"🟢 مفتوحة":isFuture?"🔵 قادمة":"⚫ مغلقة"}
                      </span>
                      {isFuture && daysLeft && <span style={{ fontSize:11, color:"#93c5fd" }}>{"تفتح خلال "+daysLeft+" يوم"}</span>}
                    </div>
                    <div style={{ fontSize:12, color:"var(--text3)", display:"flex", gap:12, flexWrap:"wrap" }}>
                      {j.department && <span>🏢 {j.department}</span>}
                      {j.applicants?.length > 0 && <span style={{ color:"var(--gold)" }}>{"👥 "+j.applicants.length+" متقدم"}</span>}
                    </div>
                  </div>
                  <div style={{ display:"flex", gap:6, flexShrink:0 }}>
                    <button onClick={e=>{e.stopPropagation();setSelJob(j);}} className="btn btn-ghost btn-sm">عرض</button>
                    <button onClick={e=>{e.stopPropagation();setEditJob(j);setShowForm(true);}} className="btn btn-ghost btn-sm">✏️</button>
                    <button onClick={e=>{e.stopPropagation();del(j);}} className="btn btn-danger btn-sm">🗑️</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
      </>}
    </div>
  );
}

function JobForm({ initial, libs, onSave, onClose, jobTitles }) {
  const init = initial || { title:"", titleId:"", department:"", city:"", status:"مفتوحة", openDate:"", closeDate:"", description:"", duties:[], requiredSkills:[], requiredSoftware:[], requiredProjectTypes:[], requiredCertifications:[], minExperience:"", courses:[], contractType:"دوام كامل", gradeCode:"", bonusCode:"" };
  const [form, setForm] = useState(init);
  const [titles] = useState(jobTitles || []);
  const [scale, setScale] = useState(null);
  useEffect(()=>{ getSalaryScale().then(setScale); },[]);
  const set = (k,v) => setForm(p=>({...p,[k]:v}));
  const toggleArr = (k, val) => set(k, form[k].includes(val) ? form[k].filter(x=>x!==val) : [...form[k], val]);
  const [newCourse, setNewCourse] = useState({ name:"", url:"", required:true });
  const [tab, setTab] = useState(0);
  const [err, setErr] = useState("");

  const submit = async () => {
    if (!form.titleId) { setErr("يجب اختيار مسمى وظيفي من المكتبة"); return; }
    if (!form.title.trim()) { setErr("عنوان الوظيفة مطلوب"); return; }
    await onSave(form);
  };

  const TABS = ["📋 التفاصيل", "🛠️ الاشتراطات", "📚 الدورات المقترحة"];

  const MultiSelect = ({ label, items, field }) => {
    // Group items by cat if available
    const hasCats = items.some(item => typeof item === "object" && item.cat);
    const renderBtn = (item) => {
      const val = typeof item==="object" ? (item.ar || item.label || item.en || "") : (item || "");
      if (!val) return null;
      const sel = (form[field]||[]).includes(val);
      return (
        <button key={val} onClick={()=>toggleArr(field, val)}
          style={{ padding:"5px 13px", borderRadius:8, cursor:"pointer", fontFamily:"inherit", fontSize:12, border:"1px solid "+(sel?"rgba(34,197,94,.5)":"var(--b)"), background:sel?"rgba(34,197,94,.1)":"transparent", color:sel?"#4ade80":"var(--text2)", fontWeight:sel?700:400 }}>
          {val}
        </button>
      );
    };
    if (hasCats) {
      const groups = {};
      const order = [];
      items.forEach(item => {
        const cat = (typeof item === "object" && item.cat) || "أخرى";
        if (!groups[cat]) { groups[cat] = []; order.push(cat); }
        groups[cat].push(item);
      });
      return (
        <div style={{ marginBottom:14 }}>
          <label className="label" style={{ display:"block", marginBottom:7 }}>{label}</label>
          {order.map(cat => (
            <div key={cat} style={{ marginBottom:8 }}>
              <div style={{ fontSize:11, color:"var(--text3)", fontWeight:700, marginBottom:4, paddingRight:2 }}>{cat}</div>
              <div style={S.flexWrap6}>{groups[cat].map(renderBtn)}</div>
            </div>
          ))}
        </div>
      );
    }
    return (
      <div style={{ marginBottom:14 }}>
        <label className="label" style={{ display:"block", marginBottom:7 }}>{label}</label>
        <div style={S.flexWrap6}>{items.map(renderBtn)}</div>
      </div>
    );
  };

  return (
    <div className="card">
      <h3 style={{ color:"var(--gold)", fontWeight:900, marginBottom:16 }}>{initial?"تعديل الوظيفة":"إعلان وظيفة جديدة"}</h3>
      <div style={{ display:"flex", gap:6, marginBottom:18, flexWrap:"wrap" }}>
        {TABS.map((t,i)=><button key={i} onClick={()=>setTab(i)} className={"tab-btn "+(tab===i?"tab-on":"tab-off")}>{t}</button>)}
      </div>

      {tab===0 && (
        <div>
          {/* Job Title from Library - Required */}
          <div className="field" style={{ marginBottom:14 }}>
            <label className="label">المسمى الوظيفي من المكتبة *</label>
            <select value={form.titleId||""} onChange={e=>{
              const t = titles.find(x=>x.id===e.target.value);
              if(t){ set("titleId",t.id); set("title",t.title); set("description",t.description||""); set("duties",t.duties||[]); }
              else { set("titleId",""); }
            }} style={{ border: !form.titleId?"1px solid rgba(239,68,68,.5)":"1px solid var(--b)", background:"var(--glass)" }}>
              <option value="">-- اختر مسمى وظيفي (إلزامي)</option>
              {titles.map(t=><option key={t.id} value={t.id}>{t.title} {t.titleEn?"("+t.titleEn+")":""}</option>)}
            </select>
            {!form.titleId && <p style={{ fontSize:11, color:"#f87171", marginTop:4 }}>⚠️ يجب اختيار مسمى وظيفي من المكتبة</p>}
          </div>
          <div className="g2" style={{ marginBottom:14 }}>
            <div className="field"><label className="label">عنوان الوظيفة *</label><input value={form.title} onChange={e=>set("title",e.target.value)} placeholder="مهندس مدني أول..." /></div>
            <div className="field"><label className="label">الإدارة</label>
              <select value={form.department||""} onChange={e=>set("department",e.target.value)}>
                <option value="">--</option>
                {(libs.jobTypes||[]).map((j,ji)=>{const jl=typeof j==="string"?j:(j&&(j.ar||j.label||j.en))||"";return jl?<option key={jl+ji} value={jl}>{jl}</option>:null;})}
              </select>
            </div>
            <div className="field"><label className="label">📍 مكان العمل</label>
              <input value={form.city||""} onChange={e=>set("city",e.target.value)} placeholder="مثال: الرياض، جدة، مكة المكرمة..." />
            </div>
            <div className="field"><label className="label">الحالة</label>
              <select value={form.status} onChange={e=>set("status",e.target.value)}>
                <option>مفتوحة</option><option>مغلقة</option><option>موقوفة</option>
              </select>
            </div>
            <div className="field"><label className="label">نوع العقد</label>
              <select value={form.contractType||"دوام كامل"} onChange={e=>set("contractType",e.target.value)}>
                <option>دوام كامل</option>
                <option>عقد مرن / بارت تايم</option>
                <option>عقد مؤقت</option>
                <option>تعاون مهني</option>
              </select>
            </div>
            <div className="field"><label className="label">الحد الأدنى للخبرة (سنوات)</label><input type="number" min="0" value={form.minExperience||""} onChange={e=>set("minExperience",e.target.value)} placeholder="0" /></div>
            <div className="field"><label className="label">تاريخ فتح الوظيفة</label><input type="date" value={form.openDate||""} onChange={e=>set("openDate",e.target.value)} /></div>
            <div className="field"><label className="label">تاريخ الإغلاق</label><input type="date" value={form.closeDate||""} onChange={e=>set("closeDate",e.target.value)} /></div>
            {/* ── Salary Grade (visible to HR Manager + Admin only) ── */}
            <div className="field" style={{ gridColumn:"1/-1" }}>
              <label className="label">🔑 رمز الدرجة الوظيفية (سري — للموارد البشرية والإدارة فقط)</label>
              {scale && (() => {
                const GROUPS = [
                  { key:"engineers", label:"👷 سلم المهندسين",        color:"#60a5fa" },
                  { key:"admin",     label:"🏢 الكوادر الإدارية",       color:"#f59e0b" },
                  { key:"technical", label:"🔧 المراقبون والمساحون",    color:"#4ade80" },
                  { key:"design",    label:"🎨 التصميم الداخلي",        color:"#a78bfa" },
                ];
                return (
                  <div style={{ display:"flex", flexDirection:"column", gap:12, marginTop:8 }}>
                    {GROUPS.map(g => (
                      <div key={g.key} style={{ padding:"10px 14px", background:"rgba(255,255,255,.03)", border:"1px solid var(--b)", borderRadius:10 }}>
                        <p style={{ fontSize:12, color:g.color, fontWeight:700, marginBottom:8 }}>{g.label}</p>
                        <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                          {(scale[g.key]||[]).map(r => (
                            <button key={r.grade} type="button" onClick={()=>set("gradeCode",r.grade)}
                              title={r.grade+": خبرة "+r.expMin+"-"+r.expMax+" سنة | أساسي "+r.basic.toLocaleString()+" | إجمالي "+r.total.toLocaleString()+" ريال"}
                              style={{ padding:"5px 12px", borderRadius:16, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700, textAlign:"right",
                                background:form.gradeCode===r.grade?"rgba(201,168,76,.25)":"rgba(255,255,255,.04)",
                                border:"2px solid "+(form.gradeCode===r.grade?"var(--gold)":"transparent"),
                                color:form.gradeCode===r.grade?"var(--gold)":"var(--text2)" }}>
                              <span style={{ fontWeight:900 }}>{r.grade}</span>
                              <span style={{ fontSize:10, color:"var(--text3)", marginRight:4 }}>({r.expMin}-{r.expMax}س)</span>
                            </button>
                          ))}
                        </div>
                        {form.gradeCode && (scale[g.key]||[]).find(r=>r.grade===form.gradeCode) && (() => {
                          const r = (scale[g.key]||[]).find(x=>x.grade===form.gradeCode);
                          return (
                            <div style={{ marginTop:8, padding:"8px 12px", background:"rgba(201,168,76,.08)", borderRadius:8 }}>
                              <p style={{ fontSize:12, color:"var(--gold)", fontWeight:700 }}>
                                {r.grade} — خبرة {r.expMin}–{r.expMax} سنة
                              </p>
                              <div style={{ display:"flex", gap:16, fontSize:12, color:"var(--text2)", marginTop:4, flexWrap:"wrap" }}>
                                <span>أساسي: <strong style={{ color:"#4ade80" }}>{r.basic.toLocaleString()}</strong></span>
                                <span>سكن (25%): <strong>{r.housing.toLocaleString()}</strong></span>
                                <span>نقل: <strong>{r.transport.toLocaleString()}</strong></span>
                                <span>الإجمالي: <strong style={{ color:"var(--gold)", fontSize:14 }}>{r.total.toLocaleString()} ريال</strong></span>
                              </div>
                            </div>
                          );
                        })()}
                      </div>
                    ))}
                    {form.gradeCode && (
                      <button type="button" onClick={()=>set("gradeCode","")}
                        style={{ fontSize:11, color:"var(--red)", background:"none", border:"1px solid rgba(239,68,68,.3)", borderRadius:8, cursor:"pointer", padding:"4px 12px", alignSelf:"flex-start" }}>
                        ✕ مسح الاختيار
                      </button>
                    )}
                  </div>
                );
              })()}
            </div>
            <div className="field" style={{ gridColumn:"1/-1", marginTop:0 }}>
              <label className="label">⭐ علاوة إضافية (اختياري)</label>
              {scale && (
                <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginTop:6 }}>
                  {(scale.bonuses||[]).map(b=>(
                    <button key={b.label} type="button" onClick={()=>set("bonusCode",form.bonusCode===b.label?"":b.label)}
                      title={b.note}
                      style={{ padding:"6px 14px", borderRadius:16, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700,
                        background:form.bonusCode===b.label?"rgba(167,139,250,.2)":"rgba(255,255,255,.04)",
                        border:"2px solid "+(form.bonusCode===b.label?"#a78bfa":"transparent"),
                        color:form.bonusCode===b.label?"#a78bfa":"var(--text2)" }}>
                      {b.label}
                      <span style={{ fontSize:10, color:"var(--text3)", marginRight:4 }}>+{b.pct}%</span>
                    </button>
                  ))}
                </div>
              )}
              {form.gradeCode && form.bonusCode && scale && (() => {
                const allG = [...(scale.engineers||[]),...(scale.admin||[]),...(scale.technical||[]),...(scale.design||[])];
                const g = allG.find(r=>r.grade===form.gradeCode);
                const b = (scale.bonuses||[]).find(x=>x.label===form.bonusCode);
                if(!g||!b) return null;
                const bonusAmt = Math.round(g.basic * b.pct / 100);
                return (
                  <p style={{ fontSize:12, color:"#a78bfa", marginTop:6 }}>
                    ✅ {form.gradeCode} + {b.label}: إجمالي مع العلاوة = <strong>{(g.total+bonusAmt).toLocaleString()} ريال</strong> (+{bonusAmt.toLocaleString()})
                  </p>
                );
              })()}
            </div>
          </div>
          <div className="field"><label className="label">وصف الوظيفة والمهام</label><textarea value={form.description||""} onChange={e=>set("description",e.target.value)} style={{ minHeight:100 }} placeholder="اكتب تفاصيل الوظيفة ومهامها الرئيسية..." /></div>
        </div>
      )}

      {tab===1 && (
        <div>
          <p style={{ color:"var(--text2)", fontSize:13, marginBottom:14 }}>اختر الاشتراطات من المكتبة — سيستخدمها AI للمطابقة مع المرشحين والموظفين</p>
          <MultiSelect label="🛠️ المهارات المطلوبة" items={libs.skills||[]} field="requiredSkills" />
          <MultiSelect label="💻 البرامج المطلوبة" items={libs.software||[]} field="requiredSoftware" />
          <MultiSelect label="📋 أنواع المشاريع" items={libs.projectTypes||[]} field="requiredProjectTypes" />
          <MultiSelect label="🏅 الشهادات المطلوبة" items={libs.certifications||[]} field="requiredCertifications" />
        </div>
      )}

      {tab===2 && (
        <div>
          <p style={{ color:"var(--text2)", fontSize:13, marginBottom:14 }}>أضف دورات مقترحة تساعد المتقدمين على تأهيل أنفسهم لهذه الوظيفة</p>
          {(form.courses||[]).map((c,i)=>(
            <div key={i} style={{ display:"flex", gap:8, alignItems:"center", marginBottom:7 }}>
              <input value={c.name} onChange={e=>{const a=[...(form.courses||[])];a[i]={...a[i],name:e.target.value};set("courses",a);}} style={{ flex:2 }} placeholder="اسم الدورة" />
              <input value={c.url||""} onChange={e=>{const a=[...(form.courses||[])];a[i]={...a[i],url:e.target.value};set("courses",a);}} style={{ flex:3 }} placeholder="رابط الدورة" />
              <button onClick={()=>set("courses",(form.courses||[]).filter((_,j)=>j!==i))} style={{ background:"none",border:"none",color:"var(--red)",cursor:"pointer",fontSize:16 }}>✕</button>
            </div>
          ))}
          <div style={{ display:"flex", gap:8, marginTop:8 }}>
            <input value={newCourse.name} onChange={e=>setNewCourse(p=>({...p,name:e.target.value}))} style={{ flex:2 }} placeholder="اسم الدورة..." />
            <input value={newCourse.url} onChange={e=>setNewCourse(p=>({...p,url:e.target.value}))} style={{ flex:3 }} placeholder="رابط الدورة" />
            <button onClick={()=>{if(newCourse.name.trim()){set("courses",[...(form.courses||[]),newCourse]);setNewCourse({name:"",url:"",required:true});}}} className="btn btn-gold btn-sm">+ إضافة</button>
          </div>
        </div>
      )}

      {err && <p style={{ color:"var(--red)", fontSize:13, marginTop:10 }}>{err}</p>}
      <div style={{ display:"flex", gap:10, marginTop:20 }}>
        <button onClick={submit} className="btn btn-gold" style={{ flex:1 }}>💾 حفظ الوظيفة</button>
        <button onClick={onClose} className="btn btn-ghost">إلغاء</button>
      </div>
    </div>
  );
}

function JobDetail({ job, candidates, employees, libs, onBack, onEdit, onDelete }) {
  const [matching, setMatching] = useState([]);
  const [matchLoad, setMatchLoad] = useState(false);
  const [linkedCands, setLinkedCands] = useState(job.linkedCandidates || []);
  const [showLinkModal, setShowLinkModal] = useState(false);
  const [selProfile, setSelProfile] = useState(null);

  const linkCandidate = async (candId) => {
    const updated = [...new Set([...linkedCands, candId])];
    setLinkedCands(updated);
    await linkCandidatesToJob(job.id, [candId]);
    show("✅ تم ربط المرشح بالإعلان");
  };
  const unlinkCandidate = async (candId) => {
    const updated = linkedCands.filter(id=>id!==candId);
    setLinkedCands(updated);
    await unlinkCandidateFromJob(job.id, candId);
    show("✅ تم إلغاء الربط");
  };
  const { show, toastEl } = useToast();
  const today = new Date().toISOString().split("T")[0];
  const isFuture = job.openDate && job.openDate > today;

  const runAIMatch = async () => {
    setMatchLoad(true);
    try {
      const allPeople = [
        ...(candidates||[]).map(c=>({...c, _type:"مرشح"})),
        ...(employees||[]).map(e=>({...e, _type:"موظف"})),
      ];
      const jobDesc = `الوظيفة: ${job.title}\nالإدارة: ${job.department||""}\nالخبرة المطلوبة: ${job.minExperience||0}+ سنوات\nالمهارات: ${(job.requiredSkills||[]).join(", ")}\nالبرامج: ${(job.requiredSoftware||[]).join(", ")}\nأنواع المشاريع: ${(job.requiredProjectTypes||[]).join(", ")}\nالشهادات: ${(job.requiredCertifications||[]).join(", ")}`;
      const peopleDesc = allPeople.slice(0,30).map((p,i)=>`${i+1}. [${p._type}] ${p.fullName}: خبرة ${p.yearsExperience||0}سنة، مهارات: ${(p.skills||[...((p.biSkill||[]).map(t=>t.ar||t.en))]).slice(0,5).join(",")||"—"}, تخصص: ${(p.specializations||[])[0]||"—"}`).join("\n");
      const res = await fetch(API, {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:MODEL_GEMINI, max_tokens:600,
          system:"HR AI matcher. Reply ONLY with JSON array: [{\"rank\":1,\"name\":\"...\",\"type\":\"مرشح|موظف\",\"score\":85,\"reason\":\"...\",\"gaps\":\"...\"}]. Max 8 results.",
          messages:[{role:"user",content:`طابق هذه الوظيفة مع الأشخاص وصنّفهم:\n${jobDesc}\n\nالأشخاص:\n${peopleDesc}`}]
        })
      });
      const d = await res.json();
      const raw=(d?.content?.[0]?.text||"").replace(/```[\w]*/g,"").replace(/```/g,"").trim();
      const s=raw.indexOf("["),e=raw.lastIndexOf("]");
      if(s>-1&&e>-1){const arr=JSON.parse(raw.slice(s,e+1));setMatching(arr);}
    } catch(err){show("❌ "+err.message);}
    setMatchLoad(false);
  };

  return (
    <div className="fade">
      {toastEl}
      <div style={{ display:"flex", gap:9, marginBottom:18, alignItems:"center", flexWrap:"wrap" }}>
        <button onClick={onBack} className="btn btn-ghost btn-sm">← رجوع</button>
        <span style={{ color:"var(--gold)", fontWeight:700, fontSize:16 }}>{job.title}</span>
        <button onClick={()=>onEdit(job)} className="btn btn-ghost btn-sm">✏️ تعديل</button>
        
        <button onClick={()=>onDelete(job)} className="btn btn-danger btn-sm" style={{ marginRight:"auto" }}>🗑️</button>
      </div>

      {/* Job details */}
      <div className="card-g" style={{ marginBottom:14 }}>
        <div style={{ display:"flex", justifyContent:"space-between", flexWrap:"wrap", gap:10 }}>
          <div>
            <h2 style={{ fontSize:20, fontWeight:900, color:"var(--gold)" }}>{job.title}</h2>
            {job.department && <p style={{ color:"var(--text2)", fontSize:13, marginTop:3 }}>🏢 {job.department}</p>}
          </div>
          <span style={{ padding:"5px 14px", borderRadius:12, fontSize:13, fontWeight:700, background:job.status==="مفتوحة"?"rgba(34,197,94,.12)":"rgba(107,114,128,.12)", color:job.status==="مفتوحة"?"#4ade80":"#9ca3af" }}>
            {isFuture?"🔵 تفتح "+new Date(job.openDate).toLocaleDateString("ar-SA"):job.status==="مفتوحة"?"🟢 مفتوحة":"⚫ "+job.status}
          </span>
        </div>
        {job.description && <p style={{ color:"var(--text2)", fontSize:13, lineHeight:1.7, marginTop:12 }}>{job.description}</p>}
        {job.minExperience && <p style={{ color:"var(--text3)", fontSize:12, marginTop:8 }}>⏱ خبرة لا تقل عن {job.minExperience} سنوات</p>}
      </div>

      {/* Requirements */}
      {[
        {label:"🛠️ المهارات المطلوبة",items:job.requiredSkills},
        {label:"💻 البرامج المطلوبة",items:job.requiredSoftware},
        {label:"📋 أنواع المشاريع",items:job.requiredProjectTypes},
        {label:"🏅 الشهادات المطلوبة",items:job.requiredCertifications},
      ].filter(r=>(r.items||[]).length>0).map(r=>(
        <div key={r.label} className="card" style={{ marginBottom:10 }}>
          <div className="sec">{r.label}</div>
          <div style={S.flexWrap6}>
            {r.items.map((s,i)=><span key={i} className="tag">{s}</span>)}
          </div>
        </div>
      ))}

      {/* Suggested courses */}
      {(job.courses||[]).length > 0 && (
        <div className="card" style={{ marginBottom:14 }}>
          <div className="sec">📚 الدورات المقترحة للتأهيل</div>
          <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
            {job.courses.map((c,i)=>(
              <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 12px", background:"rgba(59,130,246,.06)", border:"1px solid rgba(59,130,246,.15)", borderRadius:8 }}>
                <span style={{ fontSize:13, color:"var(--text)" }}>{c.name}</span>
                {c.url && <a href={c.url} target="_blank" rel="noreferrer" className="btn btn-ghost btn-sm" style={{ fontSize:11, color:"#93c5fd" }}>🔗 رابط الدورة</a>}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* AI Matching */}
      <div className="card">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
          <div>
            <div className="sec" style={{ marginBottom:4 }}>🤖 مطابقة AI مع المرشحين والموظفين</div>
            <p style={S.txt3s12}>يحلل AI جميع ملفات المرشحين والموظفين ويرتّبهم حسب ملاءمتهم</p>
          </div>
          <button onClick={runAIMatch} disabled={matchLoad} className="btn btn-gold btn-sm" style={{ opacity:matchLoad?0.7:1 }}>
            {matchLoad?"⏳ جاري التحليل...":"🔍 تشغيل المطابقة"}
          </button>
        </div>

        {matching.length > 0 && (
          <div style={{ display:"flex", flexDirection:"column", gap:9 }}>
            {matching.map((m,i)=>(
              <div key={i} style={{ padding:"12px 14px", background: m.score>=75?"rgba(34,197,94,.07)":m.score>=50?"rgba(245,158,11,.07)":"rgba(107,114,128,.07)", border:"1px solid "+(m.score>=75?"rgba(34,197,94,.25)":m.score>=50?"rgba(245,158,11,.25)":"var(--b)"), borderRadius:10, cursor:"pointer" }}
                onClick={()=>{ const c=candidates.find(x=>x.fullName===m.name); if(c) setSelProfile(c); }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10 }}>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:5, flexWrap:"wrap" }}>
                      <span style={{ fontWeight:700 }}>{"#"+(i+1)+" "+m.name}</span>
                      <span style={{ fontSize:11, padding:"1px 8px", borderRadius:8, background:m.type==="موظف"?"rgba(139,92,246,.12)":"rgba(59,130,246,.12)", color:m.type==="موظف"?"#c4b5fd":"#93c5fd" }}>{m.type}</span>
                      <span style={{ fontSize:13, fontWeight:900, color:m.score>=81?"#4ade80":m.score>=61?"#fbbf24":"#9ca3af" }}>{m.score}%</span>
                      <button onClick={e=>{ e.stopPropagation(); const c=candidates.find(x=>x.fullName===m.name); if(c){ const cid=c.uid||c.idNumber||c.email; linkCandidate(cid); show("✅ تم ربط "+m.name+" بالإعلان"); } }} className="btn btn-gold btn-sm" style={{ fontSize:10, padding:"2px 8px" }}>🔗 ربط</button>
                    </div>
                    {m.reason && <p style={{ fontSize:12, color:"var(--text2)", marginBottom:3 }}>✅ {m.reason}</p>}
                    {m.gaps && <p style={{ fontSize:12, color:"#f87171" }}>⚠️ {m.gaps}</p>}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* ── Candidate Profile Panel ── */}
      {selProfile && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.85)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:700, maxHeight:"93vh", overflowY:"auto" }}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:16 }}>
              <p style={{ color:"var(--gold)", fontWeight:900, fontSize:18 }}>👤 {selProfile.fullName}</p>
              <button onClick={()=>setSelProfile(null)} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:22 }}>✕</button>
            </div>
            <div className="g2" style={{ marginBottom:14 }}>
              {[["📧 البريد",selProfile.email],["📱 الهاتف",selProfile.phone],["🎓 المؤهل",selProfile.education],["⏱️ الخبرة",(selProfile.yearsExperience||"")+" سنة"],["🏢 آخر شركة",selProfile.lastCompany],["💼 آخر وظيفة",selProfile.lastJob]].map(([l,v])=>v?(
                <div key={l} style={{ padding:"8px 12px", background:"rgba(255,255,255,.03)", borderRadius:8 }}>
                  <p style={{ fontSize:11, color:"var(--text3)", marginBottom:2 }}>{l}</p>
                  <p style={{ fontSize:13, color:"var(--text)", fontWeight:600 }}>{v}</p>
                </div>
              ):null)}
            </div>
            {selProfile.cvFullText && (
              <div style={{ padding:"12px 16px", background:"rgba(0,0,0,.2)", borderRadius:10, maxHeight:300, overflowY:"auto" }}>
                <p style={{ fontSize:11, color:"var(--gold)", fontWeight:700, marginBottom:8 }}>📄 نص السيرة الذاتية</p>
                <pre style={{ fontSize:12, color:"var(--text2)", lineHeight:1.8, whiteSpace:"pre-wrap", fontFamily:"inherit", margin:0 }}>{selProfile.cvFullText}</pre>
              </div>
            )}
            <div style={{ marginTop:14, display:"flex", gap:8 }}>
              <button onClick={async()=>{ await linkCandidatesToJob(job.id, [selProfile.uid||selProfile.idNumber||selProfile.email]); setLinkedCands(p=>[...new Set([...p,selProfile.uid||selProfile.idNumber||selProfile.email])]); show("✅ تم الربط"); setSelProfile(null); }} className="btn btn-gold">🔗 ربط بالإعلان</button>
              <button onClick={()=>setSelProfile(null)} className="btn btn-ghost btn-sm">إغلاق</button>
            </div>
          </div>
        </div>
      )}

      {/* ── Applicants (from portal) ── */}
      {(job.applicants||[]).length > 0 && (
        <div className="card" style={{ marginTop:16 }}>
          <p style={{ color:"#4ade80", fontWeight:700, fontSize:14, marginBottom:10 }}>👥 المتقدمون على هذا الإعلان ({job.applicants.length})</p>
          <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
            {job.applicants.map((app,i)=>{
              const c = (candidates||[]).find(x=>(x.uid||x.idNumber||x.email)===(app.candidateId||app.email));
              return (
                <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 12px", background:"rgba(74,222,128,.04)", border:"1px solid rgba(74,222,128,.15)", borderRadius:8 }}>
                  <div>
                    <span style={{ fontWeight:700, color:"var(--text)", fontSize:13 }}>{app.name || c?.fullName || "مرشح"}</span>
                    {c?.hrCode && <span style={{ fontSize:11, color:"var(--gold)", marginRight:8 }}> {c.hrCode}</span>}
                    <span style={{ fontSize:11, color:"var(--text3)", marginRight:8 }}>{app.appliedAt ? new Date(app.appliedAt).toLocaleDateString("ar-SA") : ""}</span>
                  </div>
                  {c && <button onClick={()=>setSelProfile(c)} className="btn btn-ghost btn-sm" style={{ fontSize:11 }}>عرض الملف</button>}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ── Linked Candidates ── */}
      {linkedCands.length > 0 && (
        <div className="card" style={{ marginTop:16 }}>
          <p style={{ color:"var(--gold)", fontWeight:700, fontSize:14, marginBottom:10 }}>🔗 المرشحون المرتبطون بهذا الإعلان ({linkedCands.length})</p>
          <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
            {linkedCands.map(cid=>{
              const c = candidates.find(x=>(x.uid||x.idNumber||x.email)===cid);
              if(!c) return null;
              return (
                <div key={cid} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 12px", background:"rgba(255,255,255,.03)", borderRadius:8 }}>
                  <div>
                    <span style={{ fontWeight:700, color:"var(--text)", fontSize:13 }}>{c.fullName}</span>
                    {c.hrCode && <span style={{ fontSize:11, color:"var(--gold)", marginRight:8 }}>{c.hrCode}</span>}
                    <span style={{ fontSize:11, color:"var(--text3)", marginRight:8 }}>{c.evaluation?.recommendation||"بدون مرحلة"}</span>
                  </div>
                  <div style={{ display:"flex", gap:6 }}>
                    <button onClick={()=>unlinkCandidate(cid)} className="btn btn-ghost btn-sm" style={{ color:"#f87171", fontSize:11 }}>❌ إلغاء</button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// ── نظام المهام المرنة (البارت تايم) ──────────────────────────────────────────
const PT_NOTICE = "⚠️ تنبيه مهم: لا يُعتمد أي مبلغ أو يُبدأ أي عمل في هذه المهام إلا بعد التكليف الرسمي المكتوب وتحديد قيمة العمل، وتوقيع الموارد البشرية والمحاسبة بالموافقة. يجب تسليم التكليف باليد أو إرساله رسمياً والحصول على رد كتابي موقّع بالموافقة.";

const PT_STATUS = {
  draft:        { label:"مسودة",              color:"#6b7280", icon:"📝" },
  open:         { label:"مفتوحة للتقديم",     color:"#e8eaf0", icon:"📢" },
  assigned:     { label:"تم اختيار المنفذ",   color:"#f59e0b", icon:"👤" },
  hr_approved:  { label:"تمت موافقة HR",       color:"#e8eaf0", icon:"✅" },
  acc_approved: { label:"تمت موافقة المحاسبة", color:"#e8eaf0", icon:"✅" },
  in_progress:  { label:"جارٍ التنفيذ",        color:"#10b981", icon:"⚙️" },
  done:         { label:"مكتملة",              color:"#4ade80", icon:"🏁" },
  cancelled:    { label:"ملغاة",               color:"#f87171", icon:"✕"  },
};
function PTPublicCard({ task, user, userType, onApply, applied }) {
  const st = PT_STATUS[task.status] || PT_STATUS.open;
  return (
    <div style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12, padding:"14px 18px", marginBottom:9 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10, flexWrap:"wrap" }}>
        <div style={{ flex:1 }}>
          <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:6, flexWrap:"wrap" }}>
            <span style={{ fontWeight:800, fontSize:15 }}>{task.title}</span>
            {applied && <span style={{ fontSize:11, padding:"2px 9px", borderRadius:10, background:"rgba(34,197,94,.15)", color:"#4ade80", fontWeight:700 }}>✓ تقدّمت</span>}
          </div>
          <div style={{ fontSize:12, color:"var(--text2)", display:"flex", gap:14, flexWrap:"wrap", marginBottom:8 }}>
            <span style={{ color:"var(--gold)", fontWeight:700 }}>💰 {(task.agreedAmount||0).toLocaleString()} ﷼</span>
            {task.duration && <span>⏱ {task.duration}</span>}
          </div>
          {task.description && <p style={{ fontSize:13, color:"var(--text2)", lineHeight:1.6 }}>{task.description}</p>}
          {task.skills && <p style={{ fontSize:12, color:"var(--text3)", marginTop:6 }}>🛠️ {task.skills}</p>}
          {/* Legal notice */}
          <div style={{ padding:"8px 12px", background:"rgba(239,68,68,.06)", border:"1px solid rgba(239,68,68,.15)", borderRadius:8, marginTop:10, fontSize:11, color:"#fca5a5", lineHeight:1.6 }}>
            {PT_NOTICE}
          </div>
        </div>
        <div style={{ flexShrink:0 }}>
          {!applied ? (
            <button onClick={onApply} className="btn btn-gold btn-sm">📝 تقدّم للمهمة</button>
          ) : (
            <span style={{ fontSize:13, color:"#4ade80" }}>✓ تقدّمت</span>
          )}
        </div>
      </div>
    </div>
  );
}

// ── Assessment Alerts for Dashboard ──────────────────────────────────────────
function AssessmentAlerts({ onGo }) {
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    getAllAssessments().then(all => {
      const now = new Date();
      const a = [];
      const pending   = all.filter(x => x.status === "pending");
      const overdue   = pending.filter(x => x.dueDate && new Date(x.dueDate) < now);
      const needScore = all.filter(x => x.status === "done" && x.finalScore === undefined);

      if (overdue.length > 0)
        a.push({ type:"overdue",   icon:"⏰", color:"#f87171", bg:"rgba(239,68,68,.08)", border:"rgba(239,68,68,.3)", text: overdue.length + " اختبار تجاوز الموعد النهائي ولم يُجرَ بعد" });
      if (pending.length - overdue.length > 0)
        a.push({ type:"pending",   icon:"📋", color:"#f59e0b", bg:"rgba(245,158,11,.08)", border:"rgba(245,158,11,.3)", text: (pending.length - overdue.length) + " اختبار معلق لم يُرسل للمرشح أو لم يُكتمل" });
      if (needScore.length > 0)
        a.push({ type:"needscore", icon:"✏️", color:"#a78bfa", bg:"rgba(167,139,250,.08)", border:"rgba(167,139,250,.3)", text: needScore.length + " اختبار مكتمل يحتاج تصحيح الأسئلة المكتوبة" });

      setAlerts(a);
    });
  }, []);

  if (alerts.length === 0) return null;

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:20 }}>
      {alerts.map(a => (
        <div key={a.type} onClick={onGo} style={{ display:"flex", alignItems:"center", gap:12, padding:"12px 16px", background:a.bg, border:"1px solid "+a.border, borderRadius:12, cursor:"pointer" }}
          onMouseEnter={e => e.currentTarget.style.opacity=".85"} onMouseLeave={e => e.currentTarget.style.opacity="1"}>
          <span style={{ fontSize:22 }}>{a.icon}</span>
          <p style={{ color:a.color, fontSize:14, fontWeight:700, flex:1 }}>{a.text}</p>
          <span style={{ color:a.color, fontSize:13, opacity:.7 }}>اضغط للعرض ←</span>
        </div>
      ))}
    </div>
  );
}

// ── Exam Portal ────────────────────────────────────────────────────────────────
function ExamLogin({ onLogin }) {
  const [ident, setIdent] = useState("");
  const [pass, setPass] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  const doLogin = async () => {
    if (!ident.trim() || !pass.trim()) { setErr("أدخل البريد وكلمة المرور"); return; }
    setLoading(true); setErr("");
    try {
      let user = ident.includes("@") ? await getUserByEmail(ident.trim()) : await getUserByUsername(ident.trim());
      if (!user) { setErr("الحساب غير موجود — تأكد من البريد الإلكتروني"); setLoading(false); return; }
      const hash = await hashPassword(pass);
      if (hash !== user.passwordHash) { setErr("كلمة المرور غير صحيحة"); setLoading(false); return; }
      onLogin(user);
    } catch(e) { setErr(e.message||"خطأ"); setLoading(false); }
  };
  return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"#0A0A0F", padding:20 }}>
      <div style={{ maxWidth:380, width:"100%", textAlign:"center" }}>
        <img src={HMA_LOGO_SM} alt="HMA" style={{ width:64, height:64, objectFit:"contain", marginBottom:16 }} />
        <h2 style={{ color:"#c9a84c", fontWeight:900, fontSize:22, marginBottom:8 }}>اختبار إلكتروني</h2>
        <p style={{ color:"#8b949e", fontSize:14, marginBottom:24, lineHeight:1.7 }}>يجب تسجيل الدخول أولاً لبدء الاختبار</p>
        <div style={{ background:"#13161A", border:"1px solid #2D323A", borderRadius:16, padding:24, textAlign:"right" }}>
          <div style={{ marginBottom:14 }}>
            <label style={{ fontSize:12, color:"#9CA3AF", display:"block", marginBottom:6 }}>البريد الإلكتروني</label>
            <input value={ident} onChange={e=>setIdent(e.target.value)} placeholder="email@example.com"
              style={{ width:"100%", padding:"12px 14px", borderRadius:10, border:"1px solid #374151", background:"#1E2229", color:"#EDEDED", fontSize:14, fontFamily:"inherit", direction:"ltr", textAlign:"left", boxSizing:"border-box" }}
              onKeyDown={e=>e.key==="Enter"&&doLogin()} />
          </div>
          <div style={{ marginBottom:14 }}>
            <label style={{ fontSize:12, color:"#9CA3AF", display:"block", marginBottom:6 }}>كلمة المرور</label>
            <input type="password" value={pass} onChange={e=>setPass(e.target.value)} placeholder="••••••"
              style={{ width:"100%", padding:"12px 14px", borderRadius:10, border:"1px solid #374151", background:"#1E2229", color:"#EDEDED", fontSize:14, fontFamily:"inherit", boxSizing:"border-box" }}
              onKeyDown={e=>e.key==="Enter"&&doLogin()} />
          </div>
          {err && <p style={{ color:"#f87171", fontSize:13, marginBottom:12, padding:"8px 12px", background:"rgba(239,68,68,.08)", borderRadius:8, border:"1px solid rgba(239,68,68,.2)" }}>{err}</p>}
          <button onClick={doLogin} disabled={loading}
            style={{ width:"100%", padding:"12px", borderRadius:10, border:"none", background:"#3B82F6", color:"#fff", fontSize:15, fontWeight:700, fontFamily:"inherit", cursor:"pointer", opacity:loading?.6:1 }}>
            {loading ? "⏳ جاري التحقق..." : "← دخول"}
          </button>
        </div>
      </div>
    </div>
  );
}

function ExamPortal({ token, onDone, currentUser }) {
  const [asmnt, setAsmnt] = useState(null);
  const [questions, setQuestions] = useState([]);
  const [status, setStatus] = useState("loading"); // loading | notfound | done | taking | forbidden
  const { confirm, dlg } = useConfirm();

  useEffect(() => {
    (async () => {
      const a = await db.get("asmnt:" + token);
      if (!a) { setStatus("notfound"); return; }
      // ── v37.42: حماية — الرابط يفتح فقط في حساب المرشح المحدد ──
      if (currentUser) {
        const cu = currentUser;
        const candId = a.candidateId || "";
        const cuIds = [cu.uid, cu.email, cu.idNumber, cu.linkedId, cu.username, cu.fullName].filter(Boolean).map(x=>String(x).trim().toLowerCase());
        const aIds = [candId, a.candidateName].filter(Boolean).map(x=>String(x).trim().toLowerCase());
        const isOwner = cuIds.some(id => aIds.includes(id)) || cu.role === "admin" || cu.role === "hr_manager";
        if (!isOwner) { setStatus("forbidden"); return; }
      }
      if (a.status === "done") { setAsmnt(a); setStatus("done"); return; }
      const idx = (await db.get("qn:idx")) || [];
      const all = await Promise.all(idx.map(id => db.get("qn:" + id)));
      const qs = (a.selectedQs || []).map(id => all.find(q => q && q.id === id)).filter(Boolean);
      setAsmnt(a); setQuestions(qs); setStatus("taking");
    })();
  }, [token]);

  // شريط الترجمة يظهر تلقائياً من الشريط العلوي الرئيسي (hma-translate-bar)

  if (status === "loading") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"var(--bg,#0d1117)" }}>
      <div style={{ textAlign:"center" }}>
        <div className="loader" style={{ width:48, height:48, margin:"0 auto 16px" }} />
        <p style={{ color:"var(--text2,#8b949e)" }}>جاري تحميل الاختبار...</p>
      </div>
    </div>
  );

  if (status === "notfound") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"var(--bg,#0d1117)", padding:20 }}>
      <div style={{ textAlign:"center", maxWidth:400 }}>
        <div style={{ fontSize:64, marginBottom:16 }}>❌</div>
        <h2 style={{ color:"#f87171", fontWeight:900, marginBottom:8 }}>رابط غير صالح</h2>
        <p style={{ color:"var(--text2,#8b949e)", marginBottom:24 }}>هذا الرابط غير موجود أو انتهت صلاحيته</p>
        <button onClick={onDone} className="btn btn-ghost">← العودة للرئيسية</button>
      </div>
    </div>
  );

  if (status === "forbidden") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"var(--bg,#0d1117)", padding:20 }}>
      <div style={{ textAlign:"center", maxWidth:400 }}>
        <div style={{ fontSize:64, marginBottom:16 }}>🔒</div>
        <h2 style={{ color:"#f59e0b", fontWeight:900, marginBottom:8 }}>غير مصرّح</h2>
        <p style={{ color:"var(--text2,#8b949e)", marginBottom:8 }}>هذا الاختبار مخصص لمرشح آخر</p>
        <p style={{ color:"var(--text3,#6b7280)", marginBottom:24, fontSize:13 }}>يجب فتح الرابط من حساب المرشح المحدد في الاختبار</p>
        <button onClick={onDone} className="btn btn-ghost">← العودة للرئيسية</button>
      </div>
    </div>
  );

  if (status === "done") return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"var(--bg,#0d1117)", padding:20 }}>
      <div style={{ textAlign:"center", maxWidth:420 }}>
        <img src={HMA_LOGO_SM} alt="HMA" style={{ width:48, height:48, objectFit:"contain", marginBottom:12 }} />
        <div style={{ fontSize:48, marginBottom:12 }}>✅</div>
        <h2 style={{ color:"#4ade80", fontWeight:900, marginBottom:8 }}>شكراً لإكمال الاختبار!</h2>
        <p style={{ color:"var(--text2,#8b949e)", marginBottom:6, fontSize:15 }}>{asmnt?.candidateName}،</p>
        <p style={{ color:"var(--text3,#6b7280)", marginBottom:8, lineHeight:1.7 }}>تم استلام إجاباتك وسيتم مراجعتها من قِبل الفريق.</p>
        <p style={{ color:"var(--text3,#6b7280)", marginBottom:20, fontSize:13 }}>📧 تم إرسال رسالة تأكيد إلى بريدك الإلكتروني</p>
        <button onClick={onDone} className="btn btn-gold" style={{ fontSize:14, padding:"11px 24px" }}>← الذهاب لحسابي</button>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg,#0d1117)", padding:"0 0 40px" }}>
      {dlg}
      <style>{`
        .exam-wrap { max-width:680px; margin:0 auto; padding:24px 16px; }
        .exam-header { background:linear-gradient(135deg,#1a2235,#0d1117); border-bottom:1px solid rgba(201,168,76,.2); padding:20px 24px; position:sticky; top:0; z-index:10; }
        .exam-q { background:rgba(255,255,255,.03); border:1px solid rgba(255,255,255,.08); border-radius:14px; padding:20px; margin-bottom:14px; transition:border-color .2s; }
        .exam-q.answered { border-color:rgba(34,197,94,.35); background:rgba(34,197,94,.03); }
        .exam-opt { display:flex; align-items:center; gap:12px; padding:11px 16px; border-radius:10px; cursor:pointer; border:1px solid rgba(255,255,255,.08); background:rgba(255,255,255,.02); margin-bottom:8px; transition:all .15s; }
        .exam-opt:hover { background:rgba(59,130,246,.08); border-color:rgba(59,130,246,.3); }
        .exam-opt.selected { background:rgba(59,130,246,.12); border-color:rgba(59,130,246,.5); }
        .exam-opt input[type=radio], .exam-opt input[type=checkbox] { width:18px; height:18px; flex-shrink:0; cursor:pointer; accent-color:#3b82f6; }
      `}</style>

      {/* Header */}
      <div className="exam-header">
        <div style={{ maxWidth:680, margin:"0 auto", display:"flex", justifyContent:"space-between", alignItems:"center", gap:12, flexWrap:"wrap" }}>
          <div>
            <h1 style={{ color:"var(--gold,#c9a84c)", fontWeight:900, fontSize:18, marginBottom:3 }}>{asmnt.title || "اختبار"}</h1>
            <p style={{ color:"var(--text2,#8b949e)", fontSize:13 }}>مرحباً {asmnt.candidateName} · {questions.length} سؤال</p>
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:8 }}>
            <ExamTimer asmnt={asmnt} />
          </div>
        </div>
      </div>

      <ExamTaker asmnt={asmnt} questions={questions} confirm={confirm} onDone={() => setStatus("done")} />
    </div>
  );
}

function ExamTimer({ asmnt }) {
  const [timeLeft, setTimeLeft] = useState(null);

  useEffect(() => {
    if (!asmnt.dueDate) return;
    const calc = () => {
      const diff = new Date(asmnt.dueDate) - Date.now();
      setTimeLeft(diff > 0 ? diff : 0);
    };
    calc();
    const t = setInterval(calc, 1000);
    return () => clearInterval(t);
  }, [asmnt.dueDate]);

  if (timeLeft === null) return null;
  const h = Math.floor(timeLeft / 3600000);
  const m = Math.floor((timeLeft % 3600000) / 60000);
  const s = Math.floor((timeLeft % 60000) / 1000);
  const isLow = timeLeft < 600000; // < 10 min
  return (
    <div style={{ padding:"6px 14px", borderRadius:10, background: isLow ? "rgba(239,68,68,.15)" : "rgba(59,130,246,.1)", border:"1px solid "+(isLow?"rgba(239,68,68,.4)":"rgba(59,130,246,.3)"), color:isLow?"#f87171":"#93c5fd", fontWeight:700, fontFamily:"monospace", fontSize:15 }}>
      ⏱ {String(h).padStart(2,"0")}:{String(m).padStart(2,"0")}:{String(s).padStart(2,"0")}
    </div>
  );
}

function ExamTaker({ asmnt, questions, confirm, onDone }) {
  const [answers, setAnswers] = useState({});
  const [saving, setSaving] = useState(false);
  const setAns = (qId, val) => setAnswers(p => ({ ...p, [qId]: val }));
  const answered = Object.keys(answers).filter(k => answers[k] !== undefined && answers[k] !== "").length;

  const submit = async () => {
    if (answered < questions.length) {
      const ok = await confirm("لم تُجب على " + (questions.length - answered) + " سؤال. هل تريد التسليم الآن؟");
      if (!ok) return;
    }
    setSaving(true);
    const scores = {};
    let autoScore = 0;
    questions.forEach(q => {
      if (q.type === "tf") { const ok = answers[q.id] === q.correctTf; scores[q.id] = ok ? q.points : 0; autoScore += scores[q.id]; }
      else if (q.type === "mcq") { const ok = answers[q.id] === q.correctIdx; scores[q.id] = ok ? q.points : 0; autoScore += scores[q.id]; }
    });
    await saveAssessment({ ...asmnt, answers, scores, autoScore, status:"done", submittedAt: new Date().toISOString() });
    setSaving(false);
    onDone();
  };

  return (
    <div className="exam-wrap">
      {/* Progress bar */}
      <div style={{ marginBottom:24, padding:"12px 16px", background:"rgba(255,255,255,.03)", borderRadius:12, border:"1px solid rgba(255,255,255,.08)" }}>
        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:8, fontSize:13 }}>
          <span style={{ color:"var(--text2,#8b949e)" }}>التقدم</span>
          <span style={{ color:"#4ade80", fontWeight:700 }}>{answered} / {questions.length}</span>
        </div>
        <div style={{ height:8, background:"rgba(255,255,255,.08)", borderRadius:4, overflow:"hidden" }}>
          <div style={{ height:"100%", width:(questions.length ? answered/questions.length*100 : 0)+"%", background:"linear-gradient(90deg,#3b82f6,#22c55e)", borderRadius:4, transition:"width .3s" }} />
        </div>
      </div>

      {asmnt.notes && (
        <div style={{ padding:"12px 16px", background:"rgba(201,168,76,.07)", border:"1px solid rgba(201,168,76,.2)", borderRadius:10, marginBottom:20, fontSize:13, color:"var(--text2,#8b949e)" }}>
          <strong style={{ color:"var(--gold,#c9a84c)" }}>تعليمات: </strong>{asmnt.notes}
        </div>
      )}

      {questions.map((q, idx) => {
        const isAns = answers[q.id] !== undefined && answers[q.id] !== "";
        return (
          <div key={q.id} className={"exam-q" + (isAns ? " answered" : "")}>
            <div style={{ display:"flex", gap:10, marginBottom:14, alignItems:"flex-start" }}>
              <span style={{ color:"var(--gold,#c9a84c)", fontWeight:900, fontSize:16, flexShrink:0 }}>{idx+1}.</span>
              <p style={{ fontSize:15, color:"#f0f6fc", lineHeight:1.7, flex:1 }}>{q.text}</p>
              <div style={{ display:"flex", gap:5, alignItems:"center", flexShrink:0 }}>
                <span style={{ fontSize:11, color:"var(--text3,#6b7280)", background:"rgba(255,255,255,.05)", padding:"2px 8px", borderRadius:8 }}>⭐{q.points}</span>
                {isAns && <span style={{ fontSize:16 }}>✅</span>}
              </div>
            </div>

            {q.type === "tf" && (
              <div style={S.flex10}>
                {[{v:true,l:"✓ صح"},{v:false,l:"✗ خطأ"}].map(opt => (
                  <label key={String(opt.v)} className={"exam-opt" + (answers[q.id]===opt.v ? " selected" : "")} style={{ flex:1, justifyContent:"center" }}>
                    <input type="radio" name={"tf-"+q.id} checked={answers[q.id]===opt.v} onChange={() => setAns(q.id, opt.v)} />
                    <span style={{ fontWeight:700, color:answers[q.id]===opt.v?"#93c5fd":"var(--text,#f0f6fc)" }}>{opt.l}</span>
                  </label>
                ))}
              </div>
            )}

            {q.type === "mcq" && (
              <div>
                {(q.options||[]).filter(o=>o.trim()).map((opt, i) => (
                  <label key={i} className={"exam-opt" + (answers[q.id]===i ? " selected" : "")}>
                    <input type="radio" name={"mcq-"+q.id} checked={answers[q.id]===i} onChange={() => setAns(q.id, i)} />
                    <span style={{ fontSize:14, color:answers[q.id]===i?"#93c5fd":"var(--text,#f0f6fc)" }}>{opt}</span>
                  </label>
                ))}
              </div>
            )}

            {q.type === "written" && (
              <textarea
                value={answers[q.id] || ""}
                onChange={e => setAns(q.id, e.target.value)}
                placeholder="اكتب إجابتك هنا..."
                style={{ width:"100%", minHeight:100, fontSize:14, lineHeight:1.7, marginTop:4 }}
              />
            )}
          </div>
        );
      })}

      <button onClick={submit} disabled={saving} className="btn btn-gold"
        style={{ width:"100%", padding:"14px", fontSize:16, marginTop:10, borderRadius:12 }}>
        {saving ? "⏳ جاري الإرسال..." : "✅ تسليم الاختبار (" + answered + "/" + questions.length + " مُجاب)"}
      </button>
    </div>
  );
}

// ── Excel Import ──────────────────────────────────────────────────────────────
function ExcelImport({ onImported, onClose, defaultType="candidate" }) {
  const [step, setStep] = useState("upload"); // upload | mapping | preview | done
  const [rows, setRows] = useState([]);
  const [headers, setHeaders] = useState([]);
  const [mapping, setMapping] = useState({});
  const [preview, setPreview] = useState([]);
  const [dupes, setDupes] = useState([]);
  const [importing, setImporting] = useState(false);
  const [result, setResult] = useState(null);
  const fileRef = useRef();

  const FIELDS = [
    { key:"fullName",       label:"الاسم الكامل *",      required:true  },
    { key:"email",          label:"البريد الإلكتروني",   required:false },
    { key:"phone",          label:"الجوال",               required:false },
    { key:"idNumber",       label:"رقم الهوية",           required:false },
    { key:"nationality",    label:"الجنسية",              required:false },
    { key:"city",           label:"المدينة",              required:false },
    { key:"yearsExperience",label:"سنوات الخبرة",         required:false },
    { key:"specialization", label:"التخصص",               required:false },
    { key:"education",      label:"المؤهل الدراسي",       required:false },
    { key:"lastJob",        label:"آخر مسمى وظيفي",       required:false },
    { key:"lastCompany",    label:"آخر جهة عمل",          required:false },
    { key:"expectedSalary", label:"الراتب المتوقع",       required:false },
    { key:"locationStatus", label:"داخل/خارج السعودية",   required:false },
    { key:"notes",          label:"ملاحظات",              required:false },
  ];

  const loadXLSX = () => new Promise((res, rej) => {
    if (window.XLSX) { res(window.XLSX); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
    s.onload = () => res(window.XLSX); s.onerror = rej;
    document.head.appendChild(s);
  });

  const downloadTemplate = async () => {
    const XLSX = await loadXLSX();
    const headers = FIELDS.map(f => f.label.replace(" *",""));
    const example = ["أحمد محمد العتيبي","ahmed@email.com","0501234567","1234567890","سعودي","الرياض","8","هندسة مدنية","بكالوريوس","مهندس مشاريع","شركة الإنشاءات","12000","داخل السعودية","مرشح موصى به"];
    const ws = XLSX.utils.aoa_to_sheet([headers, example]);
    ws['!cols'] = headers.map(() => ({ wch: 22 }));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "المرشحون");
    XLSX.writeFile(wb, "template_مرشحون.xlsx");
  };

  const handleFile = async (file) => {
    if (!file) return;
    const ext = file.name.split('.').pop().toLowerCase();
    if (!['xlsx','xls','csv'].includes(ext)) {
      alert('يرجى رفع ملف Excel (xlsx/xls) أو CSV فقط');
      return;
    }
    setStep("mapping");
    setMapping({}); setHeaders([]); setRows([]);
    try {
      const XLSX = await loadXLSX();
      const buf = await new Promise((res, rej) => {
        const r = new FileReader();
        r.onload = e => res(e.target.result);
        r.onerror = rej;
        r.readAsArrayBuffer(file);
      });
      const wb = XLSX.read(new Uint8Array(buf), { type:"array" });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const data = XLSX.utils.sheet_to_json(ws, { defval:"" });
      if (!data.length) { alert('الملف فارغ أو لا يحتوي على بيانات'); setStep("upload"); return; }
      const hdrs = Object.keys(data[0]);
      const sampleRow = data[0];
      setHeaders(hdrs);
      setRows(data);

      const systemFields = FIELDS.map(f => f.key + " (" + f.label.replace(" *","") + ")").join(", ");
      const headersWithSample = hdrs.map(h => `"${h}": "${String(sampleRow[h]||"").substring(0,30)}"`).join(", ");

      const res = await fetch(API, {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({
          model: MODEL, max_tokens: 600,
          system: "You are a data mapper. Return ONLY a valid JSON object. No markdown. No explanation.",
          messages: [{
            role:"user",
            content: `Map these Excel columns to system fields.\n\nExcel columns with sample values: {${headersWithSample}}\n\nSystem fields: ${systemFields}\n\nReturn JSON like: {"fullName":"ColumnName","email":"ColName",...} — only include fields you are confident about. Use exact Excel column names as values.`
          }]
        })
      });
      const d = await res.json();
      const raw = (d?.content?.[0]?.text||"").replace(/```[\w]*/g,"").replace(/```/g,"").trim();
      const s = raw.indexOf("{"), e = raw.lastIndexOf("}");
      let aiMap = {};
      if (s !== -1 && e !== -1) {
        try { aiMap = JSON.parse(raw.slice(s, e+1)); } catch {}
      }
      const validMap = {};
      FIELDS.forEach(f => {
        if (aiMap[f.key] && hdrs.includes(aiMap[f.key])) {
          validMap[f.key] = aiMap[f.key];
        }
      });
      setMapping(validMap);
    } catch(err) {
      alert('خطأ في قراءة الملف: ' + (err.message||'تأكد أن الملف سليم'));
      setStep("upload");
    }
  };

  const buildPreview = async () => {
    const existing = defaultType === "employee" ? await getAllEmployees() : await getAllCandidates();
    const existSet = new Set(existing.map(c => (c.email||"")+"__"+(c.idNumber||"")));
    const mapped = rows.map(row => {
      const c = {};
      FIELDS.forEach(f => { if (mapping[f.key]) c[f.key] = String(row[mapping[f.key]] || "").trim(); });
      const uid = (c.email||"")+"__"+(c.idNumber||"");
      c._isDup = existSet.has(uid) && (c.email||c.idNumber);
      return c;
    }).filter(c => c.fullName);
    const dups = mapped.filter(c => c._isDup);
    setPreview(mapped);
    setDupes(dups);
    setStep("preview");
  };

  const doImport = async (skipDupes) => {
    setImporting(true);
    let added = 0, skipped = 0;
    const isEmp = defaultType === "employee";
    for (const c of preview) {
      if (c._isDup && skipDupes) { skipped++; continue; }
      const rec = { ...c, specializations: c.specialization ? [c.specialization] : [], createdAt: new Date().toISOString() };
      delete rec._isDup; delete rec.specialization;
      if (isEmp) {
        rec.isEmployee = true;
        rec.employmentType = rec.employmentType || "موظف دوام كامل";
        rec.joinDate = rec.joinDate || new Date().toISOString().split("T")[0];
        await saveEmployee(rec);
      } else {
        await saveCandidate(rec);
      }
      added++;
    }
    await addAudit("excel_import", "استيراد " + added + " " + (isEmp?"موظف":"مرشح") + " من Excel");
    setResult({ added, skipped });
    setStep("done");
    setImporting(false);
    onImported();
  };

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid rgba(34,197,94,.3)", borderRadius:18, padding:26, width:"100%", maxWidth:640, maxHeight:"92vh", overflowY:"auto" }}>

        {/* Header */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{ fontSize:26 }}>📊</span>
            <div>
              <h3 style={{ color:"#4ade80", fontWeight:900, fontSize:17 }}>استيراد من Excel</h3>
              <p style={{ color:"var(--text2,#8b949e)", fontSize:12 }}>
                {step==="upload"?"رفع الملف":step==="mapping"?"تحديد الأعمدة":step==="preview"?"مراجعة البيانات":"تم الاستيراد"}
              </p>
            </div>
          </div>
          <button onClick={onClose} style={{ background:"#ff5f57", border:"none", borderRadius:"50%", width:13, height:13, cursor:"pointer", flexShrink:0, padding:0, boxShadow:"0 0 0 1px rgba(0,0,0,.2)" }} title="إغلاق"/>
        </div>

        {/* Steps indicator */}
        <div style={{ display:"flex", gap:0, marginBottom:22 }}>
          {["رفع الملف","تحليل AI","مراجعة","اكتمل"].map((s,i) => {
            const steps = ["upload","mapping","preview","done"];
            const active = steps.indexOf(step);
            const done = i < active; const cur = i === active;
            return (
              <div key={s} style={{ flex:1, textAlign:"center" }}>
                <div style={{ height:4, background: done||cur?"#4ade80":"rgba(255,255,255,.1)", marginBottom:5, borderRadius:2 }} />
                <span style={{ fontSize:11, color: cur?"#4ade80":done?"rgba(74,222,128,.6)":"var(--text3,#6b7280)", fontWeight:cur?700:400 }}>{s}</span>
              </div>
            );
          })}
        </div>

        {/* STEP 1: Upload */}
        {step === "upload" && (
          <div>
            <div
              onDragOver={e=>{e.preventDefault();e.currentTarget.style.borderColor="var(--gold)";}}
              onDragLeave={e=>{e.currentTarget.style.borderColor="rgba(34,197,94,.3)";}}
              onDrop={e=>{e.preventDefault();e.currentTarget.style.borderColor="rgba(34,197,94,.3)";const f=e.dataTransfer.files[0];if(f)handleFile(f);}}
              style={{ padding:28, background:"rgba(34,197,94,.05)", border:"2px dashed rgba(34,197,94,.3)", borderRadius:12, textAlign:"center", marginBottom:16, transition:"border-color .2s" }}>
              <p style={{ fontSize:36, marginBottom:8 }}>📊</p>
              <p style={{ color:"var(--text)", fontWeight:700, marginBottom:4 }}>اسحب ملف Excel هنا أو اضغط للاختيار</p>
              <p style={{ color:"var(--text3)", fontSize:12, marginBottom:16 }}>XLSX / XLS / CSV مدعومة</p>
              <input ref={fileRef} type="file" accept=".xlsx,.xls,.csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,text/csv" style={{ display:"none" }} onChange={e => e.target.files[0] && handleFile(e.target.files[0])} />
              <button onClick={() => fileRef.current?.click()} className="btn btn-gold">📂 اختر ملف Excel</button>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:8, padding:"12px 16px", background:"rgba(59,130,246,.07)", border:"1px solid rgba(59,130,246,.2)", borderRadius:10 }}>
              <span style={{ fontSize:18 }}>💡</span>
              <div style={{ flex:1 }}>
                <p style={{ color:"#93c5fd", fontSize:13, fontWeight:700 }}>تحتاج قالباً جاهزاً؟</p>
                <p style={{ color:"var(--text3,#6b7280)", fontSize:12 }}>حمّل القالب وأضف بياناتك ثم ارفعه</p>
              </div>
              <button onClick={downloadTemplate} className="btn btn-ghost btn-sm" style={{ border:"1px solid rgba(59,130,246,.3)", color:"#93c5fd", flexShrink:0 }}>⬇️ تحميل القالب</button>
            </div>
          </div>
        )}

        {/* STEP 2: Column Mapping (AI result) */}
        {step === "mapping" && (
          <div>
            {headers.length === 0 ? (
              <div style={{ textAlign:"center", padding:"32px 0" }}>
                <div className="loader" style={{ width:44, height:44, margin:"0 auto 16px" }} />
                <p style={{ color:"#c4b5fd", fontWeight:700, fontSize:15 }}>🤖 الذكاء الاصطناعي يحلل الأعمدة...</p>
                <p style={{ color:"var(--text3,#6b7280)", fontSize:12, marginTop:6 }}>يقرأ أسماء الأعمدة ويطابقها مع حقول النظام</p>
              </div>
            ) : (
              <div>
                {/* AI badge */}
                <div style={{ display:"flex", alignItems:"center", gap:8, padding:"9px 14px", background:"rgba(167,139,250,.08)", border:"1px solid rgba(167,139,250,.2)", borderRadius:10, marginBottom:16 }}>
                  <span style={{ fontSize:18 }}>🤖</span>
                  <div>
                    <p style={{ color:"#c4b5fd", fontSize:13, fontWeight:700 }}>تم التحليل بالذكاء الاصطناعي</p>
                    <p style={{ color:"var(--text3,#6b7280)", fontSize:12 }}>{"قرأ " + rows.length + " صف و " + headers.length + " عمود — راجع المطابقة وعدّل إن احتجت"}</p>
                  </div>
                  <span style={{ marginRight:"auto", color:"#4ade80", fontSize:13, fontWeight:700 }}>{Object.keys(mapping).length + " عمود مُطابق"}</span>
                </div>

                <div style={{ display:"flex", flexDirection:"column", gap:7, marginBottom:18, maxHeight:360, overflowY:"auto" }}>
                  {FIELDS.map(f => {
                    const mapped = !!mapping[f.key];
                    return (
                      <div key={f.key} style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, alignItems:"center", padding:"7px 10px", borderRadius:8, background: mapped?"rgba(34,197,94,.05)":"rgba(255,255,255,.02)", border:"1px solid "+(mapped?"rgba(34,197,94,.2)":"rgba(255,255,255,.06)") }}>
                        <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                          <span style={{ fontSize:14 }}>{mapped?"✅":"⚪"}</span>
                          <span style={{ fontSize:13, color: f.required?"var(--gold,#c9a84c)":"var(--text,#f0f6fc)", fontWeight: f.required?700:400 }}>{f.label}</span>
                        </div>
                        <select value={mapping[f.key]||""} onChange={e => setMapping(p=>({...p,[f.key]:e.target.value||undefined}))}
                          style={{ fontSize:12, background: mapped?"rgba(34,197,94,.08)":"" }}>
                          <option value="">-- تجاهل --</option>
                          {headers.map(h => <option key={h} value={h}>{h}</option>)}
                        </select>
                      </div>
                    );
                  })}
                </div>
                <div style={S.flex10}>
                  <button onClick={buildPreview} disabled={!mapping.fullName} className="btn btn-gold" style={{ flex:1, opacity:mapping.fullName?1:0.4 }}>
                    {"التالي: مراجعة " + rows.length + " صف →"}
                  </button>
                  <button onClick={() => setStep("upload")} className="btn btn-ghost">رجوع</button>
                </div>
              </div>
            )}
          </div>
        )}

        {/* STEP 3: Preview */}
        {step === "preview" && (
          <div>
            <div style={{ display:"flex", gap:10, marginBottom:14, flexWrap:"wrap" }}>
              <div style={{ padding:"8px 16px", background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.3)", borderRadius:9, fontSize:13, color:"#4ade80", fontWeight:700 }}>{preview.filter(c=>!c._isDup).length + " مرشح جديد"}</div>
              {dupes.length > 0 && <div style={{ padding:"8px 16px", background:"rgba(245,158,11,.1)", border:"1px solid rgba(245,158,11,.3)", borderRadius:9, fontSize:13, color:"#fbbf24", fontWeight:700 }}>{dupes.length + " مكرر"}</div>}
            </div>

            <div style={{ maxHeight:280, overflowY:"auto", marginBottom:16 }}>
              <table style={{ fontSize:12 }}>
                <thead><tr><th></th><th>الاسم</th><th>البريد</th><th>التخصص</th><th>الخبرة</th></tr></thead>
                <tbody>
                  {preview.map((c,i) => (
                    <tr key={i} style={{ background: c._isDup?"rgba(245,158,11,.07)":"" }}>
                      <td>{c._isDup ? <span style={{ color:"#fbbf24", fontSize:11 }}>⚠️ مكرر</span> : <span style={{ color:"#4ade80", fontSize:11 }}>✓</span>}</td>
                      <td style={{ fontWeight:700 }}>{c.fullName}</td>
                      <td style={{ color:"var(--text3,#6b7280)" }}>{c.email||"—"}</td>
                      <td>{c.specialization||"—"}</td>
                      <td>{c.yearsExperience ? c.yearsExperience+" سنة":""}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div style={{ display:"flex", gap:9, flexWrap:"wrap" }}>
              <button onClick={() => doImport(true)} disabled={importing} className="btn btn-gold" style={{ flex:1 }}>
                {importing?"⏳ جاري الاستيراد...":"✅ استيراد الجديد فقط (" + preview.filter(c=>!c._isDup).length + ")"}
              </button>
              {dupes.length > 0 && (
                <button onClick={() => doImport(false)} disabled={importing} className="btn btn-ghost" style={{ flex:1 }}>
                  استيراد الكل مع المكررات
                </button>
              )}
            </div>
            <button onClick={() => setStep("mapping")} className="btn btn-ghost btn-sm" style={{ marginTop:8, width:"100%" }}>← رجوع</button>
          </div>
        )}

        {/* STEP 4: Done */}
        {step === "done" && result && (
          <div style={{ textAlign:"center", padding:"20px 0" }}>
            <div style={{ fontSize:56, marginBottom:12 }}>🎉</div>
            <h3 style={{ color:"#4ade80", fontWeight:900, fontSize:22, marginBottom:8 }}>تم الاستيراد بنجاح</h3>
            <div style={{ display:"flex", gap:12, justifyContent:"center", marginBottom:24 }}>
              <div style={{ padding:"12px 20px", background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.3)", borderRadius:10 }}>
                <div style={{ fontSize:28, fontWeight:900, color:"#4ade80" }}>{result.added}</div>
                <div style={{ fontSize:12, color:"var(--text3,#6b7280)" }}>مرشح أُضيف</div>
              </div>
              {result.skipped > 0 && (
                <div style={{ padding:"12px 20px", background:"rgba(245,158,11,.1)", border:"1px solid rgba(245,158,11,.3)", borderRadius:10 }}>
                  <div style={{ fontSize:28, fontWeight:900, color:"#fbbf24" }}>{result.skipped}</div>
                  <div style={{ fontSize:12, color:"var(--text3,#6b7280)" }}>مكرر تم تجاهله</div>
                </div>
              )}
            </div>
            <button onClick={onClose} className="btn btn-gold" style={{ minWidth:160 }}>إغلاق</button>
          </div>
        )}

      </div>
    </div>
  );
}

function JobCard({ job, today, applied, onView, onApply }) {
  const isFuture = job.openDate && job.openDate > today;
  const daysLeft = isFuture ? Math.ceil((new Date(job.openDate) - new Date()) / 86400000) : null;
  return (
    <div style={{ background:"var(--glass)", border:"1px solid "+(isFuture?"rgba(59,130,246,.2)":"rgba(34,197,94,.2)"), borderRadius:12, padding:"14px 18px" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10, flexWrap:"wrap" }}>
        <div style={{ flex:1 }}>
          <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:6, flexWrap:"wrap" }}>
            <span style={{ fontWeight:800, fontSize:16, color:"var(--text)" }}>{job.title}</span>
            {applied && <span style={{ fontSize:11, padding:"2px 9px", borderRadius:10, background:"rgba(34,197,94,.15)", color:"#4ade80", border:"1px solid rgba(34,197,94,.3)", fontWeight:700 }}>✓ تقدّمت</span>}
          </div>
          <div style={{ fontSize:12, color:"var(--text2)", display:"flex", gap:12, flexWrap:"wrap", marginBottom:8 }}>
            {job.department && <span>🏢 {job.department}</span>}
            {job.minExperience && <span>⏱ {job.minExperience}+ سنوات</span>}
            {isFuture && <span style={{ color:"#93c5fd" }}>{"📅 يفتح خلال "+daysLeft+" يوم"}</span>}
          </div>
          {(job.requiredSkills||[]).length > 0 && (
            <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
              {(job.requiredSkills||[]).slice(0,4).map((s,i)=><span key={i} style={{ fontSize:11, padding:"2px 9px", borderRadius:8, background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.1)", color:"var(--text2)" }}>{s}</span>)}
              {(job.requiredSkills||[]).length>4 && <span style={S.txt3s11}>+{(job.requiredSkills||[]).length-4}</span>}
            </div>
          )}
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:7, flexShrink:0 }}>
          <button onClick={onView} className="btn btn-ghost btn-sm">عرض التفاصيل</button>
          {!isFuture && onApply && !applied && (
            <button onClick={onApply} className="btn btn-gold btn-sm">📝 تقدّم الآن</button>
          )}
        </div>
      </div>
    </div>
  );
}

function JobPublicDetail({ job, today, applied, onApply, candidateData }) {
  const isFuture = job.openDate && job.openDate > today;
  const daysLeft = isFuture ? Math.ceil((new Date(job.openDate) - new Date()) / 86400000) : null;

  // Gap analysis
  const gapAnalysis = candidateData ? (() => {
    const candSkills = [...(candidateData.skills||[]), ...(candidateData.software||[])].map(s=>s.toLowerCase());
    const candCerts = (candidateData.certifications||[]).map(c=>c.toLowerCase());
    const reqSkills = job.requiredSkills||[];
    const reqCerts = job.requiredCertifications||[];
    const hasSkills = reqSkills.filter(s=>candSkills.some(cs=>cs.includes(s.toLowerCase())||s.toLowerCase().includes(cs)));
    const missingSkills = reqSkills.filter(s=>!hasSkills.includes(s));
    const hasCerts = reqCerts.filter(c=>candCerts.some(cc=>cc.includes(c.toLowerCase())||c.toLowerCase().includes(cc)));
    const missingCerts = reqCerts.filter(c=>!hasCerts.includes(c));
    const expOk = !job.minExperience || (candidateData.yearsExperience||0) >= Number(job.minExperience);
    return { hasSkills, missingSkills, hasCerts, missingCerts, expOk };
  })() : null;

  return (
    <div>
      <div className="card-g" style={{ marginBottom:14 }}>
        <div style={{ display:"flex", justifyContent:"space-between", flexWrap:"wrap", gap:10 }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:8 }}>
              <h2 style={{ fontSize:22, fontWeight:900, color:"var(--gold)", margin:0 }}>{job.title}</h2>
              <button onClick={()=>{
                const url = window.location.origin + "?job=" + job.id;
                const shareText = "📢 اطّلع على هذا الإعلان الوظيفي\n\n💼 " + job.title + (job.department ? "\n🏢 " + job.department : "") + (job.city ? "\n📍 " + job.city : "") + "\n\nنظام كوادر HMA – بوابة التوظيف والتدريب لمكتب هاني محمد عسيري للاستشارات الهندسية\n🔗 " + url;
                if(navigator.share){ navigator.share({ title:"📢 إعلان وظيفي: " + job.title, text: shareText, url }); }
                else { navigator.clipboard.writeText(shareText).then(()=>alert("تم نسخ رابط الإعلان")); }
              }} style={{ background:"none", border:"none", cursor:"pointer", fontSize:18, color:"#93c5fd", padding:2, flexShrink:0 }} title="مشاركة">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>
              </button>
            </div>
            {job.city && <p style={{ color:"#60a5fa", fontSize:13, marginTop:5, fontWeight:700 }}>{"📍 مكان العمل: " + job.city}</p>}
            {job.department && <p style={{ color:"var(--text2)", fontSize:13, marginTop:3 }}>🏢 {job.department}</p>}
            {job.minExperience && <p style={{ color:"var(--text3)", fontSize:12, marginTop:3 }}>⏱ خبرة لا تقل عن {job.minExperience} سنوات</p>}
          </div>
          {isFuture ? (
            <div style={{ padding:"12px 18px", background:"rgba(59,130,246,.1)", border:"1px solid rgba(59,130,246,.3)", borderRadius:12, textAlign:"center" }}>
              <div style={{ fontSize:22, fontWeight:900, color:"#93c5fd" }}>{daysLeft}</div>
              <div style={{ fontSize:11, color:"var(--text2)" }}>يوم حتى الفتح</div>
            </div>
          ) : applied ? (
            <div style={{ padding:"12px 18px", background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.3)", borderRadius:12, textAlign:"center" }}>
              <div style={{ fontSize:22 }}>✅</div>
              <div style={{ fontSize:12, color:"#4ade80", fontWeight:700 }}>تقدّمت على هذه الوظيفة</div>
            </div>
          ) : (
            <button onClick={onApply} className="btn btn-gold" style={{ padding:"12px 24px", fontSize:15, alignSelf:"flex-start" }}>📝 تقدّم الآن</button>
          )}
          {/* Gap Analysis */}
          {gapAnalysis && (gapAnalysis.missingSkills.length > 0 || gapAnalysis.missingCerts.length > 0 || !gapAnalysis.expOk) && (
            <div style={{ padding:"14px 16px", background:"rgba(245,158,11,.06)", border:"1px solid rgba(245,158,11,.3)", borderRadius:12, marginTop:12 }}>
              <p style={{ color:"#f59e0b", fontWeight:700, fontSize:13, marginBottom:10 }}>💡 ما يمكنك تطويره لتعزيز فرصتك</p>
              {!gapAnalysis.expOk && <p style={{ fontSize:12, color:"var(--text2)", marginBottom:6 }}>⏱️ الخبرة المطلوبة: {job.minExperience} سنوات</p>}
              {gapAnalysis.missingSkills.length > 0 && (
                <div style={{ marginBottom:8 }}>
                  <p style={{ fontSize:12, color:"#f87171", fontWeight:700, marginBottom:4 }}>❌ مهارات ناقصة:</p>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
                    {gapAnalysis.missingSkills.map(s=><span key={s} style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:"rgba(239,68,68,.1)", border:"1px solid rgba(239,68,68,.3)", color:"#f87171" }}>{s}</span>)}
                  </div>
                </div>
              )}
              {gapAnalysis.missingCerts.length > 0 && (
                <div>
                  <p style={{ fontSize:12, color:"#fbbf24", fontWeight:700, marginBottom:4 }}>📜 شهادات مطلوبة:</p>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
                    {gapAnalysis.missingCerts.map(c=><span key={c} style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:"rgba(245,158,11,.1)", border:"1px solid rgba(245,158,11,.3)", color:"#fbbf24" }}>{c}</span>)}
                  </div>
                </div>
              )}
              {gapAnalysis.hasSkills.length > 0 && (
                <div style={{ marginTop:8 }}>
                  <p style={{ fontSize:12, color:"#4ade80", fontWeight:700, marginBottom:4 }}>✅ مهاراتك المتطابقة:</p>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
                    {gapAnalysis.hasSkills.map(s=><span key={s} style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:"rgba(34,197,94,.1)", border:"1px solid rgba(34,197,94,.3)", color:"#4ade80" }}>{s}</span>)}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Description */}
      {job.description && (
        <div className="card" style={{ marginBottom:12 }}>
          <div className="sec">📋 وصف الوظيفة</div>
          <p style={{ fontSize:14, color:"var(--text2)", lineHeight:1.8 }}>{job.description}</p>
        </div>
      )}

      {/* Requirements */}
      {[
        {label:"🛠️ المهارات المطلوبة", items:job.requiredSkills},
        {label:"💻 البرامج المطلوبة", items:job.requiredSoftware},
        {label:"📋 أنواع المشاريع", items:job.requiredProjectTypes},
        {label:"🏅 الشهادات المطلوبة", items:job.requiredCertifications},
      ].filter(r=>(r.items||[]).length>0).map(r=>(
        <div key={r.label} className="card" style={{ marginBottom:10 }}>
          <div className="sec">{r.label}</div>
          <div style={S.flexWrap6}>
            {r.items.map((s,i)=><span key={i} className="tag">{s}</span>)}
          </div>
        </div>
      ))}

      {/* Suggested courses */}
      {(job.courses||[]).length > 0 && (
        <div className="card" style={{ marginBottom:12 }}>
          <div className="sec">📚 دورات مقترحة للتأهيل</div>
          <p style={{ color:"var(--text3)", fontSize:12, marginBottom:10 }}>هذه الدورات ستساعدك على التأهل لهذه الوظيفة</p>
          <div style={S.flexCol8}>
            {job.courses.map((c,i)=>(
              <div key={i} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 14px", background:"rgba(59,130,246,.06)", border:"1px solid rgba(59,130,246,.15)", borderRadius:9 }}>
                <div>
                  <p style={{ fontSize:14, fontWeight:700, color:"var(--text)" }}>{c.name}</p>
                  {c.provider && <p style={S.txt3s11}>{c.provider}</p>}
                </div>
                {c.url && (
                  <a href={c.url} target="_blank" rel="noreferrer" className="btn btn-ghost btn-sm" style={{ color:"#93c5fd", border:"1px solid rgba(59,130,246,.3)", flexShrink:0 }}>
                    🔗 ابدأ الدورة
                  </a>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Apply button at bottom */}
      {!isFuture && !applied && (
        <button onClick={onApply} className="btn btn-gold" style={{ width:"100%", padding:"13px", fontSize:16, marginTop:8 }}>
          📝 تقدّم على هذه الوظيفة
        </button>
      )}
    </div>
  );
}

