function JobsPortal({ user, userType, onBack, initLang="ar", onLangChange }) {
  const [lang, setLang] = useState(initLang || "ar");
  const changeLang = (l) => { setLang(l); if(onLangChange) onLangChange(l); };
  const t = PORTAL_I18N[lang] || PORTAL_I18N.ar;
  const [tab, setTab] = useState("jobs");
  const [myNotifs, setMyNotifs] = useState([]);
  const [offerResponse, setOfferResponse] = useState({});
  const { show: showMsg, toastEl } = useToast();
  const myEmpId2 = user?.idNumber || user?.email || "";

  useEffect(()=>{ getNotifications(myEmpId2).then(setMyNotifs); },[]);

  return (
    <div className="fade" dir={lang==="en"?"ltr":"rtl"} style={{ maxWidth:740, margin:"0 auto", padding:"22px 16px", fontFamily:"inherit" }}>
      {toastEl}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18, flexWrap:"wrap", gap:10 }}>
        <div>
          <h2 style={{ color:"var(--accent)", fontWeight:900, fontSize:22 }}>{t.portal_title}</h2>
          <p style={{ color:"var(--text2)", fontSize:13, marginTop:3 }}>{t.welcome}، {user.fullName || user.email}</p>
        </div>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <button onClick={onBack} className="btn btn-ghost btn-sm desktop-only">{t.back}</button>
        </div>
      </div>

      {/* Mobile footer for jobs page */}
      <div className="mobile-footer-bar" style={{ justifyContent:"space-around", padding:"6px 8px", gap:4 }}>
        <button onClick={onBack} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid var(--b)", background:"transparent", color:"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>
          <span style={{ fontSize:20 }}>🏠</span>
          <span style={{ fontSize:9, fontWeight:700 }}>رجوع</span>
        </button>
        <button onClick={()=>setTab("jobs")} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid "+(tab==="jobs"?"rgba(34,197,94,.4)":"var(--b)"), background:tab==="jobs"?"rgba(34,197,94,.08)":"transparent", color:tab==="jobs"?"#4ade80":"var(--text3)", cursor:"pointer", fontFamily:"inherit" }}>
          <span style={{ fontSize:20 }}>💼</span>
          <span style={{ fontSize:9, fontWeight:700 }}>وظائف</span>
        </button>
        <button onClick={()=>setTab("notifs")} style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", gap:2, padding:"6px 4px", borderRadius:10, border:"1px solid "+(tab==="notifs"?"rgba(34,197,94,.4)":"var(--b)"), background:tab==="notifs"?"rgba(34,197,94,.08)":"transparent", color:tab==="notifs"?"#4ade80":"var(--text3)", cursor:"pointer", fontFamily:"inherit", position:"relative" }}>
          <span style={{ fontSize:20 }}>🔔</span>
          <span style={{ fontSize:9, fontWeight:700 }}>إشعارات</span>
          {myNotifs.filter(n=>!n.read).length>0 && <span style={{ position:"absolute", top:4, left:"50%", marginLeft:6, background:"#ef4444", color:"#fff", borderRadius:"50%", width:16, height:16, display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, fontWeight:900 }}>{myNotifs.filter(n=>!n.read).length}</span>}
        </button>
      </div>

      <div style={{ display:"flex", gap:8, marginBottom:18 }}>
        <button onClick={()=>setTab("jobs")} className={"tab-btn "+(tab==="jobs"?"tab-on":"tab-off")}>{t.jobs_tab}</button>
        {(user?.email || user?.idNumber) && (
          <button onClick={()=>setTab("notifs")} className={"tab-btn "+(tab==="notifs"?"tab-on":"tab-off")}>
            {t.notifs_tab} {myNotifs.filter(n=>!n.read).length>0?"("+myNotifs.filter(n=>!n.read).length+")":""}
          </button>
        )}
      </div>

      {tab === "jobs" && <JobsListPublic user={user} userType={userType} lang={lang} />}

      {tab === "notifs" && (
        <div>
          <p style={{ color:"var(--accent)", fontWeight:700, fontSize:16, marginBottom:14 }}>🔔 {t.notifs_tab}</p>
          {myNotifs.length === 0
            ? <div className="card" style={{ textAlign:"center", padding:32 }}>
                <p style={{ fontSize:32 }}>🔔</p>
                <p style={{ color:"var(--text3)" }}>{t.no_notifs}</p>
              </div>
            : <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                {[...myNotifs].sort((a,b)=>b.createdAt>a.createdAt?1:-1).map(n=>(
                  <div key={n.id} onClick={()=>markNotifRead(n.id).then(()=>setMyNotifs(p=>p.map(x=>x.id===n.id?{...x,read:true}:x)))}
                    style={{ padding:"12px 16px", background:n.read?"var(--glass)":"rgba(0,113,227,.06)", border:"1px solid "+(n.read?"var(--b)":"rgba(0,113,227,.3)"), borderRadius:12, cursor:"pointer" }}>
                    <p style={{ fontSize:13, fontWeight:n.read?400:700, color:n.read?"var(--text2)":"var(--accent)", marginBottom:4 }}>{n.message}</p>
                    <p style={{ fontSize:11, color:"var(--text3)" }}>{n.createdAt?new Date(n.createdAt).toLocaleDateString("ar-SA"):""} — {n.sentBy||t.from_admin}</p>
                    {n.type === "offer" && !n.candidateResponse && (
                      <div onClick={e=>e.stopPropagation()} style={{ marginTop:12 }}>
                        <div style={{ display:"flex", gap:8, marginBottom:8 }}>
                          <button onClick={async()=>{
                            const note = offerResponse[n.id]?.note || "";
                            await saveNotification({...n, candidateResponse:"موافق", candidateNote:note, responseAt:new Date().toISOString(), read:true});
                            setMyNotifs(p=>p.map(x=>x.id===n.id?{...x,candidateResponse:"موافق",candidateNote:note,read:true}:x));
                            addPersonEvent(myEmpId2,{type:"offer_response",text:"وافق على العرض الوظيفي",by:user.fullName||"المرشح",byRole:"candidate",private:false}).catch(()=>{});
                          }} className="btn btn-gold btn-sm">{t.offer_accept}</button>
                          <button onClick={async()=>{
                            const note = offerResponse[n.id]?.note || "";
                            if (!note.trim()) { showMsg("⚠️ "+t.required_on_decline); return; }
                            await saveNotification({...n, candidateResponse:"غير موافق", candidateNote:note, responseAt:new Date().toISOString(), read:true});
                            setMyNotifs(p=>p.map(x=>x.id===n.id?{...x,candidateResponse:"غير موافق",candidateNote:note,read:true}:x));
                            addPersonEvent(myEmpId2,{type:"offer_response",text:"رفض العرض — السبب: "+note,by:user.fullName||"المرشح",byRole:"candidate",private:false}).catch(()=>{});
                          }} className="btn btn-ghost btn-sm" style={{ color:"#f87171", border:"1px solid rgba(248,113,113,.3)" }}>{t.offer_reject}</button>
                        </div>
                        <textarea placeholder={t.offer_note_ph} rows={2}
                          value={offerResponse[n.id]?.note||""}
                          onChange={e=>setOfferResponse(p=>({...p,[n.id]:{...p[n.id],note:e.target.value}}))}
                          style={{ width:"100%", fontFamily:"inherit", fontSize:12, borderRadius:8, border:"1px solid var(--b)", background:"rgba(255,255,255,.04)", color:"var(--text)", padding:"6px 10px", resize:"vertical" }} />
                      </div>
                    )}
                    {n.candidateResponse && (
                      <div style={{ marginTop:8, padding:"6px 10px", borderRadius:8, background:n.candidateResponse==="موافق"?"rgba(74,222,128,.1)":"rgba(248,113,113,.1)", border:"1px solid "+(n.candidateResponse==="موافق"?"rgba(74,222,128,.3)":"rgba(248,113,113,.3)") }}>
                        <p style={{ fontSize:12, color:n.candidateResponse==="موافق"?"#4ade80":"#f87171", fontWeight:700 }}>{n.candidateResponse==="موافق"?t.accepted_msg:t.rejected_msg}</p>
                        {n.candidateNote && <p style={{ fontSize:12, color:"var(--text3)", marginTop:2 }}>{n.candidateNote}</p>}
                      </div>
                    )}
                    {!n.read && <span style={{ fontSize:9, background:"#ef4444", color:"#fff", borderRadius:8, padding:"1px 6px" }}>جديد</span>}
                  </div>
                ))}
              </div>
          }
        </div>
      )}
    </div>
  );
}


function JobsListPublic({ user, userType, lang="ar" }) {
  const t = PORTAL_I18N[lang] || PORTAL_I18N.ar;
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selJob, setSelJob] = useState(null);
  const [appliedIds, setAppliedIds] = useState([]);
  const { show, toastEl } = useToast();
  const today = new Date().toISOString().split("T")[0];

  useEffect(() => {
    getAllJobs().then(all => {
      setJobs(all.filter(j => j.status === "مفتوحة"));
      const key = "apps_" + (user.email || user.idNumber || "");
      db.get(key).then(v => setAppliedIds(v || []));
      setLoading(false);
    });
  }, []);

  const apply = async (job) => {
    if (appliedIds.includes(job.id)) return;
    const applicant = { id:user.idNumber||user.email, name:user.fullName||user.email, email:user.email, type:userType, appliedAt:new Date().toISOString() };
    const updJob = { ...job, applicants:[...(job.applicants||[]), applicant] };
    await saveJob(updJob);
    const key = "apps_" + (user.email || user.idNumber || "");
    const newIds = [...appliedIds, job.id];
    await db.set(key, newIds);
    setAppliedIds(newIds);
    setJobs(p => p.map(j => j.id===updJob.id ? updJob : j));
    if (selJob?.id===job.id) setSelJob(updJob);
    show(lang==="en" ? "✅ Application submitted for: " + job.title : "✅ تم تقديم طلبك على وظيفة: " + job.title);
  };

  if (selJob) return (
    <div>
      {toastEl}
      <button onClick={() => setSelJob(null)} className="btn btn-ghost btn-sm" style={{ marginBottom:16 }}>← رجوع</button>
      <JobPublicDetail job={selJob} today={today} applied={appliedIds.includes(selJob.id)} onApply={() => apply(selJob)} candidateData={user || null} />
    </div>
  );

  const openNow = jobs.filter(j => !j.openDate || j.openDate <= today);
  const upcoming = jobs.filter(j => j.openDate && j.openDate > today);

  const today2 = new Date().toISOString().split("T")[0];
  const openJobs = jobs.filter(j=>j.status==="مفتوحة"&&(!j.openDate||j.openDate<=today2)&&(!j.closeDate||j.closeDate>=today2));
  const upcomingJobs = jobs.filter(j=>j.status==="مفتوحة"&&j.openDate&&j.openDate>today2);

  return (
    <div>
      {toastEl}
      {/* Header */}
      <div style={{ marginBottom:18 }}>
        <h2 style={{ color:"var(--accent)", fontWeight:900, fontSize:20, marginBottom:4 }}>
          {lang==="en"?"Job Announcements":"إعلانات الوظائف"}
        </h2>
        <p style={{ color:"var(--text3)", fontSize:13 }}>
          {lang==="en"
            ? "Browse open positions at HMA Engineering Consulting"
            : "تصفح الوظائف المتاحة في مكتب هاني محمد عسيري للاستشارات الهندسية"}
        </p>
      </div>
      {loading ? <div style={{ textAlign:"center",padding:48 }}><div className="loader"/></div>
      : jobs.length === 0 ? (
        <div className="card" style={{ textAlign:"center",padding:48 }}>
          <p style={{ fontSize:36,marginBottom:10 }}>📭</p>
          <p style={{ color:"var(--text3)",fontSize:16 }}>{lang==="en"?"No open positions at the moment":"لا توجد وظائف مفتوحة حالياً"}</p>
        </div>
      ) : (
        <div>
          {openNow.length > 0 && (
            <div style={{ marginBottom:20 }}>
              <p style={{ color:"#4ade80",fontWeight:700,fontSize:13,marginBottom:10 }}>{lang==="en"?"🟢 Open Positions (":"🟢 وظائف مفتوحة الآن ("}{openNow.length})</p>
              {openNow.map(j=><JobCard key={j.id} job={j} today={today} applied={appliedIds.includes(j.id)} onView={()=>setSelJob(j)} onApply={()=>apply(j)} />)}
            </div>
          )}
          {upcoming.length > 0 && (
            <div>
              <p style={{ color:"#93c5fd",fontWeight:700,fontSize:13,marginBottom:10 }}>🔵 وظائف قادمة ({upcoming.length})</p>
              {upcoming.map(j=><JobCard key={j.id} job={j} today={today} applied={appliedIds.includes(j.id)} onView={()=>setSelJob(j)} onApply={null} />)}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── EmpAddPage — full-page employee add form (like CandForm for candidates) ──
function EmpAddPage({ libs, specsMap, onSave, onBack }) {
  const [data, setData] = useState({});
  const [tab, setTab] = useState(0);
  const [saving, setSaving] = useState(false);
  const [formErr, setFormErr] = useState("");
  const set = (k,v) => setData(p=>({...p,[k]:v}));
  const TABS = ["👤 البيانات الأساسية","💼 الخبرة","🏷️ التصنيفات"];

  const handleExtract = (ex) => {
    if (!ex) return;
    setData(prev => {
      const merged = { ...prev };
      Object.entries(ex).forEach(([k,v]) => {
        if (v===null||v===undefined) return;
        if (Array.isArray(v)&&v.length===0) return;
        // Never overwrite existing non-empty data with empty
        const existing = prev[k];
        if ((v==="" || (typeof v==="string" && v.trim()==="")) && existing && String(existing).trim()!=="") return;
        merged[k] = v;
      });
      return merged;
    });
    setTab(0);
  };

  const save = async () => {
    if (!data.fullName) { setFormErr("الاسم الكامل مطلوب"); return; }
    setSaving(true);
    await onSave(data);
    setSaving(false);
  };

  return (
    <div style={{ maxWidth:900, margin:"0 auto", padding:"22px 16px" }}>
      <div style={{ display:"flex", gap:9, marginBottom:18, alignItems:"center" }}>
        <button onClick={onBack} className="btn btn-ghost btn-sm">← رجوع</button>
        <span style={{ color:"var(--gold)", fontWeight:700 }}>إضافة موظف جديد</span>
      </div>

      {/* CV Upload */}
      <div style={{ marginBottom:16, background:"linear-gradient(135deg,rgba(201,168,76,.1),rgba(201,168,76,.04))", border:"2px solid rgba(201,168,76,.3)", borderRadius:14, padding:"14px 16px" }}>
        <p style={{ fontSize:13, fontWeight:900, color:"var(--gold)", marginBottom:8 }}>🤖 رفع السيرة الذاتية للاستخراج التلقائي</p>
        <CVExtractor onExtract={handleExtract} libs={libs} sessionEmail="" isAdmin={true} candidateId="" />
      </div>

      {/* Tabs */}
      <div style={{ display:"flex", gap:6, marginBottom:14, borderBottom:"1px solid var(--b)", paddingBottom:10 }}>
        {TABS.map((t,i) => (
          <button key={i} onClick={()=>setTab(i)}
            className={"tab-btn "+(tab===i?"tab-on":"tab-off")}
            style={{ fontSize:13 }}>
            {t}
          </button>
        ))}
      </div>

      {/* Form */}
      <div className="card-g fade">
        <InlineEditContent record={data} tab={tab===0?"info":tab===1?"exp":"tags"} type="employee" libs={libs} specsMap={specsMap}
          onSave={async(d)=>{ setData(d); }} hideFooter={true} />
      </div>

      {/* Navigation + Save */}
      <div style={{ display:"flex", justifyContent:"space-between", marginTop:14, marginBottom:80, flexWrap:"wrap", gap:8 }}>
        <div style={{ display:"flex", gap:7 }}>
          {tab > 0 && <button onClick={()=>setTab(p=>p-1)} className="btn btn-ghost">← السابق</button>}
          {tab < TABS.length-1 && <button onClick={()=>setTab(p=>p+1)} className="btn btn-gold">التالي →</button>}
        </div>
        {formErr && <p style={{ color:"var(--red)", fontSize:13 }}>{formErr}</p>}
        <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap" }}>
          <button onClick={save} disabled={saving} className="btn btn-gold" style={{ fontSize:14, padding:"10px 24px" }}>
            {saving ? "⏳ جاري الحفظ..." : "💾 حفظ البيانات"}
          </button>
          {onSmartCheck && (
            <button onClick={async()=>{
              const saved = await saveOnly();
              if(saved && onSmartCheck) { setData(saved); onSmartCheck(saved); }
            }} disabled={saving}
              style={{ padding:"10px 18px", borderRadius:10, border:"1px solid "+(
                data.aiCheckStatus==="checked" && data.aiCheckedAt && !data.aiCheckStatus?.includes("updated") ? "rgba(16,185,129,.5)" :
                data.aiCheckStatus==="updated_after_check" ? "rgba(245,158,11,.5)" :
                "rgba(96,165,250,.4)"
              ), background:
                data.aiCheckStatus==="checked" && !data.aiCheckStatus?.includes("updated") ? "rgba(16,185,129,.08)" :
                data.aiCheckStatus==="updated_after_check" ? "rgba(245,158,11,.08)" :
                "rgba(96,165,250,.06)",
              color:
                data.aiCheckStatus==="checked" && !data.aiCheckStatus?.includes("updated") ? "#10b981" :
                data.aiCheckStatus==="updated_after_check" ? "#f59e0b" :
                "#60a5fa",
              fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
              {data.aiCheckStatus==="checked" && !data.aiCheckStatus?.includes("updated")
                ? "✅ تم الفحص"
                : data.aiCheckStatus==="updated_after_check"
                ? "⚠️ تغيّرت البيانات — أعد الفحص"
                : "🔍 فحص ذكي"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

function EmployeeSectionWrapper({ emps, setEmps, libs, specsMap, onDelete, onReload }) {
  const [selEmpIds, setSelEmpIds] = useState([]);
  const [selEmp, setSelEmp] = useState(null);
  const [empPage, setEmpPage] = useState(0);
  const EMP_PAGE_SIZE = 100;
  const [showCompare, setShowCompare] = useState(false);
  const [showEvalAll, setShowEvalAll] = useState(false);
  const [evalLoading, setEvalLoading] = useState(false);
  const [showExcelEmp, setShowExcelEmp] = useState(false);
  const [addNewEmp, setAddNewEmp] = useState(false);
  const [showAIChat, setShowAIChat] = useState(false);
  const [showEmpArchive, setShowEmpArchive] = useState(false);
  const [empSearch, setEmpSearch] = useState("");
  const [empFilt, setEmpFilt] = useState({});
  const { confirm, dlg } = useConfirm();
  const { show, toastEl } = useToast();

  const toggleSelEmp = (id) => setSelEmpIds(p => p.includes(id)?p.filter(x=>x!==id):[...p,id]);

  const doDeleteSelected = async () => {
    if (!selEmpIds.length) return;
    if ((window._effectiveRole === "assistant_supervisor")) { show("⛔ ليس لديك صلاحية الحذف"); return; }
    const pw = window.prompt("أدخل كلمة مرور المدير العام لتأكيد حذف "+selEmpIds.length+" موظف:"); if(!pw) return; const pwOk = await verifyPassword("admin",pw); if(!pwOk){show("⛔ كلمة المرور غير صحيحة");return;} const names = selEmpIds.slice(0,5).map(id=>(emps.find(x=>(x.idNumber||x.email)===id)||{}).fullName||id).join("، "); const ok = await confirm("⚠️ حذف "+selEmpIds.length+" موظف؟\n\n"+names+(selEmpIds.length>5?"\n... و"+(selEmpIds.length-5)+" آخرين":""));
    if (!ok) return;
    for (const id of selEmpIds) {
      const e = emps.find(x=>(x.idNumber||x.email)===id);
      if (e) await delEmployee(id);
    }
    setEmps(p=>p.filter(x=>!selEmpIds.includes(x.idNumber||x.email)));
    setSelEmpIds([]);
    show("✅ تم الحذف");
  };

  const doEvalEmployees = async () => {
    const todo = selEmpIds.length>0
      ? emps.filter(e=>selEmpIds.includes(e.idNumber||e.email))
      : emps.filter(e=>!e.empEvaluation);
    if (!todo.length) { show("لا يوجد موظفون للتقييم"); return; }
    setEvalLoading(true);
    for (const e of todo) {
      try {
        const prompt = `قيّم هذا الموظف وأعط JSON فقط: {"score":75,"level":"متوسط","strengths":["s1"],"weaknesses":["w1"],"developmentAreas":["d1"],"summary":"..."}
المستويات: مبتدئ/متوسط/متقدم/خبير
الموظف: ${e.fullName}، خبرة: ${e.yearsExperience||0} سنة، تخصص: ${(e.specializations||[])[0]||"—"}، إدارة: ${e.department||"—"}، مهارات: ${(e.skills||[]).slice(0,5).join(",")||"—"}، شهادات: ${(e.certifications||[]).map(c=>c.name).join(",")||"—"}، دورات مكتملة: ${(e.courses||[]).filter(c=>c.status==="مكتملة").map(c=>c.name).join(",")||"—"}`;
        const res = await fetch(API, { method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify({ model:MODEL_FLASH, max_tokens:300, system:"HR evaluator. Return ONLY valid JSON.", messages:[{role:"user",content:prompt}] }) });
        const d = await res.json();
        const raw=(d?.content?.[0]?.text||"").replace(/```[\w]*/g,"").replace(/```/g,"").trim();
        const s=raw.indexOf("{"),en=raw.lastIndexOf("}");
        if(s>-1&&en>-1){
          const ev=JSON.parse(raw.slice(s,en+1));
          const upd={...e,empEvaluation:ev,empEvaluatedAt:new Date().toISOString()};
          await saveEmployee(upd);
          setEmps(p=>p.map(x=>(x.idNumber||x.email)===(upd.idNumber||upd.email)?upd:x));
          show("✅ "+e.fullName);
        }
      } catch {}
    }
    setEvalLoading(false);
    show("✅ اكتمل التقييم");
  };

  // ── Full-page add employee (like candidate add) ──
  if (addNewEmp) {
    return <EmpAddPage libs={libs} specsMap={specsMap} onSave={async (data) => {
      await saveEmployee({ ...data, employmentType: data.employmentType || "موظف دوام كامل", joinDate: data.joinDate || new Date().toISOString().split("T")[0] });
      onReload();
      setAddNewEmp(false);
      show("✅ تم حفظ الموظف: " + (data.fullName||""));
    }} onBack={() => setAddNewEmp(false)} />;
  }

  return (
    <div className="fade">
      {dlg}{toastEl}

      {showExcelEmp && <ExcelImport onImported={onReload} onClose={() => setShowExcelEmp(false)} defaultType="employee" />}
      {showAIChat && <GroupAIChat people={emps.filter(e=>selEmpIds.includes(e.idNumber||e.email)||selEmpIds.length===0?emps:emps.filter(e=>selEmpIds.includes(e.idNumber||e.email)))} type="موظف" onClose={()=>setShowAIChat(false)} />}
      {showEmpArchive && <AIAnalysisArchive onClose={()=>setShowEmpArchive(false)} />}

      {/* Header — same layout as candidates */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12, flexWrap:"wrap", gap:10 }}>
        <div>
          <h2 style={{ color:"var(--gold)", fontWeight:900, fontSize:22, marginBottom:4 }}>👨‍💼 الموظفون</h2>
          <p style={S.txt3s13}>{emps.length} موظف</p>
        </div>
        {(() => {
          const today = new Date();
          const expiredContracts = emps.filter(e=>e.contractEnd && new Date(e.contractEnd)<today).length;
          const expiringContracts = emps.filter(e=>{if(!e.contractEnd)return false;const d=Math.floor((new Date(e.contractEnd)-today)/86400000);return d>=0&&d<90;}).length;
          const expiredHaya = emps.filter(e=>e.hayaExpiry && new Date(e.hayaExpiry)<today).length;
          return (
            <div style={{ display:"flex", gap:7, flexWrap:"wrap" }}>
              {expiredContracts>0 && <span style={{ padding:"4px 12px", borderRadius:16, background:"rgba(239,68,68,.12)", color:"#f87171", border:"1px solid rgba(239,68,68,.3)", fontSize:12, fontWeight:700 }}>❌ {expiredContracts} عقد منتهٍ</span>}
              {expiringContracts>0 && <span style={{ padding:"4px 12px", borderRadius:16, background:"rgba(234,179,8,.12)", color:"#fbbf24", border:"1px solid rgba(234,179,8,.3)", fontSize:12, fontWeight:700 }}>⚠️ {expiringContracts} تنتهي قريباً</span>}
              {expiredHaya>0 && <span style={{ padding:"4px 12px", borderRadius:16, background:"rgba(239,68,68,.12)", color:"#f87171", border:"1px solid rgba(239,68,68,.3)", fontSize:12, fontWeight:700 }}>🏛️ {expiredHaya} هيئة منتهية</span>}
            </div>
          );
        })()}
      </div>
      {/* ── 2. Action buttons + Bulk actions ── */}
      <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginBottom:16, justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
          <button onClick={()=>setAddNewEmp(true)} className="btn btn-green">➕ موظف جديد</button>
          <button onClick={()=>setShowExcelEmp(true)} className="btn btn-ghost btn-sm mob-hide" style={{ border:"1px solid rgba(34,197,94,.3)", color:"#4ade80" }}>📊 Excel</button>
          <button onClick={doEvalEmployees} className="btn btn-gold btn-sm"
            style={{ background:evalLoading?"rgba(239,68,68,.15)":"", borderColor:evalLoading?"rgba(239,68,68,.4)":"", color:evalLoading?"#f87171":"" }}>
            {evalLoading ? "⏹ إيقاف" : "🤖 تقييم AI"}
          </button>
        </div>
        {selEmpIds.length > 0 && (
          <div style={{ display:"flex", gap:6, alignItems:"center", flexWrap:"wrap" }}>
            <span style={{ color:"#c4b5fd", fontWeight:700, fontSize:12 }}>✓ {selEmpIds.length} محدد</span>
            {hasAIAccess(window._currentUser) && <>

            </>}
            <button onClick={doDeleteSelected} className="btn btn-danger btn-sm" style={{ fontSize:11 }}>🗑️ حذف</button>
            <button onClick={()=>setSelEmpIds([])} className="btn btn-ghost btn-sm" style={{ fontSize:11 }}>✕ إلغاء</button>
          </div>
        )}
      </div>

      {/* ── 3. Search & Filters ── */}
      <div className="card" style={{ marginBottom:14, padding:"12px 14px" }}>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap", alignItems:"center" }}>
          <div style={{ position:"relative", flex:"2 1 200px" }}>
            <span style={{ position:"absolute", right:10, top:"50%", transform:"translateY(-50%)", color:"var(--text3)", fontSize:14 }}>🔍</span>
            <input value={empSearch} onChange={e=>setEmpSearch(e.target.value)}
              placeholder="بحث بالاسم، التخصص، الإدارة..."
              style={{ width:"100%", height:34, padding:"0 32px 0 13px", fontSize:12, boxSizing:"border-box" }} />
          </div>
          <select value={empFilt.specId||""} onChange={e=>setEmpFilt(p=>({...p,specId:e.target.value}))} style={{ flex:"1 1 140px", height:34, fontSize:12, padding:"0 10px", boxSizing:"border-box" }}>
            <option value="">🏗️ كل التخصصات</option>
            {(libs.specs||[]).map(s=><option key={s.id} value={s.id}>{s.icon} {s.label}</option>)}
          </select>
          <select value={empFilt.dept||""} onChange={e=>setEmpFilt(p=>({...p,dept:e.target.value}))} style={{ flex:"1 1 130px", height:34, fontSize:12, padding:"0 10px", boxSizing:"border-box" }}>
            <option value="">🏢 كل الإدارات</option>
            {[...(new Set([
              ...emps.map(e=>e.department).filter(Boolean),
              ...(window._jobTitles||[]).map(t=>t.dept).filter(Boolean)
            ]))].sort().map(d=><option key={d}>{d}</option>)}
          </select>
          <select value={empFilt.empType||""} onChange={e=>setEmpFilt(p=>({...p,empType:e.target.value}))} style={{ flex:"1 1 130px", height:34, fontSize:12, padding:"0 10px", boxSizing:"border-box" }}>
            <option value="">👨‍💼 نوع الموظف</option>
            {[...(new Set(emps.map(e=>e.employmentType).filter(Boolean)))].map(t=><option key={t}>{t}</option>)}
          </select>
          {/* ── تصنيف الترشيح — multi-select ── */}
          {(()=>{
            const empTags=[...new Set(emps.flatMap(e=>[...(e.biSpec||[]),...(e.biSkill||[]),...(e.biDept||[]),...(e.biSW||[]),...(e.biProj||[]),...(e.biCert||[])].filter(t=>t.source==="screening").map(t=>t.ar||"")))].filter(Boolean);
            try { const idx=JSON.parse(localStorage.getItem("hma_qn:idx")||"[]"); idx.forEach(id=>{ try { const q=JSON.parse(localStorage.getItem("hma_qn:"+id)||"null"); if(q&&q.isScreening) { if(q.tagLabel&&!empTags.includes(q.tagLabel)) empTags.push(q.tagLabel); (q.optionTags||[]).forEach(t=>{if(t&&t.trim()&&!empTags.includes(t.trim())) empTags.push(t.trim());}); } } catch{} }); } catch{}
            const screenTags = [...new Set(empTags)].filter(Boolean);
            const selTags = empFilt.screenTags || [];
            if (screenTags.length === 0) return null;
            return (
              <div style={{ position:"relative", flex:"1 1 150px" }}>
                <button onClick={()=>setEmpFilt(p=>({...p,_screenDropdown:!p._screenDropdown}))}
                  style={{ width:"100%", height:34, padding:"0 12px", borderRadius:8, border:"1px solid "+(selTags.length?"rgba(167,139,250,.5)":"var(--b)"), background:selTags.length?"rgba(167,139,250,.08)":"var(--glass2)", color:selTags.length?"#a78bfa":"var(--text2)", fontFamily:"inherit", fontSize:12, fontWeight:700, cursor:"pointer", textAlign:"right", display:"flex", alignItems:"center", justifyContent:"center", boxSizing:"border-box" }}>
                  🎯 {selTags.length ? selTags.length + " تصنيف" : "تصنيفات الترشيح"}
                </button>
                {empFilt._screenDropdown && (
                  <div style={{ position:"absolute", top:"110%", right:0, left:0, background:"var(--dark2)", border:"1px solid var(--b)", borderRadius:10, padding:8, zIndex:99, maxHeight:200, overflowY:"auto", boxShadow:"0 8px 24px rgba(0,0,0,.4)" }}>
                    {screenTags.map(tag=>(
                      <label key={tag} style={{ display:"flex", alignItems:"center", gap:8, padding:"5px 8px", cursor:"pointer", borderRadius:6, background:selTags.includes(tag)?"rgba(167,139,250,.1)":"transparent" }}>
                        <input type="checkbox" checked={selTags.includes(tag)}
                          onChange={()=>setEmpFilt(p=>{
                            const cur = p.screenTags || [];
                            const next = cur.includes(tag) ? cur.filter(t=>t!==tag) : [...cur, tag];
                            return {...p, screenTags:next, _screenDropdown:true};
                          })}
                          style={{ width:14, height:14, accentColor:"#a78bfa" }} />
                        <span style={{ fontSize:12, color:selTags.includes(tag)?"#a78bfa":"var(--text2)" }}>{tag}</span>
                      </label>
                    ))}
                  </div>
                )}
              </div>
            );
          })()}
          
          {(empSearch||Object.keys(empFilt).some(k=>empFilt[k]&&!k.startsWith("_"))) && (
            <button onClick={()=>{setEmpSearch("");setEmpFilt({});}} className="btn btn-ghost btn-sm" style={{ color:"#f87171", border:"1px solid rgba(239,68,68,.3)", flexShrink:0 }}>
              ✕ مسح
            </button>
          )}
        </div>
      </div>

      <SmartFileImport libs={libs} onDone={onReload} />

      {/* ── 5. Employment type pills (above table) ── */}
      {emps.length > 0 && (
        <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:12 }}>
          {[
            { key:"موظف دوام كامل",      label:"دوام كامل",  icon:"🏢", color:"#60a5fa" },
            { key:"عقد مرن",             label:"عقد مرن",    icon:"🔄", color:"#a78bfa" },
            { key:"موظف دوام كامل ومرن", label:"كامل ومرن", icon:"⚡", color:"#34d399" },
            { key:"موظف سابق",           label:"سابق",       icon:"📁", color:"#94a3b8" },
          ].map(t => {
            const n = emps.filter(e=>e.employmentType===t.key).length;
            if (!n) return null;
            const active = empFilt.empType === t.key;
            return (
              <button key={t.key} onClick={()=>setEmpFilt(p=>({...p,empType:active?"":t.key}))}
                style={{ padding:"5px 12px", borderRadius:20, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700,
                  background:active?t.color+"22":"rgba(255,255,255,.04)",
                  border:"2px solid "+(active?t.color:"rgba(255,255,255,.08)"),
                  color:active?t.color:"var(--text3)" }}>
                {t.icon} {t.label} ({n})
              </button>
            );
          })}
        </div>
      )}

      <EmployeeSection
        selEmp={selEmp} setSelEmp={setSelEmp}
        emps={emps.filter(e => {
          const s = empSearch.toLowerCase();
          if (s && !e.fullName?.toLowerCase().includes(s) && !(e.specializations||[]).join(" ").toLowerCase().includes(s) && !e.department?.toLowerCase().includes(s)) return false;
          if (empFilt.specId && (e.primarySpecId||e.specId) !== empFilt.specId) return false;
          if (empFilt.empType && e.employmentType !== empFilt.empType) return false;
          if (empFilt.dept && e.department !== empFilt.dept) return false;
          if (empFilt.minScore && ((e.empEvaluation||{}).score||0) < +empFilt.minScore) return false;
          if (empFilt.dateFrom) { const d = e.updatedAt||e.createdAt||""; if (d && d < empFilt.dateFrom) return false; }
          if (empFilt.dateTo)   { const d = e.updatedAt||e.createdAt||""; if (d && d > empFilt.dateTo+"T23:59:59") return false; }
          if (empFilt.screenTags && empFilt.screenTags.length > 0) {
            const allTags = [...(e.biSpec||[]),...(e.biSkill||[]),...(e.biDept||[]),...(e.biSW||[]),...(e.biProj||[]),...(e.biCert||[])];
            const personScreenTags = allTags.filter(t => t.source === "screening").map(t => (t.ar||"").toLowerCase());
            if (!empFilt.screenTags.some(ft => personScreenTags.includes(ft.toLowerCase()))) return false;
          }
          return true;
        })}
        setEmps={setEmps} libs={libs} specsMap={specsMap}
        onDelete={onDelete}
        selIds={selEmpIds} onToggle={toggleSelEmp}
      />

      {/* ── Inline viewer below employee table ── */}
      {selEmp && (
        <ErrorBoundary>
        <InlineViewer
          record={selEmp}
          type="employee"
          libs={libs}
          specsMap={specsMap}
          onSave={async (data) => {
            const saved = await saveEmployee(data);
            setEmps(p => p.map(x => (x.idNumber||x.email)===(data.idNumber||data.email) ? data : x));
            setSelEmp({ ...data });
          }}
          onDelete={(e) => { onDelete(e); setSelEmp(null); }}
          onEval={null}
          evalLoad={false}
          onClose={() => setSelEmp(null)}
        />
        </ErrorBoundary>
      )}
    </div>
  );
}

// ── CompareModal — unified table + AI chat for candidates & employees ─────────
function CompareModal({ people, type, onClose }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [aiLoading, setAiLoading] = useState(false);
  const [tableData, setTableData] = useState(null);
  const [tableLoading, setTableLoading] = useState(false);
  const chatEndRef = useRef(null);

  const isEmp = type === "موظف";

  const CONTEXT = people.map((p,i) => {
    const ev = p.empEvaluation || p.evaluation || {};
    const skills = (p.skills || [...((p.biSkill||[]).map(t=>t.ar||t.en||""))]).filter(Boolean).slice(0,5).join("،");
    const certs = isEmp
      ? (p.certifications||[]).map(c=>typeof c==="string"?c:c.name).filter(Boolean).join("،")
      : [...((p.biCert||[]).map(t=>t.ar||t.en||""))].filter(Boolean).slice(0,3).join("،");
    return `${i+1}. ${p.fullName}: خبرة ${p.yearsExperience||0}سنة، تخصص:${(p.specializations||[])[0]||"—"}، مهارات:${skills||"—"}، شهادات:${certs||"—"}، درجة:${ev.score||"—"}`;
  }).join("\n");

  const buildTable = async () => {
    setTableLoading(true);
    try {
      const fields = isEmp
        ? ["سنوات الخبرة","التخصص","المهارات الرئيسية","الشهادات","درجة التقييم","الإدارة","نوع التوظيف"]
        : ["سنوات الخبرة","التخصص","المهارات الرئيسية","الشهادات","درجة التقييم","التوصية","المدينة"];

      const prompt = `بناءً على بيانات ${isEmp?"الموظفين":"المرشحين"} التالية، أنشئ جدول مقارنة بصيغة JSON فقط:
${CONTEXT}

المعايير المطلوبة: ${fields.join("، ")}

أعد JSON فقط بهذا الشكل بالضبط (لا تضف أي نص):
{"rows":[{"label":"سنوات الخبرة","values":["val1","val2",...]},{"label":"التخصص","values":[...]},...],"summary":"خلاصة قصيرة","top":"اسم الأفضل"}`;

      const res = await fetch(API, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ model:MODEL, max_tokens:600,
          system:"Return ONLY valid JSON. No markdown, no explanation.",
          messages:[{role:"user",content:prompt}] })
      });
      const d = await res.json();
      const raw=(d?.content?.[0]?.text||"").replace(/```[\w]*/g,"").replace(/```/g,"").trim();
      const s=raw.indexOf("{"),e=raw.lastIndexOf("}");
      if(s>-1&&e>-1) setTableData(JSON.parse(raw.slice(s,e+1)));
    } catch(err) { console.error(err); }
    setTableLoading(false);
  };

  useEffect(() => { buildTable(); }, []);

  const send = async () => {
    if (!input.trim() || aiLoading) return;
    const userMsg = {role:"user", content:input};
    const history = [...messages, userMsg];
    setMessages(history);
    setInput("");
    setAiLoading(true);
    try {
      const res = await fetch(API, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:MODEL, max_tokens:500,
          system:`أنت مساعد موارد بشرية. تقارن ${isEmp?"موظفين":"مرشحين"}:\n${CONTEXT}\nأجب بالعربية باختصار ووضوح.`,
          messages: history.map(m=>({role:m.role,content:m.content}))
        })
      });
      const d = await res.json();
      const reply = d?.content?.[0]?.text || "❌ لم يتم الرد";
      setMessages(p=>[...p,{role:"assistant",content:reply}]);
      setTimeout(()=>chatEndRef.current?.scrollIntoView({behavior:"smooth"}),100);
    } catch(e){ setMessages(p=>[...p,{role:"assistant",content:"❌ "+e.message}]); }
    setAiLoading(false);
  };

  const CELL_W = Math.floor(100 / (people.length+1));

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.85)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:12 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, width:"100%", maxWidth:860, maxHeight:"94vh", display:"flex", flexDirection:"column" }}>

        {/* Header */}
        <div style={{ padding:"14px 20px", borderBottom:"1px solid rgba(255,255,255,.07)", display:"flex", justifyContent:"space-between", alignItems:"center", flexShrink:0 }}>
          <div>
            <h3 style={{ color:"var(--gold,#c9a84c)", fontWeight:900, fontSize:16 }}>🔄 مقارنة {isEmp?"الموظفين":"المرشحين"}</h3>
            <p style={{ color:"var(--text2,#8b949e)", fontSize:12, marginTop:2 }}>{people.map(p=>p.fullName.split(" ")[0]).join(" · ")}</p>
          </div>
          <button onClick={onClose} style={{ background:"#ff5f57", border:"none", borderRadius:"50%", width:13, height:13, cursor:"pointer", flexShrink:0, padding:0, boxShadow:"0 0 0 1px rgba(0,0,0,.2)" }} title="إغلاق"/>
        </div>

        <div style={{ flex:1, overflowY:"auto", padding:"16px 20px" }}>
          {/* Comparison table */}
          {tableLoading ? (
            <div style={{ textAlign:"center", padding:32 }}>
              <div className="loader" />
              <p style={{ color:"var(--text2,#8b949e)", fontSize:13, marginTop:10 }}>جاري تحليل البيانات...</p>
            </div>
          ) : tableData ? (
            <div style={{ marginBottom:18 }}>
              {/* Top pick banner */}
              {tableData.top && (
                <div style={{ padding:"9px 16px", background:"rgba(201,168,76,.1)", border:"1px solid var(--modal-border)", borderRadius:10, marginBottom:12, display:"flex", gap:10, alignItems:"center" }}>
                  <span style={{ fontSize:18 }}>🏆</span>
                  <span style={{ color:"var(--gold,#c9a84c)", fontWeight:700, fontSize:14 }}>الأفضل: {tableData.top}</span>
                </div>
              )}

              {/* Table */}
              <div style={{ overflowX:"auto" }}>
                <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
                  <thead>
                    <tr style={{ background:"rgba(255,255,255,.04)" }}>
                      <th style={{ padding:"10px 12px", textAlign:"right", color:"var(--text2,#8b949e)", fontWeight:700, width:CELL_W+"%", borderBottom:"2px solid rgba(255,255,255,.1)" }}>المعيار</th>
                      {people.map((p,i)=>(
                        <th key={i} style={{ padding:"10px 12px", textAlign:"center", color:"var(--gold,#c9a84c)", fontWeight:700, width:CELL_W+"%", borderBottom:"2px solid rgba(201,168,76,.3)" }}>
                          {p.fullName.split(" ").slice(0,2).join(" ")}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {(tableData.rows||[]).map((row,ri)=>(
                      <tr key={ri} style={{ background:ri%2===0?"rgba(255,255,255,.02)":"transparent" }}>
                        <td style={{ padding:"9px 12px", color:"var(--text,#f0f6fc)", fontWeight:600, borderBottom:"1px solid rgba(255,255,255,.05)" }}>{row.label}</td>
                        {(row.values||[]).map((val,vi)=>(
                          <td key={vi} style={{ padding:"9px 12px", textAlign:"center", color:"var(--text2,#8b949e)", borderBottom:"1px solid rgba(255,255,255,.05)", fontSize:12 }}>
                            {val||"—"}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Summary */}
              {tableData.summary && (
                <div style={{ padding:"10px 14px", background:"rgba(255,255,255,.03)", border:"1px solid rgba(255,255,255,.07)", borderRadius:10, marginTop:12, fontSize:13, color:"var(--text2,#8b949e)", lineHeight:1.7 }}>
                  {tableData.summary}
                </div>
              )}
            </div>
          ) : null}

          {/* AI Chat */}
          <div style={{ borderTop:"1px solid rgba(255,255,255,.07)", paddingTop:14 }}>
            <p style={{ color:"var(--text2,#8b949e)", fontSize:12, marginBottom:10 }}>💬 اسأل عن {isEmp?"الموظفين":"المرشحين"} المحددين</p>
            <div style={{ display:"flex", flexDirection:"column", gap:10, maxHeight:240, overflowY:"auto", marginBottom:10 }}>
              {messages.map((m,i)=>(
                <div key={i} style={{ display:"flex", justifyContent:m.role==="user"?"flex-end":"flex-start" }}>
                  <div style={{ maxWidth:"80%", padding:"9px 13px", borderRadius:m.role==="user"?"12px 12px 4px 12px":"12px 12px 12px 4px", background:m.role==="user"?"rgba(201,168,76,.12)":"rgba(255,255,255,.05)", border:"1px solid "+(m.role==="user"?"rgba(201,168,76,.25)":"rgba(255,255,255,.08)"), fontSize:13, color:"var(--text,#f0f6fc)", lineHeight:1.6, whiteSpace:"pre-wrap" }}>
                    {m.content}
                  </div>
                </div>
              ))}
              {aiLoading && <div style={{ display:"flex" }}><div style={{ padding:"9px 14px", borderRadius:"12px 12px 12px 4px", background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.08)" }}><div className="loader" style={{ width:18,height:18 }}/></div></div>}
              <div ref={chatEndRef}/>
            </div>
            <div style={S.flex8}>
              <input value={input} onChange={e=>setInput(e.target.value)}
                onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}
                placeholder={"من الأفضل للترقية؟ ما الفجوات؟ اقترح خطة تطوير..."}
                style={{ flex:1, fontSize:13 }} />
              <button onClick={send} disabled={!input.trim()||aiLoading} className="btn btn-gold btn-sm" style={{ opacity:(!input.trim()||aiLoading)?0.5:1 }}>
                إرسال
              </button>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

