// ── AI Analysis Archive ───────────────────────────────────────────────────────
async function saveAIAnalysis(data) {
  const id = "aia_" + Date.now();
  const record = { ...data, id, savedAt: new Date().toISOString() };
  await db.set("aia:" + id, record);
  const idx = (await db.get("aia:idx")) || [];
  await db.set("aia:idx", [id, ...idx].slice(0, 50)); // keep last 50
  return record;
}
async function getAllAIAnalyses() {
  const idx = (await db.get("aia:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("aia:" + id)));
  return all.filter(Boolean);
}

// ── AI Reports Archive ────────────────────────────────────────────────────────
async function saveAIReport(data) {
  const id = "air_" + Date.now();
  const record = { ...data, id, savedAt: new Date().toISOString() };
  await db.set("air:" + id, record);
  const idx = (await db.get("air:idx")) || [];
  await db.set("air:idx", [id, ...idx].slice(0, 30));
  return record;
}
async function getAllAIReports() {
  const idx = (await db.get("air:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("air:" + id)));
  return all.filter(Boolean);
}


// ── AIAnalysisArchive — shows past AI analysis sessions ──────────────────────
function AIAnalysisArchive({ onClose }) {
  const [analyses, setAnalyses] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [viewing, setViewing]   = useState(null);
  const [continuing, setContinuing] = useState(null); // for continuing a chat

  useEffect(() => {
    getAllAIAnalyses().then(a => { setAnalyses(a); setLoading(false); });
  }, []);

  if (viewing) return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.85)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid #a78bfa44", borderRadius:18, padding:24, width:"100%", maxWidth:680, maxHeight:"92vh", display:"flex", flexDirection:"column" }}>
        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:14, flexShrink:0 }}>
          <div>
            <p style={{ color:"#a78bfa", fontWeight:900, fontSize:15 }}>🤖 تحليل AI — {new Date(viewing.savedAt).toLocaleDateString("ar-SA")}</p>
            <p style={{ fontSize:12, color:"var(--text3)" }}>👤 {viewing.by} · {viewing.personType} · {viewing.people?.length} شخص</p>
          </div>
          <button onClick={()=>setViewing(null)} style={{ background:"none", border:"none", color:"var(--text3)", cursor:"pointer", fontSize:20 }}>✕</button>
        </div>
        <div style={{ overflowY:"auto", flex:1, display:"flex", flexDirection:"column", gap:10 }}>
          {(viewing.messages||[]).map((m,i) => (
            <div key={i} style={{ padding:"10px 14px", borderRadius:10, background: m.role==="user"?"rgba(167,139,250,.08)":"rgba(255,255,255,.04)", border:"1px solid "+(m.role==="user"?"rgba(167,139,250,.25)":"var(--b)") }}>
              <p style={{ fontSize:11, color: m.role==="user"?"#a78bfa":"#4ade80", fontWeight:700, marginBottom:4 }}>{m.role==="user"?"👤 المشرف":"🤖 AI"}</p>
              <p style={{ fontSize:13, color:"var(--text)", lineHeight:1.7, whiteSpace:"pre-wrap" }}>{typeof m.content==="string"?m.content:JSON.stringify(m.content)}</p>
            </div>
          ))}
        </div>
        <div style={{ display:"flex", gap:8, marginTop:12, flexShrink:0 }}>
          <button onClick={()=>{ setContinuing(viewing); setViewing(null); }} className="btn btn-gold btn-sm">💬 استكمال المحادثة</button>
          <button onClick={()=>setViewing(null)} className="btn btn-ghost btn-sm">← رجوع</button>
        </div>
      </div>
    </div>
  );

  // Open GroupAIChat with previous messages
  if (continuing) return (
    <GroupAIChat
      people={continuing.people?.map(p=>({fullName:p.name, hrCode:p.hrCode})) || []}
      type={continuing.personType || "مرشح"}
      preloadMessages={continuing.messages || []}
      onClose={()=>setContinuing(null)}
    />
  );

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid rgba(245,158,11,.3)", borderRadius:18, padding:24, width:"100%", maxWidth:560, maxHeight:"90vh", overflowY:"auto" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <p style={{ color:"#f59e0b", fontWeight:900, fontSize:16 }}>📚 أرشيف تحليلات AI</p>
          <button onClick={onClose} style={{ background:"none", border:"none", color:"var(--text3)", cursor:"pointer", fontSize:20 }}>✕</button>
        </div>
        {loading ? <div style={{ textAlign:"center", padding:40 }}><div className="loader"/></div>
        : analyses.length === 0 ? <p style={{ color:"var(--text3)", textAlign:"center", padding:32 }}>لا توجد تحليلات سابقة</p>
        : <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {analyses.map(a => (
              <div key={a.id} onClick={()=>setViewing(a)}
                style={{ padding:"12px 16px", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:10, cursor:"pointer" }}
                onMouseEnter={e=>e.currentTarget.style.borderColor="#a78bfa44"}
                onMouseLeave={e=>e.currentTarget.style.borderColor="var(--b)"}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                  <div>
                    <p style={{ fontWeight:700, fontSize:13, color:"var(--text)", marginBottom:3 }}>
                      🤖 {a.personType} — {a.people?.map(p=>p.name).join("، ")||"—"}
                    </p>
                    <p style={{ fontSize:11, color:"var(--text3)" }}>
                      👤 {a.by} · {new Date(a.savedAt).toLocaleDateString("ar-SA")} · {a.messages?.length||0} رسائل
                    </p>
                  </div>
                  <span style={{ color:"#a78bfa", fontSize:12 }}>عرض ←</span>
                </div>
              </div>
            ))}
          </div>
        }
      </div>
    </div>
  );
}

function GroupAIChat({ people, type, onClose, preloadMessages }) {
  const [messages, setMessages] = useState(preloadMessages || []);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const chatRef = useRef(null);

  const CONTEXT = people.map((p,i) => {
    const ev = p.evaluation || p.empEvaluation || {};
    return `${i+1}. ${p.fullName} [${type}]: خبرة ${p.yearsExperience||0}سنة، تخصص:${(p.specializations||[])[0]||"—"}، إدارة:${p.department||"—"}، مهارات:${(p.skills||[...((p.biSkill||[]).map(t=>t.ar||""))]).slice(0,5).join(",")||"—"}، درجة AI:${ev.score||"لم يُقيَّم"}`;
  }).join("\n");

  const SYSTEM = `أنت مساعد موارد بشرية ذكي. لديك بيانات هؤلاء ${type === "موظف" ? "الموظفين" : "المرشحين"}:\n${CONTEXT}\n\nأجب بالعربية بشكل مفيد وعملي. يمكنك:
- مقارنتهم وترتيبهم
- اقتراح خطط تطوير
- تحليل الفجوات في المهارات
- اقتراح دورات تدريبية
- وضع توصيات للترقية أو التوظيف
- الإجابة على أي سؤال يتعلق بهم`;

  const send = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role:"user", content:input };
    const history = [...messages, userMsg];
    setMessages(history);
    setInput("");
    setLoading(true);
    // Auto-save to archive
    const archiveEntry = {
      type: "group_analysis",
      people: people.map(p=>({name:p.fullName, hrCode:p.hrCode})),
      personType: type,
      by: window._currentUser?.displayName || "المشرف",
      byUsername: window._currentUser?.username || "",
      messages: history,
    };
    saveAIAnalysis(archiveEntry).catch(()=>{});
    // Add salary context for employees
    let systemContext = "أنت مساعد موارد بشرية. أجب بالعربية.";
    if (type === "موظف") {
      const scale = await getSalaryScale().catch(()=>null);
      const salaryInfo = people.map(p => {
        const exp = Number(p.yearsExperience)||0;
        const suggested = scale ? getSuggestedSalary(scale, exp) : null;
        const actual = Number(p.basicSalary||p.salary||0);
        const diff = suggested ? actual - suggested.basic : 0;
        return p.fullName + ": راتب فعلي=" + (actual||"غير محدد") + " | مقترح=" + (suggested?.basic||"—") + (diff?(" | فرق="+(diff>0?"+":"")+diff):"") + "\n";

      }).join("");
      if (salaryInfo) systemContext += "\n\nمعلومات الرواتب للمقارنة مع السلم:\n" + salaryInfo;



    }
    try {
      const res = await fetch(API, {
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:MODEL, max_tokens:800, system:SYSTEM,
          messages: history.map(m=>({ role:m.role, content:m.content }))
        })
      });
      const d = await res.json();
      const reply = d?.content?.[0]?.text || "عذراً، لم أتمكن من الرد";
      setMessages(p=>[...p, { role:"assistant", content:reply }]);
    } catch(e) {
      setMessages(p=>[...p, { role:"assistant", content:"❌ خطأ: "+e.message }]);
    }
    setLoading(false);
    setTimeout(()=>chatRef.current?.scrollTo(0,9999),100);
  };

  const SUGGESTIONS = type==="موظف" ? [
    "قارن بين هؤلاء الموظفين وحدد الأفضل أداءً",
    "اقترح خطة تطوير لرفع كفاءة هذه المجموعة",
    "ما الدورات المناسبة لهم بناءً على تخصصاتهم؟",
    "من منهم مؤهل للترقية؟ ولماذا؟",
    "ما الفجوات في مهارات هذه المجموعة؟"
  ] : [
    "قارن بين هؤلاء المرشحين وأعطني ترتيبهم",
    "من الأنسب للتوظيف ولماذا؟",
    "ما نقاط القوة والضعف لكل مرشح؟",
    "اقترح توصية لكل مرشح منهم",
    "هل يمكن توظيف أكثر من واحد؟ لأي أدوار؟"
  ];

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.8)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, width:"100%", maxWidth:620, height:"85vh", display:"flex", flexDirection:"column" }}>

        {/* Header */}
        <div style={{ padding:"16px 20px", borderBottom:"1px solid rgba(255,255,255,.07)", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div>
            <h3 style={{ color:"var(--gold,#c9a84c)", fontWeight:900, fontSize:16 }}>🤖 محادثة AI</h3>
            <p style={{ color:"var(--text2,#8b949e)", fontSize:12, marginTop:2 }}>
              {people.length+" "+(type==="موظف"?"موظف محدد":"مرشح محدد")+" — "+people.map(p=>p.fullName.split(" ")[0]).join("، ")}
            </p>
          </div>
          <button onClick={onClose} style={{ background:"#ff5f57", border:"none", borderRadius:"50%", width:13, height:13, cursor:"pointer", flexShrink:0, padding:0, boxShadow:"0 0 0 1px rgba(0,0,0,.2)" }} title="إغلاق"/>
        </div>

        {/* Chat area */}
        <div ref={chatRef} style={{ flex:1, overflowY:"auto", padding:"16px 20px", display:"flex", flexDirection:"column", gap:12 }}>
          {messages.length===0 && (
            <div>
              <p style={{ color:"var(--text2,#8b949e)", fontSize:13, marginBottom:14, textAlign:"center" }}>
                {"اسألني أي شيء عن "+(type==="موظف"?"هؤلاء الموظفين":"هؤلاء المرشحين")}
              </p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:7 }}>
                {SUGGESTIONS.map((s,i)=>(
                  <button key={i} onClick={()=>setInput(s)}
                    style={{ padding:"7px 13px", borderRadius:9, cursor:"pointer", fontFamily:"inherit", fontSize:12, background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.1)", color:"var(--text2,#8b949e)", textAlign:"right", lineHeight:1.4 }}>
                    {s}
                  </button>
                ))}
              </div>
            </div>
          )}
          {messages.map((m,i)=>(
            <div key={i} style={{ display:"flex", justifyContent:m.role==="user"?"flex-end":"flex-start" }}>
              <div style={{ maxWidth:"85%", padding:"10px 14px", borderRadius:m.role==="user"?"12px 12px 4px 12px":"12px 12px 12px 4px", background:m.role==="user"?"rgba(201,168,76,.15)":"rgba(255,255,255,.05)", border:"1px solid "+(m.role==="user"?"rgba(201,168,76,.3)":"rgba(255,255,255,.08)"), fontSize:13, color:"var(--text,#f0f6fc)", lineHeight:1.7, whiteSpace:"pre-wrap" }}>
                {m.content}
              </div>
            </div>
          ))}
          {loading && (
            <div style={{ display:"flex", justifyContent:"flex-start" }}>
              <div style={{ padding:"10px 16px", borderRadius:"12px 12px 12px 4px", background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.08)" }}>
                <div className="loader" style={{ width:20, height:20 }} />
              </div>
            </div>
          )}
        </div>

        {/* Input */}
        <div style={{ padding:"14px 16px", borderTop:"1px solid rgba(255,255,255,.07)", display:"flex", gap:9 }}>
          <textarea
            value={input} onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}
            placeholder={"اسأل عن "+(type==="موظف"?"الموظفين":"المرشحين")+"..."}
            style={{ flex:1, resize:"none", minHeight:44, maxHeight:100, fontSize:13, padding:"10px 12px" }}
          />
          <button onClick={send} disabled={!input.trim()||loading} className="btn btn-gold" style={{ alignSelf:"flex-end", padding:"10px 18px", opacity:(!input.trim()||loading)?0.5:1 }}>
            إرسال
          </button>
        </div>
      </div>
    </div>
  );
}

