// ── Development & Innovation Section ─────────────────────────────────────────
async function saveProposal(data) {
  const id = data.id || ("prop_"+Date.now());
  const rec = { ...data, id, updatedAt: new Date().toISOString() };
  await db.set("prop:"+id, rec);
  const idx = (await db.get("prop:idx")) || [];
  if (!idx.includes(id)) await db.set("prop:idx", [...idx, id]);
  return rec;
}
async function getAllProposals() {
  const idx = (await db.get("prop:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("prop:"+id)));
  return all.filter(Boolean);
}
// ── DevViewPane — read-only view of proposals & initiatives for one employee ──
function DevViewPane({ employees }) {
  const [proposals, setProposals] = useState([]);
  const [initiatives, setInitiatives] = useState([]);
  const [loading, setLoading] = useState(true);
  const empIds = new Set(employees.map(e => e.idNumber||e.email).filter(Boolean));

  useEffect(() => {
    Promise.all([getAllProposals(), getAllInitiatives()]).then(([p, i]) => {
      const myP = p.filter(x => empIds.has(x.submittedById) || employees.some(e=>e.fullName===x.submittedBy));
      const myI = i.filter(x => empIds.has(x.assignedTo) || employees.some(e=>e.fullName===x.assignedTo));
      setProposals(myP); setInitiatives(myI); setLoading(false);
    }).catch(()=>setLoading(false));
  }, []);

  if (loading) return <div style={{ textAlign:"center", padding:24 }}><div className="loader"/></div>;

  return (
    <div>
      <div className="sec" style={{ marginBottom:10 }}>💡 المقترحات والطلبات</div>
      {proposals.length === 0
        ? <p style={{ color:"var(--text3)", fontSize:13, marginBottom:16 }}>لا توجد مقترحات</p>
        : proposals.map(p => (
          <div key={p.id} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:10, padding:"10px 14px", marginBottom:8 }}>
            <div style={{ fontWeight:700, fontSize:13, marginBottom:3 }}>{p.title}</div>
            <div style={S.txt3s11}>{p.type} · {new Date(p.createdAt).toLocaleDateString("ar-SA")}</div>
            {p.description && <p style={{ fontSize:12, color:"var(--text2)", marginTop:5, lineHeight:1.7 }}>{p.description}</p>}
          </div>
        ))
      }
      <div className="sec" style={{ marginBottom:10, marginTop:14 }}>🚀 المبادرات والدورات</div>
      {initiatives.length === 0
        ? <p style={S.txt3s13}>لا توجد مبادرات</p>
        : initiatives.map(i => (
          <div key={i.id} style={{ background:"var(--glass)", border:"1px solid var(--b)", borderRadius:10, padding:"10px 14px", marginBottom:8 }}>
            <div style={{ fontWeight:700, fontSize:13, marginBottom:3 }}>{i.title}</div>
            <div style={S.txt3s11}>{i.type||""} · {i.status||""}</div>
          </div>
        ))
      }
    </div>
  );
}

