// ── Initiatives & Innovations Storage ────────────────────────────────────────
async function getAllInitiatives() {
  const idx = (await db.get("init:idx")) || [];
  const all = await Promise.all(idx.map(id => db.get("init:" + id)));
  return all.filter(Boolean);
}
async function saveInitiative(data) {
  const id = data.id || "init_" + Date.now();
  const record = { ...data, id, updatedAt: new Date().toISOString() };
  if (!data.createdAt) record.createdAt = record.updatedAt;
  await db.set("init:" + id, record);
  const idx = (await db.get("init:idx")) || [];
  if (!idx.includes(id)) await db.set("init:idx", [...idx, id]);
  return record;
}
// ── InitiativesMgr — full initiatives & innovations management ────────────────
function InitiativesMgr({ currentUser, employees, candidates }) {
  const [initiatives, setInitiatives] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [initSearch, setInitSearch]   = useState("");
  const [tab, setTab]                 = useState("all"); // all | office | mine
  const [showForm, setShowForm]       = useState(false);
  const [editItem, setEditItem]       = useState(null);
  const [selInit, setSelInit]         = useState(null);
  const [form, setForm]               = useState({
    title:"", type:"office", // office | employee | extra
    description:"", goal:"", source:"",
    needsTeam:false, teamSize:2, withCompensation:false,
    compensationType:"", status:"مقترحة",
    ownerId:"", ownerName:"",
    reward:"", rewardType:"مبلغ مالي", // مبلغ مالي | شهادة تقدير
    published:false,
    contributors:[],
  });
  const { show, toastEl } = useToast();
  const { confirm, dlg } = useConfirm();
  const isAdmin = currentUser?.username === "admin" || currentUser?.role === "hr_manager";
  const myId = currentUser?.linkedId || currentUser?.id || "";

  useEffect(() => { getAllInitiatives().then(d=>{ setInitiatives(d); setLoading(false); }); }, []);

  const set = (k,v) => setForm(p=>({...p,[k]:v}));

  const save = async () => {
    if (!form.title.trim()) { show("⚠️ عنوان المبادرة مطلوب"); return; }
    const record = await saveInitiative({
      ...form,
      id: editItem?.id,
      ownerId: form.ownerId || myId,
      ownerName: form.ownerName || currentUser?.displayName || "المشرف",
      createdBy: currentUser?.displayName || "المشرف",
      createdAt: editItem?.createdAt,
    });
    setInitiatives(p => editItem ? p.map(x=>x.id===record.id?record:x) : [...p, record]);
    show("✅ تم الحفظ"); setShowForm(false); setEditItem(null);
    setForm({title:"",type:"office",description:"",goal:"",source:"",needsTeam:false,teamSize:2,withCompensation:false,compensationType:"",status:"مقترحة",ownerId:"",ownerName:"",reward:"",rewardType:"مبلغ مالي",published:false,contributors:[]});
  };

  const joinInitiative = async (init) => {
    const contrib = { id:myId, name:currentUser?.displayName, joinedAt:new Date().toISOString() };
    const updated = { ...init, contributors:[...(init.contributors||[]).filter(c=>c.id!==myId), contrib] };
    await saveInitiative(updated);
    setInitiatives(p=>p.map(x=>x.id===updated.id?updated:x));
    show("✅ تم تسجيل مساهمتك");
  };

  const STATUS_COLORS = {
    "مقترحة":"#94a3b8","قيد الدراسة":"#f59e0b","معتمدة":"#4ade80",
    "جارية":"#60a5fa","مكتملة":"#22c55e","مرفوضة":"#f87171","موقوفة":"#9ca3af"
  };
  const TYPE_LABELS = { office:"🏢 من المكتب", employee:"💡 من موظف" };

  const filtered = initiatives.filter(init => {
    if (tab === "mine") return init.ownerId === myId || (init.contributors||[]).some(c=>c.id===myId);
    if (tab === "office") return init.type === "office";
    if (tab === "employee") return init.type === "employee";
    if (tab === "extra") return init.type === "extra";
    return true;
  }).filter(init => isAdmin || init.published || init.ownerId === myId)
    .filter(init => !initSearch.trim() || [init.title, init.description, init.ownerName, init.goal].join(" ").toLowerCase().includes(initSearch.toLowerCase()));

  if (selInit) return (
    <div className="fade">
      {toastEl}{dlg}
      <button onClick={()=>setSelInit(null)} className="btn btn-ghost btn-sm" style={{ marginBottom:14 }}>← رجوع</button>
      <div className="card">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:16, flexWrap:"wrap", gap:10 }}>
          <div>
            <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:6 }}>
              <span style={{ fontSize:13, color:"var(--text3)" }}>{TYPE_LABELS[selInit.type]||selInit.type}</span>
              <span style={{ fontSize:11, padding:"2px 8px", borderRadius:8, background:(STATUS_COLORS[selInit.status]||"#94a3b8")+"22", border:"1px solid "+(STATUS_COLORS[selInit.status]||"#94a3b8")+"44", color:STATUS_COLORS[selInit.status]||"#94a3b8" }}>{selInit.status}</span>
            </div>
            <h2 style={{ color:"var(--gold)", fontWeight:900, fontSize:20 }}>{selInit.title}</h2>
            <p style={{ fontSize:12, color:"var(--text3)", marginTop:4 }}>بواسطة: {selInit.ownerName} · {selInit.createdAt?new Date(selInit.createdAt).toLocaleDateString("ar-SA"):""}</p>
          </div>
          {isAdmin && (
            <div style={{ display:"flex", gap:6 }}>
              <button onClick={()=>{setForm({...selInit});setEditItem(selInit);setShowForm(true);setSelInit(null);}} className="btn btn-ghost btn-sm">✏️ تعديل</button>
              {!selInit.published && <button onClick={async()=>{const u={...selInit,published:true};await saveInitiative(u);setInitiatives(p=>p.map(x=>x.id===u.id?u:x));setSelInit(u);show("✅ تم النشر");}} className="btn btn-gold btn-sm">📢 نشر</button>}
            </div>
          )}
        </div>

        {selInit.description && <div style={{ marginBottom:14 }}><p style={{ fontSize:13, color:"var(--text2)", lineHeight:1.8 }}>{selInit.description}</p></div>}
        {selInit.goal && <div style={{ padding:"10px 14px", background:"rgba(201,168,76,.06)", borderRadius:10, marginBottom:14 }}><p style={{ fontSize:12, color:"var(--gold)", fontWeight:700, marginBottom:4 }}>🎯 الهدف</p><p style={{ fontSize:13, color:"var(--text2)" }}>{selInit.goal}</p></div>}

        {selInit.needsTeam && (
          <div style={{ padding:"12px 16px", background:"rgba(96,165,250,.06)", border:"1px solid rgba(96,165,250,.2)", borderRadius:10, marginBottom:14 }}>
            <p style={{ color:"#93c5fd", fontWeight:700, fontSize:13, marginBottom:8 }}>👥 فريق العمل ({selInit.contributors?.length||0}/{selInit.teamSize})</p>
            {selInit.withCompensation && <p style={{ fontSize:12, color:"#4ade80", marginBottom:8 }}>✅ بمقابل مادي — {selInit.compensationType}</p>}
            {(selInit.contributors||[]).map(c=><p key={c.id} style={{ fontSize:12, color:"var(--text2)", marginBottom:3 }}>• {c.name}</p>)}
            {(selInit.contributors||[]).length < (selInit.teamSize||2) && (selInit.contributors||[]).every(c=>c.id!==myId) && (
              <button onClick={()=>joinInitiative(selInit)} className="btn btn-gold btn-sm" style={{ marginTop:8 }}>🙋 انضم للفريق</button>
            )}
          </div>
        )}

        {isAdmin && selInit.status === "مكتملة" && (
          <div style={{ padding:"12px 16px", background:"rgba(34,197,94,.06)", border:"1px solid rgba(34,197,94,.2)", borderRadius:10 }}>
            <p style={{ color:"#4ade80", fontWeight:700, fontSize:13, marginBottom:8 }}>🏆 المكافأة</p>
            <p style={{ fontSize:13, color:"var(--text2)" }}>{selInit.rewardType}: {selInit.reward||"غير محدد"}</p>
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="fade">
      {toastEl}{dlg}
      {showForm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.85)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"var(--modal-bg)", border:"1px solid var(--modal-border)", borderRadius:18, padding:24, width:"100%", maxWidth:640, maxHeight:"92vh", overflowY:"auto" }}>

            {/* Header */}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
              <div>
                <p style={{ color:"var(--gold)", fontWeight:900, fontSize:17 }}>
                  {editItem?"✏️ تعديل ":"➕ "}{form.type==="extra"?"عمل إضافي":form.type==="employee"?"مقترح موظف":"مبادرة المكتب"}
                </p>
                <p style={{ fontSize:11, color:"var(--text3)", marginTop:2 }}>
                  {form.type==="extra"?"تسجيل عمل إضافي خارج الدوام الرسمي":form.type==="employee"?"مقترح تقدم به موظف للمكتب":"مبادرة تطوير من المكتب للموظفين"}
                </p>
              </div>
              <button onClick={()=>{setShowForm(false);setEditItem(null);}} style={{ background:"none",border:"none",color:"var(--text3)",cursor:"pointer",fontSize:22 }}>✕</button>
            </div>

            {/* النوع والحالة */}
            <div className="g2" style={{ marginBottom:14 }}>
              <div className="field">
                <label className="label">النوع *</label>
                <select value={form.type} onChange={e=>set("type",e.target.value)}>
                  <option value="office">🏢 مبادرة المكتب</option>
                  <option value="employee">💡 مقترح موظف</option>
                  <option value="extra">⏰ عمل إضافي</option>
                </select>
              </div>
              <div className="field">
                <label className="label">الحالة</label>
                <select value={form.status} onChange={e=>set("status",e.target.value)}>
                  {["مقترحة","قيد الدراسة","معتمدة","جارية","مكتملة","مرفوضة","موقوفة"].map(s=>(
                    <option key={s}>{s}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* العنوان */}
            <div className="field" style={{ marginBottom:12 }}>
              <label className="label">
                {form.type==="extra"?"اسم العمل الإضافي *":form.type==="employee"?"عنوان المقترح *":"عنوان المبادرة *"}
              </label>
              <input value={form.title} onChange={e=>set("title",e.target.value)}
                placeholder={form.type==="extra"?"مثال: إنجاز مخططات مشروع X خارج الدوام":form.type==="employee"?"مثال: تطبيق نظام BIM في جميع المشاريع":"مثال: برنامج تدريبي على تقنيات BIM"} />
            </div>

            {/* الوصف والهدف */}
            <div className="g2" style={{ marginBottom:12 }}>
              <div className="field">
                <label className="label">الوصف التفصيلي</label>
                <textarea value={form.description} onChange={e=>set("description",e.target.value)}
                  rows={3} style={{ fontFamily:"inherit", fontSize:13 }}
                  placeholder="اشرح الفكرة أو العمل بالتفصيل..." />
              </div>
              <div className="field">
                <label className="label">الهدف / النتيجة المتوقعة</label>
                <textarea value={form.goal} onChange={e=>set("goal",e.target.value)}
                  rows={3} style={{ fontFamily:"inherit", fontSize:13 }}
                  placeholder="ماذا نريد أن نحقق؟" />
              </div>
            </div>

            {/* صاحب الفكرة */}
            {(form.type==="employee"||form.type==="extra") && (
              <div className="field" style={{ marginBottom:12 }}>
                <label className="label">
                  {form.type==="extra"?"الموظف المنفذ *":"صاحب الفكرة / مقدم المقترح *"}
                </label>
                <select value={form.ownerId} onChange={e=>{
                  const emp = employees.find(x=>(x.uid||x.idNumber||x.email)===e.target.value);
                  set("ownerId",e.target.value); set("ownerName",emp?.fullName||"");
                }}>
                  <option value="">-- اختر موظفاً</option>
                  {employees.map(e=><option key={e.uid||e.email} value={e.uid||e.idNumber||e.email}>{e.fullName}</option>)}
                </select>
              </div>
            )}

            {/* الفريق */}
            <div style={{ padding:"12px 14px", background:"rgba(255,255,255,.03)", borderRadius:10, marginBottom:12, border:"1px solid var(--b)" }}>
              <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer", marginBottom:8 }}>
                <input type="checkbox" checked={form.needsTeam} onChange={e=>set("needsTeam",e.target.checked)} style={{ accentColor:"#60a5fa", width:15, height:15 }} />
                <span style={{ fontSize:13, fontWeight:700, color:"#60a5fa" }}>👥 يحتاج فريق عمل</span>
              </label>
              {form.needsTeam && (
                <div>
                  <div className="g2" style={{ marginBottom:8 }}>
                    <div className="field" style={{ marginBottom:0 }}>
                      <label className="label">الحجم المطلوب</label>
                      <input type="number" min={1} max={20} value={form.teamSize} onChange={e=>set("teamSize",+e.target.value)} />
                    </div>
                    <div className="field" style={{ marginBottom:0 }}>
                      <label className="label">إضافة عضو من الموظفين</label>
                      <select onChange={e=>{
                        if (!e.target.value) return;
                        const emp = employees.find(x=>(x.uid||x.idNumber||x.email)===e.target.value);
                        if (!emp) return;
                        const id = e.target.value;
                        if ((form.contributors||[]).some(c=>c.id===id)) return;
                        set("contributors",[...(form.contributors||[]),{id,name:emp.fullName,type:"employee"}]);
                        e.target.value="";
                      }}>
                        <option value="">-- اختر موظفاً</option>
                        {employees.filter(e=>!(form.contributors||[]).some(c=>c.id===(e.uid||e.idNumber||e.email))).map(e=>(
                          <option key={e.uid||e.email} value={e.uid||e.idNumber||e.email}>{e.fullName}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                  {(form.contributors||[]).length > 0 && (
                    <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:8 }}>
                      {(form.contributors||[]).map(c=>(
                        <span key={c.id} style={{ padding:"3px 10px", borderRadius:20, background:"rgba(96,165,250,.12)", border:"1px solid rgba(96,165,250,.3)", fontSize:12, color:"#93c5fd", display:"flex", alignItems:"center", gap:6 }}>
                          {c.name}
                          <button onClick={()=>set("contributors",(form.contributors||[]).filter(x=>x.id!==c.id))} style={{ background:"none",border:"none",color:"#f87171",cursor:"pointer",fontSize:12,padding:0,lineHeight:1 }}>✕</button>
                        </span>
                      ))}
                    </div>
                  )}
                  <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer" }}>
                    <input type="checkbox" checked={form.withCompensation} onChange={e=>set("withCompensation",e.target.checked)} style={{ accentColor:"#4ade80" }} />
                    <span style={{ fontSize:12, color:"var(--text3)" }}>بمقابل مادي (عقد مرن / بارت تايم)</span>
                  </label>
                  {form.withCompensation && (
                    <div className="field" style={{ marginTop:8, marginBottom:0 }}>
                      <label className="label">تفاصيل المقابل</label>
                      <input value={form.compensationType} onChange={e=>set("compensationType",e.target.value)} placeholder="مبلغ / عقد / وصف..." />
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* المكافأة */}
            {["مكتملة","معتمدة"].includes(form.status) && (
              <div style={{ padding:"12px 14px", background:"rgba(34,197,94,.04)", borderRadius:10, marginBottom:12, border:"1px solid rgba(34,197,94,.15)" }}>
                <p style={{ fontSize:12, color:"#4ade80", fontWeight:700, marginBottom:10 }}>🏆 المكافأة</p>
                <div className="g2">
                  <div className="field" style={{ marginBottom:0 }}>
                    <label className="label">نوع المكافأة</label>
                    <select value={form.rewardType} onChange={e=>set("rewardType",e.target.value)}>
                      <option>مبلغ مالي</option><option>شهادة تقدير</option><option>كلاهما</option>
                    </select>
                  </div>
                  <div className="field" style={{ marginBottom:0 }}>
                    <label className="label">قيمة / وصف المكافأة</label>
                    <input value={form.reward} onChange={e=>set("reward",e.target.value)} placeholder="المبلغ أو الوصف" />
                  </div>
                </div>
              </div>
            )}

            {/* النشر والإجراءات */}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
              <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer" }}>
                <input type="checkbox" checked={form.published} onChange={e=>set("published",e.target.checked)} style={{ accentColor:"#a78bfa", width:15, height:15 }} />
                <span style={{ fontSize:13 }}>📢 نشر للموظفين</span>
              </label>
            </div>
            <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
              <button onClick={()=>{setShowForm(false);setEditItem(null);}} className="btn btn-ghost btn-sm">إلغاء</button>
              <button onClick={save} className="btn btn-gold">💾 حفظ</button>
            </div>
          </div>
        </div>
      )}

      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16, flexWrap:"wrap", gap:10 }}>
        <h2 style={S.gold900s20}>💡 المبادرات والابتكارات</h2>
        {isAdmin && <button onClick={()=>{setForm({title:"",type:"office",description:"",goal:"",source:"",needsTeam:false,teamSize:2,withCompensation:false,compensationType:"",status:"مقترحة",ownerId:"",ownerName:"",reward:"",rewardType:"مبلغ مالي",published:false,contributors:[]});setEditItem(null);setShowForm(true);}} className="btn btn-gold">➕ إضافة جديدة</button>}
      </div>

      <div style={{ display:"flex", gap:6, marginBottom:10, flexWrap:"wrap" }}>
        {[{id:"all",l:"الكل"},{id:"office",l:"🏢 مبادرات المكتب"},{id:"employee",l:"💡 مقترحات الموظفين"},{id:"extra",l:"⏰ أعمال إضافية"},{id:"mine",l:"⭐ مشاركاتي"}].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{ padding:"5px 14px", borderRadius:20, cursor:"pointer", fontFamily:"inherit", fontSize:12, fontWeight:700,
              background:tab===t.id?"rgba(201,168,76,.2)":"none", border:"1px solid "+(tab===t.id?"rgba(201,168,76,.5)":"var(--b)"),
              color:tab===t.id?"var(--gold)":"var(--text3)" }}>
            {t.l}
          </button>
        ))}
      </div>
      <div style={{ position:"relative", marginBottom:16 }}>
        <span style={{ position:"absolute", right:10, top:"50%", transform:"translateY(-50%)", color:"var(--text3)", fontSize:14 }}>🔍</span>
        <input value={initSearch} onChange={e=>setInitSearch(e.target.value)} placeholder="بحث في المبادرات..."
          style={{ width:"100%", height:34, padding:"0 32px 0 13px", fontSize:12, boxSizing:"border-box" }} />
      </div>

      {loading ? <div style={{ textAlign:"center", padding:40 }}><div className="loader"/></div>
      : filtered.length === 0 ? <div className="card" style={{ textAlign:"center", padding:40 }}><p style={{ fontSize:32 }}>💡</p><p style={{ color:"var(--text3)" }}>لا توجد مبادرات</p></div>
      : <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {filtered.map(init => (
            <div key={init.id} onClick={()=>setSelInit(init)}
              style={{ padding:"14px 16px", background:"var(--glass)", border:"1px solid var(--b)", borderRadius:12, cursor:"pointer" }}
              onMouseEnter={e=>e.currentTarget.style.borderColor="rgba(201,168,76,.3)"}
              onMouseLeave={e=>e.currentTarget.style.borderColor="var(--b)"}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10 }}>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:5, flexWrap:"wrap" }}>
                    <span style={{ fontWeight:800, fontSize:14, color:"var(--text)" }}>{init.title}</span>
                    <span style={{ fontSize:10, padding:"2px 7px", borderRadius:7, background:(STATUS_COLORS[init.status]||"#94a3b8")+"22", color:STATUS_COLORS[init.status]||"#94a3b8" }}>{init.status}</span>
                    <span style={{ fontSize:11, color:"var(--text3)" }}>{TYPE_LABELS[init.type]||init.type}</span>
                  </div>
                  {init.description && <p style={{ fontSize:12, color:"var(--text3)", marginBottom:4 }}>{init.description.slice(0,100)}{init.description.length>100?"...":""}</p>}
                  <p style={{ fontSize:11, color:"var(--text3)" }}>
                    👤 {init.ownerName||"المكتب"} · {init.createdAt?new Date(init.createdAt).toLocaleDateString("ar-SA"):""}
                    {init.needsTeam&&<span style={{ marginRight:8 }}>· 👥 {init.contributors?.length||0}/{init.teamSize}</span>}
                  </p>
                </div>
                <span style={{ color:"var(--text3)", fontSize:16 }}>←</span>
              </div>
            </div>
          ))}
        </div>
      }
    </div>
  );
}

function DevelopmentSection({ candidates, employees, libs, singleMode=false }) {
  return (
    <div className="fade">
      <InitiativesMgr currentUser={window._currentUser} employees={employees} candidates={candidates} />
    </div>
  );
}

function ProposalsTab({ employees=[] }) {
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [empSearch, setEmpSearch] = useState("");
  const [showEmpDrop, setShowEmpDrop] = useState(false);
  const [form, setForm] = useState({ title:"", description:"", type:"مقترح", attachmentUrl:"", submittedBy:"", submittedById:"" });
  const { show, toastEl } = useToast();

  useEffect(() => { getAllProposals().then(p=>{setProposals(p.sort((a,b)=>b.updatedAt>a.updatedAt?1:-1));setLoading(false);}); }, []);

  const submit = async () => {
    if (!form.title.trim()) { show("❌ العنوان مطلوب"); return; }
    const saved = await saveProposal({ ...form, status:"جديد", createdAt:new Date().toISOString() });
    setProposals(p=>[saved,...p]);
    setForm({ title:"", description:"", type:"مقترح", attachmentUrl:"", submittedBy:"" });
    setShowForm(false);
    show("✅ تم رفع المقترح");
  };

  const TYPE_COLORS = { "مقترح":"#3b82f6","طلب دورة":"#a78bfa","فكرة تطوير":"#22c55e","شكوى":"#f59e0b" };

  return (
    <div>
      {toastEl}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
        <p style={S.txt2s13}>مقترحات وطلبات منسوبي المكتب — دورات، أفكار، مبادرات</p>
        <button onClick={()=>setShowForm(p=>!p)} className="btn btn-gold btn-sm">➕ رفع مقترح</button>
      </div>
      {showForm && (
        <div className="card" style={{ marginBottom:14, border:"1px solid rgba(59,130,246,.25)" }}>
          <div className="g2" style={{ marginBottom:10 }}>
            <div className="field"><label className="label">العنوان *</label><input value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))} placeholder="عنوان المقترح..." /></div>
            <div className="field"><label className="label">النوع</label>
              <select value={form.type} onChange={e=>setForm(p=>({...p,type:e.target.value}))}>
                <option>مقترح</option><option>طلب دورة</option><option>فكرة تطوير</option><option>شكوى</option>
              </select>
            </div>
            <div className="field" style={{ position:"relative" }}>
              <label className="label">مقدّم المقترح (موظف)</label>
              <input value={empSearch} onChange={e=>{ setEmpSearch(e.target.value); setShowEmpDrop(true); }}
                onFocus={()=>setShowEmpDrop(true)}
                placeholder="ابحث عن موظف..."
                style={{ width:"100%" }} />
              {showEmpDrop && empSearch && (
                <div style={{ position:"absolute", top:"100%", right:0, left:0, background:"var(--dark2)", border:"1px solid var(--b)", borderRadius:9, zIndex:50, maxHeight:160, overflowY:"auto", boxShadow:"0 4px 16px rgba(0,0,0,.4)" }}>
                  {employees.filter(e=>e.fullName?.toLowerCase().includes(empSearch.toLowerCase())).slice(0,6).map(e=>(
                    <div key={e.idNumber||e.email} onClick={()=>{ setForm(p=>({...p,submittedBy:e.fullName,submittedById:e.idNumber||e.email})); setEmpSearch(e.fullName); setShowEmpDrop(false); }}
                      style={{ padding:"8px 12px", cursor:"pointer", fontSize:13, borderBottom:"1px solid var(--b)" }}
                      onMouseEnter={ev=>ev.currentTarget.style.background="rgba(201,168,76,.08)"}
                      onMouseLeave={ev=>ev.currentTarget.style.background=""}>
                      <span style={{ fontWeight:700 }}>{e.fullName}</span>
                      <span style={{ fontSize:11, color:"var(--text3)", marginRight:6 }}>{e.department||""}</span>
                    </div>
                  ))}
                  {employees.filter(e=>e.fullName?.toLowerCase().includes(empSearch.toLowerCase())).length===0&&(
                    <p style={{ padding:"10px 12px", fontSize:12, color:"var(--text3)" }}>لا توجد نتائج</p>
                  )}
                </div>
              )}
            </div>
            <div className="field"><label className="label">رابط مرفق (Drive/YouTube)</label><input value={form.attachmentUrl} onChange={e=>setForm(p=>({...p,attachmentUrl:e.target.value}))} placeholder="https://..." /></div>
          </div>
          <div className="field" style={{ marginBottom:12 }}>
            <label className="label">التفاصيل</label>
            <textarea value={form.description} onChange={e=>setForm(p=>({...p,description:e.target.value}))} style={{ minHeight:80 }} placeholder="اشرح مقترحك بالتفصيل..." />
          </div>
          <div style={{ display:"flex", gap:9 }}>
            <button onClick={submit} className="btn btn-gold btn-sm">📤 إرسال</button>
            <button onClick={()=>setShowForm(false)} className="btn btn-ghost btn-sm">إلغاء</button>
          </div>
        </div>
      )}
      {loading?<div style={{ textAlign:"center",padding:32 }}><div className="loader"/></div>
      :proposals.length===0?<div className="card" style={{ textAlign:"center",padding:40 }}><p style={{ color:"var(--text3)" }}>لا توجد مقترحات بعد</p></div>
      :(
        <div style={{ display:"flex", flexDirection:"column", gap:9 }}>
          {proposals.map(p=>{
            const c=TYPE_COLORS[p.type]||"#666";
            return (
              <div key={p.id} className="card">
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:10, flexWrap:"wrap" }}>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", gap:7, alignItems:"center", marginBottom:5, flexWrap:"wrap" }}>
                      <span style={{ fontWeight:700 }}>{p.title}</span>
                      <span style={{ fontSize:11,padding:"2px 9px",borderRadius:10,background:c+"18",color:c,border:"1px solid "+c+"33" }}>{p.type}</span>
                      <span style={{ fontSize:11,padding:"2px 8px",borderRadius:8,background:"rgba(34,197,94,.1)",color:p.status==="مراجعة"?"#fbbf24":"#4ade80" }}>{p.status||"جديد"}</span>
                    </div>
                    {p.description&&<p style={{ fontSize:13,color:"var(--text2)",lineHeight:1.7,marginBottom:5 }}>{p.description}</p>}
                    <div style={{ fontSize:11,color:"var(--text3)",display:"flex",gap:10,flexWrap:"wrap" }}>
                      {p.submittedBy&&<span>👤 {p.submittedBy}</span>}
                      <span>📅 {new Date(p.createdAt).toLocaleDateString("ar-SA")}</span>
                      {p.attachmentUrl&&<a href={p.attachmentUrl} target="_blank" rel="noreferrer" style={{ color:"#93c5fd" }}>🔗 مرفق</a>}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
// ── Trash Section ─────────────────────────────────────────────────────────────
function TrashSection({ onRestore }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");
  const [selected, setSelected] = useState([]);
  const { confirm, dlg } = useConfirm();
  const { show, toastEl } = useToast();

  const TYPE_LABELS = {
    candidate: "👤 مرشح", employee: "👨‍💼 موظف", interview: "🎯 مقابلة",
    assessment: "🧪 اختبار", template: "📑 نموذج", commlog: "💬 تواصل",
    job: "📢 وظيفة", ptTask: "⏰ مهمة"
  };
  const TYPE_COLORS = {
    candidate: "#3b82f6", employee: "#a78bfa", interview: "#f59e0b",
    assessment: "#22c55e", template: "#ec4899", commlog: "#06b6d4",
    job: "#f97316", ptTask: "#84cc16"
  };

  useEffect(() => { load(); }, []);

  const load = async () => {
    setLoading(true);
    const all = await getAllTrash();
    setItems(all);
    setLoading(false);
  };

  const filtered = filter === "all" ? items : items.filter(x => x.type === filter);
  const toggleSel = (id) => setSelected(p => p.includes(id) ? p.filter(x=>x!==id) : [...p,id]);

  const getName = (item) => {
    const d = item.data || {};
    return d.fullName || d.title || d.candidateName || d.name || item.originalId;
  };

  const daysLeft = (item) => {
    const diff = Math.ceil((new Date(item.expiresAt) - new Date()) / 86400000);
    return diff;
  };

  const doRestore = async (item) => {
    await restoreFromTrash(item);
    setItems(p => p.filter(x => x.trashId !== item.trashId));
    setSelected(p => p.filter(x => x !== item.trashId));
    if (onRestore) onRestore();
    show("✅ تم الاسترجاع: " + getName(item));
  };

  const doRestoreSelected = async () => {
    const ok = await confirm("استرجاع " + selected.length + " عنصر؟");
    if (!ok) return;
    for (const id of selected) {
      const item = items.find(x => x.trashId === id);
      if (item) await restoreFromTrash(item);
    }
    setItems(p => p.filter(x => !selected.includes(x.trashId)));
    if (onRestore) onRestore();
    setSelected([]);
    show("✅ تم استرجاع " + selected.length + " عنصر");
  };

  const doDelete = async (item) => {
    const ok = await confirm("حذف نهائي لـ \"" + getName(item) + "\"؟ لا يمكن التراجع.");
    if (!ok) return;
    await permanentlyDelete(item);
    setItems(p => p.filter(x => x.trashId !== item.trashId));
    show("🗑️ تم الحذف النهائي");
  };

  const doDeleteSelected = async () => {
    const ok = await confirm("حذف نهائي لـ " + selected.length + " عنصر؟ لا يمكن التراجع.");
    if (!ok) return;
    for (const id of selected) {
      const item = items.find(x => x.trashId === id);
      if (item) await permanentlyDelete(item);
    }
    setItems(p => p.filter(x => !selected.includes(x.trashId)));
    setSelected([]);
    show("🗑️ تم الحذف النهائي");
  };

  const doEmptyTrash = async () => {
    const pw = window.prompt("أدخل كلمة مرور المدير العام للتأكيد:"); if(!pw) return; const pwOk = await verifyPassword("admin",pw); if(!pwOk){show("⛔ كلمة المرور غير صحيحة");return;} const ok = await confirm("⚠️ تفريغ سلة المحذوفات كاملاً؟ لا يمكن التراجع أبداً.");
    if (!ok) return;
    for (const item of items) await permanentlyDelete(item);
    setItems([]);
    setSelected([]);
    show("🗑️ تم تفريغ السلة");
  };

  const types = [...new Set(items.map(x => x.type))];

  return (
    <div className="fade">
      {dlg}{toastEl}

      {/* Header */}
      <div style={{ marginBottom:10 }}>
        <h2 style={{ color:"var(--gold)", fontWeight:900, fontSize:20, marginBottom:10 }}>🗑️ المحذوفات ({items.length})</h2>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
          {selected.length > 0 && (
            <button onClick={doRestoreSelected} className="btn btn-green btn-sm">{"↩️ استرجاع ("+selected.length+")"}</button>
          )}
          {selected.length > 0 && (
            <button onClick={doDeleteSelected} className="btn btn-danger btn-sm">{"🗑️ حذف نهائي ("+selected.length+")"}</button>
          )}
          {items.length > 0 && selected.length === 0 && (
            <button onClick={doEmptyTrash} className="btn btn-danger btn-sm" style={{ marginRight:"auto" }}>🗑️ تفريغ السلة</button>
          )}
        </div>
      </div>

      {/* Info banner */}
      <div style={{ padding:"10px 16px", background:"rgba(245,158,11,.07)", border:"1px solid rgba(245,158,11,.2)", borderRadius:10, marginBottom:16, fontSize:13, color:"#fbbf24" }}>
        ⚠️ العناصر المحذوفة تُحفظ لمدة 30 يوماً ثم تُحذف تلقائياً بشكل نهائي.
      </div>

      {/* Filter tabs */}
      <div style={{ display:"flex", gap:6, marginBottom:14, flexWrap:"wrap" }}>
        <button onClick={()=>setFilter("all")} className={"tab-btn "+(filter==="all"?"tab-on":"tab-off")}>الكل ({items.length})</button>
        {types.map(t=>(
          <button key={t} onClick={()=>setFilter(t)} className={"tab-btn "+(filter===t?"tab-on":"tab-off")}>
            {TYPE_LABELS[t]||t} ({items.filter(x=>x.type===t).length})
          </button>
        ))}
      </div>

      {/* Select all */}
      {filtered.length > 0 && (
        <div style={{ display:"flex", alignItems:"center", gap:10, padding:"6px 4px", marginBottom:8 }}>
          <input type="checkbox"
            checked={selected.length === filtered.length && filtered.length > 0}
            onChange={() => setSelected(p => p.length === filtered.length ? [] : filtered.map(x=>x.trashId))}
            style={{ width:15, height:15, cursor:"pointer" }} />
          <span style={S.txt3s12}>تحديد الكل</span>
          {selected.length > 0 && <span style={{ fontSize:12, color:"#93c5fd" }}>{selected.length} محدد</span>}
        </div>
      )}

      {loading ? (
        <div style={{ textAlign:"center", padding:40 }}><div className="loader"/></div>
      ) : filtered.length === 0 ? (
        <div className="card" style={{ textAlign:"center", padding:48 }}>
          <p style={{ fontSize:36, marginBottom:10 }}>✅</p>
          <p style={{ color:"var(--text3)", fontSize:16 }}>السلة فارغة</p>
        </div>
      ) : (
        <div style={S.flexCol8}>
          {filtered.map(item => {
            const isSel = selected.includes(item.trashId);
            const days = daysLeft(item);
            const urgent = days <= 7;
            const tc = TYPE_COLORS[item.type] || "#666";
            return (
              <div key={item.trashId}
                style={{ background:"var(--glass)", border:"1px solid "+(isSel?"rgba(59,130,246,.35)":"var(--b)"), borderRadius:12, padding:"12px 16px" }}>
                <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                  <input type="checkbox" checked={isSel}
                    onChange={()=>toggleSel(item.trashId)}
                    style={{ width:15, height:15, cursor:"pointer", flexShrink:0 }} />
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4, flexWrap:"wrap" }}>
                      <span style={{ fontWeight:700, fontSize:14 }}>{getName(item)}</span>
                      <span style={{ fontSize:11, padding:"2px 9px", borderRadius:10, background:tc+"18", color:tc, border:"1px solid "+tc+"33" }}>
                        {TYPE_LABELS[item.type]||item.type}
                      </span>
                      <span style={{ fontSize:11, color:urgent?"#f87171":"var(--text3)" }}>
                        {urgent ? "⚠️ " : "🕐 "}
                        {days <= 0 ? "ينتهي اليوم" : "يتبقى "+days+" يوم"}
                      </span>
                    </div>
                    <p style={S.txt3s11}>
                      {"🗑️ حُذف: "+new Date(item.deletedAt).toLocaleDateString("ar-SA")}
                    </p>
                  </div>
                  <div style={{ display:"flex", gap:6, flexShrink:0 }}>
                    <button onClick={()=>doRestore(item)} className="btn btn-green btn-sm" style={{ fontSize:12 }}>↩️ استرجاع</button>
                    <button onClick={()=>doDelete(item)} className="btn btn-danger btn-sm" style={{ fontSize:12 }}>🗑️</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

